window.BEAUBIRD_BIRD_PROFILE_SHARDS["shard-032.json"] = [{"name":"小山椒鸟","english_name":"Small Minivet","scientific_name":"Pericrocotus cinnamomeus","overview":"小山椒鸟（英文名：Small Minivet，学名：Pericrocotus cinnamomeus），是雀形目鹃鵙科山椒鸟属的最小成员。分布于热带南部亚洲，自印度次大陆至印尼。雄鸟具灰色冠、颊与背部，橙色胸渐变为腹部的黄色。雌鸟灰顶，黄色脸与下体，橙翼斑与尾缘。常见于棘丛林与灌木丛。","appearance":"小山椒鸟长约16厘米，体重6至12克。雄鸟具有深灰色眼区、面、上眼至耳羽、颏至喉部；额至背和肩羽呈淡灰色，臀部和尾上覆羽为鲜艳的红橙色；上翼黑如烟煤，大覆羽端橙色，初级飞羽有黄色闪光，次级飞羽淡橙色；最内侧两根尾羽黑如烟煤，其余四根主要为浅橙色；胸部鲜橙色，逐渐过渡至腹部的黄色和臀下覆羽的乳黄色；下翼覆羽淡黄色。雌鸟较雄鸟暗淡，上体、颊和冠为浅灰色，深灰色翅膀，白色喉部，下体淡黄。幼鸟似雌鸟，但头至背、小覆羽和中覆羽更棕色，白羽边缘，尾羽和覆羽边缘及尖端白色。各亚种在色彩深度和鲜艳程度上有所不同。","call":"发出尖细的连续‘swee swee’声，为接触叫声，通常重复。","habits":"栖息于森林、林地、红树林、荆棘林、灌木丛、果园和其他耕地，有时靠近村庄。偏好比同类更开阔的林地环境。海拔低至1600米。以蛾、毛虫、甲虫、蝉等昆虫为食，常在树冠群居觅食，加入混合物种群体，以树叶上的昆虫为食，偶尔捕捉飞行中的猎物。","breeding":"繁殖季节为2月至11月，主要集中在4月至9月。筑巢由双亲共同完成，约需7天，使用细枝、草茎、苔藓、死叶或树皮，内衬细根，用蛛丝固定，置于离地面高达14米的树枝或叉口。每窝产卵2至4枚，雌鸟孵卵，雄鸟提供食物。孵化期11天，幼鸟离巢期12天。","identification":"通过较小体型、灰顶与上体（面部较暗）、橙黄下体与同类区分。雌雄亚种在色彩深度和鲜艳程度上有差异。","protection":"IUCN：LC（无危）。在印度次大陆适宜生境中非常普遍；在孟加拉国广泛分布，局部常见；巴基斯坦局部存在；不丹罕见。东南亚大部分地区常见，但在泰国半岛因内陆缺乏记录而被视为‘Vulnerable’（易危）。爪哇和巴厘岛少见。19世纪在婆罗洲有可疑标本记录。","distribution":"分布于远东的巴基斯坦、印度、斯里兰卡至越南和马来半岛北部，间断分布于爪哇和巴厘岛。","other":"小山椒鸟形成小群，常见于受保护区域，如尼泊尔的皇家奇特旺国家公园和印度的纳加霍尔与基奥拉德奥加纳（巴哈特普尔）国家公园。"},{"name":"火红山椒鸟","english_name":"Fiery Minivet","scientific_name":"Pericrocotus igneus","overview":"火红山椒鸟（英文名：Fiery Minivet，学名：Pericrocotus igneus），是雀形目鹃鵙科山椒鸟属的鸟类。广泛分布于东南亚地区，包括泰国、马来西亚、印度尼西亚及菲律宾等地。居住在低地及山脚森林中，以小昆虫为食。火红山椒鸟以其独特的橙红色背部和黑色头部著称。","appearance":"成年雄鸟头部、肩部和肩羽呈光泽的黑色，背部至尾上覆羽为鲜艳的橙红色；翅膀为光泽的黑色，次级飞羽外缘有橙红色边框，形成明显的翼斑；尾羽中央两枚为黑色，其余为橙红色；下体橙红色，翼下覆羽黄色。雌鸟头部橙色，脸部、耳羽、头顶和颈背铅灰色，臀部和尾上覆羽橙红色，上翼灰色，翼斑较雄鸟淡且较小，下体黄色。幼鸟上体烟灰色带黄边，下体灰白色，喉部至腹部淡黄色。","call":"发出高而尖锐上升的'swee'声。","habits":"栖息于低地和山脚森林及森林边缘，主要以小昆虫如蚂蚁和甲虫为食，常在树冠层觅食，有时会访问无花果树。群居性较强，常见于混合物种觅食群体中。","breeding":"繁殖期从5月至7月，营巢于树叉上，由枝条和纤维构成，巢外覆盖苔藓和树皮碎片，蛋色为淡黄色，带有褐色和灰色斑点。","identification":"与赤红山椒鸟、长尾山椒鸟和短嘴山椒鸟相似，但体型更小，颜色更偏橙色而非红色，翼斑较小。雌性火红山椒鸟的橙红色臀部是独特的辨识特征。","protection":"IUCN：NT（近危）","distribution":"分布于马来半岛、苏门答腊岛、婆罗洲和菲律宾的巴拉望岛。","other":"因栖息地丧失而受到威胁，如森林砍伐和土地转换，以及森林火灾。"},{"name":"三色山椒鸟","english_name":"Little Minivet","scientific_name":"Pericrocotus lansbergei","overview":"三色山椒鸟（英文名：Little Minivet，学名：Pericrocotus lansbergei），是雀形目鹃鵙科山椒鸟属的鸟类。以黑色、白色和橙红色的鲜明对比羽毛而著称，栖息于亚热带或热带的湿润低地森林。","appearance":"成年雄性三色山椒鸟具有光泽的黑色头部、肩部和上胸，橙红色臀部和上尾覆羽；翅膀上部呈深黑色，中翼和大翼覆羽有橙红色斑块，尾羽基部广泛橙红；中央一对尾羽为黑色，其余为橙红色；胸部和上侧橙红色，其余下体纯白色。雌鸟相似但黑色部分被烟灰色取代，具淡黄色臀部，较小的翼斑，喉部及下体灰白至纯白色。幼鸟未详述。","call":"常发出轻柔的颤音叫声，包括高音的“tzee-tzee-tzee”或“tzee-tzee-tzew”声，也会发出短促尖锐的“pip”声。","habits":"在松巴哇岛和弗洛勒斯岛的低地森林及其边缘，开放的公园型森林中，通常在稀疏的下层植被中活动，海拔高度从海平面到1150米（松巴哇岛）和1820米（弗洛勒斯岛），主要在500米以下。以小型节肢动物为食，通常成对或小群体觅食，经常加入混合物种群。觅食时通过从中间层的水平栖息处掠食和悬停掠食。","breeding":"繁殖期为4月至6月，具体繁殖行为信息不足。","identification":"雄鸟与Cinnamomeus山椒鸟的区别在于头部和背部颜色更深，翅膀无黄色，腹部白色；与Flammeus山椒鸟相比体型更小，腹部白色。雌鸟与雄鸟的区别在于黑色部位被烟灰色替代，翼斑较小，喉部和下体灰白至白色。","protection":"IUCN：LC（无危）；是限制分布区物种，存在于北方努沙登加拉EBA；总体数量罕见，但在局部地区可达到中等常见程度。","distribution":"分布于澳大利亚新几内亚区的松巴哇岛和弗洛勒斯岛（小巽他群岛西部，中部）。"},{"name":"白腹山椒鸟","english_name":"White-bellied Minivet","scientific_name":"Pericrocotus erythropygius","overview":"白腹山椒鸟（英文名：White-bellied Minivet，学名：Pericrocotus erythropygius），是雀形目鹃鵙科山椒鸟属的鸟类。美丽的山椒鸟，由英国医生兼自然学家托马斯·卡文希尔·杰顿于1840年命名。雄鸟上体黑亮，面部、颈部和背部呈蓝黑色，橙色胸部斑块明显，其余腹部为白色，翼部有白色标记，尾部黑色而臀部橙色。雌鸟上体灰暗，翅膀和尾部黑色，喉咙和腹部白色，臀部同样为橙色。主要分布于印度的干燥落叶森林。","appearance":"雄鸟的头部、颈部、背部及肩羽为蓝黑色，光泽亮丽，胸部有一圆形橙色斑块，腹部白色。雌鸟上体灰暗，翅膀和尾部为黑色，具有白色的喉部和腹部，臀部橙色。两性皆有白色翼斑。雄鸟尾部黑色，带有橙色臀部，翅膀上有白色标记。成鸟体长约18.5至20厘米。","call":"鸣唱包括断断续续且音调极高的‘seeu’音符，伴随‘chup’和‘tsip’音符，以及细长的哨声和清脆的口哨声，持续时间较长。叫声包含各种流利但间隔开的音符，有时在飞行中形成更为连贯的序列，如‘tittit-trit-tirrit-trit..’。接触叫声为柔和的‘tchip’。","habits":"栖息于开放的干燥灌木丛、草地、稀树草原、干燥的耕作区伴生有灌木和零星树木、篱笆和荆棘灌木丛。常出现在较干燥的区域，如岩石覆盖的斜坡，有时甚至在半沙漠地带。以昆虫为主食，包括蚱蜢和蜘蛛，也捕食空中飞虫。成对或小群体活动，较少栖于树冠，倾向于低矮的灌木、长草乃至地面捕食。","breeding":"在树梢高处筑巢，巢为杯状，由小枝条编织而成，加入蛛丝以增强巢的坚固性。通常产四枚卵，孵化期为17至18天，孵化主要由雌鸟承担，但双亲共同育雏。","identification":"雄鸟的黑白色羽毛搭配橙色臀部和胸部斑块使其易于识别。雌鸟的灰黑色上体、白色喉部和腹部，以及橙色臀部也具有显著特征。与同类相比，其黑白橙的色彩组合和行为模式容易区分。","protection":"IUCN：LC（无危）","distribution":"主要分布于印度，包括古吉拉特邦、旁遮普邦东部至比哈尔邦，南至安得拉邦和泰米尔纳德邦。在班达夫加尔国家公园、吉尔国家公园、马德哈夫国家公园、穆杜马拉伊国家公园和萨特普拉国家公园等地有记录。","other":"存在两个亚种：P. e. albifrons，分布在中缅平原；P. e. erythropygius，分布在印度半岛（旁遮普邦和拉贾斯坦邦到比哈尔邦和迈索尔）。"},{"name":"白额山椒鸟","english_name":"Jerdon's Minivet","scientific_name":"Pericrocotus albifrons","overview":"白额山椒鸟（英文名：Jerdon's Minivet，学名：Pericrocotus albifrons），是雀形目鹃鵙科山椒鸟属的鸟类。主要分布于缅甸中部的干燥落叶林中，偶尔可见于农田边缘地带。雄鸟以黑白相间为主色调，胸带橙色斑块；雌鸟色彩较淡，黑色部分被柔和的灰褐色替代。两性均具宽阔的白色眉纹、显著的翼白斑及带有橙色中心的白色臀部。","appearance":"成年雄鸟上体呈光泽黑，头部有白色眉纹和额斑，下体白色，胸带橙红至橙色斑块，翼上有宽大的白色斑点。雌鸟冠至背部为鼠灰色至灰褐色，下体白色略带灰色晕染。幼鸟似雌鸟，但头部和背部有白色鳞状斑点，翼覆羽白尖，胸侧有暗色斑点。","call":"鸣唱为高亢甜美的颤音连串，叫声包括尖锐的‘djeep’声和下降的哨音。","habits":"偏好干枯森林、灌木地和耕作区边缘，常以成对或小群体活动。食物习性细节未知，推测以昆虫为主。","breeding":"繁殖季节不详，已知至少到7月。巢由两性共建，位于灌木或小树的枝条上，离地面约1.2米，巢为小巧杯状。每窝产3枚灰褐色蛋，带深棕色和少量蓝灰色斑点，平均尺寸为17.3毫米×13.7毫米。","identification":"与白腹山椒鸟相似，但两者地理分布全然分离，通过羽色和叫声差异辨识。","protection":"IUCN：NT（近危）","distribution":"分布于缅甸中部的伊洛瓦底平原，该区域因农业开发而自然生境所剩无几。","other":"曾被视为白腹山椒鸟的亚种，现已独立为种。"},{"name":"灰喉山椒鸟","english_name":"Grey-chinned Minivet","scientific_name":"Pericrocotus solaris","overview":"灰喉山椒鸟（英文名：Grey-chinned Minivet，学名：Pericrocotus solaris），是雀形目鹃鵙科山椒鸟属的鸟类。俗名: 十字鸟，雄鸟头部和背部呈暗灰色，具亮橙色腹部和逗号状翼斑，雌鸟上部颜色较淡，橙色部位为黄色。分布于喜马拉雅山脉至中国东部、台湾、东南亚等地。留鸟，常见于海拔1,000-2,000米的山区森林。","appearance":"成年雄鸟头部、肩部及大部分翅膀为铅黑色，下巴淡灰色，喉咙橙色，腹部橙红至鲜橙色，雌鸟类似，但橙色部分为黄色，上体较淡。幼鸟似雌鸟，但背部具黄橄榄色条纹或斑点。成年雄鸟体重约13.5-16克，全长17-19厘米。","call":"发出非常高的、薄而快的“tsisisip”声节，伴有短暂向下弯曲的极高音哨声。觅食时发出轻薄重复的“tswee-seet”声。","habits":"栖息于开阔森林，包括常绿和湿润落叶林，有时为针叶林。海拔范围从600米至3050米，冬季下降至湿润森林。集群活动，觅食小昆虫，如白蚁有翅型。加入混合种群，与小型鹎和其他食虫鸟一起。","breeding":"繁殖期在喜马拉雅山脉至少为4月至6月，推测可能两次繁殖。巢由两性共同建造，位于树冠层，高度可达14米以上。每窝产卵3枚，卵色淡绿，有淡锈色细斑点。","identification":"翼斑为清晰的“7”字形。与短嘴山椒鸟区别在于雄鸟喉及耳羽暗深灰色，雌鸟额基无黄色。雌鸟可通过额基颜色和耳羽区分。","protection":"IUCN：LC（无危）。在中国受国家保护，具有生态和观赏价值。","distribution":"分布于喜马拉雅山脉从中西部尼泊尔至中国东部，台湾，越南，印尼苏门答腊岛和婆罗洲。","other":"适应性辐射在亚洲大陆发生，后扩散至印尼群岛。"},{"name":"长尾山椒鸟","english_name":"Long-tailed Minivet","scientific_name":"Pericrocotus ethologus","overview":"长尾山椒鸟（英文名：Long-tailed Minivet，学名：Pericrocotus ethologus），是雀形目鹃鵙科山椒鸟属的色彩斑斓的鸟类。雄鸟黑红相间，雌鸟灰黄交错，以翼上的独特色斑和较长的尾巴著称。广泛分布于南亚和东南亚地区，包括阿富汗至老挝一带，中国境内可见于西藏、云南、河北、河南、山西、陕西、甘肃、青海、四川和东北地区。","appearance":"雄鸟头部及上背黑色，泛蓝光泽，下背至尾上覆羽鲜红；翼黑，大覆羽全红，次级飞羽及三级飞羽黑，最内侧2-3枚次级飞羽/最外侧三级飞羽边缘红，内侧初级飞羽基部有红带，外羽更明显，最外侧初级飞羽边缘粉白；尾相对较长，中央两对尾羽黑，R2有窄红缘，外四枚尾羽大部分鲜红；喉部暗黑，胸部至尾下覆羽鲜红；翼下覆羽橙色；虹膜深褐；喙、腿和脚黑色。雌鸟额部及眼上黄带窄，颊部灰白，耳羽灰；上体橄榄灰，背部至尾上覆羽黄绿；翼黄取代红，尾黄取代红，R2色浅；颏和喉部白，下体黄。幼鸟似雌鸟，但上体斑驳黄，翼覆羽尖端黄白，胸白，喉侧、胸及胁部点斑灰褐；亚成鸟似雌鸟，但雄鸟上体更暗，黄色部位更橙，缺乏次级飞羽/三级飞羽彩色边缘。","call":"发出悦耳的滚动‘prrr’wi’和‘prrr’í’声，以及尖细嘶嘶的‘swii-swii swii-swii-swii’声。","habits":"栖息于中至高海拔的森林中，主要以昆虫为食，包括正翅目、膜翅目、鞘翅目、半翅目、直翅目昆虫，偶尔食用蜘蛛、金合欢芽和果实。在繁殖季节外可能形成大群。活动范围广泛，从山地常绿阔叶林、落叶阔叶林、针阔叶混交林到针叶林都有所分布。","breeding":"繁殖期在5-7月，巢建于森林中的乔木上，高度约10米，巢呈杯状，由雌雄双方共同筑造。每窝产卵2-4枚，通常3枚，由雌鸟孵化，雄鸟警戒。雏鸟晚成性，由双亲共同抚养。","identification":"雄鸟与赤红和短嘴山椒鸟区分在于翼斑形状和色泽，雌鸟与灰喉山椒鸟雌鸟的区别在于上嘴基部模糊的暗黄色。长尾山椒鸟雄鸟喉部黑色，而雌鸟上嘴基部有暗黄色模糊斑点。","protection":"IUCN：LC（无危）在中国常见，在巴基斯坦、北印度、尼泊尔、不丹、缅甸、泰国和越南（安南）常见，但在孟加拉国稀少且局部分布。在老挝和越南西部状况不明。存在于多个保护区。","distribution":"分布于喜马拉雅山脉至老挝，包括中国西藏、云南、河北、河南、山西、陕西、甘肃、青海、四川和东北地区。","other":"长尾山椒鸟有多个亚种，它们主要在雌鸟的羽毛颜色上有所不同。"},{"name":"短嘴山椒鸟","english_name":"Short-billed Minivet","scientific_name":"Pericrocotus brevirostris","overview":"短嘴山椒鸟（英文名：Short-billed Minivet，学名：Pericrocotus brevirostris），是雀形目鹃鵙科山椒鸟属的鸟类。分布于喜马拉雅山脉至老挝一带。该鸟以艳丽的羽色著称，雄鸟呈现醒目的红黑配色，雌鸟则为灰黄相间，是中国某些地区的夏候鸟。","appearance":"雄性短嘴山椒鸟头部至上胸、肩及背部为光泽蓝黑色，背部至尾上覆羽为深红色；翼上覆羽为光泽黑色，较大的覆羽为红色，翅膀黑色，基部半部的初级飞羽P1-P7为红色；中央尾羽黑色，紧邻的一对尾羽红色带黑色基部，外三对尾羽全红；下体为红色，大腿黑色，翼下覆羽橙黄色。雌鸟头部黄色，上体暗灰，下背至尾上覆羽橄榄绿黄色，翼和尾为黄色取代了雄鸟的红色；下体黄色。幼鸟类似雌鸟，但上体有黄色斑点，翼上覆羽尖端黄色，喉侧、胸及两胁有灰色斑点和条纹，下体颜色较淡，更接近白色。","call":"发出高亢清脆的哨声。","habits":"栖息于海拔1000-2500m的山地森林，包括常绿阔叶林、落叶阔叶林、针阔叶混交林和针叶林，偏好常绿阔叶林和混交林边缘。夏季活动于山中上部，冬季下移至山中下部或山脚平原的疏林。主要以昆虫为食，偶尔摄取少量种子和果实。成对或小群体活动，活跃于树冠层，通过叫声保持联系。","breeding":"繁殖期为5-7月，巢建于树木侧枝，由细枝、草茎等构成，外表覆盖苔藓和地衣以伪装，产卵2-4枚，卵呈钝卵圆形，带有红褐色斑点。","identification":"雄性短嘴山椒鸟与赤红山椒鸟相比，体型较小，尾较长，赤红山椒鸟具双叉型红色翼斑。与长尾山椒鸟雄鸟相比，长尾山椒鸟第一枚初级飞羽有粉红色外缘，内侧3-4枚飞羽具红色外缘，而短嘴山椒鸟第一枚初级飞羽全黑，内侧第三、四枚飞羽红斑不沿羽缘延伸。雌性短嘴山椒鸟额部为鲜艳黄色，与其他种类有所区别。","protection":"IUCN：LC（无危），被列入国家林业局2000年发布的《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》。","distribution":"分布于喜马拉雅山脉至老挝，具体包括尼泊尔、锡金、不丹、孟加拉国、印度、缅甸、老挝、泰国、越南以及中国的西藏、四川、云南、贵州、广西、广东等地。","other":"短嘴山椒鸟与人类关系密切，但由于栖息地破坏，种群数量有减少趋势，需加强保护。"},{"name":"巽他山椒鸟","english_name":"Sunda Minivet","scientific_name":"Pericrocotus miniatus","overview":"巽他山椒鸟（英文名：Sunda Minivet，学名：Pericrocotus miniatus），是雀形目鹃鵙科山椒鸟属的鸟类。印度尼西亚特有种。这种鸟色彩鲜艳，尾部长，常见于苏门答腊和爪哇的山地森林中（海拔1200-2700米）。","appearance":"雄性巽他山椒鸟头部和上体黑色，略带蓝色光泽；下背、臀部和上覆羽呈现鲜亮的红色；翅膀黑色，大覆羽红色，内侧具黑色斑点；主要飞羽有宽阔的红色横纹；尾羽中央对黑色，边缘和尖端略带红色，其余部分红色，基部黑色；喉咙黑色，下体红色，翼下覆羽较淡红色，大腿黑色，点缀粉色；虹膜棕色；喙和腿黑色。雌鸟与雄鸟相似，但额头、眉线、脸部侧面、喉咙和整个下体为玫瑰红色，肩部和小覆羽有暗红色羽缘，大覆羽黑色，宽幅红色尖端。幼鸟和未成熟个体的描述未详。","call":"发出刺耳的金属般‘chee-chee-chee’声和拉长的响亮‘tsree-ee’声。","habits":"社会性鸟类，常以大群出现在森林树冠层。它们栖息于苏门答腊和爪哇的山地森林，高度从1200至2700米。","identification":"雄鸟与同类其他雄鸟山椒鸟相似，但注意其连续的红色翼斑、更深的红色色调以及深黑色喉部无灰色痕迹。雌鸟更为独特，背部和脸部草莓红色。与同类的区别在于黑色头部、极长的尾巴以及内侧次级飞羽上无红色斑点。","distribution":"分布于印度尼西亚的苏门答腊岛和爪哇岛的山区。"},{"name":"赤黄山椒鸟","english_name":"Orange Minivet","scientific_name":"Pericrocotus flammeus","overview":"赤红山椒鸟（英文名：Scarlet Minivet，学名：Pericrocotus flammeus），是雀形目鹃鵙科山椒鸟属的鸟类。色彩鲜艳的长尾林鸟，雄鸟黑橙相间、雌鸟灰黄分明；曾分拆“赤黄山椒鸟”。主要分布于印度半岛西部与斯里兰卡，栖于常绿、半常绿及落叶阔叶林，海拔可达2100米，基本留鸟，喜马拉雅种群冬季有短程降迁。","appearance":"体长17–22厘米，体重19–24.5克，嘴粗厚，尾相对宽阔。雄鸟头、喉至上背为亮蓝黑色，下背、腰及尾上覆羽呈火橙红色；翅黑，大覆羽及初级飞羽基部具宽阔橙红色带，最内侧三级飞羽外缘近端处具孤立红斑；尾羽黑，除中央对外均具橙红端斑；下体亮橙红，大腿黑褐色，翼下覆羽鲜黄；虹膜暗褐，嘴与脚黑色。雌鸟前额及眉纹鲜黄，头顶至上背灰褐，腰及尾上覆羽绿黄色，翼与尾黑褐，雄鸟的红色部分均被黄色取代，下体全黄。幼鸟似雌鸟，头顶至背具黄色鳞状斑，胸侧与胁具灰色鳞纹，三级飞羽及大覆羽具宽黄边；雄亚成体黄色部位渐转橙色。各亚种差异在于体型大小、雄鸟红色深浅、雌鸟黄色浓淡及中央尾羽与翼部亮色的范围。","call":"鸣声为响亮而尖锐的哨音，常见串音如 “sweep-sweep-sweep-sweep” 或 “weep-weep-weep-wit-wip”。","habits":"栖于常绿、半常绿及落叶阔叶林，亦见于泥炭沼泽林与果园；在受扰森林中仍需高大乔木覆盖，回避低灌丛。喜马拉雅种群繁殖季可达1800米以上，冬季降至低地；指名亚种冬季可迁往泰国东北部。群居，常与其他种类混群觅食，多在林冠或高大树冠层活动，飞行呈波浪式，常越过林梢。食物以昆虫为主，包括鳞翅目幼虫、直翅目虫、蝉及蜘蛛；亦在榕树果穗中寻食被果香吸引的昆虫，多在冠层叶间取食，偶作悬停捕食。","breeding":"繁殖期：喜马拉雅4–6月，印度半岛2月与6–10月，斯里兰卡2–5月及8–9月第二窝，东南亚6–7月，龙目岛与菲律宾3–4月。巢为小而整洁的开放杯状，以苔藓、蛛丝构成并饰以树皮，置于距地6–20米的水平枝杈。每窝2–3枚卵，仅雌鸟孵卵，双亲共同育雏，孵化及离巢期暂无数据。","identification":"与同属其他种相比，雄鸟三级飞羽与最内侧次级飞羽末端具孤立红色斑纹，缺少小灰山椒鸟头顶与背部的灰色对比；雌鸟通体亮黄而无橙红。亚种间差异主要见于体型、雄鸟红色深浅、雌鸟黄色浓淡及中央尾羽和翼部红色范围，例如speciosus体型最大、雄鸟为深猩红，andamanensis红色更鲜，minythomelas雄鸟中央尾羽几乎全红等。","protection":"IUCN: LC（无危）。尼泊尔、不丹、斯里兰卡及东南亚等地普遍，印度、孟加拉、中国局部分布亦较常见，仅新加坡与婆罗洲较稀少。已列入多个国家公园及保护区，如尼泊尔奇旺、印度穆杜马莱、泰国岗卡章、越南南白吉仙、马来西亚大汉山、苏门答腊韦坎巴斯及婆罗洲丹浓谷等。","distribution":"繁殖区：印度半岛西部（东南古吉拉特向南经西高止山脉，至泰米尔纳德邦西南东高止山）及斯里兰卡。非繁殖区：喜马拉雅种群冬季降至平原，指名亚种可至泰国东北部。","other":"系统分类复杂，目前认可19个亚种，形态与羽色研究表明可能拆分为4–5个独立种，但界限尚不明；菲律宾种群可能包含额外物种，有待进一步研究。"},{"name":"赤红山椒鸟","english_name":"Scarlet Minivet","scientific_name":"Pericrocotus speciosus","appearance":"赤黄山椒鸟已删除体长约20-22厘米，拥有结实的黑色喙与长翼。雄鸟具有黑色的头部与背部，以及鲜艳的红色下体、尾缘、臀部和翼斑；雌鸟上体为灰色，下体为黄色，脸、尾缘、臀部和翼斑亦为黄色。不同亚种在颜色深浅和翼斑形状上有细微差异。","call":"发出响亮、尖锐的哨声，如“sweep-sweep-sweep-sweep”或“weep-weep-weep-wit-wip”。","habits":"栖息于常绿、半常绿及落叶森林，包括沼泽森林和果园，偏好高大的树木覆盖，高度可达2100米。主要以昆虫为食，包括毛虫、蚱蜢、绿色蟋蟀和蝉，偶尔食用蜘蛛。群体活动，加入混合物种觅食群，常在树冠或突出树梢觅食，也会捕捉飞过的猎物。","breeding":"繁殖期在4月至6月，筑杯状巢于树叉或横枝上，由苔藓编织而成，内部衬以松针等软材料。每窝产卵2-3枚，仅雌鸟孵卵，两性共同喂养幼鸟。","identification":"与其他山椒鸟属物种区分的关键在于色彩、体型和分布区域。雄鸟与雌鸟的颜色差异明显，雌鸟更易与同类识别。","protection":"IUCN：LC（无危）","distribution":"广泛分布于喜马拉雅山脉至印度尼西亚，菲律宾，以及中国西藏、云南、福建、湖南、广西、广东、海南等地。","other":"赤黄山椒鸟已删除的多个亚种因地理隔离而存在显著的色彩差异，部分亚种已升格为独立物种。现仍为赤红山椒鸟亚种。"},{"name":"黄头刺莺","english_name":"Yellowhead","scientific_name":"Mohoua ochrocephala","overview":"黄头刺莺（英文名：Yellowhead，学名：Mohoua ochrocephala），是雀形目黄头刺莺科黄头刺莺属的鸟类。小型森林栖息的鸣禽，为新西兰南岛特有种。以鲜明的黄色头部和黄至白色的下体而著称，通常栖息在高大的本土森林树冠层。黄头刺莺偏好在成熟森林中活动，常以小群家族形式移动，发出响亮的断音和颤音叫声。雄鸟具有类似金丝雀的悦耳歌声，雌鸟则会发出独特的嗡嗡声。黄头刺莺是长尾杜鹃寄生巢的首选宿主，后者会将其远大于黄头刺莺的雏鸟喂养长大。","appearance":"黄头刺莺体长14至15厘米，体重28至32克。头部和颈部明亮黄色，头顶和颈后部带有不同程度的橄榄色斑点；背部橄榄棕色，渐变为橄榄色的上尾覆羽；翅膀深棕色，外缘橄榄色，翼覆羽黄褐色；尾巴暗黄橄榄色；下巴、喉咙和胸部鲜黄色，下腹淡灰白色，胸侧、胁部和大腿常常带有浅棕色；尾下覆羽略带黄色；虹膜非常深棕色；喙和腿黑色。一些雌鸟的头部斑点更多，但许多个体性别难以辨别。幼鸟的上体比成鸟更橄榄色，下体颜色较浅。","call":"黄头刺莺的鸣唱包含6至8个快速重复的音乐般、频繁变化的颤音音符，通常会在歌曲结尾添加一串急促的断音。报警时发出尖锐的责骂声；雌鸟在蛋孵化前后几天会发出“lukaart, lukaart”的叫声。","habits":"黄头刺莺主要栖息于新西兰的南部山毛榉森林，偏好大片开阔下层植被的林区，分布于山间谷地至约900米海拔处。它们进行季节性局部迁移，通常在冬季形成小群；沿相同海拔移动，也会从山区山谷下降。以昆虫为主的无脊椎动物为食，偶尔食用小果实和花蜜。觅食主要在中间至顶层，亚树冠和树冠层，极少在地面觅食，更多在树冠层内部进行。形成3至40个个体的觅食群，也常加入混种群。","breeding":"繁殖季节从10月至2月，大部分产卵发生在11月至12月；双窝。以一夫一妻制繁殖，通常有一名帮手。繁殖期间领地性明显。巢由雌鸟建造，杯状结构，由根须、树枝、草和其他植物材料构成，内衬精细植被和羽毛，置于死树或活树树干或树桩的空洞中，距离地面1.7至31米（通常约14至15米）。巢中产2至4枚粉白至红奶油色的蛋，带淡暗红褐色斑点和斑块，偶尔灰色带有浅棕色标记，尺寸23至24×17.5至19毫米。孵化期约21天，由雌鸟（有时两个雌鸟共享角色）负责，雄鸟喂食。雏鸟由父母双方及可能存在的帮手喂养，离巢期约22天；所有成鸟还会继续喂养离巢的幼鸟数日，幼鸟在小家庭群中停留一段时间；雌鸟有时在第一窝离巢前就开始筑新巢和产卵。巢被长尾杜鹃寄生。孵化成功率28.6%至69.2%，38.1%至80%的雏鸟能成功离巢；引入的貂和黑鼠对巢、雏鸟和孵卵雌鸟造成大量捕食。","identification":"黄头刺莺很容易与色彩相似的黄鹀区分开来，因为黄鹀偏好开阔的农田和灌木丛而非成熟的森林。","protection":"IUCN：NT（近危）","distribution":"分布于新西兰南岛，包括斯图尔特岛（现已绝迹）及其周边岛屿。"},{"name":"白头刺莺","english_name":"Whitehead","scientific_name":"Mohoua albicilla","overview":"白头刺莺（英文名：Whitehead，学名：Mohoua albicilla），是雀形目黄头刺莺科黄头刺莺属的鸟类。小型的特有鸣禽，仅在新西兰北岛发现。其最显著的特征是独特的白色头部和下体。雌鸟和幼鸟的冠部和颈背带有肉桂色调。通常以小群快速而嘈杂的方式在树冠中穿梭，发出尖锐的喋喋不休声、颤音和滑音。偏好高大的原生森林和灌木丛。尽管飞行不太情愿，但它们在觅食昆虫时敏捷且具有杂技般的动作，常常倒挂。雄鸟的叫声清晰，类似金丝雀。成年鸟会喂养比它们大得多的长尾果鸠幼鸟，因为它们是这种巢寄生者的首选宿主。","appearance":"白头刺莺体型小，全长约15厘米，雄鸟体重18克，雌鸟15克。雄鸟头部和颈部呈偏白色，颈背偶尔带淡灰棕色，上体冷褐色，上尾覆羽略深；上翼和尾巴为棕色，外侧初级飞羽边缘呈淡灰棕色；下体偏白色，两胁略带淡灰棕色。雌鸟与雄鸟相似，但冠部至颈背带有棕色色调。幼鸟似雌鸟，但头部侧面、颈部、两胁和下尾覆羽带棕色洗染。虹膜深棕色，喙和腿黑色。","call":"雄鸟的叫声是一串下降的钟铃般的颤音，开始三个'viu'音符，接着是三到四个或更多的'zir'音符和其他音符。群体情况下会发出'che-che-che-che'和'swerre'的叫声，当兴奋时，会发出'chirrt'的声音。","habits":"白头刺莺主要栖息于原生森林和密集的灌木丛，有时也会出现在外来松树林、花园、农场和果园中。它们主要在南洋杉森林和茶树灌木丛中繁殖。从海岸线到海拔1300米的范围内都有分布。它们大部分时间定居不动，但可能有局部移动。它们以昆虫为主食，偶尔也会吃种子和果实。觅食时会在所有植被层次活动。","breeding":"繁殖季节通常在10月至12月，有时会有两窝。一夫一妻制，成对繁殖，经常有最多六个辅助者帮助。筑巢由雌鸟承担，巢是一个深杯状，主要由草、树枝、树叶、根须、树皮条和苔藓构成，外部用蜘蛛网固定，内部铺有羽毛、羊毛、苔藓、树皮和其他植被。孵化期为17至19天，雏鸟期16至19天。雏鸟依赖父母和辅助者喂养4至6周，有时长达8至9个月。雌鸟可能在雄鸟和任何辅助者继续喂养第一窝的同时开始建造第二个巢穴。","identification":"白头刺莺与其他同属物种的区别在于其独特的白色头部和下体，以及其特有的叫声。雄鸟和雌鸟之间主要通过冠部和颈背的颜色差异来辨认。","protection":"IUCN：LC（无危）","distribution":"主要分布在新西兰北岛南部，包括Mt Egmont和轴向山脉系统，从东角南至库克海峡，以及小屏障岛和卡皮蒂岛。","other":"白头刺莺曾在整个岛屿的植被区域广泛分布，但在19世纪70年代北岛的数量开始减少，随后在某些地区灭绝。在一些地区数量已有所回升。"},{"name":"新西兰刺莺","english_name":"Pipipi","scientific_name":"Mohoua novaeseelandiae","overview":"新西兰刺莺（英文名：Pipipi，学名：Mohoua novaeseelandiae），是雀形目黄头刺莺科黄头刺莺属的鸟类。新西兰特有的小型鸣禽，广泛分布于南岛、斯图尔特岛及其邻近岛屿。以昆虫为主要食物来源，具有强健的腿和脚趾，能在树枝上倒挂觅食。","appearance":"新西兰刺莺体长约13厘米，重约11至13.5克。头部呈混合的栗色和深褐色，脸部和颈部为灰暗色，眼后有一条白纹，下体颜色较淡，呈浅灰棕色，两侧略带粉红色。眼睛为深红棕色，喙和腿呈粉色至灰棕色。两性相似，但幼鸟头部颜色较暗，眼后无白纹，喙基黄色明显。","call":"雄鸟的歌声由5至14个响亮的口哨声、滑音和尖锐音组成，雌鸟的歌声则为4至9个快速、短暂的音符，最后一个音符长而高亢。两性会合唱，也会发出‘chee-up’的声音。","habits":"主要栖息于各种森林类型，从地面到树冠都能觅食，偏好在树冠层活动。以昆虫为主食，秋季也吃小果实。通常成对觅食，非繁殖季节形成3至12只的小群，有时可达50只，常与其他物种混群。","breeding":"繁殖季节为春季，雌鸟单独筑巢，由雄鸟守护。巢位于森林树冠密集处，离地1至10米。每窝产2至4枚蛋，孵化期为17至21天。幼鸟在18至22天后离巢，双亲共同喂养。","identification":"与林岩鹨相比，新西兰刺莺下体颜色更浅；与灰噪刺莺相比，新西兰刺莺体型更大，脸部与下体颜色对比更鲜明。","protection":"IUCN：LC（无危）","distribution":"主要分布于新西兰南岛、斯图尔特岛及其附近岛屿。","other":"是长尾杜鹃的主要寄主，成鸟可能被看到喂养比自己大得多的长尾杜鹃幼鸟。"},{"name":"杂色澳䴓","english_name":"Varied Sittella","scientific_name":"Daphoenositta chrysoptera","overview":"杂色澳䴓（英文名：Varied Sittella，学名：Daphoenositta chrysoptera），是雀形目澳鳾科澳鳾属的鸟类。小型鸣禽，身长约10至11厘米。其外观随地理位置而变化，因此得名“杂色”。分布于澳大利亚大陆（除塔斯马尼亚州）。","appearance":"此鸟短尾，上喙稍向上弯曲，黄色眼环明显。头部颜色变化大，从白色到黑色，体羽呈灰色或灰白，常带有黑色条纹。翅膀黑色，具显著的白色或橙色宽翼带。虹膜深橙色，眼环、腿脚橙黄。喙橙色，尖端黑色，有时黑至基部。亚种间色彩差异明显，部分亚种间可杂交，未来可能某些亚种会独立为新种。","call":"发出细薄高音的\"chwit\"声，结合成响亮金属质感的\"tchweit-tchweit-tchweit\"声，众多鸟儿在向另一棵树移动时持续进行呼应式的叫声。","habits":"栖息于各种干桉树林和灌木丛，偏好有草本覆盖的环境，亦见于高大的金合欢灌木林或卡苏阿里纳木林。常加入混群，与其他小型林鸟共同觅食。以昆虫和蜘蛛为主食，通过从树皮下挖掘猎物。","breeding":"繁殖季节为春夏季，北方8月至10月，南方9月至12月。繁殖群通常由一对繁殖鸟和数个未配对成鸟及前季幼鸟组成。筑锥形巢于树叉或枝条上，高度5至25米，以树皮、纤维和蜘蛛网制成。雌鸟孵卵，每窝产2至3枚蓝斑白蛋，孵化期18至20天。","identification":"与其他物种的区别在于其独特的头部色彩变化、翼带颜色以及叫声。亚种间主要区别在于头部颜色、翼带大小和性二型性的程度。","protection":"IUCN：LC（无危）","distribution":"广泛分布于澳大利亚大陆（除塔斯马尼亚州），常见于多种桉树林和灌木丛生境。","other":"该物种在一些地区因栖息地破坏而数量减少。"},{"name":"巴布亚澳䴓","english_name":"Papuan Sittella","scientific_name":"Daphoenositta papuensis","overview":"巴布亚澳䴓（英文名：Papuan Sittella，学名：Daphoenositta papuensis），是雀形目澳鳾科澳鳾属的小型鸟类，体长约10.5至11.5厘米，体重8至20克。分布于新几内亚的山区，常见于中海拔雨林地带。","appearance":"巴布亚澳䴓是一种非常小巧的鸟类，体羽多呈条纹状，具黄色眼环，背部和腹部有深色重斑。头部颜色随亚种而异，从黑色到白色不等，有时带条纹。成年雄鸟上体颜色从深棕色到灰色不一，具明显暗色条纹，尾部短小，尾尖白色。雌鸟头部较淡，或白或灰，条纹或无。幼鸟上体暗色，下体灰，喉部较白，条纹模糊。不同亚种间存在细微差异，特别是在头部色彩、翼带的有无、身体条纹程度以及两性异形上。","call":"在觅食时，巴布亚澳䴓会频繁发出\"chip-chip\"声，音调较高，类似\"tsip\"的强调音节，有时呈不规则系列，有时快速重复，如同雏鸟叫声。","habits":"巴布亚澳䴓栖息于海拔1400至2200米的中高山区的雨林及下层云雾森林边缘，偶尔下至1075米，最高可达2650米。通常以4至10只的小群出现，它们在树干和树枝上搜索昆虫，向下移动，采食和挖掘猎物，持续活跃。","breeding":"关于巴布亚澳䴓的繁殖信息目前资料较少。","identification":"巴布亚澳䴓与同类相比，最显著的区别在于其短尾、白色臀部和飞行时可见的白色翼带。头部图案因亚种而异，从全黑帽到全白头，有助于与其他物种区分。","protection":"IUCN：LC（无危）","distribution":"巴布亚澳䴓仅见于新几内亚的山区，具体分布在新几内亚的中部高地。"},{"name":"黑澳䴓","english_name":"Black Sittella","scientific_name":"Daphoenositta miranda","overview":"黑澳䴓（英文名：Black Sittella，学名：Daphoenositta miranda），是雀形目澳鳾科澳鳾属的鸟类。稀有的小型森林鸟类，分布于新几内亚的中西部至东南部山区。其显著特征为全身黑色，脸部红色，尾端下方粉色，翼部有白色带纹，腿黄色。","appearance":"成年雄性黑澳䴓的额头、眼周和下巴呈鲜艳的粉红至红色，头部、身体和上翅为灰黑色，边缘略显灰色，形成模糊的鳞状图案。尾羽除中央两对外均为黑色，尖端粉白。雌鸟与雄鸟相似，但虹膜和腿为黄色。幼鸟比成鸟更暗淡，头部前端和喉咙上方为肉桂色或锈棕色，虹膜颜色各异。","call":"觅食时，群体中的多个成员会持续发出接触叫声，声音短促、微弱、甜美，有吸气声和轻微的吱吱声，飞行时叫声比停栖时更响亮。互动时也会发出微弱的叽叽喳喳声。","habits":"主要栖息于高山森林（苔藓林），包括部分清理过的区域，海拔高度主要在2450至3700米之间，有时会降至2000米。以昆虫为主食，包括长达3厘米的幼虫和蜘蛛。在树冠层的高处枝条（活枝和死枝）上觅食，偶尔在倒木上活动。快速跳跃于树枝上，常以之字形移动，偶尔倒挂在水平枝下，或在树干上上下移动。","breeding":"繁殖季节似乎在旱季而非雨季，记录显示雄鸟在五月和八月睾丸增大，雌鸟在八月卵巢稍大，且发现晚期的幼鸟雌鸟。通常以3到10个个体的群体形式出现，包括生殖器官发育的成鸟、未发育的成鸟和幼鸟，暗示了合作繁殖的可能性。","identification":"与巴布亚澳䴓在形态和习性上相似，但黑澳䴓生活在更高的海拔，二者很少重叠。幼鸟的色彩可能引起混淆，但巴布亚澳䴓腹部颜色较浅。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚的中西部至东南部山区，主要栖息地在海拔2450至3700米间，最低可达2000米。","other":"该物种在当地可能常见于某些地区，但在全球范围内并不受到威胁。"},{"name":"肉垂犁嘴鸟","english_name":"Wattled Ploughbill","scientific_name":"Eulacestoma nigropectus","overview":"肉垂犁嘴鸟（英文名：Wattled Ploughbill，学名：Eulacestoma nigropectus），是雀形目肉垂鵙雀鹟科肉垂鵙雀鹟属的唯一物种，又称作肉垂鵙雀或犁嘴鵙。体型较小，主要分布于新几内亚的中央山脉，以独特的犁状喙和脸颊两侧的肉垂著称。","appearance":"雄鸟头部和上体呈黄绿色，额部更显金色，面部和肩羽为橄榄色，眼周黑色，脸颊两侧有大型玫瑰粉色肉垂；翼上覆羽黑褐色，初级飞羽边缘橄榄绿，尾羽黑褐色边缘橄榄绿；颏部和喉上部黄色，下喉和胸部黑色，余下体羽橄榄绿。雌鸟上体橄榄色，下体淡橄榄色，胸部微带白色条纹，无肉垂。雏鸟上体锈棕色，翼覆羽锈色，飞羽和尾羽边缘锈棕色，胸部灰色带锈色晕染。","call":"叫声包括细长水平哨音，约6个交替上升和下降的哨音序列，以及重复的嗡嗡声。","habits":"栖息于海拔1950至2850米的山地森林及其周边地带，尤其偏爱茂密的再生林，常在竹丛中活动。以昆虫为主食，从林下层到中间层觅食，高度可达10米，善于从树枝表面捕食猎物，通过啄剥树皮和挖掘苔藓寻找食物。经常加入混合物种觅食群。","breeding":"繁殖季节似乎跨越雨季和旱季，已知幼鸟出现在5月和6月底，成年雌鸟在7月处于繁殖状态，表明在两个季节都有繁殖行为。雄鸟参与孵化，雌鸟的角色未知，可能共同承担孵化任务。具体繁殖细节尚不清楚。","identification":"雄鸟的黑色下体、金色前额、橄榄色肩羽和脸颊两侧的肉垂是其显著特征。雌鸟无肉垂，上体橄榄色，下体淡橄榄色，胸部微带白色条纹。喙型独特，侧扁，上喙钩状，易于识别。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚中部山脉，从韦兰德山脉向东延伸至东南部的欧文斯坦利山脉。","other":"肉垂犁嘴鸟是其家族中的独生子，遗传和形态特征独特，2014年被归类于单独的肉垂鵙雀鹟科(Eulacestomatidae)。"},{"name":"棕颈钟鹟","english_name":"Rufous-naped Bellbird","scientific_name":"Aleadryas rufinucha","overview":"棕颈钟鹟（英文名：Rufous-naped Bellbird，学名：Aleadryas rufinucha），是雀形目冠钟鹟科棕颈啸鹟属的唯一物种。体型中等，栖息于新几内亚山区的亚热带或热带湿润山林中。","appearance":"成年个体呈橄榄色身体，黄色喉咙，黑色髭纹，白色胸部，灰色面部搭配头部后部的棕红色斑块，眼睛较小且颜色淡。某些地区的个体额头为白色。幼鸟上体橄榄色，下体棕红色。两性相似，但在成年雄鸟中虹膜颜色最浅。","call":"鸣唱由清晰响亮的哨音或上升音调组成，有时交替发声，有时单调重复。叫声则是一种响亮而粗糙的嘶声。","habits":"栖息于海拔1200至3600米的山地森林和次生林中，主要活动于1400至2600米的高度。以昆虫为主食，也会吃蠕虫和果实。偶尔能捕获较大的猎物。频繁地在地面和林下层觅食，偶尔到达树冠层。主要在树干和大枝上进食，沿树枝爬行或攀爬垂直的树干。","identification":"成鸟的独特羽色使其在同类中无相似物种。与幼鸟的区别在于颜色更深的上体和头部，以及更清晰的白色下体。不同亚种之间在额头羽毛的暗色中心扩展程度和体色深浅上有细微差异。","protection":"IUCN状态未提供。","distribution":"主要分布于新几内亚山区，包括蒙坦纳地区。","other":"系统学历史未详细提及，可能涉及分类学上的调整或研究。"},{"name":"冠林钟鹟","english_name":"Piping Bellbird","scientific_name":"Ornorectes cristatus","overview":"冠林钟鹟（英文名：Piping Bellbird，学名：Ornorectes cristatus），是雀形目冠钟鹟科冠林鵙鹟属的鸣禽。体长约为25-26厘米，拥有黑色的羽毛和红色的眼睛，头部具有独特的羽冠，腹部和背部呈现鲜明的橙色。这种鸟因散发出类似垃圾的难闻气味而被当地人称为“垃圾鸟”。其自然分布于新几内亚的热带雨林中。","appearance":"冠林钟鹟体长约25至26厘米，上体为深褐色，下体为锈色。最显著的特征是头部后方的蓬松羽冠，以及粗厚的黑色喙。眼睛颜色鲜艳，与古书中描述的鸩鸟相似，但体型远小于秃鹫。","call":"其鸣声为一系列连续重复的中音调铃铛般的音符，起初缓慢，随后速度逐渐加快，音高缓慢下降，每个音符前有时伴有短暂柔和的‘tst’声。这种鸣唱可能持续2到3分钟，偶尔长达15分钟，形成一种节奏感强、单调的声音。此外，还有上升和下降的音符序列，如‘stick-ahhhh’和‘whoo-iiyyy’，报警叫声为刺耳的嘶哑音符。","habits":"栖息于新几内亚的原始雨林，主要在山麓地带，也出现在低地和高达1300米的山区。以昆虫为主食，主要在地面觅食，有时也在树上，特别是在中层。常加入混合物种觅食群。","identification":"与锈色林鵙鹟类似，但冠林钟鹟有明显的羽冠，且不具备淡色眼睛。身上的剧毒毒素使其与同类中的其他物种明显区分开来。","protection":"IUCN：LC（无危）","distribution":"主要分布在新几内亚的热带雨林中，包括山麓地带、低地和高达1300米的山区。"},{"name":"冠钟鹟","english_name":"Crested Bellbird","scientific_name":"Oreoica gutturalis","overview":"冠钟鹟（英文名：Crested Bellbird，学名：Oreoica gutturalis），是雀形目冠钟鹟科冠钟鹟属的鸟类。广泛分布于澳大利亚内陆干旱地区。其典型生境包括金合欢灌木丛、桉树林、针茅和盐碱地平原以及沙丘。雄鸟体长约20厘米，头部灰色，具黑色可竖立的羽冠和胸部，身体其余部分灰或橄榄褐色。雌鸟和幼鸟颜色较为柔和，缺乏明显的黑胸特征。该物种以高音清脆、似牛铃般的鸣叫声著称，远距离亦能听见。","appearance":"雄性冠钟鹟体长19至23厘米，重56至67克。雄鸟具有小而可竖立的黑色羽冠，脸部白色，胸前有黑色带状斑纹；雌鸟及幼鸟整体呈灰褐色，缺乏明显的面部图案。幼鸟主要为棕色，带有浅色条纹。","call":"其鸣声具有金属般清脆的音质，起初柔和而后逐渐增强，前三音单调，最后三音较快，最后一音低沉而流利，如同牛铃或石落水中的声音。","habits":"栖息于地面或靠近地面的浓密植被中，偶尔在树上较高位置活动。以昆虫和其他无脊椎动物为主食，也会进食种子。常加入混合物种觅食群。","breeding":"繁殖期通常在8月至12月，营巢于离地面几米高的树叉或树桩裂缝中，巢由细枝和树皮构成，内衬柔软材料。每窝产卵1至4枚，由双亲共同孵化。","identification":"与楔嘴鹟和西部鞭鸟在外观上有相似之处，尤其是雌鸟和幼鸟，但通过鸣叫声和分布区域可加以区分。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚内陆，包括澳大利亚的半干旱海岸线和较干燥的内陆地区，主要集中在金合欢灌木丛、桉树林、针茅和盐碱地平原或沙丘地带。","other":"在维多利亚州，由于栖息地破坏和土地清理导致的栖息地碎片化，其分布范围已大幅缩减。"},{"name":"东鵙雀鹟","english_name":"Eastern Shriketit","scientific_name":"Falcunculus frontatus","overview":"东鵙雀鹟（英文名：Eastern Shriketit，学名：Falcunculus frontatus），是雀形目鵙雀鹟科鵙雀鹟属的鸟类。独特的雀形目鸟类。其体型中等，背部呈橄榄绿色，腹部为亮黄色，头部拥有鲜明的黑白相间图案。雄鸟具有可竖立的黑色冠羽。分布于澳大利亚东南部，从昆士兰州东部至南澳大利亚州和维多利亚州南部。偏好栖息在桉树林和某些较湿润的森林地带。","appearance":"东鵙雀鹟的体长约为15.5至19厘米，翼展24至29厘米，雄鸟体重介于26.5至40克之间，雌鸟则为23至33克。其背部橄榄绿至暗橄榄色，腹部明亮黄色，带有橄榄色调的侧面。头部有显著的黑白色块，雄鸟的喉部为黑色，雌鸟则为橄榄色，而幼鸟的喉部、胸部和腹部呈现淡黄色，翅膀更显棕色。","call":"其叫声为柔和、哀伤的哨音，通常被描述为\"whiert, whit-whit, wheeir\"，同时也会发出重复的口吃声或咯咯声。它能完美模仿其栖息环境中多种鸟类的鸣叫。","habits":"东鵙雀鹟偏好居住在桉树森林和开阔的林地，偶尔也会出现在雨林中。它们主要在6至10米的高度活动，擅长利用强健的喙撕开树皮寻找昆虫、蜘蛛、甲虫和昆虫幼虫等猎物。有时会加入混合物种的鸟群。","breeding":"繁殖季节从8月底至次年1月初，北方地区常有双胎现象，南方则多为单胎。巢穴为深杯状，由树皮纤维和蜘蛛网构成，内衬细草和苔藓，一般建在离地面5至30米高的桉树嫩枝上。雌鸟为主孵化2至3枚斑点状白色蛋，孵化期约15至16天。雏鸟出生后14至17天离巢，之后3至6个月由父母共同照料。","identification":"与金笛鸟（Golden Whistler）区别明显，后者头大部分为黑色，喉部白色带黑色胸带，喙较细，黄色羽毛延至颈背。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东部和东南部，包括昆士兰热带地区的阿瑟顿高原，向南延伸至新南威尔士州和维多利亚州，包括墨累-达令盆地，直至南澳大利亚州的洛夫蒂山脉和弗勒里厄半岛。","other":"其巢穴可能受到布谷鸟寄生，同时面临野猫和家猫的捕食威胁，以及因森林火灾和人类活动导致的栖息地丧失。"},{"name":"北鵙雀鹟","english_name":"Northern Shriketit","scientific_name":"Falcunculus whitei","overview":"北鵙雀鹟（英文名：Northern Shriketit，学名：Falcunculus whitei），是雀形目鵙雀鹟科鵙雀鹟属的小型鸟类，拥有短而粗壮的喙。上体绿色，下体黄色，头部具有鲜明的黑白相间图案。雄鸟下巴黑色，雌鸟暗绿橄榄色。主要分布在澳大利亚北部领地的顶端和西澳大利亚州的金伯利地区，栖息于桉树林地。","appearance":"北鵙雀鹟是一种中等体型的鸣禽，体长16至19厘米，喙厚实且略呈钩状。雄雌两性的头部都具有对比强烈的黑白图案，仅雄鸟具有可竖立的冠羽。背部绿色带橄榄色，腹部鲜黄色。雌雄差异主要体现在头部图案和喉部颜色上，雄鸟喉部全黑，雌鸟喉部橄榄色。","call":"鸣声为响亮清晰的三音节哨声，随后是一段上升的哨音。","habits":"主要栖息于桉树林地，如由Eucalyptus opaca、Darwin box（E. tectifica）、roughleaf cabbage gum（E. confertiflora）或Darwin woollybutt（E. miniata）或Darwin stringybark（E. tetrodonta）等物种主导的林地。偶尔也会出现在由纸皮树（Melaleuca spp.）或Nutwood（Terminalia arostrata）为主的林地中。常见于低地。","breeding":"关于生长繁殖的信息在文献中未详尽描述。","identification":"与金啸鹟和西方啸鹟相比，虽然都有金色的下体和黑白头部，但头纹不同，且后两者喙较细长。此外，雄鸟北方鵙雀鹟具有可竖立的冠羽。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚西北部的金伯利地区和北部领地的顶端。","other":"过去曾被视为Crested Shrike-tit的地理隔离亚种。"},{"name":"西鵙雀鹟","english_name":"Western Shriketit","scientific_name":"Falcunculus leucogaster","overview":"西鵙雀鹟（英文名：Western Shriketit，学名：Falcunculus leucogaster），是雀形目鵙雀鹟科鵙雀鹟属的鸟类。主要栖息于西澳大利亚州的桉树林地带，尤其是那些以光滑树皮的桉树为主导的森林，如karri、wandoo、salmon gum或flooded gum，以及acacias等。西鵙雀鹟的体型中等，头部黑白相间，上体橄榄绿，下体黄色，腹部有明显的白色条纹。性别之间存在差异，雄鸟的下巴黑色，而雌鸟为深绿色。该物种曾被视为东鵙雀鹟的地理隔离亚种。","appearance":"西鵙雀鹟是一种中等体型的鸟类，体长16-19厘米，拥有粗壮且略呈鹰嘴状的喙。雄鸟和雌鸟都具有醒目的黑白头纹，雄鸟还具有可竖立的冠羽。上体颜色为黄橄榄色，下体黄色，胸中部至腹部颜色较浅，腹部和两侧为洁净的白色。幼鸟的头部图案相似，但下巴、喉咙和上胸部为黄白色，额头和耳罩的黑色部分往往带有灰色调。翅膀上覆羽为棕色，下覆羽为淡灰色，下体颜色比成鸟更淡，主要为灰白色，胸部羽毛中心带淡黄色。","call":"西鵙雀鹟的鸣唱包括响亮而清晰的两部分上升哨声。","habits":"西鵙雀鹟主要栖息于桉树林地带，尤其偏好光滑树皮的桉树种类。它们生活在低海拔地区，几乎全部分布在400米以下的高度。这种鸟类在觅食时会利用其特殊的脚部技巧固定猎物，有时甚至使用小树枝作为工具获取隐蔽在缝隙中的昆虫。","breeding":"关于西鵙雀鹟的繁殖习性信息有限，但已知它们通常在桉树林中筑巢。","identification":"西鵙雀鹟与其他鸟类，特别是金啸鹟和西方啸鹟的区别在于，后两者虽然共享金色下体和黑白头部图案，但其头部图案完全不同（整个头部黑色，而非条纹，包含大片白色喉部斑块），并且缺乏任何冠羽迹象，同时，这两者的喙更为纤细，远不如西鵙雀鹟的喙结实。","protection":"IUCN：LC（无危）","distribution":"西鵙雀鹟主要分布在澳大利亚西南部，包括西澳大利亚州的桉树林地带。它们的分布区域位于400米以下的低海拔地区。","other":"西鵙雀鹟曾被归类为东鵙雀鹟的一个地理隔离亚种，但在形态和分布上的显著差异促使它被认定为独立物种。"},{"name":"栗背啸鹟","english_name":"Maroon-backed Whistler","scientific_name":"Coracornis raveni","overview":"栗背啸鹟（英文名：Maroon-backed Whistler，学名：Coracornis raveni），是雀形目啸鹟科栗背啸鹟属的鸟类。特有于印度尼西亚苏拉威西岛的山地森林中。以其独特的栗色背部和灰黑色的头部而著称。","appearance":"雄性栗背啸鹟几乎全身呈现深灰色，最显著的特点是其栗色的背部。雌鸟和幼鸟外观较为普通，上部为暗锈褐色，下方为淡橄榄色，下尾羽处颜色较浅。雄鸟的头颈、面部侧面为烟灰色，稍带橄榄色；背部、臀部为深栗棕色，上尾覆羽为黑色；上翼大部分为黑色，内侧主飞羽和次级飞羽内缘略带淡绿黄褐色；尾巴黑色；下巴和喉部烟灰色，胸部至腹部为暗橄榄灰，带有淡黄橄榄色的洗染；虹膜为深红棕色；喙和腿均为深灰色。雌鸟整体呈褐色，头顶较浅，带灰色调，上尾覆羽同样为褐色，翅膀边缘为淡赭色；尾巴暗灰色，尾羽边缘为褐色；下方为淡赭色，腹部中部洗染黄色，下尾覆羽为赭色。幼鸟与雌鸟相似。","call":"栗背啸鹟发出典型的啸鹟鞭打声，声音响亮且突然爆发，常连续快速发出两次。","habits":"生活在海拔1500至2200米的山地森林中，通常在林下层和较低的中层活动。以昆虫为食，通过突袭和捕捉的方式获取猎物。","breeding":"关于繁殖行为的信息尚未报道。","identification":"雌性栗背啸鹟胸部为暗色，与硫黄腹啸鹟形成对比，且不同于林啸鹟，后者具有黄色的侧腹。","protection":"IUCN：LC（无危）。在Lore Lindu国家公园中报告为罕见。","distribution":"仅分布于印尼苏拉威西岛的山区。"},{"name":"桑岛啸鹟","english_name":"Sangihe Whistler","scientific_name":"Coracornis sanghirensis","overview":"桑岛啸鹟（英文名：Sangihe Whistler，学名：Coracornis sanghirensis），是雀形目啸鹟科栗背啸鹟属的鸟类。体型健壮、外观暗淡的厚喙鸣禽，上体呈深橄榄棕色，头部略显灰色，下体带有浅黄褐色调。该鸟种仅限于印度尼西亚桑岛的成熟山地森林树冠层，极为罕见。","appearance":"成年桑岛啸鹟体长17至19厘米，体重约36克。上体橄榄灰，头部颜色较深，耳羽深棕色并有淡黄褐色条纹；翅膀棕色，内侧较深；尾羽棕色，内侧边缘色深；腹部绿色泛黄，两胁及下尾覆羽色深。虹膜深灰色，上喙暗灰角质色，下喙淡角质色，腿灰色。雌雄外观相似，幼鸟特征未详。","call":"其鸣唱由约四组重复的乐句组成，声音响亮。此外，还会发出“churr”声和尖锐的“wit”叫声。","habits":"通常以小群或成对出现，栖息于高大成熟山地森林的树冠层，偏好在山脊地带。具体栖息地、迁徙、飞行特点、活动范围、觅食方式等细节尚待更多研究。","breeding":"关于桑岛啸鹟的繁殖信息目前资料有限，需进一步观察研究。","identification":"与桑岛金冠鹎最为相似，但桑岛啸鹟具有双色喙，且不具备黄色的喉部和面部。","protection":"IUCN：CR（极危）","distribution":"仅分布于印度尼西亚苏拉威西岛北侧的桑岛山区，具体为Sahendaruman山和Sahengbalira山。","other":"桑岛啸鹟曾长期仅知于19世纪的两个标本，直到1985年才被重新发现。自1998至1999年间再次访问时，发现其更难寻踪迹。现存适宜栖息地仅剩极小部分，且正遭受严重退化或丧失，估计剩余鸟群数量可能不足百只。"},{"name":"黑林鵙鹟","english_name":"Black Pitohui","scientific_name":"Melanorectes nigrescens","overview":"黑林鵙鹟（英文名：Black Pitohui，学名：Melanorectes nigrescens），是雀形目啸鹟科黑林鵙鹟属的唯一物种。分布于新几内亚的高山森林地带，以昆虫为食。其自然栖息环境为亚热带或热带湿润低地森林。","appearance":"黑林鵙鹟是一种中等体型的鸟，雄鸟全身黑色，喙部呈钩状；雌鸟颜色较暗淡，为暗褐色。雄鸟与须嘴扇尾鹟有几分相似，但更倾向于水平姿态，头部不如后者扁平。雌鸟与冠园丁鸟雌鸟类似，但体型较小，喙部同样呈钩状。","call":"黑林鵙鹟的鸣叫声独特，包括缓慢上升的‘pooiii!’声，较快上升的‘whip-whip-whip…’声，有时会加速至颤音，以及有力的向下‘tiiaoo!’声。","habits":"黑林鵙鹟通常单独或成对活动，活跃于森林各层，寻找昆虫为食。","identification":"雄鸟与须嘴扇尾鹟的区别在于更加水平的体态和非扁平头部；雌鸟与冠园丁鸟雌鸟的区别在于体型较小和钩状喙。","protection":"IUCN状态未知。","distribution":"繁殖区域与非繁殖区域均为新几内亚的山区。","other":"黑林鵙鹟的系统分类历史中，曾被归入Rectes（Pitohui的同义词）属，2013年重新分类至Melanorectes属。"},{"name":"绿啸鹟","english_name":"Olive Whistler","scientific_name":"Pachycephala olivacea","appearance":"成年绿啸鹟约18-20厘米长，体重35-41克。雄鸟头部深灰色，颈部亦如此，前额、眼罩、耳羽基部和颊部有时隐约可见白色斑点；上体呈深橄榄褐色，臀部和尾上覆羽略浅，上翼深褐色，所有羽毛边缘橄榄褐色，尤其在三级飞羽最宽；尾羽深橄榄褐色，边缘稍淡；喉部白色，精细地带有暗灰色斑点；上胸深灰色，逐渐过渡至下胸和前侧腹的深黄褐色，再渐变为较浅的黄褐色于腹部、后侧腹和下尾覆羽；下腹和肛周淡黄褐色到米白色。雌鸟比雄鸟略偏褐色，但通常难以区分。幼鸟主要为赤褐色；亚成体头部和胸部更偏褐色，保留了幼鸟的赤褐色翼覆羽，喙色较淡。不同亚种间存在差异。","call":"鸣声响亮，最远可达135米，地理分布不同，鸣声类型也有所变化。北方（macphersoniana亚种）的鸣声由三音节组成，中间夹杂两次滑音，类似“we-et-chaw-et-tee”，也有拉长音的“peee pooo”，最后一个音节较低；东南部（指名亚种）已识别九组不同的鸣唱，通常被转写为‘tu-ww-e-chou’、‘you’re cranky’或‘wee-o pretty’，以尖锐结尾；维多利亚州南部奥特威山脉（bathychroa亚种）的个体平均拥有五种鸣唱类型，其中三种为所有鸟共享。","habits":"主要栖息于海拔1000米以上的雨林，偏好冷温带森林，如南方山毛榉（Nothofagus）或教练木（Ceratopetalum）林，偶尔出现在温暖的雨林和湿润桉树（Eucalyptus）森林中。南部地区的绿啸鹟则广泛分布于各种生境，从海岸至约1800米的高度，包括雨林、湿润桉树林、密集沟谷植被、茶树（Leptospermum）和纸皮树（Melaleuca）灌丛、沿海灌木地、山地灌木丛以及异域松林（Pinus）中的茂密植被。生活习性上，基本定居，仅报道过局部移动，包括冬季从高海拔向低处迁移。食物以节肢动物为主，尤其是昆虫，偶尔食用种子、叶片和小果实。觅食于低矮密集植被和地面，偶尔会攀至中层林冠。","breeding":"繁殖季节从9月持续至翌年1月初，每季只繁殖一次，但如果失去巢卵，则最多可产四次替代卵。以简单配偶关系繁殖，领域性明显。巢由双亲共建，呈深杯状，由枝条、树皮碎片、叶子、棕榈叶段和根须构成，内衬草、根须，偶尔有树叶，外部直径10.2-12.7厘米，高度22.9-25.4厘米，内部直径7.6-8.3厘米，深度4.4-5.1厘米；巢置于离地面0.9-2米（平均1.4米）的密集植被中的树叉或藤蔓缠绕处。每窝产2-3枚蛋，蛋壳颜色为奶油白至乳黄色，布满褐色斑点，底层有紫灰色斑块，常在大端形成环状；双亲共同孵卵和喂养幼鸟，关于孵化期和育雏期的具体时长未知；雏鸟由双亲共同喂养。最长记录寿命为5年8个月。","identification":"与金啸鹟相比，绿啸鹟体型更大，金啸鹟的下体有黄色部分，而绿啸鹟没有；此外，绿啸鹟的喉部斑纹更为明显。不同亚种之间，如macphersoniana、bathychroa和apatetes在色彩和性二型性上有细微差别。","protection":"IUCN：LC（无危）；但在新南威尔士州因栖息地破碎化以及外来猫和狐狸的威胁，被列为Vulnerable（易危）。","distribution":"绿啸鹟主要分布于澳大利亚东南部，包括昆士兰州麦克弗森山脉以南，经新南威尔士州、维多利亚州和东南南澳大利亚，以及塔斯马尼亚州和弗林德斯岛、金岛。","other":"绿啸鹟能在停止砍伐森林约两年后返回，但通常直到十多年后才会定居。北部种群的大部分栖息地现已得到保护，南部种群发生的地区也有相当面积受到保护。"},{"name":"红眼先啸鹟","english_name":"Red-lored Whistler","scientific_name":"Pachycephala rufogularis","overview":"红眼先啸鹟（英文名：Red-lored Whistler，学名：Pachycephala rufogularis），是雀形目啸鹟科啸鹟属的鸟类。分布局限于澳洲南部沙漠地带的Mallee林地，包括南澳大利亚东部、维多利亚西北部和新南威尔士州西南及中部地区。该鸟以其独特的橙色面部和喉部，灰褐色的上体以及红棕色的下体而著称。","appearance":"雄鸟具有橙色的面部、喉部和下颚，头、背部、翅膀和尾巴呈暗棕灰色，翼羽边缘略带浅棕灰色，上胸部和胁部为棕灰色，下胸部至尾下覆羽为浅红橙色。雌鸟相似，但色调较淡，最淡个体面部和下体的红橙色较少。幼鸟为棕色，具红棕色眉纹，上体灰褐色带红棕色调，飞羽、翼覆羽和尾羽染有红棕色，下体有条纹。初次换羽的幼鸟比成鸟更暗淡，面部和下体缺乏红橙色，保留幼鸟的飞羽、翼覆羽和尾羽。","call":"发出响亮、清脆的哨声，随后是类似闭唇吸气的声音，形成“see-saw”声，有时带有上升的尾音。还有拉长的单音哨声和尖锐的“chut chut”声。","habits":"栖息于低矮的Mallee林地，通常伴有Melaleuca uncinata灌木丛和Triodia草丛，植被年龄至少在受扰后5年。偏好具有开阔树冠和中等密度、斑驳的下层植被的环境。","breeding":"建造由粗树皮和Mallee树叶构成的杯状巢，置于低矮的灌木中，每次产卵2-3枚。","identification":"与吉氏啸鹟相比，红眼先啸鹟的眼前部颜色更深，橙色下巴不延伸到喙上方。雌鸟和幼鸟与吉氏啸鹟非常相似，但红眼先啸鹟的下体略显淡黄色。","protection":"IUCN：VU（易危）","distribution":"分布于南澳大利亚东南部（包括东北部的Eyre半岛）、维多利亚西北部和新南威尔士州西南及中部地区。","other":"在新南威尔士州被列为“极危”，在维多利亚州被视为受威胁物种，而在南澳大利亚州则被列为“易危”。"},{"name":"吉氏啸鹟","english_name":"Gilbert's Whistler","scientific_name":"Pachycephala inornata","overview":"吉氏啸鹟（英文名：Gilbert's Whistler，学名：Pachycephala inornata），是雀形目啸鹟科啸鹟属的鸟类。仅分布于澳大利亚南部的半干旱地区，以灰褐色为主色调，雄鸟喉部橙色，雌鸟喉部灰色。在Mallee林地和灌木丛中生活。","appearance":"体型中等，长17-20.5厘米，重28-36克。雄鸟头部、颈部暗灰色，眼眶周围黑色；雌鸟眼眶周围淡灰色，喉部灰色，下体有时有浅灰色条纹。幼鸟上体和翅膀深棕色，下体白色并有深棕色条纹。","call":"鸣声多变，最远可达900米。包括快速重复的单音节“chop”或“chook”，以及一系列2-10个“er-whit”。叫声包括尖锐的“aw-whit”、“e-chung”等。","habits":"栖息于半干旱的树林和灌木丛，尤其偏爱Mallee林地和Acacia环境。食物主要是节肢动物，偶尔吃水果和种子。在地面和树枝上觅食。","breeding":"筑巢于密林中，通常在旧的鸟巢上。两性共同筑巢、孵卵和育雏，每窝产2-4枚蛋，孵化期约15天。","identification":"与红眼先啸鹟区别在于雄鸟眼眶周围的颜色，与金色啸鹟的区别在于雌鸟和幼鸟的嘴型和虹膜颜色。","protection":"IUCN：LC（无危）。在新南威尔士州列为脆弱物种。","distribution":"分布于澳大利亚南部，从西南部西澳大利亚州（除角落地带）东至维多利亚州东北部和新南威尔士州中部。","other":"历史上曾分为两个亚种，但现在认为差异是连续的。"},{"name":"红树啸鹟","english_name":"Mangrove Whistler","scientific_name":"Pachycephala cinerea","overview":"红树啸鹟（英文名：Mangrove Whistler，学名：Pachycephala cinerea），是雀形目啸鹟科啸鹟属的鸟类。但后者不应与同名的混淆。该鸟分布于南亚东北部海岸至印度尼西亚群岛，包括安达曼群岛、越南、苏门答腊及其周边岛屿、婆罗洲、马腊图阿岛、爪哇海诸岛、爪哇、巴厘岛、龙目岛及菲律宾西南部的巴拉望岛。其最显著的特征是上身呈暗灰色，下身白色。","appearance":"成年红树啸鹟体长约15.5至17厘米，体重介于19至25克之间。额部淡灰色，头顶和侧面暗灰棕色，眼周淡灰；背部灰褐色，飞羽和上翼覆羽灰棕色，尾羽深棕色；腹部白色，喉部和脸颊微带棕色斑点，上胸略染棕色，大腿羽毛基部棕色，末端白色；虹膜棕色，喙黑色，腿脚深灰色。两性外观相似。幼鸟上体呈暖锈棕色，次级飞羽和翼覆羽边缘锈棕色，下体白色，喙色粉棕色。亚种plateni上体均匀灰棕色，喉部灰白色，胸部灰色，腹部和下尾覆羽白色。","call":"红树啸鹟的鸣声通常是一系列响亮悦耳的音符，以一到两个更响亮的音符结尾。在印度，它们会发出响亮清脆的哨声，重复3-4次逐渐上升的音阶，或延长拖长，随后是更高或更低的音符；在东南亚，鸣声变化多样，从2-4个短音开始，常以一个更大声、更具爆发力的音符结束；在马来半岛，8-9个相同音高的哨声，略微加速并增加音量，以双音结尾；在巴拉望岛（亚种plateni），则是一种‘peee purr chiaounkk’或‘peeee pur-purrr chiaounkk’的吹哨声，最后一个音符响亮结束。","habits":"栖息于红树林和邻近的沿海植被中，包括木麻黄森林、局部种植园和树木繁茂的花园、岛屿森林、河岸植被；通常靠近海岸，偶尔向内陆延伸，有时可达较高海拔，部分地区的高度可达1830米。红树啸鹟主要在印度和安达曼群岛的繁殖区内定居，以昆虫为食，通过掠食和从树枝和树干上捡拾来捕捉猎物。它们常加入混合物种觅食群。","breeding":"繁殖季节在印度为4月至7月，在东南亚为3月至6月，在爪哇为4月；在巴拉望岛上，雄鸟在5月有增大的睾丸，部分年份的3月底至4月底可见到变异增大的生殖腺。巢穴为轻薄的杯状结构，通过蜘蛛网固定在距离地面1至4米（偶尔高达15米）的支撑枝条上。每窝产两枚蛋，颜色为奶油色至浅棕色，带有紫色底纹上的赤褐色至深棕色斑点，通常在较宽的一端形成区域，尺寸约为20.9至25.4毫米×15.7至17毫米。","identification":"红树啸鹟与范围内其他红树林物种的主要区别在于其缺乏显著的标记。亚种间辨识要点在于plateni亚种上体颜色更为均匀，喉部灰白色，胸部灰色，而标准亚种的上体灰褐色，下体白色。","protection":"IUCN：LC（无危）。广泛分布，但在任何地方都不算非常常见。在印度和安达曼群岛较为常见；在东南亚罕见至局部常见，新加坡稀少。在华莱士区中等常见。","distribution":"分布于南亚东北部海岸至印度尼西亚群岛，包括安达曼群岛、越南、苏门答腊及其周边岛屿、婆罗洲、马腊图阿岛、爪哇海诸岛、爪哇、巴厘岛、龙目岛及菲律宾西南部的巴拉望岛。"},{"name":"绿背啸鹟","english_name":"Green-backed Whistler","scientific_name":"Pachycephala albiventris","overview":"绿背啸鹟（英文名：Green-backed Whistler，学名：Pachycephala albiventris），是雀形目啸鹟科啸鹟属的鸟类。这种小型森林鸟广泛分布于菲律宾吕宋岛和民都洛岛的低地至山地中间海拔地区。其最显著的外部特征为橄榄绿色的头部、背部、翅膀和尾巴，以及灰白色的胸部和带有淡黄色的腹部。","appearance":"绿背啸鹟体长约16厘米，体重介于18至25克之间。成鸟头顶和背部呈暗橄榄绿色，渐变为明亮的橄榄黄色至臀部和上尾羽覆羽；侧面头部和耳羽橄榄灰色；飞羽棕色黑色，外缘橄榄黄色；尾羽橄榄黄色，外缘更亮；下颚和喉咙淡灰白色，胸部淡棕色灰色，两侧较暗并带些橄榄色，腹部纯白，肛周和下尾羽覆羽泛黄；虹膜深褐色；喙黑色；腿灰色紫色。雌雄相似。幼鸟上部深棕色，次级飞羽内侧和翼羽覆羽红棕色，下部暗肉桂色；亚成鸟似成鸟，但保留幼鸟的次级飞羽和翼羽覆羽。","call":"绿背啸鹟发出响亮的金属声“peee”或“peee-wit”，频繁地鸣叫。","habits":"绿背啸鹟栖息于森林环境，从低地到高山，可达海拔2000米。它似乎过着定居的生活，以昆虫为食，从林下层至树冠层觅食。常加入混合物种觅食群。","breeding":"繁殖季节变化不定，部分年份在2月至5月期间观察到处于繁殖状态的鸟，3月见到幼鸟。没有其他相关信息。","identification":"绿背啸鹟与灰胸鹟较为相似，但体型较小，喙较厚实。亚种crissalis上体橄榄棕色，腹部和下尾羽覆羽更白；mindorensis喉部和胸部更深的灰色，腹部白色略带灰色调，下尾羽覆羽泛黄。","protection":"IUCN：LC（无危）；绿背啸鹟是限制分布物种，出现在Mindoro和Luzon生态区。据报道，在某些地方常见至丰富，特别是在海拔1000米以上更为常见。","distribution":"绿背啸鹟分布于远东地区的吕宋岛和民都洛岛（菲律宾北部）。","other":"历史上，一些权威认为绿背啸鹟是红树林啸鹟的一个亚种。"},{"name":"白臀啸鹟","english_name":"White-vented Whistler","scientific_name":"Pachycephala homeyeri","overview":"白臀啸鹟（英文名：White-vented Whistler，学名：Pachycephala homeyeri），是雀形目啸鹟科啸鹟属的鸟类。背部呈暖棕色，腹部白色，肩部附近带有淡淡的肉桂色斑纹，营造出一种‘穿马甲’的外观。在菲律宾中部至婆罗洲东北海岸的岛屿上被发现，栖息于低地到亚山地森林中。","appearance":"白臀啸鹟的上半身颜色温暖的棕色，下半身为白色，肩部附近有淡肉桂色的洗染效果，给人一种穿着马甲的印象。头部相对较小，颈部较长，胸部可能有一条不完整的、模糊的带状斑纹。与其他同属物种相比，它的体型和头部比例有所不同。","call":"发出高亢、清脆的哨音，以及各种颤音和哨音的组合。","habits":"通常与混合鸟群一起活动，多在森林较低层次，但也会上升至树冠层。其分布范围从菲律宾中部南至婆罗洲东北海岸的岛屿，偏好低地至亚山地森林。","identification":"与Negros Jungle-Flycatcher相似，但后者一般出现在更高海拔。白臀啸鹟具有更长的颈部和较小的头部，以及不完整且模糊的胸带，这是辨认的关键。","distribution":"分布在菲律宾的米沙鄢群岛西部和苏禄群岛（中西部和南部）以及婆罗洲东部的小岛。","other":"过去曾被认为是红树林啸鹟的一个亚种，现已确认为独立物种。"},{"name":"海岛啸鹟","english_name":"Island Whistler","scientific_name":"Pachycephala phaionota","overview":"海岛啸鹟（英文名：Island Whistler，学名：Pachycephala phaionota），是雀形目啸鹟科啸鹟属的鸟类。原生于摩鹿加群岛和新几内亚西部岛屿的木栖环境中。其自然栖息地为亚热带或热带的干燥森林及红树林。","appearance":"海岛啸鹟是一种中等体型的鸟，外观较为朴素。头部呈灰色，喉部白色，背部棕色，下体非常浅的棕色，胸侧带有略深的棕色斑点。与褐背啸鹟相似，但二者不会在同一区域出现。在其分布范围内无相似物种。","call":"发出杂乱的哨声歌曲，间或夹杂着典型的Whistler 'whip!'音符。叫声为尖锐下降的'jip!'。","habits":"海岛啸鹟生活在小岛屿的林木环境中，其具体生态习性和行为特征尚需更多研究。","breeding":"关于海岛啸鹟的繁殖信息，目前资料有限。","identification":"与褐背啸鹟相比，海岛啸鹟的分布区域完全不同，是区分二者的显著特征。","protection":"IUCN状态未知，具体保护措施不详。","distribution":"分布于摩鹿加群岛东部至新几内亚西部及班达海南部的小岛屿，包括Mayu岛，Halmahera岛附近的岛屿（Ternate, Tidore, Mare, Moti, Damar），West Papuan群岛（Waigeo, Sorong, Salawati, Kofiau, Misool, Schildpad）以及Geelvink湾（Rani）；Seram岛东北部（Bula），Seram Laut岛和Banda群岛（Bandaneira）；Tayandu群岛（Kur, Manggur, Taam）和Kai群岛（Kai Kecil和其他较小的岛屿）；Aru群岛（Pulau Babi及其他较小的岛屿）。","other":"海岛啸鹟最初被描述为属于Myiolestes属（现为Colluricincla的同义词）。"},{"name":"棕胸啸鹟","english_name":"Rusty Whistler","scientific_name":"Pachycephala hyperythra","overview":"棕胸啸鹟（英文名：Rusty Whistler，学名：Pachycephala hyperythra），是雀形目啸鹟科啸鹟属的鸟类。主要分布在新几内亚低地山区的亚热带或热带湿润森林。","appearance":"体长约15厘米，体重25至29克。额头、眼周和头顶为暗灰色，眼下的羽毛呈黑色，耳羽为深褐色；上体橄榄棕色，翅膀暗淡，飞羽边缘更显黄橄榄色，翼盖暖橄榄棕色；尾巴橄榄棕色，尾羽外缘黄色橄榄色；下巴、喉咙和颊区白色，下体浅红棕色；虹膜深棕色；喙黑色；腿粉色至粉灰或肉棕色。两性相似。幼鸟体色以锈红色为主，飞羽和翼盖边缘带锈色；亚成鸟似成鸟，但保留幼鸟的飞羽和覆羽。不同亚种有细微差异。","call":"具有丰富的鸣唱，包括1至12个响亮的钟声般哨音，音量逐渐增强，最后以1至3个响亮的“whik！”下滑或上扬音结束。叫声是一种低沉、略带哀伤的双音哨声，听起来像“tooi”或“tu-ee”。","habits":"栖息于海拔400至1200米的森林中，偶尔出现在低地（山脚）。主要以昆虫为食，通过在树干和树枝上的扫掠捕获猎物，主要活动于树冠下部的三分之二处。似乎在许多看似适宜的栖息地中较为罕见。","breeding":"筑巢活动在11月进行。巢为大型杯状，主要由小叶蕨类植物构成，辅以一些藤蔓和苔藓，内部铺垫叶片碎片和根须。一窝通常产2枚蛋，颜色为紫粉色至粉棕色，带有灰色和棕色斑点，靠近较大端形成宽环状图案，尺寸约为22.3×16.9至24.2×17.9毫米。","identification":"与棕鵙鹟相似，但棕胸啸鹟体型较小，喉部颜色对比明显。亚种sepikiana上体更偏橄榄色，喉部白色斑块更大，胸部和腹部色彩更鲜艳；reichenowi类似前者，但背部更深、更棕色，下体色彩较暗淡；salvadorii像指名亚种，但背部更棕色，下体颜色更浅、更暗淡。","protection":"IUCN：LC（无危）；在某些地区较为常见，但在其他地方稀少。在许多看似适宜的栖息地中似乎缺失。","distribution":"分布于澳新界的新几内亚。","other":"物种历史系统学信息未提供，可能涉及分类调整或研究进展。"},{"name":"褐背啸鹟","english_name":"Brown-backed Whistler","scientific_name":"Pachycephala modesta","overview":"褐背啸鹟（英文名：Brown-backed Whistler，学名：Pachycephala modesta），是雀形目啸鹟科啸鹟属的小型至中型山地森林鸟类，主要分布在新几内亚山区中部和东部，常见于亚热带或热带湿润的山地森林。","appearance":"成鸟具有暗灰色的冠部，面部上侧至眼眶下方为灰色，耳羽棕色，背部呈烟熏状棕色并带有橄榄色晕染；上翼和尾部为板岩棕色，所有翼羽边缘为浅灰色；喉咙和下体白色，胸部和两肋略带灰色；虹膜深棕色或深红棕色；喙和腿黑色。两性相似。幼鸟的羽毛杂乱，带有栗棕色至深红棕色的斑点；亚成鸟上体橄榄绿色，次级飞羽边缘锈色，下体淡黄色，上胸有时有一条不明显的锈色带，腹部泛淡黄色。hypoleuca亚种与指名亚种相比，上体颜色更偏向灰棕色，下体颜色更深的灰色；telefolminensis亚种与前者相似，但上下体颜色更深。","call":"鸣唱由上升的\"wheet\"哨声组成，前四个音符依次降低，随后的音符音高交替，以1-2个响亮的下降音符\"chiew\"结束。","habits":"栖息于森林、生态扰动区，偶尔在高山草甸的小树丛中。主要栖息高度从1830米到林线（3350-3600米），局部地区低至1130米（Efogi东南部）。似乎为留鸟。主要以昆虫为食，偶尔吃水果。频繁出现在树冠层（占观察次数的70%-85%）和中层。通过从大枝、小枝、枝梢和外层叶子上啄食捕获猎物，偶尔会从空中掠夺。","breeding":"已知在早期9月发现携带发育良好的卵的雌鸟，以及在晚11月和早12月发现繁殖期的鸟类，这表明其繁殖期可能在旱季后期到雨季初期，至少部分时间如此。其他信息尚不清楚。","identification":"与海岛啸鹟非常相似，但不会在同一地点共存。山鼠莺颜色相似，但体型更小，限制在林下层或地面活动。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚的山区中部和东部，主要栖息地从1830米至林线（3350-3600米），局部地区低至1130米（Efogi东南部）。","other":"历史系统学上，曾被最初描述在Poecilodryas属中。"},{"name":"黄腹啸鹟","english_name":"Yellow-bellied Whistler","scientific_name":"Pachycephala philippinensis","overview":"黄腹啸鹟（英文名：Yellow-bellied Whistler，学名：Pachycephala philippinensis），是雀形目啸鹟科啸鹟属的小型鸟类，主要分布于菲律宾的低地和山脚森林。其上部呈棕色，下部黄色，喉部白色，是菲律宾特有种。","appearance":"体长约15至16厘米，体重约21至27克。成鸟头部顶部灰褐色，略带橄榄色，头部侧面和耳羽灰色偏棕，背部橄榄绿；翅膀上部灰色，初级飞羽边缘灰橄榄色，其他飞羽外缘橄榄绿色；尾巴橄榄绿；下巴和喉咙淡白色，带有微弱条纹，腹部黄色较暗，上胸部略带灰橄榄色，两侧黄色橄榄色；虹膜深棕色到红棕色；喙暗角质色至黑色；腿灰粉色。雌雄相似。幼鸟与成鸟类似，但胸部和腹部赤褐色。不同亚种之间存在颜色和体型差异。","call":"叫声包括响亮、上升的单音哨声'peeeeup'，反复长时间发出；还有哨音'hu-i-yu wít weeu'，最后一个音节拉长。","habits":"栖息于亚热带或热带湿润的低地和山地森林。","breeding":"关于繁殖行为的具体信息未提供。","identification":"与Mindanao白眼鸟有些相似，但具有略厚的喙，背部缺乏橄榄绿色，通常在较低海拔发现。不同亚种在颜色上有细微差别。","protection":"IUCN状态未知。","distribution":"分布于菲律宾，具体包括除巴拉望岛外的菲律宾民都洛、米沙鄢群岛西部和苏禄群岛。","other":"已知有七个亚种，系统发育历史未详细描述。"},{"name":"硫黄腹啸鹟","english_name":"Sulphur-vented Whistler","scientific_name":"Pachycephala sulfuriventer","overview":"硫黄腹啸鹟（英文名：Sulphur-vented Whistler，学名：Pachycephala sulfuriventer），是雀形目啸鹟科啸鹟属的鸟类。该鸟以其独特的黄色腹部标记而闻名，分布于印尼苏拉威西岛的山区。","appearance":"成年硫黄腹啸鹟体长约14至15厘米，体重约22克。雄鸟上部橄榄棕色，头部较暗，眼上方、眼周区域和耳羽较淡，背部和尾羽覆羽略带红褐色；上翼深棕色，飞羽边缘橄榄棕色，覆羽大部橄榄棕色；尾部橄榄棕色；下颏、喉部、胸部和上腹部呈偏白色，胸部微染浅棕色，腹部中央渐变为黄色，下腹部变为鲜黄色，尾下覆羽和大腿部位黄色，两胁泛黄；虹膜深棕色；喙黑色；腿灰蓝色。雌鸟相似，但下部颜色更淡。幼鸟头部灰色调减弱，羽毛泛红褐色。","call":"鸣唱由五个哨音组成，音高逐渐降低同时音量增加，以响亮的音符结束，'wiwiwiwiwiuwhít'。还有长上滑音前接三个短音，'wheeu tu tu tu'。","habits":"栖息于苏拉威西岛的原始森林中，偶尔出现在森林边缘和次生林，海拔从海平面到2500米，主要分布在800至2500米之间（通常在800米以下少见）；在Lompobattang山的海拔范围为1000至2500米。以昆虫为食，从近地面的下层植被向上至较低的树冠层觅食，但主要在中间层活动。沿着树干和大树枝觅食，常加入混群觅食。","breeding":"关于繁殖的信息暂无。","identification":"通过其独特的黄色腹部和尾部基部的黄色标记，在其有限的分布范围内易于识别。","protection":"IUCN：LC（无危）。硫黄腹啸鹟是一种限制范围物种，仅存在于苏拉威西岛的生态区。广泛分布且一般常见。受栖息地改变和清除的负面影响；密度从原始森林到次生林，再到混合农村栖息地和种植园依次减少。在Lore Lindu国家公园有分布。","distribution":"主要分布于苏拉威西岛北部、中部、东南部和远南部的山区。"},{"name":"加里啸鹟","english_name":"Bornean Whistler","scientific_name":"Pachycephala hypoxantha","appearance":"婆罗洲啸鹟的上部羽毛为暗橄榄绿色，腹部呈现黄色调。雄鸟的颜色普遍比雌鸟更加鲜艳。这种鸟的体型适中，具有典型的啸鹟科特征，如结实的喙和紧凑的身体结构。","call":"其鸣声嘹亮而清脆，由一系列尖锐有力的音符组成，常带有波动的节奏，发出类似‘wit-chi’CHEW-chi’CHEW-chi’CHEW的声音。","habits":"婆罗洲啸鹟栖息于婆罗洲中部高海拔的森林中，偏好在森林中层活动，常见于混合物种的鸟群中，展示出一定的群居习性。","breeding":"具体繁殖细节未详述，但一般遵循啸鹟科的繁殖模式，包括筑巢、交配和育雏等过程。","identification":"在婆罗洲的中央高地森林中，婆罗洲啸鹟通过其特有的上体深橄榄色和下体黄色的组合，以及独特的鸣叫声，易于与其他啸鹟属成员区分开来。","protection":"IUCN状态未知，需查阅最新数据确认。在华盛顿公约(CITES)或中国国家重点保护野生动物名录中的状态未知。","distribution":"婆罗洲啸鹟的分布局限于东洋界的婆罗洲岛，主要在岛上的繁殖区域内被发现。","other":"系统学历史和其他重要信息未提供。"},{"name":"弗格克啸鹟","english_name":"Vogelkop Whistler","scientific_name":"Pachycephala meyeri","overview":"弗格克啸鹟（英文名：Vogelkop Whistler，学名：Pachycephala meyeri），是雀形目啸鹟科啸鹟属的小型鸟类，主要分布在印度尼西亚西巴布亚的鸟头半岛山区，自然栖息于亚热带或热带湿润山地森林。","appearance":"弗格克啸鹟具有典型的雌鸟啸鹟外观，其腹部呈黄色，上体橄榄色，头部灰色，胸部有一条模糊的横带，与喉咙的非常淡灰色形成鲜明对比。雌雄羽毛相似，大小适中，头部略显圆润。","call":"其鸣唱为一段短暂的、吹口哨般的中音调短语，音量逐渐增强。此外，还有一种加速上升的连续音符序列，音高相同，带有爆发性的质感。","habits":"生活在海拔较高的山地森林中，活动范围限于其特有的栖息地，主要以昆虫和其他小型无脊椎动物为食。关于其具体的食物选择和捕食策略，现有资料有限。","breeding":"繁殖信息有限，但据观察，繁殖期可能与雨季相关联，筑巢于树丛中，雌鸟负责孵化和育雏。","identification":"与斯氏啸鹟雌鸟区别的关键在于其较浅、单一色调的灰喉，而与黑领啸鹟雌鸟的区别在于其灰色的头部。","protection":"IUCN：LC（无危）","distribution":"主要分布于印度尼西亚西巴布亚的鸟头半岛山区，包括Tamrau山脉和Arfak山脉，可能也存在于Foja山脉。","other":"弗格克啸鹟还有其他名称，如灰冠啸鹟和Meyer's Whistler。"},{"name":"灰啸鹟","english_name":"Grey Whistler","scientific_name":"Pachycephala simplex","overview":"灰啸鹟（英文名：Grey Whistler，学名：Pachycephala simplex），是雀形目啸鹟科啸鹟属的鸟类。以及澳大利亚北部。其显著特征为灰色上部和苍白下部，常见于低地森林和红树林地带。","appearance":"灰啸鹟体长约14至15厘米，体重介于16至20克。成年雄鸟具离白色眉纹，灰褐色面颊和耳羽，橄榄棕色的颈部侧面和背部，翅膀和尾部呈暗橄榄棕色，腹部偏白，下巴和喉部有轻微的淡褐色条纹，胸部有棕色洗染，有时伴有深色条纹。虹膜呈红棕色，喙和腿黑色。雌雄相似，幼鸟全身偏赤褐色，下部更浅，翅膀和尾羽边缘赤褐色。亚种间存在色彩差异，如背部颜色、腹部黄色程度和下部条纹程度。","call":"灰啸鹟的鸣唱是一系列缓慢的模糊哨音，有时以鞭裂声结尾，叫声包括短哨音。","habits":"栖息于高大的雨林、季风雨林、较干燥的藤本森林边缘及再生区，也见于红树林。主要以昆虫和蜘蛛为食，偶尔食用种子。在新几内亚，多在约5至30米的高度觅食，偶尔接近地面。在澳大利亚，觅食高度主要在中间到上层树冠，偶尔低于1米。通常在树叶中觅食，偶尔在树枝上或空中捕食。","breeding":"繁殖季节为12月至翌年3月，可能持续到9月。维持全年松散的领地。巢由草、叶、根须、枝条、植物纤维和蜘蛛网构成，内衬细丝、羽毛和草籽，置于树枝分叉处、藤本植物中或树桩上的直立枝条间，高度通常在6至15米之间。每窝产卵2枚，淡黄色带有深棕色和淡紫色斑点。","identification":"与金啸鹟雌鸟相比，灰啸鹟体型较小且更为修长。亚种间通过羽毛颜色和腹部色调区分。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚北部，新几内亚及周边岛屿，以及印尼摩鹿加群岛南部。在澳大利亚，常见于低地和丘陵地区，海拔可达900米；在新几内亚，分布于低地和山丘，海拔高达1550米。","other":"灰啸鹟通常被视为Pachycephala griseiceps的同种，但基于形态学和鸣叫的差异，现将其视为独立物种。"},{"name":"褐胸啸鹟","english_name":"Fawn-breasted Whistler","scientific_name":"Pachycephala orpheus","overview":"褐胸啸鹟（英文名：Fawn-breasted Whistler，学名：Pachycephala orpheus），是雀形目啸鹟科啸鹟属的鸟类。雀形目的小型鸟类，也被称为Sunda whistler和Timor whistler，尤其在小巽他群岛的罗地岛、帝汶岛、Jaco岛、Atauro岛和Wetar岛可见其踪迹。","appearance":"褐胸啸鹟是一种外表普通的厚喙、麻雀大小的鸣禽。上部颜色统一为灰褐色，下部较淡，喉部白色，腹部淡色而暗淡。幼鸟的喙呈淡色，胸部有隐约的条纹。成年个体的大小和喙的尺寸明显小于雌性黄喉啸鹟，且没有雌性印尼啸鹟的喉部条纹。","call":"其鸣唱由响亮的上滑哨声组成，音量逐渐增大，例如发出类似‘pi-pi-pi-pi-CHWEE’或‘doo-doo-doo…DEE’的声音，也会发出‘swee’音符。","habits":"褐胸啸鹟常以单个、成对或家庭群的形式出现在低地和山丘的森林、灌木丛或红树林中。它们的栖息地限于东小巽他群岛。","identification":"与雌性黄喉啸鹟相比，褐胸啸鹟体型更小，喙更细小，且缺乏喉部的条纹，这是与印尼啸鹟雌鸟的明显区别。","protection":"IUCN状态未知。","distribution":"褐胸啸鹟主要分布在东小巽他群岛的罗地岛、帝汶岛、Jaco岛（帝汶岛东部）、Atauro岛（位于帝汶岛和Wetar岛之间）和Wetar岛。","other":"褐胸啸鹟的分类学和生态学研究仍有待深入。"},{"name":"黑领啸鹟","english_name":"Sclater's Whistler","scientific_name":"Pachycephala soror","overview":"黑领啸鹟（英文名：Sclater's Whistler，学名：Pachycephala soror），是雀形目啸鹟科啸鹟属的鸟类。中等体型的啸鹟科鸟类，主要分布于新几内亚的中海拔森林地带。其黄腹、橄榄绿背和白喉为其显著特征。以英国动物学家Philip Lutley Sclater命名。","appearance":"雄鸟成鸟头部至眼眶下方黑色，上体暗橄榄绿色，翼与尾部呈暗灰色，边缘略带橄榄色，下体黄色，胸部具黑色带纹；雌鸟头侧棕色，胸带淡橄榄色，腹部黄色。幼鸟体羽偏红栗色，翼覆羽与尾上覆羽尖端亦同色。","call":"鸣唱由一系列典型的‘chew！’或‘whip！’音调构成，音量逐渐增大，结尾带有爆发性。","habits":"栖息于350至2450米的森林、林缘及次生植被中，主要活动于1000至2000米高度，偶尔下降至400米或上升至1450米。通常为留鸟，可能有局部海拔迁移。以昆虫为食，常在森林较低层和中层觅食，有时加入混群觅食。","breeding":"繁殖期横跨雨季与旱季，巢为小型杯状，由茎、叶、苔藓和蜘蛛网构成，置于距地面1.5至6米的树叉或藤蔓丛中。每窝产卵1至2枚，粉奶油色，具深棕色与深紫灰色斑点。","identification":"雄鸟与其它金色啸鹟相似，但无头部后方黄色斑块；雌鸟与帝王啸鹟、洛伦兹啸鹟和沃格尔考普啸鹟相似，但有白色喉咙和棕色头部。","protection":"IUCN：LC（无危）","distribution":"主要分布于新几内亚的山地森林，特别是在Kumawa山脉的550至1300米（有时低至400米或高至1450米）以及Fakfak山脉的600至1200米。"},{"name":"锈红胸啸鹟","english_name":"Rusty-breasted Whistler","scientific_name":"Pachycephala fulvotincta","appearance":"体长14–15厘米。雄鸟：头、颈侧及上胸形成大片黑色，与白色喉部及金黄色颈环、胸腹形成强烈对比；背橄榄黄，翼黑而缘橄榄灰，尾黑基部灰褐。雌鸟：全身灰褐，背部带橄榄色，喉白色，胸带粉褐，腹部淡黄，尾羽暗褐缘沙色。幼鸟羽色混杂，飞羽外缘带红褐色。亚种间差异细微，主要在于雄鸟下体锈红浓淡、雌鸟喉部及胸带色调。","call":"鸣声为4–9声嘹亮而逐渐升高的哨音，每秒约2音，常见变体如“we…wee…weee…urWEEEH”或“cho…chow…CHOW”。另有短促平稳的“weet”连叫及单音“weet”叫声。帝汶岛种群会发“tee-tee-work-chop”式的下滑音节。","habits":"栖息于常绿林、藤蔓灌丛、红树林（如Rhizophora、Sonneratia）及耕地灌丛。主要在树冠及灌丛中上层觅食，偶至地面；以探取方式捕捉枝叶上的昆虫、蜘蛛为主，偶食小果，极少吃种子。留鸟，未见明显迁徙。","breeding":"繁殖期3–8月，盛期4–6月。巢筑于树上。每窝1–2枚卵，卵呈乳白或奶油色，具不规则橄榄或乌黑斑及灰底晕斑，斑点多集中大端。卵大小约21.3–23×15.4–17.4毫米。","identification":"与同属其他种相比，雄鸟黑白头纹与金黄胸腹组合独特；雌鸟灰褐而无明显翼斑，可与白胸啸鹟等区分。与塞岛啸鹟的区别在于后者雄鸟似雌鸟羽色，无黑色颈环。亚种间需凭雄鸟锈红浓淡、雌鸟喉胸色调及体型大小辨识。","protection":"IUCN: LC（无危）","distribution":"繁殖区：印度尼西亚小巽他群岛（松巴哇岛以东至阿洛岛、松巴岛、罗地岛、帝汶岛、塞毛岛、韦塔岛）及爪哇极东部（东爪哇、巴厘岛）；非繁殖区无迁徙记录。","other":"历史上曾被并入“Golden Whistler”广义复合种，后经分子与形态研究拆出独立种，并将原置于黄喉啸鹟的亚种 calliope 并入本种，形成现分类格局。"},{"name":"黄喉啸鹟","english_name":"Yellow-throated Whistler","scientific_name":"Pachycephala macrorhyncha","overview":"黄喉啸鹟（英文名：Yellow-throated Whistler，学名：Pachycephala macrorhyncha），是雀形目啸鹟科啸鹟属的鸟类。体型敦实、喙厚重的小型鸣禽，雄鸟黑罩白头、喉部亮黄、腹面金黄，背部橄榄绿并具金黄颈圈，雌鸟灰褐朴素，胸腹淡黄；分布于印尼马鲁古群岛、苏拉群岛、邦盖群岛及塔宁巴尔群岛等，栖息于潮湿至干燥林地和灌丛，海拔自海平面至1600米，基本为留鸟，以昆虫、蜘蛛为主食，兼食少量果实。","appearance":"体胖、喙粗壮。雄鸟头顶至颈背黑色，形成显著“黑兜帽”，喉部白或亮黄（塔宁巴尔亚种为鲜黄），上体橄榄绿，颈背具金色细圈，下体鲜黄；雌鸟上体灰褐，喉部淡色，胸腹淡黄至浅褐色。五个亚种体型与色彩深浅略有差异。","call":"鸣声多变，通常由响亮清晰的哨音组成，尾音常带1–2声鞭裂似“wee-wee-wee-WHIP-CHOO”；苏拉群岛种群发出先升后平的“whit tu tu tsit”爆破音节。","habits":"主要栖于潮湿或多林生境，可进入较干燥及人为改造的灌丛、次生林、沿海灌丛及红树林。海拔分布随岛屿地形而异，苏拉群岛可达1000米，塞兰岛至1630米（多在600米以上），布鲁岛至1250米。属留鸟，未见长距离迁徙。觅食多在树冠或灌丛枝叶间，偶尔下地，常加入混合种类觅食群。","breeding":"暂无具体繁殖期、求偶、巢址、卵数及育雏等资料。","identification":"与同属种类区别：雌鸟与褐胸啸鹟相比体型更大、喙更长更厚；与印尼啸鹟相比喉部无纵纹；与褐啸鹟相比下体更黄、上体更褐。亚种间差异主要体现在体型大小、黄色浓淡及颈圈宽窄。","protection":"IUCN: LC（无危）","distribution":"繁殖区与非繁殖区重叠，仅分布于印尼东部岛屿：塔宁巴尔群岛（拉腊特、延德纳）、中马鲁古（塞兰岛、安汶岛、布鲁岛）、苏拉群岛及邦盖群岛。","other":"系统分类复杂，曾被视为金啸鹟的亚种之一；与巴巴岛啸鹟曾合并，现已分立。分子系统学研究表明其与黑颏啸鹟、黄背啸鹟及黑尾啸鹟等亲缘关系较近。"},{"name":"巴列姆啸鹟","english_name":"Baliem Whistler","scientific_name":"Pachycephala balim","overview":"巴列姆啸鹟（英文名：Baliem Whistler，学名：Pachycephala balim），是雀形目啸鹟科啸鹟属的鸟类。中等体型的啸鹟科鸟类，主要分布于新几内亚的巴里姆山谷的山地森林和次生栖息地中。典型的雄鸟‘金色’啸鹟，具有黄色腹部、黑色头部和胸部带，以及白色喉咙。雌鸟则有棕色头部和胸部带，喉部有斑驳状。该物种与斯克莱特啸鹟相似，但巴列姆啸鹟的雄鸟在颈背有一圈宽广的黄色环带，而雌鸟的喉部呈斑驳而非纯白。","appearance":"雄性巴列姆啸鹟的头部顶部和侧面、颈背为黑色，黑色延伸至胸带，包围着白色的颏、喉咙和颊部区域；颈后部有黄色的项圈，延伸至两侧的胸部；上体为黄橄榄色，臀部和上尾羽稍淡；飞羽为烟熏黑色，外缘有橄榄灰色边缘（一级飞羽细小，二级飞羽窄，三级飞羽宽）；上翼覆羽为烟熏灰色，边缘和尖端为橄榄黄色；尾巴为黑色，基部为深灰褐色，尾羽尖端为灰色；下体胸带以下为黄色，胁部微带橄榄色；虹膜为暗红色；喙为黑色；腿为灰黑色至黑色。雌鸟头部顶部和侧面为棕色至灰棕色，与上体的暗橄榄棕色融合，上尾覆羽微带橄榄色，眼周为浅棕色，耳羽为灰棕色；上翼为橄榄棕色，飞羽边缘为灰橄榄色（从初级飞羽到三级飞羽逐渐增加），翼覆羽边缘和尖端为橄榄灰色，尾巴为暗橄榄棕色，尾羽狭窄地边缘为橄榄色；颏和喉咙为偏白色，有模糊的灰棕色横纹，胸部为浅棕色，腹部和胁部为偏白色，下尾覆羽为淡黄色。幼鸟全身几乎为赤褐色，飞羽为烟熏棕色，外缘为赤褐色（三级飞羽宽，向初级飞羽变细），初级覆羽边缘为赤褐色，大和中次级覆羽为赤褐色，尾羽边缘为赤褐色，虹膜和喙为深棕色。","call":"巴列姆啸鹟发出杂乱的哨音歌曲，包含一些具有爆炸性质的声音元素。","habits":"栖息于各种树木茂密的环境，包括湿润森林、次生林和次级栖息地。在澳大利亚，进入较干燥和被改造的栖息地。在新几内亚，巴列姆啸鹟主要生活在山地森林中，但也可见于卡苏里纳树林和村庄周围的遮阴树。","breeding":"繁殖季节为8月至次年2月，筑巢由雌鸟主导，雄鸟提供协助。巢通常位于离地面0.5至9米的密集外层树叶中的直立或垂直分叉处。每窝产卵2至3枚，孵化期15至16天，雏鸟期10至12天。","identification":"与斯克莱特啸鹟相比，巴列姆啸鹟的雄鸟颈背有一圈宽广的黄色环带，雌鸟的喉部呈斑驳而非纯白。","protection":"IUCN：LC（无危）","distribution":"巴列姆啸鹟主要分布在新几内亚的巴里姆山谷，具体而言，位于印尼巴布亚省的雪山山脉。","other":"该物种的分类历史复杂，曾被认为是澳大利亚金喉啸鹟、红喉啸鹟和黄喉啸鹟的亚种，2016年被IOC重新分类为独立物种。"},{"name":"黑颏啸鹟","english_name":"Black-chinned Whistler","scientific_name":"Pachycephala mentalis","overview":"黑颏啸鹟（英文名：Black-chinned Whistler，学名：Pachycephala mentalis），是雀形目啸鹟科啸鹟属的鸟类。分布于印尼摩鹿加群岛北部。雄鸟具有显著的黑色头部、黄色颈圈、醒目的白色喉部、黑色胸线以及鲜艳的黄色下体，雌鸟颜色较为低调，头灰褐色，喉部较淡，下体泛黄。在奥比岛和暗淡啸鹟中，雌鸟的黄色下体和橄榄色上体有助于区分。","appearance":"雄性黑颏啸鹟体型健壮，喙厚实，额头至冠羽、头部两侧和颈背黑色，黄色颈圈明显；背部橄榄绿，翅膀黑色边缘带橄榄色；下巴黑色，喉咙和颊区白色，胸部狭窄的黑色胸带，下体黄色，两胁带有赭石/锈色；虹膜深红色，喙黑色，腿灰褐色至灰黑色。雌鸟头部顶部和两侧灰褐色，背部橄榄色，喉咙有灰色和白色的条纹，胸部灰色，胸部和两侧橄榄色，腹部至尾下覆羽柠檬色。幼鸟类似雌鸟，但有赤褐色元素在羽毛中。提多伦斯亚种稍大，雌鸟冠羽略浅，橄榄色部分更黄；奥比岛亚种雄鸟下巴白色而非黑色，喉咙羽毛不那么延长，雌鸟冠羽和披肩棕色，喉咙条纹和喉下带淡黄色，胸部和两胁橙色，腹部鲜黄色。","call":"其鸣唱由一系列相同且间隔均匀的哨声组成，通常5到15个，以稳定节奏发出（或略微加速），音量逐渐增大，以1到4个爆发性的哨声结束。结尾哨声通常急剧上扬或下滑。叫声包括上扬的‘whit’。","habits":"栖息于森林、林缘、灌木丛和红树林，从低地到山丘，但通常在较高海拔更为常见。主要在树冠层觅食，偶尔在地面活动。加入混合物种群落。","breeding":"繁殖信息不确定。繁殖行为可能与金啸鹟和其他复杂中的物种相似。","identification":"雄性黑颏啸鹟的白色喉部、不完整的黑色胸带和小的黑色下巴（在奥比岛缺乏）是其与其他啸鹟的重要区别点。","protection":"IUCN：LC（无危）。该物种在其分布范围内相对普遍，种群似乎稳定，但总数未知。","distribution":"分布于印尼摩鹿加群岛北部，包括哈马黑拉岛及其周边较小岛屿。","other":"该物种有时被视为澳大利亚金啸鹟的亚种，但也有观点认为应视为独立物种，进一步研究有待解决复杂的分类学问题。"},{"name":"金啸鹟","english_name":"Australian Golden Whistler","scientific_name":"Pachycephala pectoralis","overview":"金啸鹟（英文名：Australian Golden Whistler，学名：Pachycephala pectoralis），是雀形目啸鹟科啸鹟属的鸟类。是澳大利亚体型紧凑、羽色鲜明的鸣禽，曾被归入多达73个亚种，后经分子研究拆分，现确认7个亚种，分布于澳大利亚大陆、塔斯马尼亚、巴斯海峡岛屿、豪勋爵岛和诺福克岛。雄鸟具黑黑头、白喉及金黄下体，雌鸟灰褐并带黄腹羽缘；鸣声为响亮尖锐的口哨并带鞭梢式尾音。该种栖于密林下层的多种森林与灌丛，以昆虫等无脊椎动物为主食，一夫一妻制，双亲共育，杯巢以草茎叶及蛛丝编织，每窝2–3卵。整体数量尚丰，IUCN未作最新评估，大陆种群无危，但岛屿亚种因范围狭小列为易危。","appearance":"体长16–19厘米，体重19–32克，因亚种而异。雄鸟：头、颈背及胸带黑色，白喉鲜明，上体橄榄黄，下体亮黄，尾黑；诺福克岛雄鸟色似雌鸟，上体棕褐，胸淡褐渐转乳黄。雌鸟：头及上体灰褐或褐灰，喉及胸浅褐，腹及胁灰白，肛周淡黄。幼鸟全身近红褐色，飞羽及尾羽具红褐缘；第一年幼鸟似雌鸟，但保留红褐色初级飞羽、覆羽及尾羽，具红褐色翼斑，眼、嘴褐色。各亚种羽色深浅、领环宽度及尾色灰黑比例略有差异。","call":"鸣声为连续响亮清晰的口哨，音量与速度常有变化，末尾常带1–2声鞭梢般短促高音。地域及个体差异显著，录音资料丰富。典型调型为“choo choo choo chip”或“peep peep peep pu-wit”；秋冬短曲仅1–2音后接鞭音“whi-whit”。另有“tweet-a-weet-a”串音及秋冬季上扬的“seep”声。","habits":"栖于多种具浓密下木的生境：雨林、湿润与干旱桉树林、灌丛、木麻黄、白千层及班克木林地，亦见于公园、花园及外来松林。海拔分布自海平面至1500 米，北部昆士兰繁殖季可达1300 m以上，非繁殖季降至1000 m以下。多数留鸟，局部具海拔迁移，2–4月离开高海拔繁殖地，8–10月返回。觅食主要在树冠及灌丛，偶尔地面；以昆虫和蜘蛛为主，偶食果实，极少种子。常加入混合种群觅食群。","breeding":"繁殖期8月至翌年2月，主产卵9–10月；豪勋爵岛9–10月，诺福克岛9–12月。一夫一妻制，双亲共育。巢置于灌木或小树外侧直立分叉处，距地0.5–9 米，通常约3 米。雌鸟主筑巢，雄鸟协助；巢杯形，外径8.9–15.2厘米，内径5.1–7厘米，深3.2–5.1厘米，由细枝、草茎、叶、根、树皮与蛛丝构成，内衬细草等。每窝2–3枚卵，卵白色或乳黄、鲑鱼色，密布褐、红褐及暗灰色斑，多集中于钝端；平均23.8×17.3 mm（大陆）、26.2×18.4 mm（诺福克岛）。双亲轮流孵卵15–16天；雏鸟留巢10–12天，双亲共同育雏。巢常被杜鹃寄生，记录有苍色杜鹃、斑噪鹃及扇尾噪鹃。","identification":"与同属绿啸鹟相比，金啸鹟雄鸟下体金黄而非褐，喉部黑白对比鲜明；雌鸟下腹带黄，绿啸鹟雌鸟喉部具明显白斑。与已分出的黑颏啸鹟、红胸啸鹟等相比，金啸鹟羽色及鸣声均有差异。亚种间差异主要表现在羽色浓淡、领环宽窄及尾灰黑比例，需结合分布区域辨别。","protection":"IUCN: Least Concern（无危，最近一次评估针对合并前复合体）。大陆种群普遍且局部丰富。豪勋爵岛亚种P. p. contempta与诺福克岛亚种P. p. xanthoprocta因分布范围极小，被列为易危（Vulnerable）。前者约2000只繁殖鸟，分布12 km²；后者约1000只繁殖鸟，分布5 km²，自1960年代起数量持续下降，主要威胁为栖息地丧失及黑家鼠捕食。","distribution":"繁殖区遍及澳大利亚东部自昆士兰凯恩斯以南至新南威尔士、维多利亚，向西贯穿南澳大利亚干旱区至西澳大利亚西南部，北至卡尔巴里；塔斯马尼亚、巴斯海峡的金岛与弗林德斯岛；豪勋爵岛；诺福克岛。非繁殖季部分种群向低海拔或开阔区移动，岛屿种群基本留居。","other":"历史上因亚种繁多，分类屡经调整；近期分子研究将多个亚种提升为独立种，如黄喉啸鹟、红胸啸鹟等，但“西部啸鹟”P. p. fuliginosa与指名亚种基因差异小，仍归本种。系统发育研究表明其与美岛啸鹟关系最近。"},{"name":"西方啸鹟","english_name":"Western Whistler","scientific_name":"Pachycephala fuliginosa","overview":"西方啸鹟（英文名：Western Whistler，学名：Pachycephala fuliginosa），是雀形目啸鹟科啸鹟属的鸟类。在澳大利亚西南部和中南部广泛分布的鸟类。其特征包括头部黑色，背部橄榄黄色，腹部鲜黄，尾羽灰色带黑尖，而雌鸟则呈现灰褐色上部和较淡的下部，腹部呈黄褐色。曾被认为是金喉啸鹟的亚种，但分子研究证实它与金喉啸鹟关系更远，近似于黑尾啸鹟物种群。","appearance":"雄性西方啸鹟具有黑色的头部和颈背，白色喉咙，黄色腹部延伸至颈部后方，翼羽覆盖着交替的橄榄色和灰色条纹，尾巴细长且灰。雌鸟则有相似的身体轮廓，但头部颜色较浅，腹部白色，翅膀和尾巴为棕色和灰色。幼鸟全身几乎呈赤褐色，翼羽深褐色，边缘橄榄色，虹膜和喙呈暗棕色。成年雄鸟指名亚种有黑色的头顶、侧面和颈背，黄色的领圈，橄榄黄色的上体，翼羽烟黑色，边缘橄榄灰色，尾羽黑色，基部暗灰褐色，腹部黄色。雌鸟上部暗灰色，下部较淡，腹部呈黄褐色。亚种大小和羽毛模式差异显著。","call":"鸣声通常由一系列响亮、清晰的哨音组成，有时音量和速度有所变化，通常以一两个鞭裂般的音符结束。在澳大利亚，重复的单音节后跟着短促、尖锐的高音哨音。","habits":"西方啸鹟偏好密集的林下植被环境，如雨林、湿润和干燥的桉树森林和灌木丛，偶尔出现在花园和公园。它们在不同海拔高度活动，从低地到山区都有分布。部分种群全年留驻在某些地区，而其他种群则有迁徙行为，冬季会向较低海拔的开阔地带迁移。以昆虫和蜘蛛为主要食物，偶尔吃水果，很少食用种子。","breeding":"繁殖季节一般从8月持续到次年2月，主要集中在9月至10月。筑巢主要由雌鸟负责，巢由树枝、草和其他植物材料构成，放置于树木或灌木的浓密枝叶中。每窝产卵2-3枚，孵化期大约15-16天，由双亲共同孵卵和喂养幼鸟。","identification":"雄性西方啸鹟通过其黑色头部、白色喉咙、黄色腹部和黑色领圈与其它啸鹟种类区分开来。雌鸟则以其灰褐色上体和黄褐色腹部区别于其他啸鹟。与金喉啸鹟相比，西方啸鹟的体型、颜色和叫声都有所不同。","protection":"IUCN：LC（无危）","distribution":"西方啸鹟主要分布在澳大利亚西南部和中南部，包括维多利亚西部和南澳大利亚东南部。在澳大利亚的分布范围从卡巴里南至南部和东部，扩展到澳大利亚南部和维多利亚州西部的较干旱地区。","other":"西方啸鹟的两个公认的亚种包括P. f. occidentalis和P. f. fuliginosa。现为金啸鹟亚种。"},{"name":"俾斯麦啸鹟","english_name":"Bismarck Whistler","scientific_name":"Pachycephala citreogaster","appearance":"雄鸟成鸟具有黑色的头顶和颈侧，黄色的颈圈，黄橄榄色的上体，黑翼缘橄榄灰色，黑色尾部基部暗灰棕色。雌鸟头部褐色至灰褐色，上体暗橄榄褐色，下体灰白至灰黄白色。幼鸟全身几乎呈锈红色，翼羽烟灰色，边缘锈色。个体大小变异大，体重介于19至32克，长度16至19厘米。","call":"鸣声由响亮的哨音组成，通常以一到两个鞭裂般的音节结束。","habits":"栖息于各种森林生境，偏好密林，但也出现在干燥和改造过的环境中。迁徙习性未知，热带和岛屿种群可能定居。澳大利亚种群部分迁徙，季节性向低海拔开阔地带移动。","breeding":"繁殖季节为8月至次年2月，筑巢于灌木或小树的浓密外叶中，高0.5至9米。每次产卵2至3枚，孵化期15至16天，雏鸟期10至12天。巢穴可能受到寄生鸟的威胁。","identification":"雄鸟喉部白色，区别于东南方向的鹂啸鹟。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚和新西兰地区的俾斯麦群岛。","other":"种群数量中等到常见，但在特定岛屿如诺福克岛（Norfolk I）和豪勋爵岛（Lord Howe I）上列为\"易危\"，由于其小范围分布而面临潜在风险。"},{"name":"鹂啸鹟","english_name":"Oriole Whistler","scientific_name":"Pachycephala orioloides","overview":"鹂啸鹟（英文名：Oriole Whistler，学名：Pachycephala orioloides），是雀形目啸鹟科啸鹟属的鸟类。以其明亮的金色腹部、黑色头罩和胸带以及橄榄色的背部和翅膀而著称。分布于所罗门群岛，除圣克鲁斯群岛外，广泛存在于岛上的森林地带。","appearance":"成年鹂啸鹟体长17至19厘米，体重41.5至57.5克。雄鸟头部和脸侧黑色，胸部有一条宽阔的黑色带，金色的喉咙（下巴黑色）和脸颊区域。颈后的项圈鲜黄色，延伸到胸部两侧。上部和尾羽覆羽为金橙橄榄色，上翼和翼羽深棕色，主翼羽边缘灰色，翼羽边缘金橙橄榄色，尾羽黑色，尾羽尖端淡橄榄色。下部为亮金色。雌鸟的头部顶部和上部颜色较暗，从灰橄榄色到棕橄榄色不等，翼羽边缘红褐色，最外侧的主翼羽带有橄榄肉桂色调，翼羽边缘红褐色，尾羽为棕橄榄色，喉咙和下部为黄色，有时有灰色橄榄色的条纹（尤其是在喉咙和胸部），胸部和两肋通常染有橄榄色或赤褐色。喙、眼睛和腿的颜色因性别而异。","call":"鹂啸鹟的叫声包括一系列简单响亮的旋律哨音或爆炸性的音符，变化多样，常夹杂着鞭裂声。黎明时分，它们会持续大声歌唱；白天则通常发出短促的歌曲片段。叫声包括单一哨音、粗糙的嘶哑责骂声和细薄的‘chup’接触音，后者常由雌鸟样的鸟儿发出。不同亚种之间存在声音差异，但记录有限。","habits":"鹂啸鹟主要栖息在森林地带，包括原始森林和次生林，以及种植园；它们也会进入有树木的花园。在布干维尔岛上，它们的记录高度为600至1200米，很少出现在低地。在圣伊莎贝尔岛，上世纪80年代被认为仅限于海拔900米以上的山区森林，但后来发现在低地森林也有分布。在科隆班加拉岛上，它们被观察到的高度可达1595米，在当前世纪可达1400米，遍布该岛的所有森林栖息地。在马基拉岛，它们在原始森林中最为常见，其次是花园、次生林和混合可可种植园。在圣克里斯托瓦尔和瓜达尔卡纳尔岛，它们生活在森林直至雾林边缘，总是在破碎的地方或半开放的森林中，非常少见于次生林；避开海岸附近的藤蔓缠绕的密林。","breeding":"在瓜达尔卡纳尔岛，7月中旬成鸟携带筑巢材料，11月见到幼鸟离巢。在科隆班加拉岛，5月份有多只处于繁殖状态的标本。","identification":"雄性鹂啸鹟以黑色头罩、金色喉咙和宽阔的黑色胸带为特征，而雌鸟则颜色较暗，从灰橄榄色到棕橄榄色不等，喉咙和下部为黄色，可能有灰色橄榄色的条纹。与其他啸鹟属物种相比，鹂啸鹟的体型较大，雄鸟具有明显的黑色下巴，喉咙黄色区域相对较小，通常有宽广的胸带，雌鸟喙色较浅。","protection":"IUCN：LC（无危）","distribution":"鹂啸鹟广泛分布于所罗门群岛，除圣克鲁斯群岛外，包括布干维尔岛、科隆班加拉岛、马基拉岛、圣克里斯托瓦尔岛和瓜达尔卡纳尔岛。","other":"鹂啸鹟曾被视为广泛分布的金啸鹟的一个亚种，或作为独立物种处理，但支持任一观点的有力证据有限，需要进一步研究以解决复杂的分类问题。"},{"name":"路易啸鹟","english_name":"Louisiade Whistler","scientific_name":"Pachycephala collaris","overview":"路易啸鹟（英文名：Louisiade Whistler，学名：Pachycephala collaris），是雀形目啸鹟科啸鹟属的鸟类。分布于巴布亚新几内亚的路易西亚德群岛，属于新几内亚东南部的特有种。其显著特征包括橄榄色背部、黄色腹部和白色喉部。雄鸟具有头部后方的黄色斑块、黑色头部和黑色或锈色胸带；雌鸟头部呈棕色。该物种在分布范围内无相似种类。","appearance":"路易啸鹟是一种中等体型的鸟，体长16至19厘米，体重19至32克，存在多种亚种差异。雄鸟具有黑色的头顶和颈背，黑色胸带包围着白色的喉部和面颊区域；颈后有黄色项圈，延伸至胸部两侧；上体呈黄橄榄色，臀部和上尾覆羽颜色略淡；翅膀呈炭黑色，边缘有橄榄灰色（初级飞羽细，次级飞羽窄，三级飞羽宽）；上翼覆羽呈炭灰色，边缘和尖端为橄榄黄色；尾巴黑色，基部暗灰褐色，尾羽尖端狭窄地呈现灰色；下体胸带以下为黄色，两胁略带橄榄色；虹膜深红色；喙黑色；腿灰色至黑色。雌鸟头部顶部和侧面呈棕色到灰棕色，与暗橄榄棕色的上体融合，上尾覆羽微带橄榄色，眼上方区域淡棕灰色，耳覆羽灰棕色；上翼橄榄棕色，飞羽边缘灰橄榄色（从初级飞羽到三级飞羽逐渐增加），翼覆羽边缘和尖端橄榄灰色，尾巴暗橄榄棕色，尾羽边缘狭窄地呈现橄榄色；下巴和喉咙淡白色，带有模糊的灰棕色条纹，胸部浅棕色，腹部和两胁淡白色，下尾覆羽淡黄色。幼鸟几乎全身赤褐色，飞羽炭褐色，边缘赤褐色（三级飞羽宽，向初级飞羽变细），初级覆羽边缘赤褐色，较大和中等次级覆羽赤褐色，尾羽边缘赤褐色，虹膜和喙深棕色；第一次换羽的亚成鸟类似于雌鸟成鸟，保留幼鸟的飞羽、翼覆羽（形成赤褐色的翼斑）和尾羽，也有棕色的眼睛和喙；第二次和第三次换羽的雄鸟亚成鸟与雌鸟成鸟无法区分。","call":"路易啸鹟的鸣唱通常为中音调、画眉般的歌声，伴有典型的‘chew！’和‘whip！’音符。","habits":"生活在沿海森林中，偏好密集的下层植被环境，如雨林、湿润和干燥的桉树（Eucalyptus）森林和灌木丛，有时也会出现在花园和公园中。在不同的季节，它们可能会迁移到海拔较低的开放生境。在澳大利亚，某些种群全年都会出现在某些地点，而其他种群则会在不同季节进行不同程度的迁徙，主要是海拔迁移，冬季移至低海拔的开阔地带。","breeding":"繁殖季节通常为8月至2月，在澳大利亚主要集中在9月至10月。筑巢由雌鸟主导，雄鸟辅助，巢为杯状，由树枝、植物茎、草、针叶、根须、树皮、枯叶、藤蔓等材料构成，外部用蜘蛛网加固，内部铺垫草、根须、树皮，偶尔有羊毛或苔藓。巢置于小树或灌木浓密枝叶中的垂直或直立分叉处，距离地面0.5至9米。每窝产卵2至3枚，孵化期为15至16天，双亲共同孵化和喂养雏鸟，巢期为10至12天。","identification":"雄性路易啸鹟具有独特的黑色头冠、黄色颈背和黑色胸带，雌鸟头部呈棕色，这与其他近似种类明显不同。","protection":"IUCN：LC（无危）","distribution":"路易啸鹟主要分布在巴布亚新几内亚的路易西亚德群岛（东南部新几内亚的东南岛屿）。","other":"尽管总体上不受到全球威胁，但在一些小岛上，如洛德豪岛和诺福克岛的种群因范围狭小而面临潜在风险，被列为‘易危’。"},{"name":"橄榄背啸鹟","english_name":"Rennell Whistler","scientific_name":"Pachycephala feminina","overview":"橄榄背啸鹟（英文名：Rennell Whistler，学名：Pachycephala feminina），是雀形目啸鹟科啸鹟属的独特鸟类。原被视为广泛分布的金啸鹟的亚种，但在2016年被国际鸟类联盟（IOC）确认为独立物种。仅分布于所罗门群岛东南部的Rennell岛，是该岛屿的特有种。","appearance":"成年橄榄背啸鹟长约15厘米，雄鸟与雌鸟外观相似。头部呈褐色橄榄色，脸部两侧带有锈色，颈部呈现锈橄榄色，背部为深橄榄色，臀部羽毛尖端略带黄橄榄色，上尾覆羽呈褐色橄榄色，尾巴深橄榄棕色。下体为柠檬黄色，胸腹部和两胁带有些许橄榄或锈橄榄色，尾下覆羽为淡黄色。喙角质色，有时基部稍淡，腿灰色，眼睛黑色，眼周有淡黄白色的眼圈。","call":"其鸣声不似典型的啸鹟，而是响亮多样，音调恒定，包含尖叫声、圆润音符、杂音、快速的双重音和三重音，以及滑音。特征性的重复音符，先在一个音高上重复2至8次，然后切换到另一个音高，每次重复逐渐变得更大声、更快且音色更杂。叫声被描述为响亮悦耳的“tjuep”声，紧接着迅速重复约六次的“jeep-jeep-jeep”。警报声为急促粗哑的“kraeh-kraeh-kraeh”或“tchara-tchara-tchara”。","habits":"橄榄背啸鹟偏好密集的原始森林或次生林，通常在林下层活动。它们的栖息地选择与独特的鸣声使其与其它啸鹟种类区分开来。","breeding":"关于橄榄背啸鹟的繁殖习性信息有限，具体繁殖期、求偶、营巢、交配、产卵、孵化和育雏的细节有待进一步研究。","identification":"与其他啸鹟种类相比，橄榄背啸鹟可通过其暗橄榄栗色头部和翅膀、黑色橄榄色的背至尾、狭窄的浅色眼圈、喙部以及淡黄色的下体来识别。","protection":"IUCN：NT（近危）","distribution":"橄榄背啸鹟的分布限于所罗门群岛中的Rennell岛。","other":"尽管岛上森林在1990年代估计仍大部分保持完好，但由于栖息地转化和丧失，该物种面临人口数量下降的威胁。"},{"name":"美岛啸鹟","english_name":"Melanesian Whistler","scientific_name":"Pachycephala chlorura","overview":"美岛啸鹟（英文名：Melanesian Whistler，学名：Pachycephala chlorura），是雀形目啸鹟科啸鹟属的鸟类。具有亮丽的金色腹部，黑色的胸部和头部，以及洁白的喉部。分布于瓦努阿图和新喀里多尼亚的忠诚群岛，常见于各种生境，包括城市花园。","appearance":"美岛啸鹟体长约为14至16厘米，体重介于18至25克，雄鸟拥有深灰色的头冠、脸部和颈背，白色喉部，橙黄色的腹部和臀部，橄榄绿色的背部和翅膀，两性均具白色喉部，但雌鸟颜色较暗淡，腹部和臀部为淡褐色，头部、背部和翅膀呈橄榄棕色。","call":"鸣声由一系列响亮而清晰的哨音组成，通常以1到2个鞭裂般的声音结尾。","habits":"栖息于湿润森林，包括退化森林和林缘，海拔高度从海平面至至少900米。它们在适宜的生境中较为常见，尤其是在300米以下的高度。物种表现出定居习性。","breeding":"建造小型巢穴，直径约6厘米，由树枝和蜘蛛网构成，悬挂在地面以上的小枝上。每窝产2枚带有棕色斑点的白色蛋，由双亲共同孵化。","identification":"与金啸鹟相近，但具明显的白色喉部，雄鸟腹部更为橙黄色，雌鸟腹部颜色更黄，喉部颜色差异明显。","protection":"IUCN：LC（无危）","distribution":"分布于瓦努阿图和新喀里多尼亚的忠诚群岛（新喀里多尼亚），在澳大利亚东南部，该物种在所有阶段的次生森林中普遍常见。"},{"name":"新喀啸鹟","english_name":"New Caledonian Whistler","scientific_name":"Pachycephala caledonica","overview":"新喀啸鹟（英文名：New Caledonian Whistler，学名：Pachycephala caledonica），是雀形目啸鹟科啸鹟属的鸟类。橙黄色与橄榄色相间的羽毛，头部呈灰色，喉咙部分对比鲜明的白色是其最显著的外部特征。该鸟种广泛分布于新喀里多尼亚群岛，偏好原生森林环境，但也能够适应受扰动的栖息地。","appearance":"雄性新喀啸鹟呈现橙黄与橄榄绿的色彩组合，头部为灰色，喉咙为醒目的白色。雌鸟的外观较为朴素，通体为暗淡的橄榄棕色，腹部颜色较浅，喉咙部分带有灰白。这种差异在成年个体间尤为明显。","call":"新喀啸鹟拥有独特的鸣叫声，其低沉而清脆的哨声歌曲是识别它们的最佳途径，声音中带有明显的上扬与下降的音调变化。","habits":"新喀啸鹟在新喀里多尼亚的原生森林中栖息，对受扰动的环境也有一定的容忍度。它们常见于海拔300米以下的地区，活跃于日间，以昆虫为食。","identification":"新喀啸鹟与同属其他种类的主要区别在于其特有的橙黄橄榄色的羽毛组合，以及独特的低沉哨声。","protection":"IUCN：LC（无危）。新喀啸鹟在新喀里多尼亚的特定生态区中数量较多，特别是在海拔300米以下的地区，且在Rivière Bleue保护区中也有分布。","distribution":"新喀啸鹟主要分布于新喀里多尼亚的Grande Terre和Ile des Pins，即新喀里多尼亚的主岛和松树岛。","other":"新喀啸鹟是一种受限制的分布物种，仅在新喀里多尼亚的生态区内被发现。"},{"name":"斐济啸鹟","english_name":"Fiji Whistler","scientific_name":"Pachycephala vitiensis","overview":"白喉斐济啸鹟（英文名：White-throated Fiji Whistler，学名：Pachycephala vitiensis），是雀形目啸鹟科啸鹟属的鸟类。斐济特有种，曾与黄喉斐济啸鹟合称“斐济啸鹟”。雄鸟具金色腹部、白喉、黑兜帽与胸带，雌鸟羽色黯淡。分布于斐济中南部岛屿的成熟森林及次生林，鸣声短促而旋律优美。目前未单独评估IUCN等级，但局部常见。","appearance":"体长17–18厘米，体重28.5–38克（kandavensis亚种25克）。雄鸟头部至后颈黑色，具极窄黄色后颈圈；上体深橄榄色带黑斑，翼黑色具橄榄缘，尾黑色羽端淡；颏、喉及颊纹白色，胸带狭窄黑色，下体亮黄色，尾下覆羽赭黄色。雌鸟头及上体灰至橄榄褐色，翅羽及尾羽均暗橄榄褐；颏与喉肉桂粉色，下体肉桂色。幼鸟通体红褐色。虹膜暗红，嘴黑色，脚褐黑色。","call":"鸣声为短促而响亮的3–10音旋律短语，约1秒，音量渐强并以尖锐上滑或下滑爆破音结束，如“wee-cho-wi-chi-WEET!”或“ti-tutwi-tuzwi”，个体及亚种间变异大；叫声包括连续的“pli, pli, pli”。","habits":"留鸟，主要栖息于成熟原生林，也见于次生林。活动以树冠及林下灌丛为主，偶至地面觅食；雄鸟可降至较低层次，雌鸟及幼鸟多在冠层。觅食方式以搜寻为主（约60%），辅以飞扑（31%）与啄取（<10%）。食物主要为昆虫及蜘蛛，偶食果实，极少取食种子。常加入混合种觅食群。留鸟，主要栖息于成熟原生林，也见于次生林。活动以树冠及林下灌丛为主，偶至地面觅食；雄鸟可降至较低层次，雌鸟及幼鸟多在冠层。觅食方式以搜寻为主（约60%），辅以飞扑（31%）与啄取（<10%）。食物主要为昆虫及蜘蛛，偶食果实，极少取食种子。常加入混合种觅食群。","breeding":"繁殖期至少为10–11月；具体繁殖细节缺乏，推测与金啸鹟相似。","identification":"与黄喉斐济啸鹟形态相近，可通过雄鸟具白色喉部及黑色胸带与后者黄色喉部区分；二者鸣声差异显著。亚种间差异：kandavensis体型较小，胸带窄而暗淡；lauana体型大，雄鸟背部黑色斑纹更多；vitiensis为指名亚种。","protection":"IUCN: 未单独评估，原“斐济啸鹟”复合体共同被列为无危（Least Concern）。局部常见，生存依赖保存完好的森林斑块。","distribution":"繁殖区：斐济中南部——瓦努阿库拉、贝卡、奥诺、坎达武岛（kandavensis）；南部劳群岛奥吉亚莱武、富拉加、武阿加瓦（lauana）；中部高岛（vitiensis）。非繁殖区：无迁徙记录，全年留居上述岛屿。","other":"分类历史复杂，曾与黄喉斐济啸鹟合称“斐济啸鹟”，后因鸣声差异及遗传分化再次分拆；未来可能进一步细分。"},{"name":"泰莫图啸鹟","english_name":"Temotu Whistler","scientific_name":"Pachycephala vanikorensis","overview":"泰莫图啸鹟（英文名：Vanikoro Whistler，学名：Pachycephala vanikorensis），是雀形目啸鹟科啸鹟属的鸟类。所罗门群岛东南圣克鲁斯群岛瓦尼科罗岛特有的小型林鸟，俗称“Temotu Whistler”。雄鸟羽色鲜艳，具金色腹部、黑色胸带及头罩，雌鸟橄榄褐上体、下体淡黄。该种曾被视为与乌图普阿啸鹟、嫩多啸鹟同种，现已独立成种，主要栖息于低地至山地森林，避开村庄。","appearance":"雄鸟：头顶、面部及胸带黑色，似披黑色披肩；上背略带橄榄绿，肩、翼及尾羽黑色，翼上覆羽与背部边缘呈亮金黄色，喉部雪白，胸带下方至腹部及尾下覆羽鲜黄色。雌鸟：整体暗淡，上体橄榄褐色，头顶至耳羽灰色，喉部橄榄色具暗色纵纹，胸、腹柠檬黄色，胸侧略褐。两性喙基部黑色，下喙基部色浅，腿灰黑。幼鸟似雌鸟而更淡，胸腹黄色带暗斑。","call":"鸣声由稀疏、纤细、缺乏起伏的哨音序列组成，节奏缓慢，音调平直。","habits":"栖息于瓦尼科罗岛海拔自海平面至山地的各类原生与次生林、林缘、灌丛，但不进入村庄周边。常单独或成对在林中层至林冠活动，偶尔与其他小型食虫鸟混群。以昆虫、小型节肢动物为主食，多在枝叶间跳跃搜捕。","breeding":"繁殖资料匮乏。推测于干季后期至湿季初期营巢，巢为杯状，筑于树叉或灌木。每窝产卵2枚，卵色乳白具红褐斑。孵卵及育雏由双亲共同承担。","identification":"雄鸟独特的黑色“披肩”与金黄色翼覆羽组合，在分布区内无相似种；雌鸟与乌岛啸鹟雌鸟相似，但后者胸腹黄色更淡、喉部条纹更粗。与同属其他岛屿种相比，体型略小，羽色对比度更高。","protection":"IUCN: NE（未评估）。瓦尼科罗岛森林尚未大规模开发，种群被认为稳定，无已知威胁。","distribution":"繁殖区：所罗门群岛东南圣克鲁斯群岛的瓦尼科罗岛（Vanikoro）。非繁殖区：留鸟，无迁徙记录。","other":"分子研究表明其与斐济、汤加、萨摩亚的若干近缘啸鹟构成姐妹群，但乌岛啸鹟尚未被纳入基因研究，需进一步取样以厘清分化格局。"},{"name":"汤加啸鹟","english_name":"Tongan Whistler","scientific_name":"Pachycephala jacquinoti","overview":"汤加啸鹟（英文名：Tongan Whistler，学名：Pachycephala jacquinoti），是雀形目啸鹟科啸鹟属的独特鸟类。雄鸟外观引人注目，拥有鲜艳的金色下体和颈部，橄榄绿色的翅膀，以及深黑色的头部、胸部和尾部。雌鸟主要呈橄榄黄色，顶冠灰暗，喉部淡色。汤加啸鹟特有于汤加的瓦瓦乌群岛和莱特岛，栖息于热带原始森林，偶尔可见于次生林或树木种植园。","appearance":"雄性汤加啸鹟的特征鲜明，其金色的腹部和颈部格外抢眼，翅膀橄榄绿色，头部、胸部及尾巴深黑。雌鸟则主要是橄榄黄色，顶冠带灰，喉部颜色较浅。雄鸟与雌鸟的体型大小相当，但颜色对比明显。","call":"汤加啸鹟的鸣唱由一系列复杂的哨声组成，以响亮且传播远的鞭裂声结尾，其声音在森林中回荡。","habits":"汤加啸鹟偏好热带原始森林的环境，偶尔也会出现在次生林和树木种植园。它们通常避开村落和花园。它们的活动范围和迁徙模式目前尚不清楚。","breeding":"关于汤加啸鹟的繁殖行为细节研究较少，但据观察，它们在适宜的季节会在树上筑巢，进行繁殖。","identification":"雄性汤加啸鹟全黑的头部和喉咙，以及雌鸟的黄色下体，与澳大利亚金色啸鹟形成对比，是其显著的辨识特征。","protection":"IUCN：NT（近危）","distribution":"汤加啸鹟主要分布在太平洋的瓦瓦乌群岛和莱特岛（n Tonga, sc Polynesia）。","other":"汤加啸鹟曾被Jacques Pucheran描述为Eopsaltria属的一员，有时也被认为是金色啸鹟的一个亚种。"},{"name":"黑尾啸鹟","english_name":"Mangrove Golden Whistler","scientific_name":"Pachycephala melanura","overview":"黑尾啸鹟（英文名：Mangrove Golden Whistler，学名：Pachycephala melanura），是雀形目啸鹟科啸鹟属的鸟类。体型圆胖、喙部粗厚的鸣禽，常见于澳大利亚北部的红树林中。雄鸟具有橄榄黄色背部、黑色头部、白色颏部、鲜亮的黄色腹部以及显著的黄色颈环；雌鸟上部灰暗，下部较浅，尾下部黄色，某些亚种腹部呈黄色。该物种在昆士兰东海岸与Golden Whistler的分布有重叠。","appearance":"黑尾啸鹟拥有厚重的喙，雄鸟的背部为橄榄黄色，头部黑色，颏部白色，腹部及颈环鲜黄。雌鸟上部灰色，下部颜色更浅，尾下部及部分亚种的腹部黄色。整体形态丰满。","call":"其叫声包括响亮而尖锐的哨音，结尾似鞭打声。","habits":"栖息于红树林和邻近的湿润森林，活动范围广泛，包括澳大利亚至俾斯麦群岛和所罗门群岛北部。","identification":"与Golden Whistler极为相似，辨识需注意其分布范围，尤其是在昆士兰东海岸的重叠区域。","distribution":"分布于澳大利亚广泛地区，通过俾斯麦群岛到达所罗门群岛北部。"},{"name":"黄额啸鹟","english_name":"Samoan Whistler","scientific_name":"Pachycephala flavifrons","overview":"黄额啸鹟（英文名：Samoan Whistler，学名：Pachycephala flavifrons），是雀形目啸鹟科啸鹟属的小型鸟类。以金黄色的下部羽毛和石板灰色的上部羽毛为显著特征。原被归类在Eopsaltria属下，曾被认为是金啸鹟的一个亚种，但在分类学上现独立为一物种。黄额啸鹟主要分布在萨摩亚群岛，包括Savaii、Upolu和Nu-utele岛。","appearance":"雄性黄额啸鹟头部羽毛颜色变化大，额头和喉部可能同为黄色或白色，或一黄一白，侧额可能呈黄色或白色；头顶和头部侧面以及上部呈暗黑色，带有橄榄色调；上翼和尾巴呈暗黑色，主飞羽外缘有浅灰色边缘；喉部暗黑色，强烈杂有黄色或白色斑点，下部羽毛黄色；眼睛深棕色，喙和腿黑色。雌鸟相似但较为暗淡，额头和上部颜色较浅，喉部灰白色。幼鸟上部暗棕色，下部赤褐色。","call":"其鸣声为一系列悦耳的哨音，表现为‘tweet-chew-twee-titi-chew-wheet’的旋律。叫声为短促的哨音‘chweep’；雌鸟的叫声为连续的‘chip chip chip’；警报叫声为嗡嗡的‘churr’。","habits":"黄额啸鹟广泛分布，但在自然环境中更为常见，栖息于森林、种植园和花园中。","identification":"雄性黄额啸鹟与金啸鹟相似，但上部羽毛更黑，额头黄色或白色，喉部暗黑色并强烈杂有黄色或白色斑点，没有黑色胸带。雌鸟外观比雄鸟更暗淡，喉部灰白色。","distribution":"黄额啸鹟主要分布在太平洋的萨摩亚群岛，具体包括Savaii、Upolu和Nu-utele岛（东部Upolu，西部萨摩亚，中部波利尼西亚）。"},{"name":"山啸鹟","english_name":"Hooded Whistler","scientific_name":"Pachycephala implicata","overview":"山啸鹟（英文名：Hooded Whistler，学名：Pachycephala implicata），是雀形目啸鹟科啸鹟属的独特鸟类。其外观暗淡，主要呈苔藓橄榄色，雄鸟的头部为黑色，喉部为石板灰色，而雌鸟则金色腹部，橄榄色背部，灰色头部和白色喉部。主要栖息于所罗门群岛中南部的瓜达尔卡纳尔岛（简称瓜岛）山区，海拔1100米以上的原始森林。","appearance":"成年山啸鹟体长约16.5厘米，雄鸟体重约33.5至37克，雌鸟约30至39克。雄鸟具有黑色头部，背部至翅膀上部、臀部和上尾覆羽为橄榄色，尾巴黑色；雌鸟头顶和头部两侧为灰色，背部为绿色橄榄色，翅膀黑色边缘橄榄色，尾巴暗色边缘棕色；幼鸟类似雌鸟，但头部顶部深橄榄色，上下体部分广泛锈红色。两性皆具暗红褐色眼睛。","call":"山啸鹟的鸣声包括一系列响亮、几乎电子般的断音哨声。歌曲较简单、安静且不如鹂啸鹟的鸣声悦耳，由响亮的双音节后跟较轻的音符组成，通常在黎明时分发出。","habits":"山啸鹟主要栖息于海拔1100至2000米的森林，包括高海拔的雾林，通常独居或成对出现，主要以昆虫为食，偶尔也会食用小型蜗牛、浆果和种子。它们在林下层觅食，有时会到中层和树冠层，常单独或成对活动。","breeding":"关于繁殖的信息有限，仅知在十月观察到过幼鸟。","identification":"雄性山啸鹟与鹂啸鹟的区别在于缺乏明亮的金色喉咙、颈部和腹部，而雌鸟的背部为橄榄色，下体无条纹。与黑喉山啸鹟曾被视为同一种类，但在2014年前被区分为独立物种。","protection":"IUCN：LC（无危）。山啸鹟为限制范围物种，存在于所罗门群岛生态区。尽管总体上被认为是不常见的，但在1400米以上的地方更为常见，取代了鹂啸鹟。","distribution":"山啸鹟主要分布在所罗门群岛中的瓜达尔卡纳尔岛的山区，特别是在1100米以上的地区。","other":"在某些局部地区，山啸鹟与鹂啸鹟共存，但在海拔1400米以上的地方，它取代了后者。"},{"name":"黑喉山啸鹟","english_name":"Bougainville Whistler","scientific_name":"Pachycephala richardsi","overview":"黑喉山啸鹟（英文名：Bougainville Whistler，学名：Pachycephala richardsi），是雀形目啸鹟科啸鹟属的独特鸟类，主要分布在布干维尔岛的山区，属于蒙特热带湿润森林中的居民。其最显著的外部特征是金色橄榄色的背部和鲜黄色的腹部，雄鸟头部至胸部呈现闪亮的黑色，而雌鸟的头部为灰暗色，喉咙白色。","appearance":"雄性黑喉山啸鹟全长约16.5厘米，体重约36克，整个头部至胸部为光泽的黑色，上部为黄色橄榄色，翅膀和尾巴黑色，翼羽边缘呈暗淡的黄绿色橄榄色；下部自胸部以下为黄色，带有浅橄榄色的洗染，胸部两侧和后部下部颜色最为鲜艳。雌鸟冠和面部为深灰色，上部和上翼覆羽为绿色橄榄色，飞羽边缘橄榄色，尾巴黑色；喉咙白色，下喉和上胸淡肉色（或粉红色）灰色，其余下部为黄色，下尾覆羽带有橄榄色的洗染。幼鸟的头部、上部、上翼和尾巴为赤褐色，带有变化的橄榄色羽毛边缘，下部为棕褐色。亚成鸟与雌鸟相似，但略显暗淡。","call":"鸣唱通常在黎明时发出，由一系列最多五个音符组成，音高交替，以鞭打音结束，例如“chee chee whit”和“whit chu whit chu”。也描述为响亮的上升音调“chu chu chu chu chu chu”，或“whee whee whee whee whip！”和“wur chi wur chi wur chi woo！”。接触叫声为“wheu wheu”，也有尖锐的“chik”声。","habits":"生活在海拔1200米以上的山地森林，偶尔会降至900米，可能达到至少1750米，甚至2000米的高度。在1500米以上替代鹂啸鹟。其栖息环境为亚热带或热带湿润的山地森林。","breeding":"具体繁殖信息未提及。","identification":"与鹂啸鹟相比，雄鸟具有黑色而非深灰色的喉咙、颊区和上胸（黑色延伸得更低），以及黄色而非暗橄榄绿的胸部侧面和下部。雌鸟胸部的（微粉色或肉色）灰色分布更广，减少了喉咙上的白色部分并延伸到胸部，背部和臀部为橄榄绿色而非橄榄棕色，尾巴为黑色而非暗中棕色。歌声比鹂啸鹟更短且不那么悦耳。","protection":"IUCN：LC（无危）","distribution":"分布于北所罗门群岛的布干维尔岛山区。","other":"2014年从山啸鹟中分离出来成为独立物种。"},{"name":"裸喉啸鹟","english_name":"Bare-throated Whistler","scientific_name":"Pachycephala nudigula","overview":"裸喉啸鹟（英文名：Bare-throated Whistler，学名：Pachycephala nudigula），是雀形目啸鹟科啸鹟属的独特鸟类，仅分布于小巽他群岛的山地森林。雄性裸喉啸鹟拥有橄榄绿色的上体和带有黄色调的下体，黑色头罩以及喉咙处醒目的红色裸露皮肤，使其极易识别。雌鸟则以灰色头部、橄榄色背部、黄色腹部以及白色喉咙为特征。幼鸟外观似雌鸟，但具有黄色喉咙。","appearance":"雄性裸喉啸鹟（指名亚种）头部黑色，上体橄榄色，臀部带有黄绿色调，翼部暗棕色，边缘略带橄榄色，尾羽黑色。下巴和上喉黑色，喉咙下方有深红色裸露皮肤，上胸中心黑色，其余下体呈黄橄榄色，腹部中心、肛周羽毛和尾下覆羽较淡，两胁和大腿带有橄榄色。雌鸟头部灰，喉咙灰白，带有小型裸露斑点（通常隐藏）。幼鸟似雌鸟，但喉咙黄色，无裸露斑点。亚种ilsa比指名亚种色彩更鲜艳，下体更呈黄绿色。","call":"裸喉啸鹟的鸣叫声响亮清晰，个体间和地方性差异显著。其歌谱由一系列看似随机排列的短语组成，一段包含11至12个单调的中音单音节或双音节哨声，常随后音调明显变化，接着是3至4个较短、甜美、柔和的上升音符或类似颤音的哨声。还发出钟铃般的音符和尖叫声，雌鸟会发出刺耳的责骂叫声。能模仿多种鸟类的声音，包括乌鸦、金莺、家鸡和卷尾。","habits":"裸喉啸鹟栖息于湿润的山地森林，包括原生林和高大的次生林，同时也在保持树冠的桉树林和退化森林中发现。常见于河流旁和海拔1200米以上的山地森林。避开半落叶林。","identification":"雌性裸喉啸鹟与帝汶啸鹟雌鸟的区别在于橄榄色的上体、纯黄色的下体、胸部无粉色，以及不明显的浅色眼环。亚种间的辨识依据颜色深浅和下体色调差异。","protection":"IUCN：LC（无危）","distribution":"分布于澳新界的山地西部和中部小巽他群岛，具体在Sumbawa岛的海拔200至1730米，Flores岛的400至2000米。"},{"name":"罗氏啸鹟","english_name":"Lorentz's Whistler","scientific_name":"Pachycephala lorentzi","overview":"罗氏啸鹟（英文名：Lorentz's Whistler，学名：Pachycephala lorentzi），是雀形目啸鹟科啸鹟属的鸟类。中型山地森林鸟类，分布于新几内亚山区中西部的高海拔地带，主要栖息于亚热带或热带湿润山地森林。","appearance":"罗氏啸鹟的雄雌外观相似，具有黄色腹部、橄榄绿色背部、暗灰色头部、淡灰色胸部和近白色的喉部。其翼上覆羽和飞羽边缘呈橄榄绿色，两翼和尾部黑色。虹膜深棕色，喙黑色，腿为石板色。幼鸟羽毛大多为栗红色，亚成鸟喉部和胸部白色，腹部灰色。","call":"其典型啸声由有力的上下起伏的哨音组成，部分音调带有爆发性。","habits":"罗氏啸鹟主要以昆虫为食，在森林的低至中层搜寻猎物，也会在空地上的树苗顶部觅食。它通常栖息于海拔1750至3800米的中高山森林、苔藓森林和高山灌木丛。当其分布区与斯氏啸鹟重叠时，它会在海拔2700米以上取代后者，但在较低海拔两者共存。","breeding":"关于繁殖的信息有限，仅知雄鸟在8月底处于繁殖状态。","identification":"与弗格克啸鹟非常相似，但两者不会在同一地区出现；与雌性斯氏啸鹟类似，但罗氏啸鹟喉部为纯灰色而非斑点状，胸部为灰色而非橄榄色。","protection":"IUCN：LC（无危）","distribution":"罗氏啸鹟分布于新几内亚山脉中西部的高地，从东部雪峰山脉向东延伸至Hindenburg山脉和Victor Emanuel山脉。","other":"最初被描述为斯氏啸鹟的一个亚种，现在确认为独立物种。"},{"name":"斯氏啸鹟","english_name":"Regent Whistler","scientific_name":"Pachycephala schlegelii","overview":"斯氏啸鹟（英文名：Regent Whistler，学名：Pachycephala schlegelii），是雀形目啸鹟科啸鹟属的鸟类。新几内亚高山区特有种。其主要特征为雄鸟头部黑色，胸白喉黄，背部具黄色斑块，雌鸟橄榄色腹部泛黄，头灰喉白。分布于新几内亚的山林地带。","appearance":"斯氏啸鹟体长约15至16.5厘米，体重19至25克。雄鸟成鸟头部、颈侧黑色，后颈有黄色环带，上体深橄榄绿，翅膀和尾部黑色，初级飞羽边缘淡棕色；下体黄色，下胸和腹部橙色明显；雌鸟头部、颈侧灰色，上体橄榄绿，上胸灰色，下胸有宽广的橄榄绿色带，其余下体黄色；幼鸟羽毛主要呈红栗色。","call":"斯氏啸鹟的叫声包括上升的嗡鸣声后接3到4个爆炸性的“whip！”音符，其歌声由约10个交替上升和下降的音符组成，速度、音量和音调逐渐增加，以短暂的高音结束。","habits":"栖息于海拔1300至3650米的森林及其边缘，主要在1850米以上。雄鸟偏好较高层的觅食区（平均离地面17米），而雌鸟则在较低层（平均10米）活动。","identification":"雄性斯氏啸鹟与其它雄鸟啸鹟的区别在于胸部下方有橙色洗涤。雌鸟与罗氏啸鹟的区别在于胸部为橄榄色而非灰色。","protection":"IUCN状态未知。","distribution":"斯氏啸鹟分布于新几内亚的山区，具体而言，位于澳大利亚新几内亚的高海拔地区。"},{"name":"黄背啸鹟","english_name":"Golden-backed Whistler","scientific_name":"Pachycephala aurea","overview":"黄背啸鹟（英文名：Golden-backed Whistler，学名：Pachycephala aurea），是雀形目啸鹟科啸鹟属的鸟类。拥有独特的黄色背部，黑色头部和胸部带纹，以及白色喉部。广泛分布于新几内亚的丘陵低地及相邻地带，常栖息于湖泊和河流边的高草丛和灌木中。","appearance":"中等体型，特征鲜明，黄色腹部，白色喉部，黑色头部和胸部有一条明显的带纹，翅膀和尾巴亦为黑色。背部呈鲜亮的黄色，与常见的橄榄色背部的啸鹟形成鲜明对比。","call":"其鸣唱具有代表性，发出‘wit-o-wit！’或‘wit-o-wityew！’的哨音，音调类似典型的啸鹟鸣叫。","habits":"偏好成对活动，通常在林中层或林下层觅食，活动范围包括湖泊和河流周边的草地和灌木丛。不常见于与其它‘金色’啸鹟的共栖环境中。","breeding":"具体繁殖细节未详述，但一般啸鹟属的繁殖习性包括在适宜季节筑巢、产卵和育雏。","identification":"与橙鹃鵙和金王鹟颜色相似，但可通过头部顶部的黑色区分辨。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚，自韦兰德山脉（Weyland Mts）和雪山区南部斜坡向东延伸至弗莱河上游（Fly R）、奥克特迪（Ok Tedi）、特莱福明（Telefomin）、诺马德河（Nomad R）、塞皮克河中游（middle Sepik R）、拉穆河上游（upper Ramu R）、科皮亚戈湖（L Kopiago）、内姆比谷（Nembi Valley）及东南部山脉的几个局部地区（包括加赖纳和纳罗）。在澳新界，零星分布于新几内亚从中西部至东南部。"},{"name":"棕啸鹟","english_name":"Rufous Whistler","scientific_name":"Pachycephala rufiventris","overview":"棕啸鹟（英文名：Rufous Whistler，学名：Pachycephala rufiventris），是雀形目啸鹟科啸鹟属的鸟类。典型的啸鹟科啸鹟属鸟类。拥有鲜明的红褐色腹部和灰色背部，雄鸟具有独特的黑色面罩和白色喉咙，雌鸟则呈现较为暗淡的灰褐色调。广泛分布于澳大利亚和新喀里多尼亚的森林、灌木丛生地带。","appearance":"棕啸鹟体型健壮，头部大而圆，喙短且结实。雄鸟上部呈浅灰色，下部橙色明显，具有一条从眼周延伸至喉部的黑色条纹，环绕着白色的喉部。雌鸟和幼鸟上部为灰褐色，下部颜色较浅，带有明显的条纹，腹部变为淡黄色。体长16至18厘米，体重介于20至27克之间。","call":"鸣声清脆响亮，由多种音乐般的叫声组成，包括重复的'joey joey joey'声和'whít'的高音。雄鸟和雌鸟都会发出这种复杂的鸣叫。","habits":"栖息于干燥的桉树森林、灌木林和河岸植被中，偶尔也会出现在潮湿的森林和松树林中。它们在澳大利亚表现为季节性迁徙，春季向南移动，秋季北迁，而在新喀里多尼亚则是留鸟。主要以昆虫为食，偶尔摄取种子、果实，甚至叶子。","breeding":"繁殖季节为7月至3月，通常每年产两窝蛋，每窝2至3枚。雌鸟独自筑巢，巢呈杯状，由枝条、草和其他材料构成，固定在树枝上。孵化期约为13天，双亲共同照顾雏鸟。","identification":"与其他啸鹟相比，棕啸鹟的红褐色腹部和雄鸟的黑色面罩是显著的识别特征。雌鸟的灰褐色外观和下部的条纹也有助于与其他种类区分开来。","protection":"IUCN：LC（无危）","distribution":"主要分布于澳大利亚和新喀里多尼亚。在澳大利亚，广泛存在于内陆地区和北部区域，在东部部分迁徙。在新喀里多尼亚，常见于开放森林、受干扰地区、草原草地和花园。","other":"尽管在一些地区由于栖息地破坏导致数量下降，但在其他地区，因开垦林地而有所增加。"},{"name":"阿鲁啸鹟","english_name":"Black-headed Whistler","scientific_name":"Pachycephala monacha","overview":"阿鲁啸鹟（英文名：Black-headed Whistler，学名：Pachycephala monacha），是雀形目啸鹟科啸鹟属的中型鸟类，分布于澳新界的印尼阿鲁群岛（西南部，新几内亚）和新几内亚，栖息于低山受扰地区的亚热带或热带湿润森林。","appearance":"该鸟具有黑色的上体、头部和胸部，腹部白色。雌鸟的灰色替代了黑色。体型较壮实，尾部较短，与缎辉阔嘴鹟有别，缺乏黑白扇尾鹟的白色眉纹，且不像冠王鹟那样常见于森林内部。","call":"阿鲁啸鹟的鸣声典型于啸鹟，包含一系列哨音和颤音，常以尖锐的“wik！”结尾。","habits":"栖息于亚热带或热带湿润的低地森林，具体生活习性细节待考。","identification":"与缎辉阔嘴鹟相比，阿鲁啸鹟更为粗壮，尾部更短；与黑白扇尾鹟的区别在于后者具有白色眉纹；与冠王鹟的栖息环境不同，后者多见于森林内部。","protection":"IUCN状态未提供。","distribution":"分布于印尼阿鲁群岛（西南部，新几内亚）和新几内亚的繁殖区域。","other":"已知能够与白腹啸鹟杂交。"},{"name":"白腹啸鹟","english_name":"White-bellied Whistler","scientific_name":"Pachycephala leucogastra","overview":"白腹啸鹟（英文名：White-bellied Whistler，学名：Pachycephala leucogastra），是雀形目啸鹟科啸鹟属的鸟类。体型类似于麻雀，具有厚实的喙。雄鸟全身灰上覆黑头，喉部有醒目的白色斑块，下缘有一条黑色胸带，腹部呈淡白色；雌鸟头部无黑色，整体颜色较淡。分布于新几内亚中北部、东南部及路易西亚德群岛，栖息于多种环境，包括湿地桉树林、红树林及橡胶种植园。","appearance":"成年雄性白臀啸鹟拥有灰色的背部，黑色的头部、颈背及宽阔的胸带，包围着白色的喉部。雌鸟头部及身体侧面为暗灰色，翅膀及尾巴为深棕色，喉部白色或微白，带有极细的黑色条纹。幼鸟外观类似雌鸟，但更为褐色，喉部及胸部有明显的灰色条纹。","call":"其鸣唱为一系列音符，以爆发性的“chéw”结尾，亦会发出各种音节，通常以逐渐增强音量的“see-see-see-see-see”结束，还会发出响亮的“eee-chóng”。","habits":"常在树冠层活动，主要以昆虫为食，栖息于湿润的桉树林、红树林、受干扰的生境及低地草原附近的高树。海拔分布从海平面至约1200米。生活习性为留鸟，不迁徙。","breeding":"繁殖期可能在雨季，也可能延伸至旱季初期。巢由植物材料制成，形状为杯状，通常位于树杈处，高度在10-20米之间，但在红树林边缘可低至2米以上水面。巢中曾观察到两只幼鸟，但关于窝卵数和蛋的信息未知。","identification":"与阿鲁啸鹟的区别在于其清晰的白色喉部。雄鸟与雌鸟在颜色上有明显差异，幼鸟则与雌鸟相似，但更为褐色，喉部及胸部有更明显的条纹。","protection":"IUCN：LC（无危）。在北巴布亚低地EBA、路易西亚德群岛EBA和东南巴布亚低地次要区域存在。一般稀少且分布局限，但在湿润桉树林中常见。","distribution":"分布于新几内亚的中北部和东南部，以及路易西亚德群岛（位于新几内亚东南部）。","other":"白臀啸鹟的名称有时也被用作其他几种啸鹟的别名，如红树啸鹟、白臀啸鹟、棕啸鹟和白胸啸鹟。"},{"name":"印尼啸鹟","english_name":"Wallacean Whistler","scientific_name":"Pachycephala arctitorquis","overview":"印尼啸鹟（英文名：Wallacean Whistler，学名：Pachycephala arctitorquis），是雀形目啸鹟科啸鹟属的鸟类。原生于东小巽他群岛，其自然栖息地包括亚热带或热带湿润低地森林和亚热带或热带红树林。","appearance":"雄鸟具有黑色头部、白色喉咙、淡灰色背部及白色下部；雌鸟上部呈赤褐色，下部白色，胸部有深色条纹。幼鸟外观类似淡嘴雌鸟。体型接近麻雀大小，喙厚实。","call":"鸣唱由一系列尖锐哨音组成，包括“choo”和“chwee”音符，有时以混乱序列呈现。","habits":"栖息于多样化的林木环境和森林，通常成对或单独活动，频繁出现在林下层和次冠层。","identification":"雄鸟与金喉啸鹟、黄喉啸鹟区别在于灰背和白底。雌鸟通过胸部条纹和强烈赤褐色调上部与上述两物种及褐胸啸鹟相区别。","distribution":"分布于澳新界的小巽他群岛和印尼摩鹿加群岛南部。"},{"name":"褐啸鹟","english_name":"Drab Whistler","scientific_name":"Pachycephala griseonota","overview":"褐啸鹟（英文名：Drab Whistler，学名：Pachycephala griseonota），是雀形目啸鹟科啸鹟属的鸟类。小型鸣禽，体长14–15.5厘米，通体以灰褐、赭色为主，雌雄羽色略有差异。该鸟种为印度尼西亚马鲁古群岛、苏拉群岛及凯群岛的特有种，栖息于低地至山地的原生林、次生林及疏林灌丛。","appearance":"雄鸟前额、头顶及头侧烟灰色，上背灰褐，翅与尾暗灰褐；颏喉近白，胸灰赭，腹锈赭；虹膜暗红褐，喙与趾黑色至铅灰。雌鸟羽色与雄鸟相似，但色调更为均匀。幼鸟似雌鸟。亚种间差异明显：kuehni喉带灰，胸更暗灰褐，腹淡赭；examinata头顶石板蓝，喉白，胸浅灰，腹赭黄；lineolata背更灰、胸灰腹白；cinerascens背褐，胸灰褐，腹白微赭；johni上体橄榄褐，与头顶反差明显，下体一色锈肉桂，雌鸟喉胸具黑纵纹。","call":"指名亚种（Seram）的鸣声为长达约15秒的欢快响亮长颤音；cinerascens（Halmahera）发出10–12个中等音高、音量渐强并稍加速的音符，收尾微弱“tu-wit”；kuehni（Kai Kecil）版本多变，最常见为4–5个响亮清脆音后接爆炸性双音，有时为6个响亮断音“kwik kwik kwik kwik kwik kwík”。","habits":"留鸟。栖于原生及高大次生林，避开最密林；亦见干燥林、择伐林、灌丛及轻度开垦的疏林；不进入红树林。分布从海平面至低山丘陵：哈马黑拉最高655 m、塞兰1100 m（两地均不在海岸出现）；巴占280–1200 m、奥比220–700 m、布鲁约500–1300 m、凯贝萨尔0–400 米；苏拉群岛仅见于低地。以昆虫为食，觅食范围从下层至冠层；偶尔加入混合种觅食群。","breeding":"仅在9月中旬记录到幼鸟，其余繁殖信息不详。","identification":"整体羽色暗淡，可与同属更鲜艳或具明显黑白对比的种类区分。cinerascens胸更灰褐、腹白，lineolata背灰腹白，examinata头顶石板蓝，johni下体一色锈肉桂且雌雄喉胸具黑纵纹，均可作为亚种识别要点。","protection":"IUCN: LC（无危）。","distribution":"繁殖区与非繁殖区一致。分布于印度尼西亚：苏拉群岛（Seho、Taliabu、Sanana），可能已记录于Peleng岛；摩罗泰、哈马黑拉、巴占、特尔纳特、蒂多雷；布鲁岛；塞兰岛；凯群岛（Kai Kecil、Tual、Kai Besar）；奥比岛。","other":"曾被视作棕啸鹟的亚种；亚种johni因羽色及鸣叫差异，有时被视为独立种红胸啸鹟，但最新研究认为其声型多样且与其他类群共享，暂列为本种亚种。"},{"name":"红胸啸鹟","english_name":"Cinnamon-breasted Whistler","scientific_name":"Pachycephala johni","overview":"红胸啸鹟（英文名：Cinnamon-breasted Whistler，学名：Pachycephala johni），是雀形目啸鹟科啸鹟属的鸟类。仅见于印尼摩鹿加群岛中北部的Obi岛。曾一度被归类为锈色林鵙鹟的亚种，也有观点认为它是淡色啸鹟的一个亚种。","appearance":"红胸啸鹟的显著特征在于其红褐色的胸部，与同属其他种类有明显区别。羽毛色彩随性别和年龄有所变化，具体细节需进一步观察记录。","call":"该鸟的鸣唱具有啸声特质，清脆悦耳，是其命名的由来之一。","habits":"红胸啸鹟栖息于Obi岛的森林环境中，对特定生境有较强依赖性。其飞行敏捷，活动范围受限于岛屿范围内，以昆虫为主要食物来源。","breeding":"关于红胸啸鹟的繁殖生态信息有限，已知它们在岛上进行繁殖，具体的繁殖习性需更多研究。","identification":"与其他啸鹟种类相比，红胸啸鹟的红褐色胸部是最直观的辨识特征，同时其啸声也是重要的识别依据。","protection":"IUCN：LC（无危）。尽管如此，因其分布范围狭窄，栖息地的保护显得尤为重要。","distribution":"红胸啸鹟的分布局限于印尼摩鹿加群岛中北部的Obi岛，属于澳新界的特有种。","other":"红胸啸鹟的分类历史复杂，曾被视为其他啸鹟种类的亚种，现确认为独立物种。现为褐啸鹟亚种。"},{"name":"白胸啸鹟","english_name":"White-breasted Whistler","scientific_name":"Pachycephala lanioides","overview":"白胸啸鹟（英文名：White-breasted Whistler，学名：Pachycephala lanioides），是雀形目啸鹟科啸鹟属的中大型鸣禽。雄鸟上身灰色，下身白色，黑冠与黑色及棕色颈环相连，环绕着白色的喉部。雌鸟和幼鸟上身灰褐色，下身淡色，腹部几乎纯白，全身细纹。分布于澳大利亚北部的红树林区域。","appearance":"体型大而结实，喙厚而钩曲。雄鸟成鸟头部顶部和侧面黑色，有宽大的栗色颈环，连接至胸部的黑色带；背部至臀部深灰色，尾羽覆羽黑色；翼羽黑色偏棕色，边缘和尖端浅灰色；下体白色，大腿外侧棕灰色；虹膜深红棕色，喙黑色，腿烟黑色。雌鸟成鸟头部、颈部及颈侧棕灰，头顶和颈背有狭窄的黑褐色条纹，脸略棕于头顶，眼先白色，斑点浅棕，有窄的眼环；上体包括翅膀呈棕灰，翼羽和翼羽覆羽边缘和尖端浅灰色；下体除尾下覆羽外均有黑褐色细纹。幼鸟上身大部分赤褐色，下体白色，有宽幅条纹。","call":"发出响亮的哨音，包含4到6个音符的优美旋律。接触叫声为响亮的‘wheet’或‘too-whee’；警戒声为‘per weet’。","habits":"栖息于密集的红树林中，偶尔进入画廊季雨林。以昆虫、甲壳类和小型软体动物为主食，通常长度在5-20毫米之间。在地面、木头、红树根、树干和低枝上觅食；也会在叶丛中寻找猎物。会从树干和树枝的裂缝中提取猎物；用喙击破软体动物的壳。","breeding":"繁殖季节从8月底持续到10月，似乎每年只繁殖一次。巢由两性共同建造，是一个小而扁平的杯状巢，由细枝制成，外部用蜘蛛网固定，内部铺有草，直径12-15.9厘米，高6-10厘米，内部直径5.5-8.3厘米，深度2.5-4.3厘米；通常位于红树林中的垂直叉枝或靠近树干的枝条上，距离地面1.5-5米。领域线性，长度从50米到几百米不等，取决于环境质量。每次产卵2枚，有时1枚，颜色从浅橄榄绿到深奶油色，带有棕色和淡紫色斑点，通常集中在较大的一端，尺寸约为25.7-26.1 x 18毫米；孵化和喂养幼鸟由两性共同承担。已知最长寿的个体超过了15年零8个月。","identification":"与棕鵙鹟相比，白胸啸鹟体型更大，具有明显的苍白眉纹。雄性白胸啸鹟与雌鸟和幼鸟在色彩上有显著差异。","protection":"IUCN：LC（无危）；在红树林生境中分布广泛，但因生境破碎化，其分布存在断层。","distribution":"分布于澳大利亚沿海西北部至中北部。"},{"name":"帕劳啸鹟","english_name":"Morningbird","scientific_name":"Pachycephala tenebrosa","overview":"帕劳啸鹟（英文名：Morningbird，学名：Pachycephala tenebrosa），是雀形目啸鹟科啸鹟属的小型鸟类。名称源于清晨时分的活跃鸣叫。帕劳啸鹟主要分布在太平洋上的帕劳群岛，包括Babeldaob、Koror、Ngercheu、Peleliu和Ngebad等岛屿，偏好深邃的原始热带雨林。","appearance":"雄性帕劳啸鹟具有橄榄棕色的身体，头部和胸部颜色较暗，喙部呈厚重的黑色。雌鸟整体上为较淡的橄榄棕色。幼鸟外观与成年相似，但头部和颈部颜色较浅，耳羽、颈侧、喉部和上胸颜色较深，下胸和腹部颜色较浅。","call":"其鸣唱包含一系列类似笛音的断续颤音和口哨声，间歇性地发出刺耳的沙哑音符。","habits":"帕劳啸鹟主要栖息在地面和森林下层，活动范围限于拥有茂密地面覆盖物的区域。以昆虫为主食，偶尔也会食用蜗牛、浆果、果实、绿色植物材料和种子。它们在地面上觅食，或在接近地面的树干和树枝上跳跃寻找食物。","breeding":"求偶行为包括伴侣间的夸张摇摆动作，但关于繁殖的其他细节尚不清楚。","identification":"与灰白眼莺相比，帕劳啸鹟体型更大，喙部更厚实。与密克罗尼西亚椋鸟相比，体型较小且颜色较淡，眼睛颜色更深。","protection":"IUCN：LC（无危）","distribution":"分布于太平洋中的帕劳群岛（加罗林群岛西部，密克罗尼西亚西部），包括Babeldaob、Koror、Garakayo、Peleliu和Ngabad等岛屿。","other":"在2013年前，帕劳啸鹟曾被归类于Colluricincla属，之后被重新分类至Pachycephala属。有时也被置于Pitohui属或单独的Malacolestes属。"},{"name":"比岛棕鵙鹟","english_name":"Biak Whistler","scientific_name":"Pachycephala melanorhyncha","overview":"比岛棕鵙鹟（英文名：Biak Whistler，学名：Pachycephala melanorhyncha），是雀形目啸鹟科啸鹟属的鸟类。分布于印尼的Biak岛，位于新几内亚西北部的鸟头湾。此物种原被认为是棕鵙鹟的一个亚种，但现已独立成种。","appearance":"中等体型，长16.5至19厘米，重33至41克。上身呈暖棕色，下身颜色较淡，脸部橙棕色，翼羽红褐色。喙厚而黑，眼睛大。两性相似。幼鸟上身颜色更深，翼覆羽更偏棕色，下身略带棕色。成年鸟的头部灰橄榄色，下身浅色，带有灰色条纹。喙颜色随亚种不同而有所变化。","call":"叫声多样，包括短促间隔的哨音，穿插快速重复的‘chew’声。在澳大利亚，发出响亮、旋律丰富的管状叫声，如‘cup of tea, wot wot wot’或‘eee, butch-butch-butcher’。","habits":"栖息于雨林、季风林、生态扰动环境、高次生林和画廊森林，常见于低地、丘陵和较低山地，最高可达1850米，局部地区可达2300米。以昆虫为主食，偶尔吃种子、果实和小型脊椎动物。在新几内亚，主要在林下层和中间层觅食，偶尔在地面或树冠层活动。","breeding":"繁殖季节在新几内亚为3月至12月，澳大利亚为8月至2月。筑巢由双亲共同完成，巢为深杯形，由树叶、树枝、树皮条、植物纤维等构成，内衬细小材料。每次产卵2枚，偶尔3枚，孵化期至少19天，雏鸟期报告为12天。每年可有多次繁殖尝试。","identification":"与棕鵙鹟的区别在于其红褐色的翼羽和橙棕色的脸部。不同亚种在羽毛颜色和喙色上有细微差异。","protection":"IUCN：LC（无危）","distribution":"主要分布在印尼的Biak岛，位于新几内亚西北部的鸟头湾。","other":"在全球范围内不被视为受威胁物种。在新几内亚，数量普遍较多。在澳大利亚东北部常见，向南逐渐稀少。"},{"name":"斑胸林鵙鹟","english_name":"White-bellied Pitohui","scientific_name":"Pseudorectes incertus","overview":"斑胸林鵙鹟（英文名：White-bellied Pitohui，学名：Pseudorectes incertus），是雀形目啸鹟科锈色林鵙鹟属的鸟类。中等体型的鸟类，拥有暖棕色的背部，腹部呈淡色，胸部带有模糊的条纹。其特征还包括宽阔的浅色眼环和浅色喙。这种鸟通常在季节性泛滥的森林中以群体或混合群的方式活动，寻找昆虫或果实为食。","appearance":"斑胸林鵙鹟的身长介于21.5至23厘米之间，体重约75克。它的冠部和上体呈深棕色，尾上覆羽略带赤褐色；上翼和尾部为深棕色，飞羽和尾羽边缘带有赤褐色；下体为棕白色，喉咙和上胸部有棕色或深棕色的斑点，有时会形成连续的带状图案；虹膜为深棕色；喙为角棕色；腿为橄榄灰色。雌雄外观相似。幼鸟的特征尚未详细描述。","call":"斑胸林鵙鹟的鸣唱是一段短促的、上下起伏的、中音调的哨声二重奏。","habits":"斑胸林鵙鹟栖息于低地森林，通常在海岸平原的断续树冠下层活动，尤其在年降水量高的地区（超过3750毫米），森林会季节性地被水淹没。它们似乎不迁徙，偏好在密集植被和藤蔓缠绕的较低树冠层（5-18米高）觅食，常加入混合物种的觅食群落。","breeding":"雄性斑胸林鵙鹟在8月中旬会有增大的睾丸，但关于繁殖的其他信息尚不清楚。","identification":"与棕鵙鹟相比，斑胸林鵙鹟体型更大，更喜欢群居。通过其独特的上体颜色、腹部颜色以及胸部的条纹可以轻易将其与其他类似物种区分开来。","protection":"IUCN：LC（无危）","distribution":"斑胸林鵙鹟在澳新界的新几内亚南部零星分布，主要集中在南巴布亚低地EBA。在新几内亚，仅知两个小区域有其分布，一处位于诺德河上游约90公里处，另一处在弗莱河与基翁加和帕尔默交汇口之间，向东320公里。在这一极小的范围内，局部地区较为常见。","other":"斑胸林鵙鹟最初被归类于Pitohui属，直到2013年被IOC分类到Pseudorectes属。一些权威机构将其归入Colluricincla属。"},{"name":"锈色林鵙鹟","english_name":"Rusty Pitohui","scientific_name":"Pseudorectes ferrugineus","overview":"锈色林鵙鹟（英文名：Rusty Pitohui，学名：Pseudorectes ferrugineus），是雀形目啸鹟科锈色林鵙鹟属的鸟类。中型鸟类，分布于新几内亚低地及周边岛屿，以其独特的锈褐色外观著称，具有白色的眼睛。","appearance":"锈色林鵙鹟长约25.5至28.5厘米，体重介于77至110克之间。头部及上体呈棕色，略带锈色，尾羽为锈色，下体淡锈色，喉部颜色更浅。眼睛白色，喙黑色，腿灰色。两性相似。幼鸟与成鸟类似，但虹膜颜色较深。不同亚种间颜色和喙色存在差异，如leucorhynchus亚种喙灰白，fuscus亚种上体颜色更深。","call":"叫声多样而有力，常发出‘woo-pat！’等音节的哨声，有时声音会逐渐增强。","habits":"栖息于雨林、季雨林、画廊森林及高大的次生植被中，偶尔出现在受干扰的地区和靠近森林边缘的柚木(Tectona)种植园。活动高度随是否有弯嘴鹛相伴而异，独自时主要在主冠层活动，与混群时更多在次冠层和下层。以昆虫（包括幼虫）和水果为食，通常成群觅食。","breeding":"在树叉处构建深杯状的巢穴，由树枝、叶子和茎构成。","identification":"与其他锈色鸟类如冠林钟鹟、弯嘴鹛或某些雌鸟蝉鸟相区别，注意其白色的虹膜。","protection":"IUCN：LC（无危）","distribution":"广泛分布于新几内亚低地及周边岛屿，包括阿鲁群岛。"},{"name":"纹胸鵙鹟","english_name":"Bower's Shrikethrush","scientific_name":"Colluricincla boweri","overview":"纹胸鵙鹟（英文名：Bower's Shrikethrush，学名：Colluricincla boweri），是雀形目啸鹟科鵙鹟属的独特鸟类。以独特的棕色上体、桃色下体和带有淡淡条纹的苍白喉部与胸部为显著特征，仅见于澳大利亚东北部的昆士兰州，尤其是库克敦至汤斯维尔之间的湿热热带雨林中。","appearance":"雄性纹胸鵙鹟具有健硕的体型，搭配着结实的喙。其上体呈棕色，下体为桃色，拥有黑色的喙，灰色头部，以及带有微弱条纹的淡色喉部和胸部。雌鸟和幼鸟外观相似，但喙部呈灰色，眼周有细薄的橙色环。","call":"鸣唱由四声轻柔的音符开始，随后跟随着三声响亮、清脆的音符。","habits":"栖息于澳大利亚东北部湿热的高海拔雨林中，偏好亚热带或热带湿润的低地和山地森林。","identification":"与其他鵙鹟属鸟类相比，纹胸鵙鹟的特征在于其特有的颜色组合和条纹图案，特别是在喉部和胸部的条纹上。","protection":"IUCN：VU（易危）","distribution":"纹胸鵙鹟的分布限于澳大利亚东北部，具体在昆士兰州的库克敦以南至汤斯维尔一带，涵盖整个东南部的约克角半岛。"},{"name":"乌鵙鹟","english_name":"Sooty Shrikethrush","scientific_name":"Colluricincla tenebrosa","overview":"乌鵙鹟（英文名：Sooty Shrikethrush，学名：Colluricincla tenebrosa），是雀形目啸鹟科鵙鹟属的中等体型的鸟类。主要分布在新几内亚中西部至中东部的山区，栖息于亚热带或热带湿润的山地森林中。","appearance":"整体呈现深邃的烟熏棕色，长时间静止于枝头，仔细搜寻昆虫。它的行为隐秘，很难被观察到。颜色介于黑色的雄性黑林鵙鹟与棕色的雌鸟之间，但体型较小。其大小与棕鵙鹟复合群中的多个物种相似，但颜色更深，栖息地海拔更高。","call":"其鸣叫声知之甚少，但已知会发出响亮、金属质感的警报声。","habits":"乌鵙鹟偏好生活在中等海拔的山地森林中，以昆虫为主要食物来源。它们的行为较为隐匿，使得观察和研究具有一定的挑战性。","breeding":"关于乌鵙鹟的繁殖习性信息有限，需要更多研究来了解其具体的繁殖周期、巢穴构建、交配行为和育雏过程。","identification":"与黑林鵙鹟有相似之处，但在颜色上介于黑雄鸟和棕雌鸟之间，且体型更小。与棕鵙鹟复合群中的物种大小相仿，但颜色更深，栖息地海拔更高。","protection":"IUCN状态未知，需关注其保护状况。","distribution":"乌鵙鹟主要分布于新几内亚中西部至中东部的山区，其自然栖息地为亚热带或热带湿润的山地森林。","other":"曾被称为Colluricincla umbrina，后因分类学调整改回原名tenebrosa。"},{"name":"棕鵙鹟","english_name":"Arafura Shrikethrush","scientific_name":"Colluricincla megarhyncha","overview":"棕鵙鹟（英文名：Little Shrikethrush，学名：Colluricincla megarhyncha），是雀形目啸鹟科鵙鹟属的鸟类。体型粗壮的林栖鸣禽，具极厚的喙。该种为“小鵙鹟”复合体拆分后的狭义物种，分布区域涵盖澳大利亚西北部和整个新几内亚低地及山脚，栖息于低地至中海拔的多种潮湿森林，包括次生林、沼泽林和红树林。其歌声洪亮多变，常被认为是最悦耳的林鸟之一。","appearance":"成鸟雌雄同色。指名亚种上体赭褐色，冠部较暗，眉纹及耳羽暗赤褐，飞羽外缘淡褐，尾羽暗赤褐色；下体淡赭红，喉胸具灰色宽纵纹，虹膜栗褐色，嘴褐角质色，脚灰色。幼鸟上体更暗，翼覆羽带赤褐缘；亚成体似成鸟，但次级飞羽与覆羽仍保留赤褐色羽缘。\n\n亚种差异显著：batantae亚种上体暗橄榄褐，喉部浅黄，胸腹赭红并带灰染，胸具灰纹；parvula亚种头及上体暗灰褐，眉纹灰白，喉白具细纹，胸黄褐，腹部中央近白，嘴黑色。","call":"歌声洪亮、旋律丰富，由数个穿透力强的哨音组成，通常呈先升后降的波浪式，结尾常带一至数个上扬的欢快节奏。叫声包括短促的“chek”和“whit”。","habits":"留鸟，极少移动。主要栖息于低地至1850 m的原始雨林、季风林、次生高大灌丛及河岸林，偶见于红树林、纸皮树林及海岸灌丛。在新几内亚，70%以上时间在距地0–8 m的中下层觅食，地面活动约占13%；在澳大利亚则偏好1–10 m的灌丛和下层树冠。觅食时多在枝叶、枝杆、枯叶堆及藤蔓间啄取猎物，捕猎以啄食为主，辅以短距离飞扑和空中突袭。食物主要为昆虫、蜘蛛、蜗牛及小型甲壳类，偶尔取食种子、果实，极少捕食小鸟。","breeding":"繁殖期在新几内亚为3月、5–6月及9–12月，呈双峰型；澳大利亚为8月至翌年2月，可多达一年五窝。领域性强，巢由两性共筑，为深而松散的杯状，由枯叶、细枝、树皮纤维、根须等构成，外径11–13厘米，内径7–8厘米，多置于距地0.5–2 m的细枝分叉或藤蔓间，偶有高达60 m记录。卵2枚（偶3枚），白色或粉/黄白带红褐及灰色斑点，大小23–28.5 × 17–21 毫米。孵化期16–19天，仅雌鸟孵卵，雄鸟可能协助；育雏期约10–12天，双亲共同喂养，每小时2–3次。孵化成功率60–72%，已知最长寿个体16年8个月。","identification":"与锈色林鵙鹟相比体型较小，眼深色而非浅色；与乌鵙鹟及黑林鵙鹟体型相似，但体色从不全黑；与灰鵙鹟相比体型更小、羽色更褐，胸具纵纹。亚种间可依上体色调、喉胸颜色及嘴色区分：指名亚种赭褐色带暗红；parvula亚种灰褐色，喉白，嘴黑；batantae亚种上体暗橄榄褐，胸腹赭红并带灰纹。","protection":"IUCN: NE（未评估）。拆分后分布仍广，目前未被认为受威胁，但在澳大利亚北部较为少见。","distribution":"繁殖区：新几内亚西部（西巴布亚的拉贾安帕群岛、阿鲁群岛、吉德芬克湾、毛克山、迪古尔河流域、奥里奥莫河至莫尔黑德河之间、弗莱河流域）、澳大利亚西北部（西澳大利亚金伯利地区至北领地阿纳姆地）。非繁殖区无迁徙记录。","other":"本种为“小鵙鹟”复合体拆分后保留学名棕鵙鹟的狭义物种。亚种parvula与C. rufogaster normani存在杂交，形成过渡种群aelptes。"},{"name":"灰鵙鹟","english_name":"Grey Shrikethrush","scientific_name":"Colluricincla harmonica","overview":"灰鵙鹟（英文名：Grey Shrikethrush，学名：Colluricincla harmonica），是雀形目啸鹟科鵙鹟属的鸟类。广泛分布于澳大利亚和新几内亚的中型鸣禽。以独特的五音符鸣唱闻名，体长约24厘米，外观上无鲜艳色彩，但在歌唱天赋上却独树一帜。","appearance":"雄鸟成鸟头部和颈背呈深灰色，眼眶白色，面部侧面和颈部颜色较头顶淡，颊部浅灰色；背部、肩羽橄榄褐色，臀部和尾上覆羽深灰色；上翼灰色带淡棕色调，飞羽和大覆羽暗灰色，边缘略显浅灰色，尾羽深灰色；喉部至胸部颜色渐变，由浅灰至深灰，两胁和腹部至白色或近白色；虹膜深红棕色；喙黑色；腿深灰色至黑色。雌鸟与雄鸟相似，但眼眶淡灰色，眼环窄而浅灰，颊部至胸上部有深灰色条纹，喙色灰色，有时下颌基部较浅。幼鸟具有宽阔的锈色眉纹，上体棕色，臀部和尾上覆羽棕灰色，飞羽和翼覆羽边缘宽广的锈色，下体重条纹，尾下覆羽和肛周白色，虹膜深棕色。","call":"灰鵙鹟的鸣唱丰富而悦耳，由一系列离散的类似长笛的声音组成，音调、音量和持续时间各异，通常至少有一声比其余更为响亮，结尾为拉长的音符或高亢清脆的哨音。歌声具有显著的地域性和个体差异。","habits":"栖息于多种林木环境，主要是桉树（Eucalyptus）或金合欢（Acacia）为主的区域，但也可见于班克西亚树林、沿海灌木丛、农田、花园、住宅区、异域松树（Pinus）林和雨林，以及干旱地区的河流旁。在新几内亚，还出现在稀树草原、红树林、海岸灌木、次生林、城镇花园、椰子种植园和橡胶园。海拔高度从海平面到1700米。","breeding":"繁殖季节在澳大利亚为7月至2月，在新几内亚为2月至5月和8月至11月。每季可产1至3窝，若卵丢失可尝试多达四次。巢由两性共同建造，位于地面至20米高的植被中，平均高度低于3.5米，偶尔建于地面。巢呈开放杯状，主要由树皮条、根须、小枝和叶子构成，内衬草和细树皮。卵数1至4枚，通常3枚，白色或乳白色，带有灰色和橄榄褐色斑点。孵化期15至19天，雏鸟期17至18天。","identification":"成年雄性灰鵙鹟的头部和颈背深灰色，眼眶白色，与同属其他物种区别明显。雌鸟与雄鸟的区别在于眼眶颜色、条纹分布和喙色。幼鸟具有明显的锈色眉纹，便于识别。","protection":"IUCN：LC（无危）","distribution":"广泛分布于澳大利亚全境和新几内亚东部，从沿海至内陆，包括城市区域。","other":"灰鵙鹟能够模仿其他鸟的叫声，是出色的模仿者。"},{"name":"褐胸鵙鹟","english_name":"Sandstone Shrikethrush","scientific_name":"Colluricincla woodwardi","overview":"褐胸鵙鹟（英文名：Sandstone Shrikethrush，学名：Colluricincla woodwardi），是雀形目啸鹟科鵙鹟属的大型陆栖鸟类，亦被称为棕色胸鵙鹟或砂岩鸫。其特征为较长的喙、尾和强壮的腿，上身呈褐色，下身呈现桃色和淡黄色，头部和胸部灰白。仅在澳大利亚北部的砂岩地带出没，偏好岩石而非森林环境。","appearance":"体长约25-26.5厘米，体重约50-60克。雄鸟头部和颈部暗灰色，渐变为橄榄褐色，面部侧面白色带淡黄，翼上部深灰棕色，尾部深棕色；下巴淡灰色，喉部灰白带细纹，下身浅棕色，胸部带灰，大腿部位更显灰色。雌鸟喙色较雄鸟淡。幼鸟颜色更淡，次级飞羽和翼覆羽边缘红褐色，喉部比胸部更浅，下身有轻微斑点；亚成鸟类似成年个体，但翼缘红褐色（很快消失）。","call":"发出丰富、清澈且多变的歌声，包含两次重复的哨音。叫声为金属质感的‘pwink’声，联系叫声为尖锐的‘peter’声。","habits":"栖息于砂岩悬崖、峡谷和山丘，偶尔延伸至石灰石、花岗岩和石英岩露头，极少进入季风悬崖森林；偏好有峭壁和巨石的区域，通常地面覆盖低矮灌木、散落树木和芒草（Triodia）。以昆虫和蜘蛛为主食，偶尔捕食小型脊椎动物。在地面、芒草丛、岩石裂缝、巨石下和岩架处觅食。","breeding":"在西澳大利亚，产卵期为10月底至11月初；在北领地，产卵期为8月末至1月。巢由芒草、小枝和根须构成的杯状结构，内部衬以根须，外部直径16-18厘米，高度6厘米，内部直径7.5-10厘米，深度3.5-5厘米，筑于悬崖基部2-11米高的岩石台或洞穴内。每窝产卵2-3枚，蛋壳白色，带棕色和深灰色标记，主要集中在较大端，尺寸16.7-29.7 x 19.1-20.8毫米。","identification":"与同大小的灰鵙鹟相比，褐胸鵙鹟拥有更长的尾巴，且下身无暖色调。叫声和歌声也有明显差异。","protection":"IUCN：LC（无危）；在当地常见。","distribution":"分布于澳大利亚北部，自西澳大利亚东北部至昆士兰西北部。"},{"name":"群岛棕鵙鹟","english_name":"Variable Shrikethrush","scientific_name":"Colluricincla fortis","overview":"群岛棕鵙鹟（英文名：Variable Shrikethrush，学名：Colluricincla fortis），是雀形目啸鹟科鵙鹟属的鸟类。原被认为是小鵙鹟复合种的一员，但遗传学研究揭示其与小鵙鹟存在显著的基因差异，证明了它应独立为一物种。分布于新几内亚东南部及其周边岛屿，常见于低地和山脚的湿润森林。","appearance":"这是一种体形粗壮的鸟，喙厚实。外表朴素，背部呈褐色，头部灰白色，腹部颜色较浅，胸部有不明显的条纹。腹部的颜色从暗淡的赤褐色到近乎白色的象牙色，随地理位置而变化。","call":"鸣唱丰富悦耳，由数个穿透力强的哨音组成，通常以升降调式排列。叫声包括‘chek’音。","habits":"栖息于低地至中海拔的湿润森林，包括次生林。预计其生活方式类似于同一物种复合群中的其他成员，偏好在地面或树叶上觅食昆虫。","identification":"与锈色林鵙鹟相似，但体型较小，眼睛深色而非浅色。与灰鵙鹟相比，体型更小，尾巴更短，背部颜色更深，面部颜色更深。与雌鸟黑鵙鹟的区别在于体型更小，颜色更浅。","protection":"IUCN：尚未评估","distribution":"分布于新几内亚东南部，包括Trobriand Islands和D'Entrecasteaux Archipelago。在低地雨林和较低的山地森林中较为常见。","other":"曾被视为棕鵙鹟复合种的一部分，近期的系统发育研究表明，群岛棕鵙鹟是独立的物种，与其它棕鵙鹟种群存在明显的遗传差异。现为棕鵙鹟亚种。"},{"name":"卫吉岛棕鵙鹟","english_name":"Waigeo Shrikethrush","scientific_name":"Colluricincla affinis","overview":"卫吉岛棕鵙鹟（英文名：Waigeo Shrikethrush，学名：Colluricincla affinis），是雀形目啸鹟科鵙鹟属的鸟类。最近被确认为一个独立物种，主要分布在新几内亚的Waigeo岛。具有厚实的淡色喙，上体呈暗棕色，下体较浅，胸部有模糊的条纹。","appearance":"卫吉岛棕鵙鹟体型粗壮，上体为暗橄榄灰褐色，飞羽和尾羽边缘带有锈色，下体颜色更浅，喉咙和腹部白色，胸部有淡灰色条纹覆盖在奶油色背景上，下部体羽略带淡黄色。喙呈淡粉色，脚和趾为蓝灰色。","call":"卫吉岛棕鵙鹟发出丰富、悦耳且多变的歌声，由几个穿透力强的哨音组成，通常呈现上升下降的模式。叫声包括‘chek’和‘whit’。","habits":"卫吉岛棕鵙鹟栖息于湿润森林的下层和中层，包括次生林。它被认为是留鸟，可能以类似其他小鵙鹟的饮食方式觅食，但具体细节有待研究。","breeding":"繁殖习性可能与其他鵙鹟相似，但具体信息需要进一步记录。","identification":"卫吉岛棕鵙鹟与锈色林鵙鹟相似，但体型较小，缺乏锈色下体，眼色较深。通过其厚实的粉色喙、轻条纹的胸部和体型易于识别。","protection":"IUCN：尚待评估（待评价）。卫吉岛棕鵙鹟是Waigeo岛的特有种，但鉴于ebird报告的数量和媒体显示，该物种在当地较为常见。","distribution":"卫吉岛棕鵙鹟主要分布于新几内亚西北部的四王群岛中的Waigeo岛。","other":"卫吉岛棕鵙鹟与小鵙鹟复杂体曾被认为是同一物种，但遗传研究表明其间的基因分化水平高，暗示存在多个隐秘物种。现为棕鵙鹟亚种。"},{"name":"褐鵙鹟","english_name":"Mamberamo Shrikethrush","scientific_name":"Colluricincla obscura","overview":"褐鵙鹟（英文名：Mamberamo Shrikethrush，学名：Colluricincla obscura），是雀形目啸鹟科鵙鹟属的鸟类。具有厚实的暗色喙，上体灰棕色，下体较淡，喉部有深灰色条纹，胸部斑驳的暗棕色。与棕鵙鹟分离，独立成为一种，此分类调整依据IOC 9.2版本。","appearance":"这是一种体型粗壮的鸟类，拥有显著的厚实而深色的喙。全身颜色较为单调，上体呈现灰棕色，下体颜色较浅，带有不太明显的胸纹。颜色随地理位置而变，从深灰至更淡更偏棕色，尤其是在下体部分。雄雌幼鸟的羽毛特征与成年鸟相似。","call":"其鸣唱丰富而悦耳，变化多样，由数个穿透力强的哨音组成，通常以升降模式排列，结尾常带有一个尖锐的上扬音符。","habits":"栖息于低海拔到中海拔的湿润森林中，包括次生林。它的活动范围和觅食方式尚待具体研究。可能以昆虫和其他无脊椎动物为主要食物来源。","identification":"与锈色林鵙鹟相比，体型较小，眼睛颜色更深而非浅色。与乌鵙鹟和黑林鵙鹟有细微差异，下体颜色稍显淡些，尤其是胸部带有条纹。","protection":"IUCN：尚未评估（待评估为独立物种，但在印尼查亚普拉地区似乎常见）","distribution":"分布于新几内亚的亚彭岛（鸟头湾）及西北部、中西部地区，包括澳大利亚的亚彭岛和新几内亚西北部及中西部。","other":"该物种曾被认为是小鵙鹟复合体的一员，但遗传研究表明其内部存在高度基因分化，提示可能存在多个隐秘物种。现为棕鵙鹟亚种。"},{"name":"塔古棕鵙鹟","english_name":"Tagula Shrikethrush","scientific_name":"Colluricincla discolor","overview":"塔古棕鵙鹟（英文名：Tagula Shrikethrush，学名：Colluricincla discolor），是雀形目啸鹟科鵙鹟属的鸟类。栖息于人类居住区附近的受扰森林。","appearance":"塔古棕鵙鹟体型较为健硕，头部以灰色为主，冠部棕色，背部橄榄绿带黄，臀部和尾上覆羽黄绿色，翅膀灰绿，下体颜色较暗淡，胸腹部带褐色，喉部和胸部有明显的条纹，下尾覆羽淡黄色，两性皆有黑色厚重且带钩的喙。","call":"此鸟鸣声丰富且悦耳，变化多端，由哨音和粗糙音组成，常以升降模式呈现，声音响亮且种类繁多。","habits":"栖息于低地湿润森林的下层，常见于人类居住区附近的受扰森林环境。生活方式可能与其他‘小鵙鹟’超种相似，但具体细节尚需研究。","breeding":"繁殖习性预计与其他‘小鵙鹟’超种相似，但具体信息有待进一步调查。","identification":"与其他‘小鵙鹟’超种成员相比，塔古棕鵙鹟具有较大的体型、大而带钩的黑色喙，以及橄榄黄色的上体。在塔古拉岛上，与灰鵙鹟有明显大小差异。","protection":"IUCN：未评估。物种虽分布范围有限，但数量似乎相当稳定，适应力强，出现在多种受扰生境。","distribution":"分布于巴布亚新几内亚的路易西亚德群岛中的塔古拉岛和Junet岛，主要栖息于低地森林。","other":"塔古棕鵙鹟曾被认为是‘小鵙鹟’复合种的一员，但遗传研究表明其内部DNA分化显著，证明了它是一个独立的物种。现为棕鵙鹟亚种。"},{"name":"塞皮克拉穆棕鵙鹟","english_name":"Sepik-Ramu Shrikethrush","scientific_name":"Colluricincla tappenbecki","overview":"塞皮克拉穆棕鵙鹟（英文名：Sepik-Ramu Shrikethrush，学名：Colluricincla tappenbecki），是雀形目啸鹟科鵙鹟属的鸟类。体型健硕，喙部粗厚且颜色深暗。分布于新几内亚中北部，特别是在Sepik-Ramu河流域和休恩半岛。通过DNA分析，确认了其物种地位，但其识别特征和自然历史仍有待深入研究。","appearance":"此鸟上体呈灰棕色，下体较淡，通常为黄白色，胸部有模糊的条纹。胸部的颜色随地理位置而异：在某些区域呈灰色，与腹部的黄白色形成鲜明对比；而在另一些区域，胸部颜色与腹部相同，均为黄白色。喙部颜色在不同亚种间有所差异，从黑色到棕色不等。","call":"鸣声丰富悦耳且变化多样，由数个尖锐的哨音组成，通常呈现上升和下降的模式。声音低沉有力，偶尔含有鞭打般的音符。","habits":"栖息于低海拔至较低山地的湿润森林，包括次生林。生活方式与同属其他物种相似，可能为定居型，以昆虫为主食。","breeding":"繁殖习性预计与之前认为同种的鵙鹟类似，具体细节尚需针对这一新分类物种进行研究。","identification":"与锈色林鵙鹟相比，体型更小，眼睛颜色更深。与乌鵙鹟相比，体型和形状相似，但不会像后者那样全身黑褐色。与灰鵙鹟相比，体型较小，尾巴较短，颜色偏棕色，胸部条纹更为明显。","protection":"IUCN状态未提供，但鉴于其分布广泛，似乎并不面临严重威胁。","distribution":"分布于新几内亚的中北部，覆盖从 Maoke（雪）山脉北侧至休恩半岛的区域，除西北部和东北部半岛之外。","other":"通过遗传研究表明，塞皮克拉穆棕鵙鹟与其近亲之间存在显著的DNA差异，暗示可能涉及多个隐秘物种。现为棕鵙鹟亚种。"},{"name":"澳洲棕鵙鹟","english_name":"Rufous Shrikethrush","scientific_name":"Colluricincla rufogaster","overview":"澳洲棕鵙鹟（英文名：Rufous Shrikethrush，学名：Colluricincla rufogaster），是雀形目啸鹟科鵙鹟属的鸟类。但遗传研究揭示其具有高遗传分化，暗示存在多个隐秘物种。在新几内亚和澳大利亚东北部广泛分布，以丰富的鸣唱和独特的觅食行为著称。","appearance":"体型壮硕，喙厚而色淡。颜色上表现出显著的地理变异，从新几内亚南部的深红褐色到澳大利亚境内背部灰暗、腹部偏黄，常有较淡的喉部和模糊的下体条纹。喙呈淡粉色。","call":"发出丰富、悦耳且多变的鸣唱，由数个穿透性的哨音组成，典型模式为几个加速的哨音后接上滑音。叫声包括‘chak’声和鼻音。","habits":"栖息于低海拔的各种湿润森林，包括次生林、河岸林、沼泽森林和红树林。主要觅食昆虫和其他无脊椎动物，偶尔吃种子和果实。在澳大利亚，偏好森林的较低层次和灌木层。","breeding":"在澳大利亚的繁殖期为8月至2月，每季可尝试繁殖多次，每次最多五次。巢由两性共建，通常位于2米以下的高度，偶尔高达60米。每次产卵2枚，孵化期16-17天，由双亲共同抚育。","identification":"与灰鵙鹟相似，但栖息于更密集的生境，整体显得较小、尾巴更短、褐色更深，腹部偏黄。与锈色林鵙鹟相比，体型更小，眼色较暗。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚沿海中南部和澳大利亚北部、东部，包括澳大利亚东北部至新几内亚的沿海地区。","other":"与塔古棕鵙鹟关系最近，尽管它们的分歧时间估计约为400万年前。现为棕鵙鹟亚种。"},{"name":"黄嘴鹊鵙","english_name":"Yellow-billed Shrike","scientific_name":"Lanius corvinus","appearance":"黄嘴鹊鵙身长32厘米，拥有渐长的尾巴和短翅膀。成鸟上部羽毛呈斑驳的棕色，下部羽毛带有条纹的淡黄色。它具有棕色的眼罩和锈色的翼斑，喙为鲜黄色。雌雄相似，但雌鸟的两胁有紫红色斑点，而雄鸟则为红棕色，这些斑点通常在飞行、展示、领地争斗或整理羽毛时可见。幼鸟的翼羽边缘呈淡黄色。腿和脚为黑色，喙为黄色，即使在幼鸟中也是如此。其叫声尖锐，常发出swee-swee和dreee-too的叫声。","call":"黄嘴鹊鵙的叫声多样，包括嘈杂的叽喳声、尖叫和沙哑的嗡嗡声，通常由群体集体发出，主对也可能二重唱。","habits":"这是一种显眼且群居的鸟类，总是成群出现，常排列在电话线上。它栖息于非洲撒哈拉以南至赤道以北的干旱灌木草原和林地。在不利天气条件下，它们也会在地面觅食，甚至像欧乌鸫一样从土中拉出蚯蚓。已记录到它们食用枣子。","breeding":"繁殖季节因地理位置而异，通常在雨季期间，如塞内加尔的6月至8月，冈比亚更南地区为7月至10月，加纳和尼日利亚全年大部分月份，肯尼亚为1月至2月及4月。一夫一妻制。合作领土繁殖，平均每个繁殖群体有12个成员（6至25人），其中只有1对繁殖伴侣，其余均为帮手（通常是繁殖对的后代），帮手负责保卫领地、预警捕食者、喂养孵卵或育雏的雌鸟，以及雏鸟和离巢幼鸟。巢由繁殖对建造，部分成员协助，耗时1至4周完成，是一个大而松散的开放杯状巢，由树枝、草构成，有时还会有叶子，内衬细草茎和根须，位于树或灌木丛中，高度1.5至10米，通常隐藏在茂密的树叶中。每窝产2至6枚蛋，通常为3至4枚，蛋壳颜色从奶油色到红色或绿色，带有灰色和黄褐色斑点。替换窝常见。孵卵由雌鸟承担，期间由雄鸟和帮手喂食，孵化期15至18天。雏鸟由雌鸟照顾，由雄鸟和帮手喂食（帮手将食物带给雌鸟），雏鸟期18至20天。幼鸟离巢时仍无法飞行，由全体成员喂食，约45至50天后独立。巢寄生现象罕见，例如在加纳，160个巢中只有一个被非洲杜鹃寄生。繁殖成功率相对较低，加纳仅为25%，57%的366枚蛋孵化，大多数窝在暴风雨和强风中丢失，只有44%的159只雏鸟成功离巢。首次繁殖年龄未知，但在六年的研究中，没有一只当年出生的幼鸟开始繁殖。","identification":"与其他伯劳属鸟类相比，黄嘴鹊鵙的显著特征是其非常长的尾部和独特的黄色喙。雄鸟和雌鸟在外观上非常相似，但雌鸟的两胁有明显的紫红色斑点，而雄鸟则是红棕色，这些斑点仅在特定行为中可见。","protection":"IUCN：LC（无危）","distribution":"黄嘴鹊鵙分布于非洲的东部、中部和西部，具体国家包括贝宁、布基纳法索、喀麦隆、中非共和国、乍得、刚果、刚果民主共和国、科特迪瓦、冈比亚、加纳、几内亚、几内亚比绍、肯尼亚、马里、毛里塔尼亚、尼日尔、尼日利亚、塞内加尔、塞拉利昂、南苏丹、苏丹、多哥和乌干达。","other":"黄嘴鹊鵙的全球趋势未量化，但其种群似乎稳定。减少农业杀虫剂的使用和保护分散的传统农业半开放生境可能是确保这一物种未来的最有效保护措施。"},{"name":"白肩鹊鵙","english_name":"Magpie Shrike","scientific_name":"Lanius melanoleucus","overview":"白肩鹊鵙（英文名：Magpie Shrike，学名：Lanius melanoleucus），是雀形目伯劳科伯劳属的鸟类。原生于东非和东南非的草原地带，其自然栖息环境为干燥和湿润的萨凡纳草地，以及亚热带或热带的干燥灌木丛。","appearance":"体型较大的黑白相间伯劳，拥有异常长且层次分明的尾巴。雄鸟具光泽的黑色头部和披风，肩部和翼上有大面积白色斑点，灰色白色的臀部形成V型，飞行时极为显眼。上翼黑色，次级飞羽和三级飞羽白色尖端，翼基部有大白色斑块。尾部和下体黑色，腹部和侧腹光泽度较低。雌鸟与雄鸟相似，但侧腹有大的白色斑块，繁殖季节可能更明显。幼鸟的黑色部分被暗褐色取代，缺乏光泽，尾羽呈暗褐色带淡色尖端，背部羽尖红褐色，肩羽白色带淡色尖端，臀部淡灰褐色，翼覆羽和飞羽带淡色尖端，下体暗褐色带白色羽尖，侧腹有变化的淡白色斑块。","call":"发出尖锐的类似八哥或鹦鹉的\"pleeee-eouuu\"叫声，常由一只或多只鸟同时发出，也发出刺耳的嘎嘎声。","habits":"主要栖息于萨凡纳林地和开阔的公园般萨凡纳，散布有金合欢树生长和短割草或裸土斑块，也见于阔叶林地和mopane（Colophospermum）生境。在博茨瓦纳西南部的分布极限处，最常见于潮湿区域、河谷和沼泽地，总是有金合欢树存在，但也出现在半沙漠生境。在当地公园（南非）和郊区（津巴布韦）也有发现。主要生活在低地，但在肯尼亚北部可达至1800米高度。","breeding":"繁殖季节大致与雨季重合，南部（指名亚种）从8月至3月，东部非洲（aequatorialis亚种）从1月至4月。可能是一夫一妻制。群居且定期合作繁殖，群体大小从两到十一只不等（冬季可达十九只）。巢由繁殖对建造，也可能有辅助者参与。巢是一个用树枝、纤维、根须和草制成的紧凑杯状，内衬精细材料，置于荆棘树，尤其是金合欢树中1.5至12米（平均约4米）高的位置。每窝产卵1至6枚，通常3至5枚，孵化期16至20天，由雌鸟单独孵化，由雄鸟和其他特定群体成员喂养。雏鸟期19至24天。","identification":"与同属其他物种相比，白肩鹊鵙具有非常长的尾巴和独特的黑白相间羽毛图案，特别是肩部和翼上的白色斑点。不同亚种在大小和尾长上有差异。","protection":"IUCN：LC（无危）","distribution":"分布于安哥拉、博茨瓦纳、斯威士兰、肯尼亚、莫桑比克、纳米比亚、南非、坦桑尼亚、赞比亚和津巴布韦。在撒哈拉以南和中部非洲的开放萨凡纳，散布有金合欢树，接近修剪过的草地和裸土，主要降雨发生在11月至4月之间。"},{"name":"虎纹伯劳","english_name":"Tiger Shrike","scientific_name":"Lanius tigrinus","overview":"虎纹伯劳（英文名：Tiger Shrike，学名：Lanius tigrinus），是雀形目伯劳科伯劳属的鸟类。俗名: 花伯劳、虎伯劳、虎鹎、粗嘴伯劳、厚嘴伯劳、虎花伯劳、三色虎伯劳，体型小，尾短，头部呈灰，具黑粗贯眼纹，下体白，双翼栗色带鳞状斑。繁殖于吉林、河北至华中及华东，冬季迁往东南亚至大巽他群岛。栖息于低地至山地的森林、林缘及农田，偏好有散树的环境。","appearance":"雄鸟头部灰色，具黑色粗大贯眼纹，下体白色，双翼深栗色带黑色粗条纹。雌鸟头顶为棕灰相间，黑色贯眼纹较小，两胁及双翼具黑色斑纹。幼鸟头及背部棕色，腹部布有棕色鳞状斑，因无黑色贯眼纹，眼睛显得较大。体长17–19厘米，雄鸟重27–29克，雌鸟重29–37克。","call":"其歌喉发出悦耳的颤音，但开始时较为低调。多种尖锐的叫声，包括响亮的重复领土叫声，叽叽喳喳的警报声，以及柔和的颤音叫声。","habits":"栖息于温带地区的低地森林、林缘及农田，海拔高度从海平面至900米。迁徙时，向南移动，夏季返回繁殖地。以昆虫为主食，也会捕食小型鸟类、蜥蜴和啮齿类。通常单独或成对活动，偶尔家庭群居。","breeding":"繁殖期5月至7月，筑巢于树木中，高1.5至5米，每窝产卵3至6枚，平均5枚。卵呈淡青色至淡粉色，带有暗色斑点。孵化期13至15天，仅雌鸟负责孵化。雏鸟留巢期13至15天，由双亲共同喂养。","identification":"与牛头伯劳及红尾伯劳相比，虎纹伯劳头部的灰色更明显，且无明显的黑色贯眼纹。幼鸟的暗色斑点更为显著。成鸟的歌声和叫声也有区别。","protection":"IUCN：LC（无危）。分布广泛，种群数量较大，但在日本和俄罗斯部分地区已明显减少。","distribution":"繁殖区包括西伯利亚东南部、中国东北至东部、朝鲜半岛和日本。非繁殖区覆盖东南亚至大巽他群岛，包括马来西亚、新加坡、越南等地。","other":"虎纹伯劳在迁徙季节中，会经过中国东南部，东至缅甸南部，南至马来半岛和印尼的苏门答腊、爪哇及巴厘岛。"},{"name":"南非伯劳","english_name":"Souza's Shrike","scientific_name":"Lanius souzae","overview":"南非伯劳（英文名：Souza's Shrike，学名：Lanius souzae），是雀形目伯劳科伯劳属的小型鸟类。以其独特的肩部白色斑纹和灰褐色的羽色而著称。分布于非洲中部，主要栖息于混交林地带，尤其是森林稀疏处与灌木丛生的环境。物种以葡萄牙科学家José Augusto de Sousa的名字命名。","appearance":"体长约17厘米，体重21至30克。雄鸟上身灰白，肩部具明显白色斑块，翅膀和尾巴棕色，下身灰白色。雌鸟较雄鸟颜色稍暗淡，具明显的土黄色侧腹。幼鸟头部棕色，面部面具呈棕色，全身密集黑色细纹，喉部白色。喙和腿黑色，虹膜深棕色。","call":"声音包括烦躁的“sveeat”声和低沉的沙哑声，还有低沉的‘tzzzzzick’声，由警惕的个体在巢边发出。","habits":"偏好生活在混交林区，特别是轻度的miombo林带，伴有短草丛。主要为留鸟，但在旱季可能有局部迁移。以昆虫和大蜘蛛为食，偶尔捕食小型脊椎动物。狩猎时通常在树冠下的中层停留，寻找地面的猎物。","breeding":"繁殖季节在安哥拉至少从9月开始，在刚果民主共和国和赞比亚为9月至11月，在马拉维为9月至12月（主要在10月）。巢由叶柄、树枝和草构成，内部以细根、藤蔓和草装饰，外部常饰以绒毛状种子头或地衣，隐藏良好，一般建在离地约5米的树叉或水平枝条上。","identification":"与红背伯劳雌鸟相似，但可通过肩部的白色标记和下身无横纹区分。","protection":"IUCN：LC（无危）","distribution":"分布在非洲中部，包括刚果民主共和国南部、卢旺达、坦桑尼亚西部和南部、安哥拉、赞比亚北部、马拉维北部至蒂约洛、莫桑比克北部、加蓬北部、纳米比亚北部和博茨瓦纳北部。","other":"已知在多个保护区出现，如马拉维的Dzalanyama森林保护区。"},{"name":"牛头伯劳","english_name":"Bull-headed Shrike","scientific_name":"Lanius bucephalus","overview":"牛头伯劳（英文名：Bull-headed Shrike，学名：Lanius bucephalus），是雀形目伯劳科伯劳属的小型鸟类，以其独特的羽色和牛头般的外观著称。分布于东亚，包括东北中国、韩国、日本和远东俄罗斯等地。偏好开阔生境，如农田、林缘地带和城市公园。主要以昆虫为食，也会捕食小型脊椎动物。","appearance":"成年雄鸟头顶及腹部呈暖橙色，具黑色贯眼纹，翅膀灰褐色带窄白边。雌鸟头部和两胁橙色更深，背部褐色，贯眼纹较不明显。幼鸟类似雌鸟成鸟，但缺乏白色眼纹边缘。雄鸟翼展有明显的白色斑块，喙较大，雌鸟则较小且翼斑不明显。","call":"发出尖锐、沙哑的连续音符，包括模仿其他鸟类的叫声；常有断续的喋喋声。","habits":"偏好开阔生境，如农田、林缘、城市公园和花园。主要以昆虫为食，如甲虫和蚱蜢，也会捕食蜥蜴和甲壳动物。部分个体在冬季会迁移到森林中，特别是在日本北部的完全雪覆环境中。","breeding":"繁殖期为春季至夏季，在日本北部从4月至7月，中国中部为5月至7月。一窝产卵2至7枚，平均孵化期为14至15天。雏鸟离巢期约为13至15天。","identification":"与红尾伯劳幼鸟相比，牛头伯劳具有更温暖的橙色调、更大的喙和较淡的贯眼纹。雄鸟有明显的白色翼斑，而雌鸟则没有。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括东北中国、韩国、日本和远东俄罗斯等地。非繁殖季节，北方种群南迁至中国东部和南部、朝鲜和日本中部及南部。","other":"牛头伯劳有将猎物穿刺于尖锐物体上的习性，以便于撕裂食物，同时也可能用于标记领地。"},{"name":"红尾伯劳","english_name":"Brown Shrike","scientific_name":"Lanius cristatus","overview":"红尾伯劳（英文名：Brown Shrike，学名：Lanius cristatus），是雀形目伯劳科伯劳属的中型鸟类。俗名: 褐伯劳，拥有细长的黑色贯眼纹和红褐色的腰部与尾羽。在日本亚种中，羽色呈现温暖的砖红色，而在普通亚种中，头部和背部带有灰色。这种伯劳广泛分布于亚洲，从俄罗斯中部至东亚和日本，冬季迁徙至南亚、东南亚等地。红尾伯劳偏好开阔的林地和有树木、灌木丛的田野，也常出现在公园和园圃。","appearance":"红尾伯劳体长17-20厘米，体重雄鸟27-34克，雌鸟28-37克。具有较大的头部，雄鸟有从眼后至耳羽的黑色面罩，宽阔的白色眉纹；额部淡黄白色，头顶至颈项红褐色，上体略显暗锈色，但臀部和尾上覆羽更鲜亮；上翼深褐色，翼羽和内飞羽边缘呈白色；尾羽暗红褐色，外侧尾羽边缘和尖端较浅；喉部白色，下体呈白色带有淡红褐色，尾下覆羽淡褐色；虹膜棕色；喙和腿黑色或黑褐色。雌鸟与雄鸟非常相似，但眉纹乳白色，面部暗色面罩在眼区稍淡，侧胸和两胁有细暗色虫蚀纹；非繁殖季节喙通常较暗，带粉色基部。幼鸟面部面罩为棕色且范围较小，头顶和上体红褐色带厚重的铅灰色横斑，上翼棕色，翼羽、次级飞羽和三级飞羽边缘红褐色，尾羽如成鸟，喉部白色，脸颊和下体淡黄色带深色虫蚀纹，腹部至肛周部位通常纯色。","call":"雄鸟重复的鸣唱声中常包含模仿其他鸟类的叫声，最常听见的鸣叫声为干涩的“哧-哧-哧”声。","habits":"红尾伯劳偏爱开阔的林地和有树木及灌木丛的开阔田野，也常见于公园和园圃中。它们的栖息地从海平面至低山，海拔可达1800米。它们是迁徙性鸟类，迁徙路线尚不清楚，但非繁殖地主要位于印度次大陆中部和南部，向东延伸至缅甸和马来半岛。","breeding":"红尾伯劳的繁殖期在5月至6月，筑巢活动由雌雄双方共同承担，巢由树枝、草梗、树皮纤维、干叶和苔藓构成，内部铺垫有毛发和细草。巢多置于树或高灌木中，距离地面6-9米，偶尔低至3米。每窝产卵3-8枚，孵化期为12-16天，主要由雌鸟孵化，雄鸟负责喂食。雏鸟的育雏期为13-16天，离巢后至少两周仍留在巢附近。","identification":"红尾伯劳雄鸟与红背伯劳雄鸟的主要区别在于尾羽：红背伯劳雄鸟尾羽侧缘白色，而红尾伯劳雄鸟尾羽侧缘非白色。红尾伯劳雌鸟或亚成鸟与红背伯劳雌鸟或亚成鸟的区别在于耳羽颜色：红尾伯劳雌鸟或亚成鸟耳羽黑色；红背伯劳雌鸟或亚成鸟耳羽棕色。红尾伯劳初级飞羽基部无白斑，而棕尾伯劳初级飞羽基部多具白斑。","protection":"IUCN：LC（无危）","distribution":"红尾伯劳繁殖于欧亚地区的俄罗斯中部、东部，蒙古，中国东部至日本。非繁殖季迁徙至印度至中国东部、菲律宾、印度尼西亚东部。","other":"红尾伯劳在某些地区如日本的superciliosus亚种数量大幅下降，可能面临灭绝风险。注意由于历史命名原因，棕尾伯劳的英文名直译为红尾伯劳，请注意区别。"},{"name":"红背伯劳","english_name":"Red-backed Shrike","scientific_name":"Lanius collurio","appearance":"雄性红背伯劳具蓝灰色头顶，黑色眼纹，鲜明的锈棕色背部，而雌鸟则以暖棕色为主调，腹部偏淡，侧翼和胸部可见细致的暗色斑点。幼鸟与雌鸟相似，但色彩更为柔和，上体呈现红棕色至棕黄色，带有明显的黑色新月状斑纹，下体斑点更重。两性成鸟的尾羽黑底白边，形成独特的T形图案。","call":"发出粗糙、沙哑的叫声，鸣唱较为安静，常模仿其他多种鸟类的鸣声。","habits":"栖息于阳光充足、干燥平坦或缓坡的地带，周围散布着低矮的灌木和小树，提供狩猎的高处。在农业地带，倾向于占据杂草丛生的角落、开阔的牧场、果园、花园、树篱和铁路旁的灌木。活动范围广泛，从欧洲至中亚的开阔地带，冬季则迁往东非和南非。","breeding":"繁殖季节从五月开始，通常一年一窝，偶尔两次。筑巢于低矮浓密的灌木中，如山楂、荆棘、黑莓或玫瑰。每窝产卵1-8枚，平均3-7枚，孵化期12-16天，由雌鸟几乎独自承担。幼鸟在巢中由雌鸟孵化，雄鸟喂养，出巢后约14天开始自行捕食，约20天后独立。","identification":"红背伯劳与其他伯劳种类的区别在于其独特的色彩模式和栖息偏好。雄鸟的蓝灰头、黑色面罩和锈棕色背部是明显标志。雌鸟则通过其暖棕色的上体和细腻的胸部斑纹与同类相区分。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧洲大部分地区至西伯利亚西部、哈萨克斯坦西部、土耳其和伊朗西北部。冬季迁徙至东非和南非。","other":"在英国，红背伯劳曾一度濒临灭绝，但在近年来出现了一些恢复迹象，尤其是在威尔士和英格兰西南部连续数年出现了繁殖记录。"},{"name":"荒漠伯劳","english_name":"Isabelline Shrike","scientific_name":"Lanius isabellinus","overview":"荒漠伯劳（英文名：Isabelline Shrike，学名：Lanius isabellinus），是雀形目伯劳科伯劳属的鸟类。体色浅沙的小型伯劳，雄鸟头顶灰褐、具黑色面罩，尾羽亮肉桂色，雌鸟色淡且具细暗纹。繁殖于蒙古、南西伯利亚至中国西北，冬季远至非洲东北、阿拉伯半岛及印度北部。","appearance":"体长16.5–18厘米，体重26–33.5克。雄鸟头顶淡灰带沙色，黑色面罩上缘具细白边；背至腰暖沙灰色，下腰及尾红褐；翼黑褐，羽缘沙白，初级飞羽基部具白斑；喉白，下体浅沙奶油色。雌鸟似雄鸟但色暗，面罩褐黑且小，初级白斑缩小或缺如，下体微具暗鳞纹，嘴基粉褐，脚灰褐。幼鸟上体灰褐具黑细波纹，尾棕红，下体乳白具褐纹；第一年冬羽残留幼羽横斑，眉纹乳白，耳羽褐，三级飞羽、腰、尾及尾上覆羽具暗端斑。亚种arenarius翅较短圆，体色更淡，雄鸟上体均一灰沙色，面罩模糊，初级白斑小且色暗，尾暗肉桂，下体浅粉沙；tsaidamensis似arenarius但翅更长（♂达102毫米）。","call":"被认为比红尾伯劳更善鸣，叫声略似红背伯劳。领域鸣声为“zea-zea”，配偶在场时转为“ko-ick”“zautzat…”或“tzautzat… tzautzat”；惊扰时发出“zeee”或“dzhikh-dzhikh-dzhikh”。告警声多样，包括“ktschaaä”“chak-chak-chak”“krkrkrkr…”；求偶及告警均可发出“tschek-tschek”。配偶间乞食声为连续的“kikikiki…”或“keee-keee-keee”，与幼鸟乞声几乎相同。歌声为轻柔婉啭，常夹杂粗厉尖曲，并能模仿其他鸟类。","habits":"栖息于河谷柽柳灌丛、干旱草原灌丛，山地可上至约2000米。非繁殖季见于南亚半荒漠耕地边缘、稀疏金合欢与柽柳草地，东非可达2400米开阔灌丛及干燥低地，偏好比红背伯劳更干多刺的植被，但在乍得亦记录于沼泽。典型“坐等”捕食，栖于电线、围栏、树枝，平均栖高2.1米；73%昆虫在地面捕获。主食甲虫、蝗虫、蟋蟀，偶食小型脊椎动物如田鼠、小蜥蜴及柳莺、鹨、鹡鸰等小鸟，常将猎物穿刺存放。","breeding":"繁殖期4–8月，中国通常单窝，偶见两窝。雄鸟以响亮鸣叫开始，随后滑翔展示飞行，并在雌鸟前上下翻飞、尾扇举鞠躬。巢由雄鸟选址，为深敞杯，由细枝、树皮、根、叶、草构成，内衬草茎、苔藓，距地0.3–3米（多1–2.5米），常置于柽柳、沙枣、胡杨等灌木。每窝4–6枚卵，淡蓝绿具褐斑，平均22.2×17.6毫米，重约3.4克；雌鸟孵卵15–16天，雄鸟喂巢，雏鸟留巢12–15天，离巢后亲鸟继续喂养约1月。大杜鹃在中国有寄生记录。甘肃种群繁殖成功率>68%，主要败因来自邻近个体争夺巢位。1岁性成熟。","identification":"与棕尾伯劳极似，但雄荒漠伯劳头顶与背同色，无暖褐色顶；雌鸟背色冷沙，胸腹缺乏红背伯劳的明显白底鳞纹。雌红背伯劳背更暖褐，胸腹白且具粗鳞斑。与同属其他种相比，体色更浅，尾更偏肉桂，翼上白斑及面罩大小亦有差异。亚种间区别：arenarius体色更淡，初级白斑小；tsaidamensis翅更长，色更浅。","protection":"IUCN: LC（无危）。全球种群未量化，但认为未接近受威胁阈值。多国受法律保护，部分区域列为“濒危”。减少农药使用、保护半开阔灌丛草地被认为是最有效的保育措施，在非繁殖区已纳入多国国家公园及保护区。","distribution":"繁殖区：蒙古（除西北部）、俄罗斯外贝加尔南部及东南部、中国新疆东北部（准噶尔北部、阿尔泰山、北天山）、甘肃西北部、内蒙古中部。非繁殖区：主要见于阿拉伯半岛、东北非洲（自尼日利亚向东至坦桑尼亚北部）、巴基斯坦及印度北部；部分个体越冬可早至10月、迟至翌年5月。迁徙时经伊拉克、伊朗南部，春季高峰在尼罗河上游4月中旬、印度西北部3月；迷鸟记录增多，远及英国、摩洛哥。","other":"分类史上曾与棕尾伯劳视为同一种；亚种命名近年因模式标本身份澄清而调整，原“arenarius”升为指名亚种，原“speculigerus”成为其异名。部分俄罗斯学者将两亚种群视为独立种，但指名亚种与arenarius在中国北部可能存在渐变。"},{"name":"棕尾伯劳","english_name":"Red-tailed Shrike","scientific_name":"Lanius phoenicuroides","overview":"棕尾伯劳（英文名：Red-tailed Shrike，学名：Lanius phoenicuroides），是雀形目伯劳科伯劳属的鸟类。栖息于干燥开阔、具低矮灌丛环境的小型伯劳，又名红尾伯劳。其头顶与尾羽呈锈红色，背灰腹白，具黑色过眼纹，外形与荒漠伯劳极似，但白色眉纹更显著、头顶偏红且下体更洁净。繁殖于中亚干旱河谷、山前灌丛及高原灌丛带，冬季迁至阿拉伯半岛及东北非干旱灌丛地带，以昆虫为主食，常伫立于灌丛顶或电线猎食。","appearance":"体长16.5–18 cm，体重25–38 g（肯尼亚越冬个体19.4–32.1 g）。体型紧凑，尾长。雄鸟头顶黄褐至棕红色，上体沙棕至亮栗色；中央尾羽栗褐，其余尾羽更淡；翼黑褐，初级飞羽基部白，形成小翼斑；眉纹白色宽而明显，过眼纹黑色；下体白色，两胁带粉葡萄色；喙黑褐至淡褐，基部更淡，眼褐，脚深灰至黑褐。部分低地繁殖个体（曾被称“karelini”型）头顶及上体偏灰，眉纹较弱，下体带皮黄。雌鸟上体褐，头顶微染栗色，尾似雄鸟但色稍暗；眉纹皮黄，耳羽具暗褐斑；下体白，颊、颈侧、胸及胁具细窄褐轴纹，有的个体纹极淡。第一冬羽似雌鸟，上体具暗色横斑，尾色更淡，翼斑常隐没或缺如，内侧飞羽及覆羽具宽皮黄缘，覆羽端部具黑褐色次端斑。","call":"鸣声似红背伯劳、荒漠伯劳及虎纹伯劳。雄鸟占区鸣唱为反复响亮粗糙的“zech”或“vehv”，如“tsch-ef, tsch-ef…”。求偶时发出更鼻音的“zauzat-zauzat…”。告警时为拖长粗糙“tsche-tsche-…”或“zeee”“dzhikh-dzhikih”，威胁时轻声嘶哑“ksss, ksss”，并伴咯咯嘴响及低沉“chat-chat…”。亚歌为轻柔连续婉啭，含丰富模仿，可似苇莺或拟苇莺。","habits":"栖息于河谷柽柳灌丛、干旱草原灌丛、山前圆柏与扁桃矮灌丛带，可达海拔3500 m（帕米尔）或2700 m（哈萨克斯坦），巴基斯坦一般高于2100 m。越冬多在海拔2400 m以下开阔灌丛及干旱低地，偏好多刺旱生植被，偶见沼泽边。栖于灌丛顶、电线上，以“坐等”方式猎食，平均栖高2.1 m；主食甲虫（叩甲、拟步甲、金龟子）、直翅目昆虫，偶食小型脊椎动物（䶄、蜥蜴、柳莺等），亦记录取食阿拉伯枸杞浆果。猎物多在地上捕获，亦见钉挂。","breeding":"单窝，南境4月底、北境5月底产卵，巴基斯坦4月中旬至6月中旬。雄鸟先到地，以响亮鸣叫及滑翔示威开始求偶，随后对雌进行空中往返展示并伴俯冲摆尾动作。巢由雄鸟选址并主筑，深杯状，外径12–24 cm，内径6.5–7 cm，高7–8.5 cm，由细枝、树皮、草根、叶及草茎构成，内衬草茎、苔藓等，距地0.3–5 m（多1–2 m），常置于具刺灌丛。雌鸟孵卵13–17天，雄鸟供食；雏鸟留巢13–16天，出巢后亲鸟继续喂约1月。卵3–7枚，多为4–6枚，底色乳白至赭红，密布红褐及灰斑，巴基斯坦个体多为粉白具淡褐斑，大小21–24 mm × 15.6–17.8 mm。巢常被大杜鹃寄生，哈萨克斯坦巴尔喀什地区寄生率14.5%；塔吉克斯坦繁殖成功率约47%。一龄即可繁殖。","identification":"与荒漠伯劳极似，区别在于本种眉纹更白、头顶栗红而非灰、下体更白洁；与红背伯劳相比，上体更沙褐，尾棕红，翼斑小，翼式不同。低地“karelini”型头顶偏灰，易混荒漠伯劳，但仍有较明显白眉及洁白领。雌鸟及幼鸟轴纹限于头侧及胸胁，尾色栗而不似荒漠伯劳的淡棕。","protection":"IUCN: LC（无危）。全球数量未量化，但估计未接近易危阈值，部分地区局部少见。多数国家受法律保护，部分地列为“濒危”。减少农药使用、保护半开放灌丛草地被认为是最有效保育措施；越冬地多个国家公园已涵盖本种。","distribution":"繁殖于哈萨克斯坦中部及东部，经土库曼至伊朗东北、东及南部，阿富汗、巴基斯坦（印度河西北）及中国新疆西北部；非繁殖期主要在阿拉伯半岛及东北非（自尼日利亚向东至坦桑尼亚东北），少量在西非（塞内加尔、冈比亚、毛里塔尼亚）。秋季迁徙主要向西南经伊拉克、伊朗至阿拉伯及非洲，春季沿相似路线返回，4月中旬过东北非；迷鸟可见于欧洲，甚至英国、荷兰、挪威。","other":"本种直至近年被归入荒漠伯劳，后因头顶颜色、上体色调、眉纹对比度、翼式、迁徙路线及换羽模式等差异被独立。提出的“karelini”型（锡尔河至土库曼）可能为与红背伯劳的渐渗杂交群体，有待深入研究。已记录与红背伯劳的野外杂交个体。"},{"name":"栗背伯劳","english_name":"Burmese Shrike","scientific_name":"Lanius collurioides","overview":"栗背伯劳（英文名：Burmese Shrike，学名：Lanius collurioides），是雀形目伯劳科伯劳属的鸟类。直译缅甸伯劳，最显著的特征为砖红色背部、深灰色冠部和宽阔的黑色面罩。分布于东南亚地区，包括印度、中南半岛以及中国的云南、贵州、广西、广东等地。该物种不常见，但不怯生。","appearance":"中等体型，体长19-21厘米，体重约26克。雄鸟具有黑色额部和面部面罩，石板灰色冠部至颈背，上体余部均匀的赤褐色；上翼深棕色，初级飞羽基部有明显的白色斑块；尾巴黑色，外侧尾羽白色；喉咙白色，下体白色略带淡黄色调，腹下部白色带黑色羽尖；虹膜暗红棕色。雌鸟相似但稍显暗淡，前额和鼻羽有白至淡黄色条纹，胸部可能有少许条纹。幼鸟似雌鸟，但面罩棕色，上体温暖的黄褐色，有黑色亚端条纹。","call":"鸣声多样而富有音乐感，包含各种音符和嘈杂的叽叽喳喳声。叫声为重复的干涩叽叽声：“tchchchchch。”","habits":"栖息于海拔1800米以下的低山丘陵和山脚平原地区的开阔次生疏林、林缘和灌丛中，也出现在沟谷、路旁和耕地边的小树及灌木上。主要以昆虫为食，尤其是直翅目昆虫，也会捕食蜥蜴和其他小型陆生脊椎动物。常单独或成对活动，多站在小树或灌木顶枝上，鸣声清脆多变，婉转动听。","breeding":"繁殖期为3月至6月，主要在4月至5月间产卵。巢为开放式的杯状，大小差异大，由树叶、草、羽毛和地衣制成，覆盖蜘蛛网，内衬细草，建于离地1.5-3.5米高的荆棘丛中。每窝产卵3-6枚，颜色变化大，多为浅绿色白色，有时为淡黄色，带有淡紫色和黄褐色斑点，主要集中在卵的大端。","identification":"与棕背伯劳相比，栗背伯劳尾部较短，且尾羽边缘为白色。","protection":"IUCN：LC（无危）","distribution":"分布于东南亚的低地至山区，包括缅甸、泰国、柬埔寨、老挝、越南、中国南部等。在非繁殖季节，广泛分布于低地的耕作区。","other":"该物种的迁徙模式复杂，部分群体为留鸟，部分则为迁徙或冬候鸟。"},{"name":"艾氏伯劳","english_name":"Emin's Shrike","scientific_name":"Lanius gubernator","overview":"艾氏伯劳（英文名：Emin's Shrike，学名：Lanius gubernator），是雀形目伯劳科伯劳属的小型鸟类，以其红棕色背部和臀部、灰色头部和颈部以及穿过眼睛的黑色面罩为显著特征。分布于非洲西部至中部，自马里南部和科特迪瓦北部至苏丹南部、乌干达北部和刚果民主共和国东北部。","appearance":"体型小，约14-15厘米长，体重约23.5克，是最小的Lanius属伯劳。雄鸟具黑色面部面罩，细白眉纹，淡灰色的冠至颈后和上背，与鲜红棕色的背部、肩部、臀部和上尾覆羽相接。翅膀深褐色，翼上的大覆羽、次级飞羽和三级飞羽有宽红棕色边缘，翼基部有白色斑块。尾巴深褐色，有浅红棕色斑点，外侧羽毛白色；腹部白色，下胸、腹和胁部呈淡红棕色至红棕黄色。雌鸟较雄鸟暗淡，黑色部位更偏褐色，灰色扩展到更多背部区域；与红背伯劳雌鸟的区别在于其均匀着色（无条纹）的下体。幼鸟有深褐色面部面罩，灰褐色顶冠、颈和上体有黑色条纹，白色喉部，下体白色带黑色新月状斑纹，但胁部和胸部为赭色。","call":"不是很鸣叫，但会发出一系列哨音和低沉、沙哑的音符。","habits":"栖息于湿润的草原灌木丛，通常成对或小群体出现，生活在草木覆盖的开阔林地和森林空地；也在退化的苏丹-几内亚草原、河岸森林、废弃的耕作地和村庄中发现。活动范围在海拔150-1500米之间。以昆虫为食，包括甲虫、螳螂和小型直翅目昆虫。独居或以4-5只的小群出现，偶尔加入混合觅食队伍。喜欢在树梢、围栏或电话线上公开停歇；大部分食物从地面捕获，但也观察到空中捕食和在树林中搜索。","breeding":"繁殖始于3-4月（雨季开始时），在刚果民主共和国，7月可见幼鸟；可能在苏丹也有3-4月繁殖。被描述为一夫一妻制，但疑似存在合作繁殖。无更多信息。","identification":"与迁徙的红背伯劳相似，但体型较小，臀部为红棕色而非灰色，下体为红棕黄色而非粉红色，喉咙颜色对比更明显，有白色的翼斑。","protection":"IUCN：LC（无危）","distribution":"分布于马里南部和科特迪瓦北部至苏丹南部、乌干达北部和刚果民主共和国东北部，形成一个间断的地带。","other":"此物种被记录在多个保护区，如科特迪瓦的Comoé和Mont Sangbé国家公园、尼日利亚的Kainji国家公园和Yankari国家公园、中非共和国的Manovo-Gounda St Floris国家公园、刚果民主共和国的Garamba国家公园以及乌干达的Kipedo Valley和Murchison Falls国家公园。"},{"name":"褐背伯劳","english_name":"Bay-backed Shrike","scientific_name":"Lanius vittatus","overview":"褐背伯劳（英文名：Bay-backed Shrike，学名：Lanius vittatus），是雀形目伯劳科伯劳属的鸟类。以鲜明的色彩和独特的外观著称。其显著特征包括黑色面罩、红褐色侧翼和背部，以及干净的白色喉部。广泛分布于南亚，偏好干燥开阔地带，常见于灌木丛生的半沙漠和栽培区。","appearance":"成年褐背伯劳体型较小，约17至19厘米长，体重18至26克。头部特征明显，具黑色前额和面部面罩，灰淡色冠部和颈背，上背部呈深灰色渐变为栗红色，翅膀上部黑色，有醒目的白色主翼斑。尾羽黑色，最外侧一对尾羽大部分为白色。下体白色，带有锈棕色到红棕色的洗染，两胁呈现更深的铁锈色。眼睛暗褐色，喙和腿均为黑色。雌雄相似，但部分雌鸟个体前额带较窄。幼鸟面罩棕色，较成鸟浅，上体灰棕色，头部和背部有黑和米色条纹，无白色翼斑，尾巴红棕色，下体颜色较淡，有深色条纹，主要出现在胸部和两胁。亚种nargianus体型较大，喙和翅较长，上体颜色较淡，不如其他亚种鲜艳。","call":"鸣唱为杂乱而悦耳的颤音，混杂着尖锐刺耳的颤音和模仿声。典型叫声包括尖锐的‘chur-r’或‘chee-urr’或‘keechuw’，警戒时发出快速的‘tzrrr’、‘krrrr-krrrr’、‘trrrr-trrr’或‘cha-a-a-a’。","habits":"栖息于各种干燥、灌木丛生的开阔地带，包括半沙漠、干河床、平原、山谷、丘陵和斜坡上的植被。在伊朗，可见于干燥的河床、平原和斜坡上的金合欢树（Acacia）、Prosopis和Ziziphus树林。在巴基斯坦和印度，繁殖于多样化的环境，从开放的灌木丛和荆棘树丛林到牧场和村落周边的栽培区。海拔高度从海平面到2000米，但在尼泊尔有观察到高达3965米的记录。","breeding":"繁殖季节为5月至7月在土库曼斯坦，3月至8月在巴基斯坦，印度西北部为4月至7月，中部为2月至9月，南部为2月至4月。通常每年繁殖两次，偶尔三次。一夫一妻制，全年领地意识强烈。巢建于荆棘灌木或小树的分叉处，高0.9至10米，大多位于1.5至4米之间，由草、羽毛、羊毛和纤维构成，外部常覆有地衣，内部铺垫柔软材料。每窝产3至5枚蛋，通常为4枚，蛋壳颜色从白色到绿色，带有棕色斑点和斑块。孵化期大约为14至15天，主要由雌鸟承担，期间雄鸟提供食物。雏鸟喂养期同样为14至15天。","identification":"与棕背伯劳相比，褐背伯劳具有更小的体型和较长的尾羽，以及独特的红褐色背部和黑色面罩。在识别时，注意其清晰的白色喉部和胸腹部的红棕色洗染。","protection":"IUCN：LC（无危）","distribution":"主要分布在阿富汗、巴基斯坦、尼泊尔和印度，最近记录显示在斯里兰卡也有发现。在土库曼斯坦和阿富汗局部地区出现，但信息稀少。","other":"尽管在许多保护区中有所分布，但其核心栖息地主要为栽培区，这些区域并未受到特别保护。"},{"name":"棕背伯劳","english_name":"Long-tailed Shrike","scientific_name":"Lanius schach","overview":"棕背伯劳（英文名：Long-tailed Shrike，学名：Lanius schach），是雀形目伯劳科伯劳属的鸟类。俗称: 桂来姆、黄伯劳，直译: 长尾伯劳，分布广泛，遍及亚洲，从远东至澳新界，包括小巽他群岛和新几内亚东部。成鸟具黑色贯眼纹或顶冠，尾长且黑，上体偏灰，下体偏棕。在中国东部沿海及南部，包括台湾和海南等省，为常见留鸟。","appearance":"体型中等，长度约20-25厘米，重量在33-53克之间。成鸟特征明显，额头和面部具黑色面具，延伸至颈部侧面，冠至背部暗灰色，背部和臀部橙色。翼黑，初级飞羽基部有显著白色斑块。尾巴黑色，末端白色，外侧尾羽边缘淡黄色。喉咙白色，下体白色，侧胸和两胁橙色。亚种差异主要体现在大小、尾长和头部及上体颜色。幼鸟较难与其他伯劳幼鸟区分，面部面具缩小，上体棕色，具细密的暗色纵纹，翅膀棕色，边缘橙黄色，初级飞羽尖端淡色，喉部白色，下体白色，带有橙黄色调和变化的暗色虫蚀状纹。","call":"发出尖锐刺耳的叫声，如'scha-scha-scha-schi'，'schach-schach'，'ketsch-ketsch...'或'tchert...'，以及二音节的'tch-ick'，'cha-dit'，'kerr-ick'。歌曲持续时间长达15分钟，包含悠扬的颤音和口哨声，模仿其他鸟类的鸣叫声。","habits":"偏好干燥开阔的生境，如灌木丛、轻度林地、农耕区、草原散生灌木、年轻种植园、花园和公园。在亚洲中部，常见于种植树木的耕作区附近。以昆虫为主食，偏好大型昆虫，如蚱蜢、甲虫，也捕食小型哺乳动物、蜥蜴、青蛙、螃蟹和小型鸟类。狩猎时从突出的栖木出击，地面捕食为主，也会空中捕食昆虫。具有领域性，繁殖期成对活动，非繁殖期多单独活动。","breeding":"繁殖期为3月至7月，主要在4月至5月，南方地区可能提前至2月，或延至6月至11月。巢为深而松散的杯形，由草茎、竹叶、嫩枝等材料构成，置于灌木或树上，高度1-8米。每窝产卵3-6枚，卵色变化大，孵化期12-14天，由雌鸟负责孵化，雄鸟负责警戒和喂食。雏鸟晚成性，留巢期13-14天，亲鸟共同育雏。","identification":"与灰背伯劳的区别在于背部羽色缺少橙色调，为深灰色。幼鸟难以与其他伯劳幼鸟区分。叫声和鸣唱特征可用于辨识。","protection":"IUCN：LC（无危）","distribution":"广泛分布于亚洲，从远东到澳新界，覆盖小巽他群岛和新几内亚东部。在中国东部沿海及南部省份常见。","other":"已知会寄生巢穴的鸟类包括大杜鹃、鹰大杜鹃和斑翅凤头鹃。"},{"name":"灰背伯劳","english_name":"Grey-backed Shrike","scientific_name":"Lanius tephronotus","overview":"灰背伯劳（英文名：Grey-backed Shrike，学名：Lanius tephronotus），是雀形目伯劳科伯劳属的鸟类。广泛分布于中国西南地区的鸟类。其显著特征包括黑色眼罩、暗灰色头部与背部、黑色翅膀和尾巴，以及近白色的下体与带有锈棕色的胸部。在南亚和东南亚地区常见，适应性强，能在森林边缘、农田和平原地带活动。","appearance":"灰背伯劳体长21-25厘米，体重39-54克，拥有较长的尾巴。成鸟具有明显的黑色下额和面部面具，从眼睛上方延伸到耳羽后方；头顶至颈部呈深灰色，背部可见小片红褐色斑块。翅膀黑色，翼覆羽、次级飞羽和三级飞羽边缘呈现淡红褐色至白色，有时可见微小的白色斑点位于初级飞羽基部（但常缺失）。尾巴为栗褐色，末端略带淡黄色，最外侧一对尾羽为浅棕色；喉咙和下体白色，胸部侧面和两胁为红褐色，尾下覆羽为灰褐色。虹膜深棕色，喙黑色，腿为暗黑色。雄雌相似，但幼鸟上部颜色更偏棕色，面部面具不明显，呈棕色而非黑色，下颌角质色，头顶有细条纹，上部和大部分下体有深棕色重条纹。拉胡尔亚种（lahulensis）比指名亚种体型更小，嘴更弱，整体颜色更淡，背部和臀部红褐色，主翼羽上的白色斑点通常较大且更显眼，尾巴有时为黑色而非棕色。","call":"灰背伯劳的鸣叫特征包括粗糙、类似呼吸的声音。领土叫声被描述为尖锐的“zzert-zzert…”，“tchert-tchert…”或“tzert-tzert…”；其鸣唱曲目还包括黄昏时或警报时发出的重复“ktcht-ktcht-ktcht”。繁殖季节的歌曲低调而富有音乐性，持续数分钟，模仿其他鸟类的叫声。其声音似乎与棕背伯劳相似。","habits":"灰背伯劳栖息于从平原到海拔4000米的山地疏林地区，尤其偏好农田和农舍附近。在繁殖季节，它们活跃于喜马拉雅山脉、中国中部的高海拔森林空地、高原草原和点缀着小树或相当大的灌木丛的山地牧场。在四川省（中国中部）的繁殖后栖息地，它们要么选择年轻开放的松树林，其中林间空地被灌木主导，要么选择海拔较高的牧场。在非繁殖地的山谷和平原，它们适应多种生境，包括花园和废弃的耕地。大多数个体在繁殖范围内较低海拔处越冬。西北亚种（lahulensis）似乎全年居住或下降到喜马拉雅山的山脚，而指名亚种要么进行海拔迁移，要么迁移到更南的非繁殖区域。","breeding":"繁殖期在印度为6月至7月，在中国南部（西藏）为4月至7月/8月（主要是5月至6月），在南西藏山区为5月底至7月初。可能在中国有两次繁殖，但缺乏确凿证据。灰背伯劳具有领地意识，全年维持领地。巢为大型、外观略凌乱的杯状结构，外部直径13-20厘米，高度约8.5厘米，主要由树枝和草制成，放置在小树或灌木上，距离地面约2米，可能位于孤立的树木、溪边灌木丛或一排树木中。每窝产4-6枚蛋，颜色为淡灰色，带有棕色或灰棕色斑点和斑块，以及众多的薰衣草标记。一项在南西藏进行的研究显示，每窝产3-5枚蛋；孵化期为15-18天，仅由雌鸟承担；幼鸟离巢期为14-15天；两性都参与喂养雏鸟；在45.8%的筑巢尝试中（n=24），至少有一只幼鸟成功离巢。","identification":"灰背伯劳与棕背伯劳共享部分分布区域，但体型明显较小，且背部缺乏橙色。与棕背伯劳相比，灰背伯劳在形态上有显著差异，尽管它们在地理分布上存在重叠，但没有确凿证据证明它们之间有杂交现象。拉胡尔亚种（lahulensis）比指名亚种更小，嘴更弱，颜色更淡，背部和臀部红褐色，主翼羽上的白色斑点通常更大且更明显，尾巴有时为黑色而非棕色。","protection":"IUCN：LC（无危）","distribution":"繁殖区包括欧亚大陆的喜马拉雅山脉和中国中部。非繁殖区覆盖东南亚。在中国大陆，分布于甘肃、宁夏、青海、陕西、四川、贵州、西藏和云南等地。","other":"灰背伯劳在中国西南地区分布广泛，数量众多，对控制农林害虫有一定作用。"},{"name":"灰顶伯劳","english_name":"Mountain Shrike","scientific_name":"Lanius validirostris","overview":"灰顶伯劳（英文名：Mountain Shrike，学名：Lanius validirostris），是雀形目伯劳科伯劳属的鸟类。分布于菲律宾的北部和南部山区。其最显著的特征是头部的灰色顶冠、黑色眼罩以及橙色的侧翼。该物种在菲律宾的热带山地森林和灌木丛中较为常见。","appearance":"灰顶伯劳体长20至22.5厘米，体重34至44.9克，拥有典型的伯劳体型，长尾和钩状喙。成鸟上半身呈灰色，翅膀和尾巴颜色较深，下半身白色，侧面橙色，眼部有黑色面罩。雌雄羽毛相似，但雌鸟体型略小。幼鸟的面罩为黑褐色，羽色较暗，下体灰白带红褐色条纹。","call":"鸣叫包括干燥的‘chit！’声和连续的摩擦警报声‘krr-krr-krr-krr-krr！’。歌唱类似柳莺的高音哨声。","habits":"栖息于海拔1200至2400米的热带山地橡树和松林开阔地带边缘、次生林地和草地。通常单独或成对出现，以昆虫为主食，尤其喜食硬壳甲虫。猎食方式为从树梢或灌木顶端的显眼位置俯冲捕捉猎物。","breeding":"繁殖季节不详，但观察到二月至六月间有成鸟喂养幼鸟的现象。可能为一夫一妻制，具有领域性。","identification":"与长尾伯劳相似，但常出现在更高海拔的森林区域，尾巴稍短，翼部无白色斑点。不同亚种在下体色彩上有差异。","protection":"IUCN：LC（无危），但在当前环境中数量稳定。","distribution":"分布于菲律宾北部和南部山区，包括吕宋岛和民都洛岛的热带山地环境。","other":"需要进行基础生物学研究和种群调查，以评估其分布和丰度，以及对栖息地退化的容忍度。"},{"name":"麦氏伯劳","english_name":"Mackinnon's Shrike","scientific_name":"Lanius mackinnoni","overview":"麦氏伯劳（英文名：Mackinnon's Shrike，学名：Lanius mackinnoni），是雀形目伯劳科伯劳属的鸟类。中等体型的伯劳科鸟类，主要分布于非洲中部热带湿润地区，包括尼日利亚东南部、喀麦隆至安哥拉西北部，刚果东北部和刚果民主共和国北部至肯尼亚西部和坦桑尼亚北部。该鸟以其灰黑色头部和背脊、白色眉纹、肩羽和黑翼著称，腹部通常为白色，有时带淡黄色调。","appearance":"麦氏伯劳体长约20厘米，具有相当长的尾羽。成年雄鸟头部和背脊呈灰黑色，拥有明显的白色眉纹，肩羽白色，翅膀黑色；尾巴黑色，边缘白色；腹部白色，偶尔泛黄。雌鸟相似，但侧腹有红褐色斑块。幼鸟为灰棕色，条纹明显。","call":"麦氏伯劳的鸣唱是一系列粗糙的‘chruu’叫声和密集多样的音符，类似莺类的鸣声，包括大量模仿其他鸟类的声音。其鸣唱还包括刺耳的哨声和延长的口哨。","habits":"麦氏伯劳栖息于森林边缘、开阔地带、次生林和灌木丛，高度从近海平面到山地2200米。它以昆虫为主食，如蚱蜢、甲虫、蝽象、飞蚁和蚂蚁，偶尔捕食小型脊椎动物如壁虎、青蛙和小鸟。狩猎时通常从高2-5米的显眼栖枝出发，从地面捕获猎物。","breeding":"繁殖季节在喀麦隆为9月至次年4月，其他地区观察到的繁殖活动在8月至次年4月之间，幼鸟喂养活动最迟至5月底（安哥拉）。东部地区繁殖期为2月至8月，与长期雨季同步。巢为大而开放的杯状，由干草、树皮碎片和植物茎组成，内部铺细纤维，置于1-3米高的荆棘灌木或小树上。每窝产卵2枚，有时3枚，卵色为浅黄色，带有黄色、紫色和灰色斑点。","identification":"与北方伯劳相比，麦氏伯劳的冠部和背部为灰色，没有翼上的白色标记。与其他戴黑色面罩、灰背的伯劳区别在于其翼上缺乏白色缺口。","protection":"IUCN：LC（无危）。麦氏伯劳分布广泛，局部地区常见，尽管在分布区东部较为罕见。由于其适应次生林和人类改造环境的能力，其数量趋势可能正在上升。","distribution":"非洲：从尼日利亚东南部的奥布杜高原和喀麦隆南部至安哥拉西北部，刚果东北部和刚果民主共和国北部至肯尼亚西部和坦桑尼亚北部。","other":"麦氏伯劳因Archibald Donald MacKinnon而得名，其种群数量被认为因附近栖息地退化而增加。"},{"name":"黑额伯劳","english_name":"Lesser Grey Shrike","scientific_name":"Lanius minor","overview":"黑额伯劳（英文名：Lesser Grey Shrike，学名：Lanius minor），是雀形目伯劳科伯劳属的鸟类。其显著特征为黑色前额和粉红色胸部与白色喉部的对比，体型中等，翼长，尾短圆，喙粗短。夏季繁殖于南欧、中欧及西亚，冬季迁徙至非洲南部。偏好干燥开阔低地，常在电线杆上栖息。","appearance":"雄性黑额伯劳的前额、面颊、耳羽及冠前部分为黑色，后冠至背部呈蓝灰色，臀部色浅，下体粉白带淡粉色。雌鸟相似但头部灰暗，腹部颜色更淡。幼鸟棕灰，上体淡褐色，下体乳白。成鸟长约19-23厘米，翼展宽大，尾短，喙厚实。","call":"领地叫声为一系列的“djejek-dschejek-dschijek...”、“kerrib-kerrib...”、“tschertscherb, tschertscherb...”或“tschilip-tschilip...”，展示飞行时发出。","habits":"栖息于开阔地带，散生树木和灌木丛，偏好阳光充足、较干燥的环境。主要以大型昆虫为食，如甲虫、蝴蝶、蛾类、蚱蜢等，偶尔捕食小型脊椎动物。狩猎时，从显眼的栖息处出击，偶尔悬停空中。","breeding":"繁殖期在5月至6月初，一窝产卵3-7枚，多为5-6枚，蛋色淡蓝绿，带橄榄棕色斑点，孵化期14-16天，雌鸟为主孵化，双亲喂养幼鸟，离巢期14-19天。","identification":"与西方灰伯劳和伊比利亚灰伯劳相比，黑额伯劳体型略小，翼长，头黑，无淡色眉纹，肩羽少白，下体粉红而非纯白。雌雄间差异不大。","protection":"IUCN：LC（无危）","distribution":"繁殖于南欧至俄罗斯南部，南部至叙利亚、伊拉克和阿富汗；越冬于非洲南部。","other":"自19世纪中期以来，欧洲种群数量下降明显，尤其是在北欧、西欧和中欧的部分国家，如比利时、卢森堡、德国、瑞士、捷克共和国和波兰等地已几乎绝迹。"},{"name":"呆头伯劳","english_name":"Loggerhead Shrike","scientific_name":"Lanius ludovicianus","overview":"呆头伯劳（英文名：Loggerhead Shrike，学名：Lanius ludovicianus），是雀形目伯劳科伯劳属的鸟类。以头大著称，因此得名。分布广泛，主要在开放地带，如草原、农田和灌木丛生的区域。以昆虫、小型哺乳动物和鸟类为食，有‘屠夫鸟’的绰号。","appearance":"体型中等，头部显著大，体长203.2-222.3毫米，翼展317.5-330.2毫米，尾长88.9-101.6毫米。上身灰色，面部有黑色面具，下身白至淡灰色，脚黑色。翅膀黑色，带有明显的白色斑点，尾巴黑色，边缘白色。喙短、黑且钩状，含有用于撕裂猎物的tomial齿。雌雄外观相似，但雄鸟稍大。","call":"鸣叫声多样，包括尖锐的哨音、颤音和粗哑的鸣叫，有时声音显得刺耳。","habits":"偏好开阔地带，如牧场、草地和有少量树木的环境。它们通常在树梢或电线杆上显眼的地方栖息，白天狩猎，以昆虫、蜘蛛、爬行动物、两栖动物、小型哺乳动物和小型鸟类为食。冬季，由于偏好昆虫和变温动物，可能会因食物稀缺而能量不足。","breeding":"繁殖季节开始于首次春季，雄鸟通过空中表演求偶。巢建在低至4米高的密集树木或灌木丛中，平均孵化期为16天，雌鸟通常在产下倒数第二个蛋后开始孵卵，导致异步孵化。幼鸟孵化后，由双亲共同喂养，平均离巢期约为19天。","identification":"与灰伯劳相似，但体型较小，上身颜色更深，面部面具覆盖整个眼睛，没有眼周白色。腰部颜色与上体一致，不像灰伯劳有白色腰部。","protection":"IUCN：NT（近危）","distribution":"繁殖区域主要在北美，包括加拿大南部、美国中部和墨西哥北部。非繁殖季节分布更为广泛，向南延伸至中美洲。","other":"自1960年代以来，其数量在北美大陆范围内显著下降，东部地区的减少尤为明显。"},{"name":"灰伯劳","english_name":"Northern Shrike","scientific_name":"Lanius borealis","overview":"灰伯劳（英文名：Northern Shrike，学名：Lanius borealis），是雀形目伯劳科伯劳属的鸟类。大型的伯劳科伯劳属鸟类，主要分布在北美洲和东北亚的开阔地带。成鸟具有浅灰色的上体，黑色眼罩，翼下可见白色斑点，下体呈淡灰色并带有模糊的条纹。幼鸟颜色较深，具更多条纹。分布于北美的北极森林及北极苔原边缘，冬季南迁至加拿大南部和美国北部。","appearance":"中型鸟类，体长23-25厘米，翼展30-35厘米，体重60-80克。头部较大，尾巴较长。成鸟上体灰色，下体白色，翅膀和尾巴上有黑白相间的对比图案，脸部有黑色眼罩，臀部白色。喙粗壮，带钩状，下颚基部冬季变为淡棕色。眼罩狭窄，通过眼眶延伸到耳羽区域，被白色的眉纹所边界。翅膀上有白色斑点，次级飞羽和内侧初级飞羽尖端有狭窄的白色。尾巴长而渐尖，中央尾羽黑色，向外逐渐变宽的白色尖端，最外侧尾羽大面积白色。雌雄相似，但雄鸟的棕色调较少，眼罩更深，翼和尾羽更黑，平均有更多的白色，喉咙更白，胸部的斑纹更稀疏。","call":"灰伯劳的叫声包括响亮的啸叫和一系列复杂的歌声，能够模仿其他鸟类的声音。虽然它们的歌声并不著名，但在冬末（二月至三月）尤其是在晴朗的日子里，两性都会唱歌。","habits":"栖息于开放的灌木林和柳树丛生的环境，冬季出现在沙丘、灌木田或农业区的篱笆行。单独活动，常在显眼的枯木或电线杆上栖息。在北美，可能与呆头伯劳在冬季重叠分布。以肉食为主，猎食小型哺乳动物和鸟类。飞行时有起伏，观察其翼上的白色斑点。","breeding":"繁殖季节，灰伯劳会在北极森林和苔原边缘的开阔地带筑巢。求偶、交配、产卵和孵化等繁殖行为在阿拉斯加的繁殖地有所研究。雌雄共同参与营巢，巢由树枝和草构成，位于灌木或低矮树木中。每窝产卵4-6枚，孵化期约18天，雏鸟由双亲共同喂养。","identification":"与呆头伯劳相比，灰伯劳体型略大，颜色更浅，眼罩更窄，特别是在眼眶处颜色较浅，鼻须白色，额头无黑色，眉纹更宽更明显，眼下方有白色新月形标记（呆头伯劳缺乏）。幼鸟颜色较深，有更广泛的条纹，眼罩不明显。在某些个体中，眼下方除几根羽毛外缺乏白色。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美的北极森林和北极苔原边缘，包括拉布拉多、魁北克至阿拉斯加西部。非繁殖季南迁至加拿大南部和美国北部，偶尔会抵达亚利桑那州、新墨西哥州、俄克拉荷马州、密苏里州、弗吉尼亚州和马里兰州。","other":"灰伯劳与西方灰伯劳在西古北界被认为是近缘种，但根据羽毛和mtDNA差异，自2017年起被视为独立物种。"},{"name":"西方灰伯劳","english_name":"Great Grey Shrike","scientific_name":"Lanius excubitor","overview":"西方灰伯劳（英文名：Great Grey Shrike，学名：Lanius excubitor），是雀形目伯劳科伯劳属的鸟类。俗名: 北寒露，直译: 大灰伯劳，大型伯劳科伯劳属的鸟类。主要分布在欧洲中部、亚洲北部，越冬于中亚、印度、非洲北部以及中国东北部至西北部地区。其特征为珍珠灰色的上体，带有黑色眼罩，白色的下体，以及明显的翼和尾部白色斑块。","appearance":"西方灰伯劳体长约22至26厘米，重约60至70克，雌雄外观相似，上体呈珍珠灰色，下体白色，脸颊和下巴白色，有深黑色眼罩延伸至耳羽，肩羽白色，翅膀黑色带白色翼斑，尾部黑色，末端尖锐，外侧尾羽有白色边缘。幼鸟全身泛灰褐色，上体有条纹，下体有模糊的棕色横纹。","call":"鸣唱包括短促悦耳的颤音和流利的口哨声，伴有流利的‘gargling’短语，通常串成重复的歌曲。","habits":"栖息于亚北极和温带气候下的开阔地带，有树木、灌木、篱笆和电线杆的地方。迁徙模式多样，部分种群会迁移到南欧和中东地区过冬。饮食以小型哺乳动物为主，如田鼠，也会捕食小鸟、鼩鼱、蜥蜴和两栖动物，以及大型昆虫。","breeding":"繁殖期从3月末至5月末，一窝产卵3至9枚，孵化期14至19天，幼鸟离巢前由双亲喂养，孵化至离巢期约为15至19天。","identification":"与呆头伯劳和楔尾伯劳相似，但可通过眼罩覆盖范围、翼部白色斑块、腰部颜色和尾型进行区分。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧洲北部、亚洲北部至中亚地区，冬季迁徙至南欧、中东、非洲北部以及中国东北部至西北部。","other":"西方灰伯劳在某些地区数量正在减少，主要受到农业集约化的影响。"},{"name":"伊比利亚灰伯劳","english_name":"Iberian Grey Shrike","scientific_name":"Lanius meridionalis","overview":"伊比利亚灰伯劳（英文名：Iberian Grey Shrike，学名：Lanius meridionalis），是雀形目伯劳科伯劳属的鸟类。与灰伯劳关系密切，但在共存区域不互相交配，因栖息地选择差异而分化。分布于法国南部和伊比利亚半岛，偏好干燥开阔地带。","appearance":"体长约24至25厘米，体重48至93克。雄鸟头部黑色面罩从眉纹至眼后延伸至耳羽，白色眉纹明显，上体深铅灰色，翼黑，翼基有小白斑，尾黑，外侧尾羽有白尖。雌鸟相似但颜色稍淡。幼鸟上体较成鸟灰淡，腹部淡粉色，面罩暗棕色。","call":"拥有丰富的叫声，包括重复的双音节‘kwi-rick’、金属质感的‘schryck’声、警报声‘kcha-kcha...’、‘djerki-djerki-djerki’以及各种颤音和模仿其他鸟类的声音。","habits":"栖息于干燥温暖的低地，遍布荆棘灌木丛的开放地带。以昆虫、小型爬行动物、哺乳动物和鸟类为食，偏好蟋蟀、蚱蜢、鼹鼠蟋蟀和粪金龟。狩猎时利用多种观察点，如灌木、铁丝网等，偶尔悬停捕食。冬季栖息地中的草本层占比增加。","breeding":"繁殖季自2月开始，单配制，领域性强。巢由两性共同建造，位于树或灌木枝叉处，高度通常不超过2米。每窝产2至7枚蛋，孵化期14至18天，幼鸟喂养期16至19天。首次繁殖年龄为一岁。","identification":"与灰伯劳相比，体型较小，上体颜色更深，翼上的白色斑块更小，翼长较短。雌雄在色彩上略有差异。","protection":"IUCN：VU（易危）","distribution":"繁殖于法国南部和伊比利亚半岛，非繁殖季节会迁至非洲西北部。","other":"自1970年代以来，其数量有所下降，主要威胁来自农业集约化和生境改变。"},{"name":"草原灰伯劳","english_name":"Steppe Grey Shrike","scientific_name":"Lanius pallidirostris","appearance":"草原灰伯劳体型较大，具有典型的伯劳科特征。羽毛色彩以灰色为主，嘴喙呈现淡色，这是其名称‘pallidirostris’（意为淡色喙）的由来。性别之间在外表上无显著差异。","call":"未提供鸣叫特征描述。","habits":"草原灰伯劳栖息于开阔地带，包括草原和半荒漠地区。它们在繁殖季节内有迁徙习性，具体迁徙路线与活动范围依赖于地理分布。食物主要包括昆虫和其他小型无脊椎动物。","breeding":"关于草原灰伯劳的繁殖习性，包括求偶、筑巢、交配、产卵、孵化和育雏等细节，现有资料未提供明确信息。","identification":"草原灰伯劳与西方灰伯劳其他亚种的区别在于其较淡的喙色。在野外辨识时，应注意这一特征以及其特定的地理分布。","protection":"IUCN：LC（无危）","distribution":"草原灰伯劳主要分布在中亚、中国北部的部分地区、伊朗、阿富汗和巴基斯坦。在中国大陆，其分布限于特定的生态区域。","other":"无额外重要信息提供。"},{"name":"楔尾伯劳","english_name":"Chinese Grey Shrike","scientific_name":"Lanius sphenocercus","overview":"楔尾伯劳（英文名：Chinese Grey Shrike，学名：Lanius sphenocercus），是雀形目伯劳科伯劳属的鸟类。俗名: 长尾灰伯劳。大型鸟类，体型超过30厘米，尾部呈明显的楔形，与灰伯劳在体型、尾形及翼斑颜色上有显著区别。分布广泛，见于中国、日本、朝鲜半岛、蒙古及俄罗斯远东地区。","appearance":"楔尾伯劳是一种体型大的灰色伯劳，身长可达31厘米，尾部长且楔形，尾部中央三根黑色尾羽尤为突出。上体灰色，下体白色，面部有黑色面罩，眼眉白色。翅膀和尾巴有明显的白色斑块，尤其在飞行中更为醒目。雌雄羽毛相似，幼鸟上体略带赭色，下体白色，腿色浅棕色。","call":"鸣叫包括粗糙的沙哑声和较为悦耳的流利音调，具体描述不详。","habits":"偏好开阔地带，如农田、草地、林缘和半荒漠疏林地带。冬季迁徙至中国东南部。以昆虫、小型脊椎动物如蜥蜴、小鸟和鼠类为食，会停在空中振翅捕食，或在突出的树枝、电线捕食，常见于农场和村庄附近。","breeding":"繁殖期为5月至7月，巢建于乔木或灌木上，距离地面2至4米。巢由树枝、草茎、兽毛、羽毛和植物纤维构成。每窝产卵5至6枚，卵呈淡青色带有灰褐色和灰色斑点。孵化期15至16天，雏鸟坐巢期约20天。幼鸟离巢后在亲鸟的照料下于巢区附近觅食。","identification":"与灰伯劳相比，楔尾伯劳体型更大，尾部更长且呈楔形，翼斑和腰部颜色亦有差异。在中国，楔尾伯劳分布更广，而灰伯劳仅限于较北方地区。","protection":"IUCN状态未知，未列入华盛顿公约(CITES)或中国国家重点保护野生动物名录。","distribution":"繁殖于蒙古东部、俄罗斯东南部、中国东北部和朝鲜半岛北部至中部。非繁殖季节迁徙至中国东南部。","other":"与青藏楔尾伯劳曾被视作同一物种的不同亚种，现已确认为独立物种。"},{"name":"灰背长尾伯劳","english_name":"Grey-backed Fiscal","scientific_name":"Lanius excubitoroides","overview":"灰背长尾伯劳（英文名：Grey-backed Fiscal，学名：Lanius excubitoroides），是雀形目伯劳科伯劳属的大型鸟类。体型健壮，尾巴细长，以灰、黑、白三色为主调。雄鸟全身下部纯白，雌鸟则可见暗褐色侧腹斑点。主要分布在非洲中部及东北部，包括干草原、灌木丛和有树木的草地。","appearance":"雄鸟成鸟头戴灰色冠羽，面颊至耳羽呈黑色，形成鲜明的面罩。背部至尾上覆羽为灰色，尾部基部白色，尾尖黑色。翅膀黑色，初级飞羽基部有醒目的白色斑块。雌鸟相似，但侧腹可见暗红褐色斑点。幼鸟头部和上体呈灰棕色，翼部和尾部为深棕色，具灰色条纹。","call":"群居时发出一系列不同的叫声，包括刺耳的音符、嘈杂的叽叽喳喳声和尖锐、刺耳的鸣叫。领地防卫时会发出金属质感的威胁叫声和类似二重唱的展示叫声。","habits":"栖息于灌木丛、有树的草地和开放的森林地带，偏好有中高树木的环境。常在树顶或树侧2-4米处停歇，俯瞰四周，主要在地面捕食。食物以大型昆虫为主，偶尔也捕食小型脊椎动物。通常群居，每群约20只，成员单独觅食。","breeding":"繁殖季节随雨季和昆虫丰富度而定，通常在雨季之后。一雄一雌组成繁殖对，其余群体成员担任辅助角色。巢由雌鸟建造，雄鸟提供材料，巢位于刺树1-12米高处，孵化期13-15天，雏鸟期约20天。","identification":"与其他黑面罩、灰背伯劳的区别在于黑色翼与面部面罩相连的线条，以及尾部基部的大白色斑块。","protection":"IUCN：LC（无危）","distribution":"广泛分布于非洲中部和东北部，包括布隆迪、喀麦隆、中非共和国等地，主要出现在低海拔的干草原和热带干旱低地草原。"},{"name":"东非长尾伯劳","english_name":"Long-tailed Fiscal","scientific_name":"Lanius cabanisi","overview":"东非长尾伯劳（英文名：Long-tailed Fiscal，学名：Lanius cabanisi），是雀形目伯劳科伯劳属的鸟类。以其长尾著称。分布于非洲南部索马里、肯尼亚东南部至坦桑尼亚中部，常见于开阔干燥生境如树少草原和灌木林地带。","appearance":"体长26-30厘米，雄鸟体重约70-80克，雌鸟略轻。头部、颈背深黑褐色，耳羽、眼周黑色，上体灰色，翼上有显著白色斑点，尾长而呈阶梯状。雄鸟下体纯白，雌鸟侧腹有小块赤褐色斑。幼鸟具褐色面罩，背部灰褐色，翼和尾暗色，腹部白色带暗斑。","call":"嘈杂，主叫声音为刺耳的金属般口哨声及嘈杂音，常由2-6只群体成员合唱，包括‘cha-cha-raa’和‘chit-er-row’的交替呼唤。","habits":"栖息于几乎无树的草原、灌木林和耕作区，海拔高度从海岸线至1600米。通常独居或小群活动，以昆虫为主食，也吃小型脊椎动物和果实，会利用红嘴牛文鸟的驱虫行为获取猎物。","breeding":"繁殖期在索马里为5-6月，肯尼亚为1-5月、8-10月及12月，坦桑尼亚为1月和6月。每对独立繁殖，筑巢于灌木或密树横枝，高2-3米处，巢呈大杯状，孵卵期13-14天，育雏期16-18天。","identification":"与领伯劳相比，具有灰色背部和更健壮的体型，长尾摆动明显。与其他伯劳区别在于体型更大，尾更长。","protection":"IUCN：LC（无危）","distribution":"繁殖区域：索马里南部、肯尼亚东南部（从维多利亚湖东岸至海岸）、坦桑尼亚东北部及南部至达累斯萨拉姆；另有孤立种群于Usanga Flats。","other":"在全球范围内并不受威胁，但在一些保护区如肯尼亚的内罗毕国家公园和坦桑尼亚的塔兰吉雷和米库米国家公园可见其踪迹。"},{"name":"肯尼亚伯劳","english_name":"Taita Fiscal","scientific_name":"Lanius dorsalis","overview":"肯尼亚伯劳（英文名：Taita Fiscal，学名：Lanius dorsalis），是雀形目伯劳科伯劳属的中型黑白灰相间的伯劳。主要分布于非洲东部，从苏丹东南部、埃塞俄比亚南部、索马里中部到坦桑尼亚东北部。其独特外观包括黑色头冠、灰背、白色‘V’字标记和白色臀部。","appearance":"雄鸟头部顶部和侧面、上背部为黑色，灰下背部，白色尾羽覆羽，肩羽明显白色；上翼黑色，翼根附近有小白色斑块；尾部黑色，外缘和尖端白色；喉部和下体纯白。雌鸟类似雄鸟，但有时侧翼可见小红棕色条纹，通常被闭合的翅膀遮掩。幼鸟上方主要为黑褐色，有细黑条纹，臀部淡黄色带暗条纹，翼羽暗色带淡黄色边缘和尖端，尾部棕黑色带白色边缘和尖端，下体淡白色。","call":"重复性的鸣唱包括短哨声、刺耳的嗡嗡声、空洞的声音和敲击音，常以升调模式呈现。也发出刺耳的‘churr’警报声。","habits":"栖息于干燥的灌木丛、金合欢（Acacia）林地和其他干燥开阔的林地，海拔从海平面至少到1600米。主要以昆虫，尤其是蚱蜢、甲虫、毛虫和蜘蛛为主食，也捕食小型脊椎动物，如啮齿动物、蜥蜴和小蛇，甚至可能掠夺红嘴奎利亚雀的雏鸟。从地面2-6米高的栖木捕猎，多数猎物在地面捕获；偶尔从植被中获取，也能捕获空中猎物。","breeding":"繁殖季节在索马里为五月，在坦桑尼亚为一月和六月；在肯尼亚为三月至六月和十二月至一月，与雨季重合。单配偶制，独巢，领地性。巢为由草和枝条制成的厚壁开放杯状，一般建在荆棘灌木或树上。每窝产3-4枚蛋，颜色为乳白色至浅灰色，大端有棕色和灰色斑点。","identification":"与其它黑头伯劳的区别在于灰背和翼部图案，如果观察得当，很容易辨认。雌鸟的红棕色侧腹通常被翅膀遮盖。","protection":"IUCN：LC（无危）","distribution":"分布于极端东南苏丹、埃塞俄比亚南部和索马里（除极南沿海地带）南至乌干达东北部（基德波谷南至莫罗托）、肯尼亚东北部和东部（缺失自马林迪南至坦桑尼亚边境的东南沿海地带）及坦桑尼亚东北部（塞伦盖蒂平原低地东至乞力马扎罗山）。"},{"name":"索马里伯劳","english_name":"Somali Fiscal","scientific_name":"Lanius somalicus","overview":"索马里伯劳（英文名：Somali Fiscal，学名：Lanius somalicus），是雀形目伯劳科伯劳属的小型黑白灰相间的伯劳。分布于非洲之角的索马里、埃塞俄比亚、吉布提以及肯尼亚的部分地区，偏好干燥的草原和灌木地带。","appearance":"体长约20至21厘米，体重48至58克。雄鸟头部、背部至肩羽黑色，背中部和尾上覆羽白色，翼上有显著的白色斑块，尾羽外侧几乎全白，喉部和腹部白色。雌鸟与雄鸟相似，但腋羽呈褐色。幼鸟面部有深褐色面罩，头顶及上体灰色带暗色细纹，尾羽暗褐色带白色边缘。","call":"重复性的叫声包括刮擦声，通常比肯尼亚伯劳的叫声更高更粗糙，常以递增模式发出。","habits":"栖息于非常干旱且植被稀疏的环境，如Acacia短草草原、开放的灌木丛和半沙漠地带。以大型节肢动物如甲虫、蝗虫和螳螂为主食，偶尔捕食小型鸟类和其他小型脊椎动物。在树梢或灌木上显眼处栖息，也会利用电线等人工高点。潜入地面捕猎，会将猎物插在棘刺上并储存。","breeding":"繁殖季节延长，通常在雨季，食物较为丰富的时期。巢筑于小灌木或棘树中心，离地1至2米，由荆棘枝条和丝质纤维材料构成。每窝产卵4枚，有时3枚，卵色多为奶油色，带有淡棕色斑点和灰色底纹。","identification":"与肯尼亚伯劳非常相似，但每翼有多处白色斑块，而非一处。叫声较高且粗糙。","protection":"IUCN：LC（无危）","distribution":"分布于非洲东南部苏丹、埃塞俄比亚（除北部和西部）、索马里（除西南部）和肯尼亚西北部（L Turkana盆地至Marsabit）。在索马里常见，埃塞俄比亚不常见至频繁，肯尼亚不常见且局部。在苏丹东南部南部的状况不确定，可能是罕见或记录不足。"},{"name":"北领伯劳","english_name":"Northern Fiscal","scientific_name":"Lanius humeralis","overview":"北领伯劳（英文名：Northern Fiscal，学名：Lanius humeralis），是雀形目伯劳科伯劳属的鸟类。广泛分布在非洲撒哈拉以南地区的伯劳科伯劳属鸟类，拥有黑白色的'西装领带'外观，如同穿着正式服装的税务官员，因而得名。其分布区域自埃塞俄比亚至南部非洲，包括安哥拉、刚果民主共和国东南部、赞比亚、马拉维和莫桑比克北部。","appearance":"北领伯劳是一种中大型的黑白相间的伯劳，体长21-23厘米，体重25-58克。头部、背部和肩部为黑色，翼底有白色斑点，尾羽外侧白色，尾端其余部分黑色。成年雄鸟的头部至背部黑色，肩部有明显的白色V形标记，雌鸟类似但两胁常带有锈色。幼鸟呈褐色，有密集的黑色条纹。雌雄差异主要体现在雌鸟下腹的锈色上。","call":"发出混合了清晰哨音、粗糙音符和模仿其他鸟类声音的复杂鸣唱，夹杂着嘶哑的刮擦声，以及三个低沉的嗡嗡声后跟四个双音哨声。","habits":"栖息于多种开放环境，包括湿润灌木丛、稀树草原、农田和草地。常见于有短草和零星灌木的开阔地带，如含金合欢的林地、半沙漠、海岸灌木丛、沼泽边缘的灌木丛，以及miombo灌木林。适应各种人工环境，如种植园边缘、农场、城市花园、公园以及沿公路的电话线和围栏。活动范围广泛，从近海平面到海拔3350米。","breeding":"主要在雨季繁殖，食物丰富时，繁殖期大多在2月至8月期间，筑巢由双方共同完成，通常建在小树或灌木上，高0.6至6米，有时高达15米。巢由各种材料构成，包括树枝、草、花头、苔藓、蜘蛛网、羽毛和人造材料，内部铺有细根、绒毛状植物下垂和细草穗。每窝产1-4枚（最多6枚）蛋，孵化期12-16.5天，通常为14-15天。雏鸟由母鸟照顾，双亲共同喂养，离巢期通常为17-21天。","identification":"与相似伯劳的区别在于背部全黑而非灰色，雌鸟两胁的锈色是一大辨识点。","protection":"IUCN：LC（无危）","distribution":"分布于非洲的埃塞俄比亚和撒哈拉以南非洲南部至安哥拉，刚果民主共和国东南部，赞比亚，马拉维和莫桑比克北部。","other":"北领伯劳在人类居住区附近数量增多，成为城市郊区甚至市中心的常见鸟类，密度可达5.4对/10公顷。"},{"name":"领伯劳","english_name":"Southern Fiscal","scientific_name":"Lanius collaris","overview":"领伯劳（英文名：Southern Fiscal，学名：Lanius collaris），是雀形目伯劳科伯劳属的鸟类。其别称'butcher bird'源自其独特的储食习性，即将猎物挂在荆棘上以备后用。广泛分布于南部非洲，自纳米比亚、安哥拉西南部直至莫桑比克南部、南非南部以及坦桑尼亚东北部、中部、西南部和马拉维北部。","appearance":"领伯劳是一种中等体型的黑白相间的伯劳，体长21-23厘米，体重25-58克。雄鸟头部至上背黑色，肩羽白色，背部灰色，翅膀黑色带白色斑点，尾巴黑色，最外侧一对尾羽几乎全白，下体灰白色。雌鸟通常较雄鸟暗淡，常带有锈色下胁。幼鸟面部有深褐色面罩，上体淡褐色，翅膀深褐色，下体淡白色，具灰色细纹。","call":"其叫声复杂，包含一系列类似伯劳的吱吱声，模仿其他鸟类的声音，以及尖锐的Dzzzttt-dzzzt-dzzzt警报声。","habits":"领伯劳栖息于开放地带，如草地、灌木丛、稀树草原，常见于有金合欢树的环境，也能适应半沙漠、沿海灌木丛、湿地边缘、米奥诺木（Brachystegia）灌木地，以及多种人工环境。海拔分布从海平面至3350米。主要以昆虫和小型脊椎动物为食，偶尔食用种子。狩猎时从1-10米高的醒目栖枝俯冲捕捉地面猎物。","breeding":"繁殖期多在雨季，食物丰富时期，如西非的2月至8月，东非的大多数月份。一夫一妻制，巢由两性共同建造，深度大，材料多样，包括树枝、草、叶状草本、苔藓、蜘蛛网、羽毛和人造物品，内部铺垫细腻。巢高0.6-6米，平均3米，位于小树或灌木中，有时在人造结构上。每窝产卵1-4枚，孵化期12-16.5天，雏鸟期17-21天。","identification":"与北领伯劳相比，南方伯劳下体更脏，呈灰白色。雌鸟具有明显的锈色下胁斑块，雄鸟缺乏这一特征。","protection":"IUCN：LC（无危）","distribution":"分布于南部非洲，包括纳米比亚、安哥拉西南部至莫桑比克南部、南非南部，以及坦桑尼亚东北部、中部、西南部和马拉维北部。","other":"由于城市化和开发，领伯劳数量有所增加，特别是在东非的城市郊区和市中心，密度可达5.4对/10公顷。"},{"name":"圣多美伯劳","english_name":"Sao Tome Fiscal","scientific_name":"Lanius newtoni","overview":"圣多美伯劳（英文名：Sao Tome Fiscal，学名：Lanius newtoni），是雀形目伯劳科伯劳属的鸟类，是圣多美岛上唯一的本地伯劳，以黑色上体、翼上的显著白色条纹和黄色下体为特征。其分布局限于圣多美岛，为极危物种。","appearance":"该鸟体长约19至21厘米，具长而渐尖的尾巴。头部顶部和侧面为黑色，上体黑亮，肩部黄褐色，翼上覆羽黑亮，三级飞羽末端明显白色，主羽基部可能带有小块白色斑点。尾羽黑色，外侧三对尾羽边缘向尖端逐渐变白。喉咙和下体白色，但在某些活体上呈淡黄色或泛黄。虹膜深棕色，喙和腿为深棕色或黑色。雌雄外观相似，幼鸟信息有限，但据观察上体棕色带细条纹，下体橙黄色，喙角棕色。","call":"其鸣唱为连续的‘teeeew’声，每秒一次，持续约30至60秒，亦会发出典型的伯劳式刺耳‘ker-ker-ker’叫声。","habits":"栖息于圣多美岛的原始低地和中海拔雨林中，偏好封闭树冠下的环境，极少出现在开阔地带。以昆虫为食，如小甲虫和飞行昆虫，似乎不捕食小型脊椎动物。活动于森林中层到下层，较难观察。","breeding":"关于繁殖信息有限，已知会在12月至1月间唱歌，雄鸟在11月至12月处于繁殖状态，雌鸟在相同月份仍可见幼鸟痕迹。推测为一夫一妻制。","identification":"与非常相似的领伯劳区别在于下体偏黄（若存在）、尾部白色较少、喙较小，通常缺乏主羽白色斑点。","protection":"IUCN：CR（极危）","distribution":"仅分布于非洲大西洋的圣多美岛，主要在低地和中海拔的原始森林中，最近的观察记录来自河流附近和高达1400米的山脊。","other":"自1888年首次发现后，曾失踪超过60年，直到1990年再次被发现。当前总人口估计少于50只，受森林破坏和可能的外来掠食者威胁。"},{"name":"林䳭伯劳","english_name":"Woodchat Shrike","scientific_name":"Lanius senator","overview":"林䳭伯劳（英文名：Woodchat Shrike，学名：Lanius senator），是雀形目伯劳科伯劳属的鸟类。伯劳科伯劳属的鸟类，以其红棕色冠和颈后而著称。体型略大于红背伯劳，偏好开阔林地和散布树木的环境，如果园，尤其在有裸露或沙质地表时。分布于南欧、中东及西北非，越冬于热带非洲。","appearance":"雄性林䳭伯劳身长17-19厘米，重21-59克，具黑色面罩至耳羽，红棕色冠至背部，翼上有白色斑块，尾羽基部有白色尖端，下体白色。雌鸟较暗淡，白眉纹延伸至眼。幼鸟上体呈混合的棕白色条纹，下体白色，有灰色弧形斑纹。不同亚种在颜色和斑纹上有细微差异。","call":"发出一系列尖锐干燥的叫声，鸣唱混合了各种声音元素，包括颤音、哨声、刺耳叫声和模仿其他鸟类的声音。","habits":"栖息于半开放地带，如稀树草原、旧果园、橄榄树林、花园、公园或有大荆棘的树篱。在非洲越冬地，偏好干燥的金合欢树丛。迁徙性鸟类，冬季迁往赤道以北的撒哈拉以南非洲。主要捕食大型昆虫，偶尔捕食小型脊椎动物。","breeding":"繁殖期为5月初至6月末，一窝通常产4-8枚蛋，平均孵化期14-16天。雌鸟孵化，雄鸟喂食。雏鸟由双亲照料，离巢后父母继续喂养约6周。在南欧、北非和以色列常见二次繁殖。","identification":"与同属物种相比，林䳭伯劳具有独特的黑面具和红棕色冠。亚种间存在差异，如badius亚种的翼斑较小。识别时注意其红棕色头部和黑白相间的背部。","protection":"IUCN：NT（近危）","distribution":"繁殖于南欧至中东和西北非，越冬于中非。","other":"自19世纪中期以来，欧洲范围内种群持续下降，尤其是在德国、波兰等国家。农业集约化、森林化和大型火灾为主要威胁。"},{"name":"云斑伯劳","english_name":"Masked Shrike","scientific_name":"Lanius nubicus","overview":"云斑伯劳（英文名：Masked Shrike，学名：Lanius nubicus），是雀形目伯劳科伯劳属的鸟类。候鸟。繁殖季节主要在东南欧和地中海东部，包括希腊东部、保加利亚、土耳其南部至以色列和伊朗西部。冬季迁徙至非洲中部和东北部。为土耳其、塞浦路斯、以色列和叙利亚的常见物种，以黑体白额、白喉、白腹、白臀、白肩斑和浅棕色两胁的雄鸟成鸟及偏红棕体色的雌鸟成鸟为显著特征。","appearance":"成年雄性云斑伯劳拥有黑色的上体，白色额头、喉咙、腹部、臀部和肩部的大斑点，以及浅棕色的两侧。雌鸟相似，但体色更偏向红棕色，上体为暗灰至棕色。幼鸟外观显著不同，全身覆盖着虎纹般的斑点，上体呈灰褐色，下体为淡色并带有条纹，头部至臀部有深色的条纹，翅膀除白色主羽外为棕色。","call":"发出典型的短促、尖锐的叫声，包括重复的“tsr”、“tzr”或“shek”音节，有时结合清晰的哨声。受惊时，能发出类似‘krrrr’的颤音。其歌声柔和，包含颤音和丰富的鸣唱，有时类似Hippolais鸣禽的歌唱元素。","habits":"偏好开阔的林地，带有灌木丛和一些大型树木。通常不在非常开阔或靠近人类居住区的地方活动，但在果园、有老树的耕地、高篱笆的小田地、葡萄园、花园和杨树林中可见。低地和丘陵地带为主，偶尔在海拔高达2000米的山区发现。迁徙期间，会在各种生境停留，包括花园和度假胜地。","breeding":"繁殖期从4月初至6月中旬，高峰在5月的前半月。一窝通常产4-6枚蛋，由雌鸟孵化14-16天。雏鸟在巢中停留18-20天，之后依赖父母喂养至少3-4周。首次繁殖年龄为第一年。","identification":"与林䳭伯劳最相似，但云斑伯劳体型较小，尾部长，上体颜色更暗，头上有白色标记，而林䳭伯劳头部为黑色，颈背锈色，臀部白色。","protection":"IUCN：LC（无危）","distribution":"繁殖区分布在东南欧至地中海东部，包括希腊东部、保加利亚、土耳其南部至以色列和伊朗西部。冬季迁徙至非洲中部和东北部。","other":"在迁徙期间，云斑伯劳可能形成小规模聚集，有时超过100只聚集在一处。"},{"name":"青藏楔尾伯劳","english_name":"Giant Grey Shrike","scientific_name":"Lanius giganteus","overview":"青藏楔尾伯劳（英文名：Giant Grey Shrike，学名：Lanius giganteus），是雀形目伯劳科伯劳属的大型伯劳，以暗灰色上体、白色下体、黑色面罩及翼上的白色斑块为显著特征。广泛分布于中国中部的高海拔开阔地带，冬季会下降至较低海拔。善于利用高而显眼的栖木。","appearance":"体型大，尾部长而呈楔形，背部深灰色，腹部白色，脸部有黑色面罩，翼上有白色斑块，尾部可见白色。雄雌羽毛相似，幼鸟上体赭色，有淡色条纹，下体白色带有赭色痕迹。成鸟长度约29-31厘米，重量在87.2-100克之间。","call":"发出刺耳的沙哑声和较为悦耳、流畅的鸣叫声。","habits":"栖息于高海拔的开阔环境，如矮小的杜鹃花丛，冬季会向低海拔迁移。偏好在高处的显眼位置停歇。食性广泛，可能包括昆虫和其他小型动物。","identification":"与楔尾伯劳相似，但体型更大，背部颜色更深，无白色眉纹。与西方灰伯劳和灰伯劳相比，尾部更长，臀部灰色。","protection":"IUCN状态未知。","distribution":"分布于中国中部，包括欧亚大陆的特定区域。","other":"曾被认为是中华灰伯劳的亚种，2021年被国际鸟类联盟（IOC）认定为独立物种。"},{"name":"白腰林鵙","english_name":"Northern White-crowned Shrike","scientific_name":"Eurocephalus ruppelli","overview":"白腰林鵙（英文名：Northern White-crowned Shrike，学名：Eurocephalus ruppelli），是雀形目伯劳科白顶林鵙属的鸟类。以其独特的白冠和白臀著称。分布于东非的干燥荆棘灌丛、半沙漠和开阔的金合欢树林，从南苏丹东南部、埃塞俄比亚南部到坦桑尼亚中部。纪念德国自然学家和探险家Eduard Rüppell。","appearance":"体长19-23厘米，体重42-58克，体态丰满。成鸟具白色额、冠和颈背，黑色眼纹，背部棕色，腰部及尾上覆羽白色，上翼和尾深棕色；下体白色，两胁淡棕色。幼鸟暗于成鸟，具暗棕色冠羽，侧面白色，灰色胸部，有模糊的条纹形成窄带，腹部白色。喙黑色，腿灰暗或棕色。雌雄相似，但幼鸟头部颜色较浅，冠羽白色。","call":"发出尖锐、高音的叫声，包括‘kek-kek’、‘chee-chee’等短促的嘶哑声和叽叽喳喳声，有时会发出快速的一系列音符组成的较长乐句。","habits":"栖息于干燥的灌木丛和半沙漠地带，常以小群形式活动，最多可达12只。从显眼的栖木上猎食，主要捕食大型昆虫，偶尔也会从大型哺乳动物背上取食，类似牛椋鸟，也会食用落在地上的果实。","breeding":"繁殖季节在不同地区有所不同，从3月至12月不等。可能实行一夫一妻制，有合作繁殖的嫌疑。巢由草和蜘蛛网构成，位于离地4-6米高的水平树叉上，每次产2-4枚带有灰色、紫色或棕色斑点的白色或淡紫色蛋。","identification":"与白冠伯劳相似，但分布范围不重叠。可通过其独特的白冠和白臀以及叫声进行辨认。","protection":"IUCN：LC（无危）","distribution":"非洲：从南苏丹东南部、埃塞俄比亚中部和索马里中部至坦桑尼亚中部。","other":"已知在红嘴奎利亚雀群中遭受毒害，出现在多个保护区，包括埃塞俄比亚的阿瓦什国家公园，肯尼亚的布法罗斯普林斯国家保护区和沙巴野生动物保护区。"},{"name":"白顶林鵙","english_name":"Southern White-crowned Shrike","scientific_name":"Eurocephalus anguitimens","overview":"白顶林鵙（英文名：Southern White-crowned Shrike，学名：Eurocephalus anguitimens），是雀形目伯劳科白顶林鵙属的鸟类。体型较大的林鵙，主要分布于安哥拉、博茨瓦纳、纳米比亚、南非和津巴布韦等地，栖息于亚热带或热带的干燥森林及干燥稀树草原。","appearance":"成年白顶林鵙长约24厘米，重51至70克。头部粗壮，尾巴相对较短。头顶、前额白色，眼周黑色线条穿过眼睛下方并连接到耳羽上的大块烟黑色斑块，喉部后侧和颈侧白色，耳羽和颈侧有时呈烟褐色。上体灰棕色，翼暗棕色，飞羽边缘和尖端淡色，覆羽较主翼羽略浅。尾羽深棕色，新鲜时边缘和尖端极窄淡色。下体从下巴到腹部中央偏白，胸上部微带淡黄色，下腹和腹侧及肛周灰棕色，尾下覆羽灰棕色。虹膜深棕色，喙黑色，腿深棕色。雌雄相似，幼鸟类似成鸟，但头冠灰色带斑纹，边缘和尖端淡黄褐色，下体灰棕色，喙色较浅，腿灰色。","call":"具有多种叫声，最典型的是一种独特的、尖锐的、类似鸻鸟的“kleeew-keeuw”叫声。","habits":"栖息于开阔的阔叶林木和河岸林木，偏好干旱灌木丛中的较高树木。常在开阔的林地和公园中发现，需有较高的落叶刺树和稀疏的地面植被。常见于大河流附近，在干旱地区，西部范围内最常见于沿河灌木丛，但在半沙漠荆棘灌木丛中也能见到。偏好低洼干燥地带；在南非东北部，不在高草原出现，但在灌木丛和低地地区广泛分布。有时在村庄花园中发现。以节肢动物为主食，尤其偏好大型猎物如蝗虫、毛虫、黑蜂、白蚁和甲虫；也会食用千足虫和小果实。从离地3至6米的栖息处扫描周围环境；大多数猎物在地上捕获。在树干、枝条和树叶上觅食；有时倒挂以检查可能的觅食点；也会在树叶间振翅驱赶猎物。空中捕食常见。单独、成对或小群体活动；系统地穿越林地。","breeding":"繁殖期从9月至次年2月，主要集中在10月至12月，似乎为单窝产。一夫一妻制。合作且领土性，单一繁殖对偶尔得到帮手的协助；合作繁殖程度各异，有时是单独一对，有时多达4至5个帮手；观察到繁殖雄鸟忽视寻求交配的帮手，但发现双倍正常大小的蛋窝（可能是两个雌鸟在同一个巢中产卵）表明可能存在额外配偶交配和/或群内寄生。巢由双方成员建造，有时得到一两个帮手的辅助，工作持续3至4周；巢是一个整洁、坚固、垂直壁面的杯状巢，直径约12.5厘米，高约7.5厘米，由细黄草茎制成，偶尔使用毛发和羽毛衬里，外部覆盖均匀的蛛网，赋予巢光滑的银灰色表面，与苔藓覆盖的树枝相匹配；通常位于4至6米高的金合欢树侧枝上，偶尔在落叶树（如Brachystegia）上。窝卵数2至6枚，通常3至4枚，偶尔较大的窝卵数（如10枚）可能是两个雌鸟的产物，蛋壳白色，有灰色和棕色斑点和斑块主要集中在大端；孵化由繁殖雌鸟承担，有时短暂时间由帮手代替，孵化期约20天；雏鸟期报告为18至20天；离巢雏鸟由所有群体成员喂养。","identification":"与白腰林鵙相比，白顶林鵙的头顶更明显地呈现白色，而北方种头顶可能更灰暗。","protection":"IUCN：LC（无危）","distribution":"非洲中部，包括安哥拉、博茨瓦纳、莫桑比克、纳米比亚、南非和津巴布韦。"},{"name":"棕眉鵙雀","english_name":"Rufous-browed Peppershrike","scientific_name":"Cyclarhis gujanensis","overview":"棕眉鵙雀（英文名：Rufous-browed Peppershrike，学名：Cyclarhis gujanensis），是雀形目莺雀科鵙雀属的鸟类。分布广泛，常见于中美至南美的热带与亚热带林地边缘、森林边缘及部分高树种植园。其显著特征为厚实的浅色喙，锈色的眉毛和粉色腿脚。","appearance":"体型较大的鵙雀，全长约14-16厘米，体重22-35克。头顶至颈侧为中灰色，耳羽处色深，有狭窄的栗棕色眉纹延伸至眼周；背部、翼上覆羽橄榄绿，至主翼羽转为暗橄榄灰；尾巴橄榄绿；下颏灰白，喉部至胸部柠檬黄，腹部灰，尾下覆羽及腹侧逐渐变为灰白色或淡黄色；虹膜红、橙或橙黄色；喙银灰色；腿脚粉红色。雌雄相似。幼鸟面部标记较模糊，虹膜褐色。各地亚种在颜色深浅、下体颜色及某些特征上有细微差异。","call":"歌声为一连串5-7个旋律优美的颤音，类似盐鸟（Saltator）的鸣唱，有时被描述为“Do you wash every week?”的节奏，会重复同一乐句几分钟后变换。叫声是一系列3-8个响亮的滑哨声，首二声最响，随后声音依次降低。报警声为尖锐的责骂声和高音鼻音。幼鸟叫声为连续的响亮‘wick’声。","habits":"杂食性，以昆虫（如甲虫、蜘蛛）、茧、毛虫、果实为主食，偶尔也会捕食小型蛙类、蜥蜴、蛇、蝙蝠、小鸟及其蛋和雏鸟。行动迟缓，主要在树冠层觅食，偶尔加入混群觅食。通常成对出现，伴侣间可能相隔较远；经常跟随混合物种的觅食群。","breeding":"筑巢期在哥斯达黎加为3月至7月，巴拿马为7月，委内瑞拉为5月，特立尼达岛为6月至9月、11月、1月和2月，厄瓜多尔西南部为2月至3月。巢为薄壁半球形杯状，由草、苔藓和植物纤维制成，常建于树的侧枝叉上，高度较高。每窝产卵2-3枚，蛋壳呈粉白带棕色斑点或污渍；雏鸟由双亲共同喂养。","identification":"与其他鵙雀属物种的区别在于其厚实的喙、锈色的眉毛和粉红色的腿脚。亚种之间在颜色深浅、下体颜色及某些特征上有细微差异，例如ochrocephala亚种有更短的锈色眉毛和微带棕色的冠羽。","protection":"IUCN：LC（无危）；普遍常见于广阔的分布范围内，能适应部分生境改变（如荫蔽咖啡种植园），只要保留足够的树木或灌木覆盖。近来在巴拿马东部和阿根廷北部的分布有所扩展。","distribution":"分布于中美洲至南美洲，包括墨西哥、特立尼达岛、阿根廷和乌拉圭等地。","other":"已确认22个亚种，各亚种在颜色和特征上存在地理变异。"},{"name":"黑嘴鵙雀","english_name":"Black-billed Peppershrike","scientific_name":"Cyclarhis nigrirostris","overview":"黑嘴鵙雀（英文名：Black-billed Peppershrike，学名：Cyclarhis nigrirostris），是雀形目莺雀科鵙雀属的中型鸟类，分布于南美洲的哥伦比亚和厄瓜多尔安第斯山脉地区。其最显著的特征是拥有粗壮且钩状的黑色喙，橄榄色的体羽和灰色的喉部及腹部。","appearance":"体长约15至16.5厘米，体重29.6至33.1克。头部前冠呈暗灰色，上颚和眼周区域为深栗色，耳羽黄色带绿。背部和翅膀上部为暗橄榄绿色，初级飞羽和次级飞羽灰暗，翼展时显橄榄绿。尾巴暗淡的橄榄褐色，喉部和下颌为灰色，胸侧带有淡黄色形成细长的黄胸带，下胸部和腹部呈近白色，大腿部分灰色略带黄色调。虹膜黄色或灰绿色，喙黑色带灰，下颚基部较浅。腿灰色或蓝灰色。两性相似，幼鸟特征未详述。","call":"其鸣唱持续而响亮，通常从隐蔽的树冠位置发出一系列清脆的哨音，歌声丰富且旋律优美，有时被描述为‘come right here right now’，重音落在倒数第二个词上，与灰蓝粗嘴雀的歌声极为相似。","habits":"栖息于潮湿和湿润的森林环境中，包括云雾林和森林边缘，海拔高度介于1600至2700米之间，通常低于2400米。避免开阔地带和灌木丛生区。食物以节肢动物为主，通过在树冠至中间层的树叶和枝梢上搜寻猎物，行动谨慎地沿枝条移动并捕捉食物。单独或成对活动，常加入混合物种群。","breeding":"繁殖季节在哥伦比亚安第斯山脉的5月至7月，以及10月，但具体繁殖习性信息有限。假设其筑巢习惯与棕眉鵙雀类似，后者巢穴建于离地面七英尺高的树木中，由苔藓构成。","identification":"与更为常见的棕眉鵙雀相比，黑嘴鵙雀具有更薄的红褐色眉纹、橄榄色的颈部和头盖，以及尖端为黑色的喙，这些都是重要的识别特征。","protection":"IUCN：LC（无危）；在相对有限的分布范围内普遍数量不多。在厄瓜多尔南部的分布边界尚不确定。","distribution":"分布在哥伦比亚和厄瓜多尔的安第斯山脉，繁殖区域与非繁殖区域相同。","other":"该物种对栖息地改变的容忍度远低于棕眉鵙雀，不会出现在受干扰的生境中。"},{"name":"栗胁鵙雀","english_name":"Chestnut-sided Shrike-Vireo","scientific_name":"Vireolanius melitophrys","overview":"栗胁鵙雀（英文名：Chestnut-sided Shrike-Vireo，学名：Vireolanius melitophrys），是雀形目莺雀科绿鵙雀属的鸟类。有时称为蜜眉鵙雀，可能为整个莺雀科体型最大的成员。广泛分布于亚热带和热带湿润山地森林，其地理范围从墨西哥中部的Jalisco和San Luis Potosí向南延伸至危地马拉南部。","appearance":"体长16.5至18厘米，平均体重约34.7克，是鵙雀科中体型较大的物种之一。雄鸟头部呈现石板灰色的冠和颈背，金色眼眉，黑色眼纹，白色脸颊，细黑的颊纹，以及白色的喉部。胸带为醒目的栗色，其余下体为白色，两胁为栗色，逐渐变淡至下腹。雌鸟的色彩较雄鸟暗淡，胸带颜色减弱。幼鸟比成鸟更暗淡，面部图案不明显，头顶呈褐色，下体为浅粉色至肉桂色，无明显的胸带。","call":"雄鸟的歌声为单一音节，持续时间不到一秒，起始为短暂的上升呻吟声，随后迅速变为下降的哀鸣哨音，可单独发出或连续重复，两次鸣叫间歇约1.2秒。叫声包括由两性发出的低沉、沙哑的联系叫声，较长的嘎吱声，以及对抗入侵者的‘myaaaah’威胁叫声。","habits":"栖息于混合林区，包括从湿润到半干旱的各种环境，通常与松树（Pinus）和橡树（Quercus）及其他落叶乔木相伴，林下常有茂密的灌木和藤蔓。食物主要为节肢动物，如甲虫、蚂蚁、毛虫、蚱蜢和蜘蛛，也会摄食一些植物物质，如山楂果实和种子。觅食时，会从栖息处寻找猎物，然后跳跃或飞向附近的另一个栖息处，大多数猎物是从树叶上捕获。","breeding":"繁殖期在墨西哥的Morelos州记录到两个巢穴，雌鸟在4月末有孵化斑，卵管内无壳蛋，6月中旬（Oaxaca州）处于繁殖状态，7月初有刚离巢的幼鸟。巢由两性共同建造，初期以雄鸟为主，后期雌鸟更多参与，建巢过程需20至25天。巢为悬挂杯状，由丝状苔藓编织，内衬细草、纤维和松针，外部装饰有蜘蛛卵囊，挂在树枝侧叉处，巢杯悬挂在叉下方。","identification":"与同属其他物种相比，栗胁鵙雀具有独特的栗色侧翼和胸部带，以及明亮的绿色背部和白色的下体。雄鸟和雌鸟在色彩上有显著差异，雌鸟的色彩较淡，胸带颜色较弱。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，从墨西哥中部至危地马拉，主要栖息于海拔1200至3500米的山区森林。","other":"该物种在部分保护区中存在，例如危地马拉的火山火国家公园。"},{"name":"绿鵙雀","english_name":"Green Shrike-Vireo","scientific_name":"Vireolanius pulchellus","overview":"绿鵙雀（英文名：Green Shrike-Vireo，学名：Vireolanius pulchellus），是雀形目莺雀科绿鵙雀属的鸟类。体型较大、颜色鲜明的鸟类，主要分布于中美洲，从墨西哥东南部到巴拿马中部的热带雨林中。绿鵙雀以其独特的草绿色外观著称，尤其是醒目的黄色喉部和某些亚种中的蓝色冠羽。","appearance":"绿鵙雀整体呈亮绿色，上体较暗，下体黄绿色，腹部颜色更深。头部两侧和上部均为鲜亮绿色，冠羽和颈背部分为天蓝色，但在下方通常不明显。下颌和喉部为黄色，其余下体为淡黄绿色。幼鸟头部和上体橄榄绿，带有淡黄色眉纹和髭纹，翼上有模糊的淡黄色斑点，喉部和下体为暗黄色。喙部上方黑色，下方灰色，靠近基部颜色较深。脚趾和跗蹠为中性灰色。","habits":"绿鵙雀偏爱湿润的常绿森林环境，能在一定程度上适应栖息地的变化和退化，通常以成对的形式出现，偶尔加入混合物种的觅食群。它们主要在中层至高层觅食，以昆虫和其他节肢动物以及小果实为食。","identification":"绿鵙雀与蓝冠氯鳩相似，后者具有更亮的黄色下体和较短的喙。与金眉绿雀相比，后者主要出现在更高海拔，拥有明亮的黄色下体、绿色喉部和宽而短的喙。雄鸟的金眉绿雀还有显著的黄色眼眉。与黄眉鵙雀的区别在于分布区域不重叠，黄眉鵙雀具有明亮的黄色眼眉、下眼处的小黄斑和蓝色冠羽。","distribution":"绿鵙雀的分布范围覆盖了中美洲，从墨西哥东南部一直延伸到巴拿马中部，主要栖息于热带雨林地带。"},{"name":"黄眉鵙雀","english_name":"Yellow-browed Shrike-Vireo","scientific_name":"Vireolanius eximius","overview":"黄眉鵙雀（英文名：Yellow-browed Shrike-Vireo，学名：Vireolanius eximius），是雀形目莺雀科绿鵙雀属的鸟类。该鸟以其鲜明的黄绿色上体和独特的黄色眉毛、喉咙著称，腹部颜色渐淡至更浅的黄色。其蓝色的冠羽和厚实的钩状喙是识别特征。在中美洲和南美洲的巴拿马东部、哥伦比亚北部及委内瑞拉西北部的低地森林中可发现它们的身影。","appearance":"黄眉鵙雀具有醒目的外观，上体为亮丽的黄绿色，头部有显著的黄色眉毛和喉咙，腹部颜色较淡，呈柔和的黄色。它们拥有蓝色的冠羽和粗壮的喙，喙尖带有轻微的钩状，这是鵙雀科鸟类的典型特征。这种鸟没有其他物种能与其厚重的喙和鲜亮的绿色相结合的特点相媲美。","call":"这种鸟的鸣唱包含了几声下降的哨音，形成其特有的歌声。","habits":"黄眉鵙雀通常单独或成对出现在树冠层，偶尔加入混合物种的鸟群中。它们偏好在未受干扰的低地森林中活动，有时也会在树木间缓慢移动。","breeding":"关于黄眉鵙雀的繁殖行为的具体信息较为有限，但一般认为它们在低地森林中的适宜环境中繁殖。","identification":"黄眉鵙雀的蓝冠、厚重的喙和鲜明的黄绿色体色是与其他鸟类区别的关键特征。","protection":"IUCN：LC（无危）。尽管在分布范围内总体上并不普遍，但黄眉鵙雀在全球范围内并未面临严重威胁。","distribution":"该物种主要分布在中美洲的巴拿马东部、南美洲的哥伦比亚北部和委内瑞拉西北部的低地森林中。"},{"name":"灰顶鵙雀","english_name":"Slaty-capped Shrike-Vireo","scientific_name":"Vireolanius leucotis","overview":"灰顶鵙雀（英文名：Slaty-capped Shrike-Vireo，学名：Vireolanius leucotis），是雀形目莺雀科绿鵙雀属的鸟类。大型且引人注目的鸟类。分布于南美洲北部，从低地至亚热带森林，高达约1,800米。其独特的灰黄头部图案和绿色眼睛使其在众多鸟类中脱颖而出。","appearance":"体长14–15厘米，体重21.5–30克。冠部和颈背蓝灰色，额部、眉纹和眼下的新月形区域明亮黄色，脸颊区黑灰色；宽阔的眼纹和颊纹深灰蓝色，中间区域暗白色；上体亮橄榄绿色；初级飞羽和次级飞羽暗黑灰色，外侧羽缘橄榄绿色（闭合翅膀时形成亮斑），尾巴橄榄绿色；下体柠檬黄色，腹部柠檬黄色，两胁较淡的黄绿色，尾下覆羽柠檬黄色；虹膜淡绿色或鲜绿色；喙上部黑色，下部淡灰色或铅蓝色；腿铅蓝色或淡灰色。雌雄相似，幼鸟未详述。有两个亚种，simplex亚种额头有浅绿色带，背部较绿带灰，颈背更淡，颊纹前端绿色，耳羽淡灰色；bolivianus亚种额头和眉纹上方有强烈的黑边。","call":"持续发出单调重复的短音“tyeer”或“eear”，带有下降效果，每2秒发出大约1个音符，连续数分钟。叫声为短促的‘whit’，还有单声哨音‘wheeuw’。","habits":"栖息于潮湿森林的树冠层，包括苔藓森林和森林边缘，海拔250至1500米。通常以一对或三到四只的小群体出现，偶尔多达七只，经常与混种群鸟一起，且常是群鸟中的领头鸟。以节肢动物为主食，包括昆虫和草蜢，偏好绿色毛虫。觅食时动作从容，沿树枝跳跃，主要在森林的树冠或中层活动，偶尔在较低处；偶尔会倒挂于树叶，但主要从底面捕食猎物。","breeding":"关于繁殖信息未知。","identification":"mikettae亚种与其他亚种相比，缺少白色的耳羽区域，下体和眉纹的黄色更深更鲜艳，胸部两侧的橄榄绿色更加明显和广泛，腿部颜色为黄色或粉红色。","protection":"IUCN：LC（无危）","distribution":"分布于哥伦比亚西部（从上圣胡安河以南）和厄瓜多尔西部（南至阿苏艾西北部）。在南美洲亚马逊雨林区域广泛分布。"},{"name":"灰蓝莺雀","english_name":"Slaty Vireo","scientific_name":"Vireo brevipennis","overview":"灰蓝莺雀（英文名：Slaty Vireo，学名：Vireo brevipennis），是雀形目莺雀科绿鹃属的鸟类。独特的莺雀科鸟类，仅分布于墨西哥南部的高海拔林地。其最显著的特征是灰蓝色的羽毛，白色的眼睛和雪白的喉部，以及绿色的羽缘。","appearance":"灰蓝莺雀是一种小型的莺雀，体长约11.5至12厘米。其头部和上体部分呈橄榄绿色，侧头、背部、臀部和上尾覆羽为蓝灰色，略带橄榄绿。翼羽和尾羽为暗黑色或蓝灰色，边缘带有更鲜艳的黄绿色。下巴纯白，喉咙、胸部和侧腹为蓝灰色，腹部中心和尾下覆羽为白色。雌雄相似，幼鸟较暗淡，具暗色眼睛，有淡淡的柠檬色翼斑。","habits":"灰蓝莺雀栖息于刷木丛生的山地和丘陵地带，通常保持在植被较低的位置，尾巴微翘，以果实和昆虫为食。它们不加入混群，行动迟缓。","breeding":"关于繁殖的信息有限，据观察，灰蓝莺雀建造典型的杯状巢，每窝产卵三枚。","identification":"灰蓝莺雀的灰绿色和蓝灰色羽毛，以及醒目的白色眼睛，在其地理范围内无类似物种。","protection":"IUCN：LC（无危）","distribution":"主要分布于墨西哥南部的高海拔区域。"},{"name":"白眼莺雀","english_name":"White-eyed Vireo","scientific_name":"Vireo griseus","overview":"白眼莺雀（英文名：White-eyed Vireo，学名：Vireo griseus），是雀形目莺雀科绿鹃属的小型鸣禽，以其独特的黄眼眶和灰头形成鲜明对比而闻名。主要分布在北美东部至墨西哥东部、加勒比地区，冬季向北中美洲和加勒比海迁移。在密集的灌木丛、森林边缘和茂密的荆棘丛中更为常见，通常通过其复杂多变的歌声被发现。","appearance":"体型小，总长度约107-130毫米。上体呈灰绿色或橄榄绿色，带黄色调；颈部更显灰色。腹部近白色，包括喉咙，两侧和两胁呈黄色。翼下覆羽灰绿色，带有黄色。翅膀和尾巴灰褐色，边缘黄至橄榄色；翅膀上有2条白色到淡黄色的翼带。眼睛周围有宽阔的黄色条纹，延伸自上喙基部环绕过眼睛。成鸟虹膜白色，有时有棕色斑点；幼鸟虹膜棕色，直至孵化年份约11月转为白色。腿蓝灰色；喙黑亮，有时边缘黄色；上喙尖端向下弯曲。","call":"白眼莺雀的叫声为快速混合的音符，开始和结束时有尖锐的‘chick’声。","habits":"栖息于废弃农田、过度生长的牧场、旧田地、森林边缘、二次生长林和溪边灌木丛中。在佛罗里达州，也会出现在红树林中。偏好密集的植被，通常隐藏在树冠层下方。以昆虫为主食，尤其是毛虫。","breeding":"在低矮的纠结灌木丛中筑巢，接近地面。巢由杂草、树叶、草、树皮或任意废弃物构成，呈整洁的杯状，用蜘蛛网固定在树枝分叉处。每次产3-5枚暗斑白蛋，由双亲共同孵化，孵化期12-16天。幼鸟在孵化后9-11天离巢。","identification":"与贝氏莺雀相比，白眼莺雀体型更大，具有明亮的黄色眼眶，且虹膜为白色而非深色。与厚嘴莺雀的区别在于后者喙更大，整体更重，且虹膜非白色。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美东部，从新英格兰西部至密苏里北部，南至得克萨斯和佛罗里达，以及墨西哥东部、中美洲北部、古巴和巴哈马群岛。美国墨西哥湾沿岸和南部地区的种群全年留居，大多数北美的白眼莺雀冬季向南迁徙。"},{"name":"厚嘴莺雀","english_name":"Thick-billed Vireo","scientific_name":"Vireo crassirostris","overview":"厚嘴莺雀（英文名：Thick-billed Vireo，学名：Vireo crassirostris），是雀形目莺雀科绿鹃属的小型鸟类，主要分布于西印度群岛，包括巴哈马、开曼群岛、特克斯和凯科斯群岛、海地的托图加岛及古巴沿海小岛。在北美，偶尔会出现在佛罗里达南部。其显著特征为厚实的喙部、灰橄榄色的头部和背部以及淡黄色的眼圈。该物种在繁殖季节活跃于灌木丛和热带丛林中。","appearance":"厚嘴莺雀长约14厘米，头部和背部呈现灰橄榄色，腹部颜色偏黄白色。翅膀和尾巴颜色较深，每侧翅膀上有两条明显的白色翼带。眼睛周围有暗色虹膜，两性外观相似，最显著的特点是喙部较为粗厚，眼上方有一圈黄色的眼环。","call":"厚嘴莺雀的鸣唱是一连串快速而多变的六至七个音符组成的乐句，以尖锐的‘chick’声开始和结束，音质略显粗糙，与白眼莺雀的鸣声类似但更加刺耳。","habits":"厚嘴莺雀偏好栖息于灌木丛和热带丛林的密集覆盖区域，其饮食几乎完全由昆虫构成。它们在繁殖季节会在树叉或灌木枝上搭建草编的杯状巢穴。","breeding":"繁殖期间，厚嘴莺雀会在树或灌木的分叉处搭建草编的杯状巢穴，每次产卵2-3枚，卵呈白色带有深色斑点。雄鸟和雌鸟共同参与孵卵过程。","identification":"与白眼莺雀相比，厚嘴莺雀的喙部更粗，背部颜色更偏向灰橄榄色，腹部颜色一致，眼圈为黄色而非白色。此外，它们的鸣叫声更为粗糙。","protection":"IUCN：LC（无危）","distribution":"主要分布在西印度群岛，包括巴哈马、开曼群岛、特克斯和凯科斯群岛、海地的托图加岛及古巴沿海小岛。偶尔出现在美国佛罗里达州南部。","other":"在Providencia岛的亚种V. c. approximans有时被归类为红树莺雀的亚种或单独作为一个物种，即普岛莺雀。"},{"name":"红树莺雀","english_name":"Mangrove Vireo","scientific_name":"Vireo pallens","overview":"红树莺雀（英文名：Mangrove Vireo，学名：Vireo pallens），是雀形目莺雀科绿鹃属的鸟类。体小（11–12厘米），羽色分黄、灰两型，分布于太平洋沿岸墨西哥西北部至哥斯达黎加西北部、加勒比海沿岸墨西哥尤卡坦半岛至尼加拉瓜及多个离岸岛屿，共8个亚种。太平洋种群专栖红树林，加勒比种群兼居灌丛、次生林缘等低地生境。","appearance":"成鸟上体暗褐微绿，飞羽深灰，初级飞羽外缘黄绿，中覆羽与大覆羽端缘黄白，形成两道明显的翼斑；尾羽深灰外缘带绿；额至后头色同背，眼先与眉纹淡黄至浅褐；颏黄白，喉与胸浅灰，腹部及胁微黄；虹膜稻草褐至污白，变化大；上嘴暗黑，下嘴较淡；脚灰蓝。两性同色。幼鸟似成鸟，面部条纹稍模糊。不同亚种间羽色浓淡、体型大小有异：加勒比种群具黄、灰二色型；太平洋种群羽色单一。","call":"歌声多变：哥斯达黎加发出沙哑“jee-wee-wee-wee”或带齿音的“chewy-chewy-chewy”；墨西哥为3–12个（多为4–6个）带金属质感的双音节音符；湾岛亚种angulensis发出一连串嗡嗡、啁啾与婉转；普罗维登西亚亚种approximans仅作短促“chatter”。另有鼻音斥责声及拖长“j-weehr”哀鸣。","habits":"留鸟，全年固守领地。太平洋种群专栖稠密红树林（尤以幼龄红茄苳为主）；加勒比种群利用红树林、灌丛、次生林缘、过耕地及林缘，伯利兹离岸小岛尤其以人心果林为主。冬季尤卡坦半岛与越冬白眼莺雀同域，但后者偏好较高植被。多在植被中低层单独或成对觅食，偶与混群；以蜘蛛、小甲虫、叶蝉等昆虫为主，兼食少量果实（如橄榄科种子）。","breeding":"繁殖信息稀少，仅记录3巢，均在伯利兹4–6月。唯一详述的巢（亚种semiflavus）为深厚椭圆形杯巢，由树皮条、草、苔藓、棉絮纤维以蛛丝及植物绒粘合，内衬松针，置于活栎树水平叉枝上约1 m处；巢内3枚白色卵，钝端密布巧克力色斑，5月30日见成鸟孵卵，后巢遭捕食。另两巢卵数分别为3枚与2枚。","identification":"与白眼莺雀外形及鸣声最近似，但白眼莺雀具明显白色虹膜及更鲜明的头纹。红树莺雀亚种辨识要点：paluster体型较大，下体黄色更深；semiflavus上体亮绿，下体鲜黄；ochraceus虹膜暗黄；salvini体型小，羽色较淡，下体黄、上体橄榄绿；angulensis面颊带褐污斑，背部淡橄榄具褐污；nicoyensis羽色最浅，喉腹近白，虹膜淡黄褐或白；approximans胸带黄色，嘴较大且基部宽；pallens背部较暗，下体灰黄。加勒比亚种具黄、灰两种色型，太平洋亚种羽色单一。","protection":"IUCN: LC（无危）。整体不属全球受胁物种，在适栖地尚属常见。","distribution":"繁殖区：太平洋岸自墨西哥西南部索诺拉州沿海至纳亚里特州，及南墨西哥瓦哈卡州南部沿海至哥斯达黎加西北部尼科亚湾；加勒比岸自尤卡坦半岛至尼加拉瓜。离岸岛屿包括洪都拉斯湾群岛（罗阿坦岛等）及普罗维登西亚岛（地理靠近尼加拉瓜，行政属哥伦比亚）。非繁殖区：全年留居，未见迁徙记录。","other":"分类史复杂，亚种approximans曾被归入厚嘴莺雀。最新研究建议太平洋亚种群、加勒比亚种群及approximans各可能代表独立种，尚需进一步研究。"},{"name":"普岛莺雀","english_name":"Providencia Vireo","scientific_name":"Vireo approximans","overview":"普岛莺雀（英文名：Providencia Vireo，学名：Vireo approximans），是雀形目莺雀科绿鹃属的鸟类。是中美洲特有种，仅见于哥伦比亚的普罗维登西亚岛与墨西哥的圣卡塔利娜岛。其生存环境面临威胁，主要栖息于亚热带或热带湿润低地森林及山地森林。","appearance":"具体外形特征资料不详，但作为Vireo属的一员，通常具有厚实的喙部，身体大小适中，羽毛色彩多样，可能随季节和年龄有变化。","call":"鸣叫特征资料不详。","habits":"生活在亚热带或热带湿润的低地和山地森林，也可能适应于种植园和严重退化的前森林环境。生活习性的详细信息有待进一步研究。","breeding":"生长繁殖的详细信息缺乏报道。","identification":"与其他Vireo属物种的区别辨识要点未详，可能通过特定的体型、颜色模式或鸣叫声音来区分。","protection":"IUCN：NT（近危）","distribution":"分布于中美洲的哥伦比亚普罗维登西亚岛和墨西哥圣卡塔利娜岛。","other":"有时被视作厚嘴莺雀的一个亚种，但目前作为独立物种被认可。现为红树莺雀亚种。"},{"name":"科岛莺雀","english_name":"Cozumel Vireo","scientific_name":"Vireo bairdi","overview":"科岛莺雀（英文名：Cozumel Vireo，学名：Vireo bairdi），是雀形目莺雀科绿鹃属的鸟类。仅分布于墨西哥科苏梅尔岛，一个位于尤卡坦半岛东北部的小岛。其独特的粉褐色羽色和可爱的面部特征，包括眼上方的白色斑块，使其在外表上独树一帜。近年来，由于外来蟒蛇的捕食，其数量有所下降。","appearance":"科岛莺雀体型小巧，长度介于11.5至12.5厘米之间，体重在11.2至14.6克间。头部冠羽呈深栗棕色，眼周有明显的白色环带，形成独特的‘眼镜’外观。上体为浅栗棕色，翅膀边缘略显橄榄黄色，两道显著的翼纹使它在闭合翅膀时更为醒目。下体颜色偏白，胸侧为栗棕色或肉桂棕色，腹部为淡白色，虹膜为棕色，喙呈暗粉色，腿色则为铅蓝色或蓝粉色。雌雄同形同色，幼鸟较成鸟色泽更淡，胸部侧面为暗棕色，虹膜颜色更深。","call":"其鸣唱由一系列3到10个鼻音组成，与白眼莺雀的歌声相似。叫声则快速而尖锐，类似鹪鹩科的责骂声。","habits":"科岛莺雀栖息于低矮的灌木林地、废弃的农田、次生林和落叶林中的灌丛地带。它们通常行动迟缓，偏好在植被的中下层觅食，食物种类未知。此物种为留鸟，全年居住在同一区域。","breeding":"繁殖期间，它们会建造类似于其他莺雀的巢穴，悬挂在小树的分叉枝条上，用植物纤维、蜘蛛丝和腐叶编织，装饰有苔藓、树皮和细根，内衬以细草碎片。每窝产2至3枚蛋，一枚测量尺寸为20.2毫米×14.4毫米。孵化期大约14天，雏鸟离巢时间为11至12天。繁殖活动发生在每年的5月至7月间。","identification":"科岛莺雀的识别特征在于其独特的粉褐色羽色、白色的翼纹和眼周斑块，以及与白眼莺雀相似的鸣唱。在科苏梅尔岛上，无相似物种与其混淆。","protection":"IUCN：NT（近危）","distribution":"科岛莺雀仅分布于中美洲墨西哥的科苏梅尔岛，一个靠近尤卡坦半岛东北部的岛屿。","other":"尽管全球分布范围狭小，但科岛莺雀在某些地区较为常见，能适应次生环境。然而，由于飓风可能带来的栖息地破坏，其种群状况需持续关注。"},{"name":"圣岛莺雀","english_name":"San Andres Vireo","scientific_name":"Vireo caribaeus","overview":"圣岛莺雀（英文名：San Andres Vireo，学名：Vireo caribaeus），是雀形目莺雀科绿鹃属的鸟类。仅分布于中美洲的哥伦比亚圣安德烈斯岛，一个位于加勒比海的岛屿，其范围极小（约17平方公里），IUCN将其列为易危状态。该鸟种具有典型的莺雀特征，黄色的颊部和显著的白色翼纹是最容易识别的特征。","appearance":"圣岛莺雀体长约12厘米，上体呈橄榄绿色，具两道白色翼带。下体白色，略带淡黄色。喙较长，直而细，喙基上方有一条淡黄色眉纹。虹膜灰褐色。性别之间无明显差异。幼鸟拥有蓬松的体羽，裸露部位颜色较深，虹膜比成鸟更暗。","call":"鸣声包括一系列的‘chuck-a’音，重复的刺耳‘dzu-wheet’声，以及连续的‘zhe-zhe-juuu’声。","habits":"圣岛莺雀活跃于灌木丛和红树林中，主要在地面附近和中等高度捕食昆虫。它们似乎能容忍一定程度的栖息地改变，但由于农业开发和岛上人口增长，正面临生存威胁。","breeding":"具体繁殖信息不详，但已知巢穴面临来自本地物种如Mangrove Cuckoos和Tropical Mockingbirds的捕食风险。如果紫辉牛鹂成功入侵圣安德烈斯岛，巢穴捕食的风险将进一步增加。","identification":"圣岛莺雀在其小范围内分布独特，最明显的辨识特征是黄色颊部和白色翼带。","protection":"IUCN：VU（易危）","distribution":"繁殖区域：中美洲哥伦比亚的圣安德烈斯岛。","other":"目前关于该物种的 molt 策略研究有限，初步观察显示雏鸟至成鸟的换羽过程可能为部分至不完全换羽，涉及次级飞羽和初级飞羽的替换。"},{"name":"牙买加莺雀","english_name":"Jamaican Vireo","scientific_name":"Vireo modestus","overview":"牙买加莺雀（英文名：Jamaican Vireo，学名：Vireo modestus），是雀形目莺雀科绿鹃属的鸟类。分布广泛，常见于多种林地生境，是岛上树林中最普遍且容易发现的鸟类之一。拥有丰富的鸣唱曲目，多达十种不同的歌曲，初听可能令人困惑。牙买加莺雀的特征包括淡色的眼睛、小而淡色的喙，以及明显的翼斑，这有助于将其与山莺雀区分开来。","appearance":"牙买加莺雀体型较为丰满，体长约12.5厘米，整体呈灰橄榄色，翼斑形成鲜明对比。头部、颈部和上体为绿色至灰橄榄色，下体颜色较浅，腹面和侧面呈淡绿色橄榄色。翼羽暗淡，但翼斑由宽大的黄白色尖端形成，与周围环境形成对比。喙为灰色，基部较浅，脚趾为灰蓝色，趾垫为黄色橙色。","call":"其鸣唱包括一系列独特的音节，如“chi-wee, chi-wee, chi-wee, chi-wee, you”、“chi-wuh, chi-wuh, chi-wuh, zha”和“Wee-wee-zhrr”。叫声包括单独或连续的“jip”声，以及尖锐上扬的“zhweee”。","habits":"生活在木林地带的灌丛中，活跃于密集的植被中寻找昆虫。偏好不修剪的林地，避开红树林和缺乏茂密下层植被的整洁林地。通常全天几乎持续鸣唱，使其更常被听到而非看到。","breeding":"关于其繁殖行为的具体细节未详述，但一般而言，莺雀科的繁殖习性包括营巢、交配、产卵和育雏。","identification":"与山莺雀相比，牙买加莺雀具有淡色眼睛、小而淡色的喙和明显的翼斑。与白眼莺雀、山莺雀、黑髭莺雀和红眼莺雀的区别在于大小、翼斑的存在与否、喙的颜色以及下体颜色。","protection":"IUCN：LC（无危）","distribution":"仅限于牙买加岛，广泛分布于岛上的各种森林环境中，包括亚热带或热带干燥森林、湿润低地森林、湿润山地森林以及严重退化的前森林。","other":"牙买加莺雀在冬季偶尔可见到稀有的白眼莺雀，但两者在外观上有明显区别。"},{"name":"古巴莺雀","english_name":"Cuban Vireo","scientific_name":"Vireo gundlachii","overview":"古巴莺雀（英文名：Cuban Vireo，学名：Vireo gundlachii），是雀形目莺雀科绿鹃属的鸟类。特有于古巴，常见于干燥森林、低地湿润森林、干旱灌木丛及退化森林地带。其特定学名是为了纪念古巴著名动物学家Juan Gundlach。","appearance":"古巴莺雀体型小巧，行动缓慢，偏好森林边缘的灌木丛和矮树丛。它通常以成对出现，偶尔会加入到混杂着莺类和其他莺雀的群落中。其独特之处在于眼周的外观，由眼后方的白色新月形状和眼前方淡黄色斑点共同营造出的“鼓眼”效果。此外，其喙部粗壮，翼带不明显，眼色暗红。相较于相似的厚嘴莺雀，后者具有明显的翼带、眼前方的黄色斑点以及颜色更深的眼睛。","call":"古巴莺雀的鸣唱声为‘chweee-ch-byuuu’，首音上滑，尾音下滑。其叫声还包括一种刺耳的‘zzzhhh’。","habits":"古巴莺雀栖息于干湿交替的森林环境中，包括干燥森林、低地湿润森林、干旱灌木丛以及退化森林。它们的活动范围广泛，能够适应多种生境。","identification":"与厚嘴莺雀相比，古巴莺雀的翼带较弱，眼前方的斑点为淡黄色，而厚嘴莺雀的眼前方斑点为黄色，眼睛颜色更暗，翼带更为明显。","protection":"IUCN：LC（无危）","distribution":"古巴莺雀仅分布于古巴，包括干燥森林、低地湿润森林、干旱灌木丛以及退化森林地带。"},{"name":"波多黎各莺雀","english_name":"Puerto Rican Vireo","scientific_name":"Vireo latimeri","overview":"波多黎各莺雀（英文名：Puerto Rican Vireo，学名：Vireo latimeri），是雀形目莺雀科绿鹃属的小型鸟类。分布于中美洲的波多黎各岛，常见于西部和中部地区的森林地带，包括红树林沼泽和阴凉咖啡种植园。其特征为头部和胸部呈灰褐色，腹部带有黄色调，缺乏明显的翼带，但在眉纹上方有一条轻微的白色条纹。","appearance":"成年波多黎各莺雀体型小（约11-12克），拥有结实且略带钩状的喙。头部和颈背呈现淡灰褐色，与温暖的橄榄棕色背部、翅膀和尾巴形成对比。下巴、喉咙和胸脯为灰白色，逐渐过渡至较浅的黄色腹部，侧面颜色最为鲜艳。两性均具有不完整的白眼环，以及较为明显的白色上眶线。虹膜呈棕色。幼鸟可能展现出模糊的黄褐色翼带，这是成鸟所不具备的。","call":"波多黎各莺雀的鸣唱包括“chuwee-chuweech-you”、“Chewee-wit-weee”或类似变奏，叫声则有哀怨的“zhe, zhe, zhe…”和强调的“djuh”。","habits":"它们栖息于各种森林类型，从干燥的沿海灌木丛到湿润的山地森林，甚至偶尔出现在红树林。以三到四个音节的独特歌声被发现，活动范围广泛。","breeding":"关于繁殖习性的具体信息有限，但已知它们面临外来哺乳动物如鼠类和野猫的捕食威胁，以及由近期登陆岛屿的紫辉牛鹂寄生其巢穴的风险。","identification":"与之相似的白眼莺雀具有显著的白色翼带和眼睛前方的黄色斑点。加勒比拟霸鹟有白色的翼带，通常站立直立或飞扑捕食昆虫。黑髭莺雀无眼环，面部图案鲜明，与波多黎各莺雀易于区分。","protection":"IUCN：LC（无危）","distribution":"波多黎各莺雀主要分布在中美洲的波多黎各岛上，包括其西部和中部地区。","other":"尽管全球不被视为受威胁，但波多黎各莺雀对引入的哺乳动物捕食和寄生牛鹂的巢寄生现象表现出脆弱性。"},{"name":"扁嘴莺雀","english_name":"Flat-billed Vireo","scientific_name":"Vireo nanus","overview":"扁嘴莺雀（英文名：Flat-billed Vireo，学名：Vireo nanus），是雀形目莺雀科绿鹃属的鸟类，相对不起眼的物种，偏好干燥的灌木丛和灌木地，常见于海地和多米尼加共和国所在的希斯帕尼奥拉岛。","appearance":"这种小型鸟儿移动缓慢，特征是明显的白色翼条和略显白色的双眼。与之相比，安岛拟霸鹟拥有较小、更尖的喙，眼睛颜色更深，通常直立栖息或在空中捕食昆虫。","call":"其鸣唱声为一连串‘we-we-we-we-we…’的音节，通常由六到十个音符组成，以每秒约七个音符的速度发出，但有时速度加快至每秒十二个音符。","habits":"扁嘴莺雀偏好在低矮处觅食，甚至偶尔在地面活动，但在较高海拔地区，它们也会在藤蔓纠缠的树冠附近觅食。它们的自然栖息地主要是亚热带或热带的干燥森林。","identification":"与安岛拟霸鹟相比，扁嘴莺雀的喙较为扁平，眼睛颜色较淡，且活动习性有所不同。","distribution":"扁嘴莺雀主要分布在中美洲的希斯帕尼奥拉岛，具体包括海地和多米尼加共和国的北部和西部海岸，以及Neiba谷地和Gonâve岛。"},{"name":"贝氏莺雀","english_name":"Bell's Vireo","scientific_name":"Vireo bellii","overview":"贝氏莺雀（英文名：Bell's Vireo，学名：Vireo bellii），是雀形目莺雀科绿鹃属的鸟类。小型昆虫食性新热带迁徙鸟类，繁殖于美国中南部至西南部及墨西哥北部，冬季主要栖息于墨西哥中部和南部。该鸟以密集植被为生，常近水源，外观较为暗淡，两性羽毛相似，无显著差异。东部个体色彩更鲜明，背部橄榄绿色，侧腹黄色；西部个体颜色从上部暗橄榄色至整体灰暗，翼条白色，尾长，活动时频繁摆动。","appearance":"体长115至125毫米，体重7至10克。翅短而圆，使尾显长。喙短直，尖端钝，基部略扁。全年羽毛颜色无性别差异，通常上部灰至绿色，下部白至黄色，胸部无斑纹。眼圈淡白，双翼具两道浅色翼条，下翼条更为明显。幼鸟羽色似成鸟夏季褪色，更白且翼条更清晰。\"最少贝氏莺雀\"（ pusillus）幼鸟脸颊和额头呈淡白色，翅膀和尾巴绿色。","call":"叫声为粗糙的两节式\"cheedle cheedle chee？Cheedle cheedle chew！\"，尽管音质不佳却极具辨识度。","habits":"偏好低矮灌木丛，常见于早期演替阶段的密林，河岸地带，杂草丛生的田野，年轻次生林或林地，及刺槐灌木丛。繁殖季节，雄鸟领地意识强，多数为一夫一妻制。雄雌共同筑巢，失败后会尝试重建。夏季在北美繁殖，冬季南迁至墨西哥。","breeding":"繁殖期内，雄鸟保卫领地，大部分配对为一雄一雌，虽有换伴现象。雌雄共担筑巢责任，若繁殖失败会持续尝试直至幼鸟离巢或季节结束。筑巢、产卵、孵化及育雏过程受褐头牛鹂寄生影响。","identification":"与明亮对比明显的白眼莺雀及体型更大、颜色更单调的灰莺雀区分，特别是在东部的白眼莺雀和西部的灰莺雀。尾部动作区别于西部个体，后者更似柳莺（Gnatcatcher）。","protection":"IUCN：LC（无危）。最少贝氏莺雀被列为加州濒危物种，自1986年被列为受威胁物种以来，其数量有所恢复。","distribution":"繁殖于美国中南部至西南部，包括加州、亚利桑那州等，冬季迁徙至墨西哥中部和南部，包括巴哈加州半岛。在加州，主要分布在圣巴巴拉以南的八个县，尤其是圣地亚哥县。","other":"受到褐头牛鹂寄生虫的严重威胁，导致因栖息地丧失和退化引发的数量下降加剧。"},{"name":"黑顶莺雀","english_name":"Black-capped Vireo","scientific_name":"Vireo atricapilla","overview":"黑顶莺雀（英文名：Black-capped Vireo，学名：Vireo atricapilla），是雀形目莺雀科绿鹃属的鸟类。以其独特的黑色头部和白色眼圈环绕着红色眼睛而著称。分布于北美的中南部和墨西哥北部，偏好橡树和杜松灌木丛生的丘陵地带。曾被列为濒危物种，其数量受褐头牛鹂寄生巢穴的影响严重。","appearance":"雄鸟成鸟上体橄榄绿色，下体白色，侧翼泛黄绿色至黄色，两翼有两条黄色条纹。头部除喉咙外全黑，眼圈显著白色，虹膜红褐色。雌鸟和幼鸟颜色较淡，头部灰色，眼圈白色，带黑色斑点。第一年雄鸟的颈背呈灰色。","call":"黑顶莺雀的鸣唱在整个繁殖季节持续，尤其在炎热的白天，其歌曲被描述为“drink yur, drink yur or drink yur teee”。","habits":"栖息于密集的灌木丛中，以昆虫幼虫为主食，常在植被低处快速跳跃寻找食物。雄鸟会在繁殖季早期，甚至在中午时分，从灌木或小树的顶部或隐蔽位置唱歌。","breeding":"筑巢由一对黑顶莺雀共同完成，通常雌鸟会产三到四个蛋，孵化期14至17天，雏鸟期10至12天。雌鸟孵卵，雄鸟提供大部分食物。一对可以一季多次繁殖。雄鸟照顾部分或全部离巢幼鸟，雌鸟再次筑巢，有时与另一雄鸟。","identification":"与蓝头莺雀的区别在于红眼和更宽的眼圈，以及头部的黑色（雄鸟）或灰色（雌鸟和幼鸟）。与赫氏莺雀的区别在于后者帽子和背部均匀灰绿色，眼圈不明显，喉咙橄榄色，下颌苍白。","protection":"IUCN：NT（近危）","distribution":"繁殖区位于美国中南部（从俄克拉荷马州南至得克萨斯州和新墨西哥州）和墨西哥中部（至科阿韦拉州）。冬季迁徙至墨西哥西海岸，从索诺拉州南部至格雷罗州。","other":"曾因栖息地丧失、城市化、放牧、植被控制等因素导致种群急剧下降，自1987年起被列入濒危物种，但在保护努力下，2018年从濒危名单中除名。"},{"name":"侏莺雀","english_name":"Dwarf Vireo","scientific_name":"Vireo nelsoni","overview":"侏莺雀（英文名：Dwarf Vireo，学名：Vireo nelsoni），是雀形目莺雀科绿鹃属的鸟类。为墨西哥西南部特有种，分布于从东贾利斯科至瓦哈卡的高海拔林地。其显著特征为暗灰色的冠羽，两道明显的翼斑，以及略显眼镜状的白色眼圈。","appearance":"侏莺雀体型小巧，上体橄榄色，头部带有轻微的眼镜状外观，双翼有两道白色翼斑，下体淡灰白色。雄鸟具有蓝灰色的冠羽，而雌鸟与雄鸟相似，但冠羽颜色更接近背部的橄榄色。幼鸟与成鸟类似，但虹膜较为暗淡。","call":"该鸟的鸣唱通常在低处觅食时反复发出，这有助于定位它们，尤其是考虑到它们隐秘的行为习性。","habits":"侏莺雀偏好半干旱灌木丛或溪边植被，主要在橡树林地带活动，单独觅食，较少加入混合物种群。它们的生活习性尚有许多未知之处。","breeding":"关于侏莺雀的繁殖习性信息有限，包括繁殖期、求偶、筑巢、孵化和育雏等细节。","identification":"雄性侏莺雀与雌性黑顶莺雀极为相似，两者可能难以区分；与红冠戴菊相比，侏莺雀体型更大，喙部更粗壮，腿脚更为粗实。","protection":"IUCN：LC（无危）","distribution":"侏莺雀主要分布在中美洲的墨西哥西南部，具体范围包括东贾利斯科至瓦哈卡的高海拔地区。","other":"其学名nelsoni纪念了美国鸟类学家联盟的第一任主席爱德华·威廉·尼尔森。"},{"name":"灰莺雀","english_name":"Grey Vireo","scientific_name":"Vireo vicinior","overview":"灰莺雀（英文名：Grey Vireo，学名：Vireo vicinior），是雀形目莺雀科绿鹃属的鸟类。分布于美国西南部至墨西哥西北部，偏好干燥山地的灌木林和树木，尤其是橡树和杜松林。其羽毛呈淡灰色，腹部略白，有淡色眼圈和翼纹，尾羽较长。在干燥岩石斜坡的浓密植被中筑巢，常单独或成对出现，通过鸣叫被发现。与贝氏莺雀和铅色莺雀相似，但可通过栖息环境和体型差异辨别。","appearance":"灰莺雀体长约14厘米，雄鸟略大于雌鸟，全身羽毛呈单调的灰色调，上体较深，下体略浅，腹部偏白。具有一条模糊的翼纹和完整的眼圈，尾羽相对较长，喙短而厚实。两性外观相似，但雄鸟的喙、翼和尾测量值稍大。幼鸟羽毛带有褐色调，翼纹相对明显。在春季和夏季，随着羽毛磨损，翼纹和白色尾缘变得不那么突出。","call":"灰莺雀的鸣唱由一系列短促、沙哑的音节组成，如'hu-wee, chu-wee, che-weet, chee, ch-churr-weet, churr, schray'，具有独特的频率调节。","habits":"灰莺雀栖息于干燥的灌木丛中，尤其偏好杜松和矮松树林，海拔高度在400至2500米之间。以昆虫为主食，冬季在墨西哥的种群会额外摄取果实。迁徙行为表现为短途迁移，秋季离开北部繁殖区。","breeding":"灰莺雀的繁殖期因地理位置而异，通常在春季开始。它们在距离地面约2米的灌木或带刺树木中筑巢，巢由干草、植物残余、树皮碎片和蜘蛛网构成，内部铺有细草和纤维。每窝产3至4枚白色卵，双亲共同孵化约13天，幼鸟在两周后离巢。","identification":"灰莺雀与贝氏莺雀和铅色莺雀相似，但可通过体型、翼纹数量和眼圈颜色进行区分。灰莺雀比贝氏莺雀稍大，翼纹仅有一条，眼圈和眉纹淡色。与铅色莺雀相比，灰莺雀体型小三分之一，仅有一条翼纹，眼圈和眉纹不显眼。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括美国西南部和墨西哥西北部，冬季迁徙至墨西哥西北部的索诺拉州西部和下加利福尼亚半岛南部，仅在得克萨斯州西南部的大本德国家公园全年留驻。","other":"灰莺雀的尾部侧向抽搐是其独特的行为特征，与莺雀科其他成员不同，类似于蚋莺的行为。"},{"name":"山莺雀","english_name":"Blue Mountain Vireo","scientific_name":"Vireo osburni","overview":"山莺雀（英文名：Blue Mountain Vireo，学名：Vireo osburni），是雀形目莺雀科绿鹃属的鸟类。体型健硕、外表朴素的鸟类，偏好生长在茂密植被覆盖的林地，尤其偏爱高海拔、湿润的森林环境。该物种在加勒比地区特有，其特征是没有明显的面部标记或翼带，这一特征将其与其它加勒比莺雀区分开来。拥有厚重的黑色喙，这一点使其与所有莺鸟明显不同。山莺雀性情隐秘，通常首先通过其声音被发现。","appearance":"体长约12.5至15厘米，体重约19.9至22克。额头、头顶、颈背及上体呈暗灰褐色，背部中部至下部和臀部带有橄榄褐色调；初级飞羽和次级飞羽呈暗灰褐色，外缘具灰色绿边（闭合翅膀时可见模糊的灰绿色斑块）；尾羽暗灰褐色，外缘淡绿色（尤其是侧尾羽）；眼周和耳羽暗灰褐色，下巴和喉部呈米白色带黄色调，与灰黄斑点的上胸部形成对比；下胸和腹部为暗淡的黄白色，有模糊的灰斑点，两胁颜色更鲜亮的黄色，肛周淡黄白色；虹膜棕色；喙粗重，上部暗黑，下部稍浅；腿灰色。性别相似。幼鸟仅在下腹部显现出黄色。","call":"其鸣唱为深思熟虑的颤音，接近尾声时音调略微下降；报警叫声为尖锐的下滑音'burr'。","habits":"栖息于牙买加的湿润和潮湿的石灰岩山地雨林，也见于高地林地和遮阴咖啡种植园；分布高度自100米以上。生活方式定居不动。食物主要包括昆虫和果实。在浓密的树叶中单独觅食，行为隐秘。","breeding":"繁殖季节主要集中在3月至7月；巢穴为悬垂的杯状，位于小树或树木的低至中等高度处。蛋上有斑点，关于窝雏数、孵化期或离巢期的信息未知。","identification":"山莺雀通过其厚重的喙和缺乏面部标记或翼带而与其他加勒比莺雀相区别。","protection":"IUCN：NT（近危）","distribution":"山莺雀主要分布于北美牙买加，特别是在蓝山和约翰克罗山脉国家公园、迪亚波罗山和洞穴国家，那里崎岖的石灰岩地形保护了大片适宜生存的栖息地。","other":"尽管在其大部分范围内遭受了大量栖息地破坏，但山莺雀的栖息地尚未被严重分割。主要的栖息地破坏原因包括砍伐树木制作木炭、人为火灾、小规模农业和土地开发。"},{"name":"黄喉莺雀","english_name":"Yellow-throated Vireo","scientific_name":"Vireo flavifrons","overview":"黄喉莺雀（英文名：Yellow-throated Vireo，学名：Vireo flavifrons），是雀形目莺雀科绿鹃属的鸟类。橄榄色头部、黄色喉咙的小型鸣禽，广泛分布于加拿大中南部到美国中南部的开阔落叶林中，偏好森林边缘地带。冬季迁徙至中美洲、南美洲北部和加勒比海地区。","appearance":"成年黄喉莺雀拥有橄榄绿色的头和背部，明亮的黄色喉咙和眼圈，白色腹部和下尾羽覆盖物。翅膀深色，有两道宽阔的白色翼带。喙粗壮，略弯，腿蓝灰色。性别间外观相似，仅雌鸟可能稍显淡黄。","call":"其鸣唱为一系列慢速起伏的音符，带有粗糙的质感。","habits":"栖息于中上层森林，以树干、枝条和树叶上的昆虫为食。偏好树木内部，尤其在裸露的枝条上缓慢移动，长时间停留在一处搜索食物。分布于开放的落叶林，冬季适应多种热带生境。","breeding":"筑杯状巢，由树皮碎片、干草和松针构成，悬挂在细枝或枝丫的水平分叉处。","identification":"与黑顶山雀相比体型较大，与东绿霸鹟相比体型较小。头部和喉咙的亮黄色和橄榄绿色形成鲜明对比，白腹和灰翅上的双白翼带是显著特征。","protection":"IUCN：LC（无危）","distribution":"繁殖区：北美，包括加拿大中南部和东南部至美国中南部和东南部。非繁殖区：南美北部。","other":"历史上曾因杀虫剂使用减少，近期种群有所恢复。"},{"name":"铅色莺雀","english_name":"Plumbeous Vireo","scientific_name":"Vireo plumbeus","overview":"铅色莺雀（英文名：Plumbeous Vireo，学名：Vireo plumbeus），是雀形目莺雀科绿鹃属的鸟类。小型北美洲鸣禽，分布自蒙大拿州东南部和南达科他州西部至墨西哥太平洋沿岸，包括下加利福尼亚南部极南地区。其迁徙习性显著，冬季移至南部范围，偏好松树林开放地带。","appearance":"全长约12.4至13.8厘米，体重介于12至20克。上体为平滑中性灰色，臀部略带橄榄绿色。下体接近白色，胸部两侧淡灰橄榄色，两胁颜色因个体差异而异，从非常淡的硫磺黄色到纯白不等。头部具宽阔的白色眉纹和眼环，后者被暗色眶纹中断。翼和尾为黑灰色，有两道宽的翼斑；外尾羽边缘白色。虹膜棕色，喙黑色，基部蓝灰色，腿蓝灰色。雌雄外观相似。","call":"其鸣唱由短促、粗糙的哨音组成，数个音节，间隔约2秒。音节常以高音和低音交替结束，给人以问答的印象。","habits":"栖息于温暖干燥的山地森林，如松树、橡树和杜松林，亦可见于大盆地河流沿线的落叶林木。迁徙时倾向于沿水道行进，越冬地海拔跨度大，从墨西哥沿海红树林至近万英尺的松栎林。","breeding":"筑巢于枝丫处，使用树皮碎片和绒毛搭建杯状巢，产3至5枚具褐色斑点的白色卵。","identification":"与卡氏莺雀和蓝头莺雀相似，但可通过体型、色彩和翼斑辨认。卡氏莺雀更小，背部灰橄榄绿，翼斑和下尾覆羽黄白色，两胁更亮更黄。蓝头莺雀体型略小，背部鲜亮橄榄绿，两胁硫磺黄。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美西部，包括蒙大拿州东南部、南达科他州西部至墨西哥太平洋沿岸。越冬地从墨西哥沿海至近万英尺的松栎林。","other":"曾被视为卡氏莺雀和蓝头莺雀的同种，现独立为种。"},{"name":"卡氏莺雀","english_name":"Cassin's Vireo","scientific_name":"Vireo cassinii","overview":"卡氏莺雀（英文名：Cassin's Vireo，学名：Vireo cassinii），是雀形目莺雀科绿鹃属的鸟类。是北美西部常见的小鸣禽，以十九世纪鸟类学家John Cassin命名。分布自加拿大西南部至美国西部，直至墨西哥下加利福尼亚州。具有灰色头部、背部及橄榄绿色的两侧，白色下体，显著的白色眼圈及翼条。偏好开放的山地森林环境。","appearance":"卡氏莺雀为中等体型的莺雀，全长约110至136毫米，体重介于13至18克。上体呈橄榄绿色至冠部和耳羽处变为褐色灰，面部与明亮的白色眼圈形成对比，由眉纹和眼环构成的眼圈被暗色的眉线中断。双翼和尾羽呈褐色黑色，有两条宽阔的黄白色翼条。飞羽和尾羽边缘为橄榄黄色或灰橄榄色，最外侧尾羽边缘为白色。臀部比背部更亮的橄榄绿色。下体为脏白色，胸部侧面沾染淡橄榄绿色，腹部更淡，两胁为淡硫黄色到橄榄黄色。虹膜为棕色，喙为黑色，基部为蓝灰色，腿为蓝灰色。雌雄在羽毛和体型上一致，尽管雌鸟可能略显暗淡。","call":"持续发出短促、粗糙的哨音短语，由几个音符组成，间隔约2秒。短语常交替以高音和低音结束，营造出一问一答的印象。","habits":"偏好西部山脉和山脚的开阔林地。通常在森林冠层的中下部活动，缓慢而从容地在树叶间寻找昆虫。","breeding":"在细枝的分叉处用树皮条和绒毛构建杯状巢，产2至5枚带褐色斑点的白色蛋。","identification":"与赫氏莺雀、贝氏莺雀、歌莺雀和灰莺雀的区别在于其大小、眼圈、下体颜色和对比度。与Blue-headed和Plumbeous vireos相似，但可以通过头侧的蓝色与喉咙和背部的对比、翼条宽度和尾羽边缘的颜色来区分。","protection":"IUCN：LC（无危）","distribution":"繁殖区域覆盖北美，从中西部加拿大至美国西部至墨西哥下加利福尼亚州（墨西哥西北部）。冬季迁徙至中美，包括墨西哥南部至亚利桑那州的索诺兰沙漠。","other":"曾被认为与铅色莺雀和蓝头莺雀属于同一物种，当时统称为'Solitary Vireo'。"},{"name":"蓝头莺雀","english_name":"Blue-headed Vireo","scientific_name":"Vireo solitarius","overview":"蓝头莺雀（英文名：Blue-headed Vireo，学名：Vireo solitarius），是雀形目莺雀科绿鹃属的鸟类。拥有鲜明的蓝色头部，对比橄榄绿色背部，黄色侧面，以及白色的眼镜状斑纹，是其最显著的特征。分布广泛，横跨加拿大至美国东部，南至墨西哥及中美洲部分地区。自1970年代以来，该物种的数量稳定增长。","appearance":"蓝头莺雀体型中等，长度约为126-148毫米，体重介于13-19克。成年雄鸟和雌鸟外观相似，上体橄榄绿色，头部深蓝灰色，两侧黄色，腹部白色，翅膀上有两条明显的黄白色翼带。幼鸟的羽毛颜色略显暗淡，但与成鸟相差不大。雄鸟和雌鸟在大小和颜色上没有明显差异。","call":"蓝头莺雀的鸣唱为缓慢、单调的音调，容易与红眼莺雀混淆，但速度较慢。雄鸟在繁殖季节会频繁鸣唱。","habits":"栖息于混合针叶和落叶林，偏好成熟的森林环境，尤其在较高海拔的地区。迁徙时，可在各种林地中发现它们的身影，通常与其他小型鸣鸟群聚。冬季，它们从美国东南部迁徙至中美洲。","breeding":"繁殖期在春季，雄鸟建立领地吸引雌鸟。双方共同筑巢，巢悬挂在树叉中。雌鸟每季产3-5枚蛋，孵化期约14天。幼鸟孵化后，父母共同喂养，直到它们能够独立。","identification":"与卡辛莺雀相比，蓝头莺雀色彩更为鲜艳，头部与背部颜色对比更强烈。在繁殖季节，可通过其更丰富和对比度更高的羽毛色彩进行辨识。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拿大至美国东部，非繁殖期分布于哥斯达黎加和古巴等地，南至墨西哥及中美洲部分地区。","other":"1997年之前，蓝头莺雀曾被归入单一物种‘莺雀’中，后来基于分子遗传学研究，恢复了其独立物种的地位。"},{"name":"黄翅莺雀","english_name":"Yellow-winged Vireo","scientific_name":"Vireo carmioli","overview":"黄翅莺雀（英文名：Yellow-winged Vireo，学名：Vireo carmioli），是雀形目莺雀科绿鹃属的小型鸟类。其最显著的特征是橄榄绿色的背部和带有两道黄色翼纹的黑灰色翅膀，以及黄色的眼眉线与眼圈。主要分布于中美洲的哥斯达黎加和巴拿马高山区。","appearance":"黄翅莺雀体长约11.5厘米，体重约13克。头部冠羽灰绿色，眼上方及眼圈呈白色至淡黄色，赋予其独特的“眼镜”外观。背部和上体颜色较暗，呈淡绿色。初级飞羽和次级飞羽为黑灰色，边缘泛黄绿色，形成醒目的翼纹。尾巴黑色，外侧带绿色黄边。喉咙为淡黄色，胸部及腹部黄色，侧面略带黄绿色，臀部黄色。虹膜棕色，上喙黑色，下喙淡灰色，腿色灰蓝。性别相似，幼鸟上体更偏褐色，下体黄色较淡。","call":"鸣唱为一系列短促、悠然的2至3音节的乐句，具有粗糙或嗡嗡的质感，最后一个音节通常加重，如“cheeyah, cheeyah, chipcheewee”。间歇以较长停顿。叫声包括鼻音“net”和类似新世界 Oriole 的“chwick”。","habits":"栖息于海拔约1900米至树线（约3000米）的凉爽湿润山林中，雨季时会降至约1500米的高度。主要以昆虫、蜘蛛和小果实为食，觅食时动作从容，有时加入混合物种群。通常单独或成对出现。","breeding":"繁殖期为3月至6月，正值雨季前及初期。巢由两性共同建造，采用树叶、苔藓、地衣等材料制成杯状，悬挂在树木或灌木枝桠的侧叉上，高度在3至20米之间。每窝产2枚带有深色斑点的白色蛋，孵化和喂养幼鸟由双亲共同承担。","identification":"黄翅莺雀可与tyrannulet科鸟类混淆，但其喙较厚实，且姿态更为水平。与同属的其他莺雀相比，其翼纹和黄色眼圈是明显的辨识特征。","protection":"IUCN：LC（无危）。黄翅莺雀在适宜的生境中较为常见，其大部分栖息地在哥斯达黎加和巴拿马的私人或公共保护区中受到保护，包括火山Poás国家公园、火山Barú国家公园和La Amistad国家公园。","distribution":"分布于中美洲的哥斯达黎加（Cordillera Central, Dota山脉和Cordillera de Talamanca）和邻近的巴拿马西部（Chiriquí高地）。","other":"在雨季结束后，部分个体可能会下降到较低海拔。"},{"name":"乔科莺雀","english_name":"Choco Vireo","scientific_name":"Vireo masteri","overview":"乔科莺雀（英文名：Choco Vireo，学名：Vireo masteri），是雀形目莺雀科绿鹃属的鸟类。罕见的莺雀科鸟类，由Paul Salaman于1991年首次在哥伦比亚发现，1996年正式描述。其自然栖息地位于南美洲的哥伦比亚西部和厄瓜多尔西北部的安第斯山脉云雾森林，海拔在800至1600米之间。这种小鸟体型小巧，约11厘米长，体重约11克，橄榄绿色的冠羽和上体，翼上有黄色条纹，喉咙和胸部呈淡黄至亮黄色。由于栖息地丧失，乔科莺雀正面临威胁。","appearance":"乔科莺雀体长11-11.5厘米，体重11-11.4克。头部上方橄榄色，向背部逐渐变为更明亮的绿色；眼上区域呈赭黄色，延伸为宽阔的白色眉纹越过眼睛，眼睑和眼周暗色，有狭窄的黄白色眼环；脸颊和耳羽赭黄色，带有橄榄色斑点；翅膀深褐色，初级飞羽基部边缘黄橄榄色，次级飞羽边缘橄榄绿色；大和中次级飞羽覆羽暗棕色，尖端宽广的黄白色（形成两道显著的翼带）；尾羽深棕色，中央一对橄榄绿色，外侧三对边缘浅棕色；下喙基部白色；腿蓝灰色。雄雌相似。幼鸟眉纹和面部颜色比成鸟更淡，翼带更宽且更黄，整体颜色较淡。","call":"乔科莺雀的鸣唱为快速连续的约10个音符，持续约2秒，声谱分析显示其歌声分为三部分，开始有约3个高音节，接着是约4个低音节，结尾通常包含一个先上升后下降的滑音。叫声包括尖锐的‘chip’声和鼻音的‘zhree-zhree-zhree’警报声。","habits":"乔科莺雀主要生活在安第斯山脉西侧的原始雨林中，常在陡峭山坡上，树冠破碎高度约20-25米，自然树倒造成的空隙，以及大量寄生植物生长的地方。它们是留鸟，活跃觅食，以毛虫为食，也吃甲虫和蝽象。觅食方式类似新世界莺雀，而非典型的悠闲方式。它们在树冠层叶子的下表面觅食，常见于混群中。","breeding":"在哥伦比亚西南部，已观察到成鸟在8月6日和15日喂养离巢幼鸟，8月25日捕获的一只幼鸟颅骨仅30%钙化。除此之外，关于繁殖的信息有限。","identification":"与常见的棕顶莺雀相比，乔科莺雀有明显的翼带和喉胸部的赭黄色。在混群中通过声音和颜色特征容易辨认。","protection":"IUCN：NT（近危）","distribution":"分布在哥伦比亚西部安第斯山脉（从安蒂奥基亚南部至纳里尼奥）和厄瓜多尔西北部（埃斯梅拉达斯、皮钦查）。","other":"该物种最初在1991年被Paul Salaman在哥伦比亚西部纳里尼奥省的Rio Nambi河沿岸观察到。"},{"name":"蓝顶绿莺雀","english_name":"Tepui Vireo","scientific_name":"Vireo sclateri","overview":"蓝顶绿莺雀（英文名：Tepui Vireo，学名：Vireo sclateri），是雀形目莺雀科绿鹃属的小型树栖鸟类。它是体型纤小的树栖鸟，头顶灰、背橄榄绿、胸黄绿，具淡色眼及粉褐色喙，是泛特普伊高地最具代表性的特有种之一，常见于委内瑞拉南部、圭亚那西南、巴西北部及苏里南塔菲尔山海拔500–2000米的山地森林。","appearance":"体长约12厘米，体重10–12.5克。雄鸟头顶和后颈灰色，前额与眉纹带皮黄色；上体橄榄绿色，翼和尾深灰，飞羽外缘色浅；颏喉白色，与黄色胸形成对比；胸侧及胁黄绿，腹部污白至微黄；虹膜灰或白；上喙暗褐、下喙及喙缘粉褐；脚粉灰至粉红色。雌鸟似雄鸟，但胸带界线较模糊。幼鸟虹膜暗色。","call":"鸣唱为短促、清晰的哨音“suuuwéééeeuu”，先升后降，快速重复；叫声包括带鼻音的下倾责骂声。","habits":"栖息于潮湿山地森林及林缘，海拔600–2000米。性定居，不迁徙。活跃于树冠或林缘上层，常倒挂枝叶觅食昆虫；常加入混合鸟群。","breeding":"暂无繁殖资料。","identification":"与里约绿莺雀外形略近，但鸣声截然不同，且分布海拔更高。","protection":"IUCN: LC（无危）。虽为分布受限物种，但多数栖息地偏远而受天然保护；部分地区位于国家公园内，然部分园区保护力度不足。在苏里南极罕见，2005年方于塔菲尔山首次记录。","distribution":"繁殖区：委内瑞拉南部（玻利瓦尔州、亚马孙州）、圭亚那西部与南部、巴西北部（罗赖马州）及苏里南中部（塔菲尔山）。无明确非繁殖区记录。","other":"分子研究证实其应归入莺雀属，结束了长期置于绿莺属的历史。"},{"name":"赫氏莺雀","english_name":"Hutton's Vireo","scientific_name":"Vireo huttoni","appearance":"赫氏莺雀体长约5英寸（12-13厘米），上身及下身均为暗橄榄灰色，拥有微弱的白色眼环和翼斑。喙厚实，腿色蓝灰，比红冠戴菊体型略大。两性外观相似，但在繁殖季节可通过雌鸟的孵卵斑和雄鸟的泄殖腔突起加以区分。幼鸟羽毛质地较稀疏，尤其尾羽覆羽部分。","call":"其最典型的鸣唱是一连串的“chu-wee”或“chew”音，但也有其他变化形式。叫声表现为类似猫叫的喋喋不休。","habits":"栖息于混合落叶林，尤其是以常绿橡树为主的森林，偏好从中层植被觅食昆虫。赫氏莺雀主要分布于北美，从加拿大西南部到危地马拉中部，部分群体表现出局部季节性迁移。冬季常加入混群，与红冠戴菊共处。","breeding":"筑巢于树叉上，呈吊挂式杯状。繁殖期内，雌鸟产卵3-4枚，卵色以白色为主，散布棕色斑点。雌雄共同参与筑巢、孵卵和育雏。","identification":"与红冠戴菊相比，赫氏莺雀的喙更厚实，腿色蓝灰，体型略大。在识别上，还应注意其更沉稳的行动方式和更粗壮的腿部。","protection":"IUCN：LC（无危）","distribution":"赫氏莺雀广泛分布于北美洲和中美洲，自加拿大西南部至危地马拉西部，包括太平洋沿岸和内陆山脉。","other":"遗传学研究表明，赫氏莺雀可能需细分为至少两个物种，沿海太平洋种群与内陆种群存在显著遗传差异。"},{"name":"金莺雀","english_name":"Golden Vireo","scientific_name":"Vireo hypochryseus","overview":"金莺雀（英文名：Golden Vireo，学名：Vireo hypochryseus），是雀形目莺雀科绿鹃属的鸟类，是墨西哥西部的特有种，分布于中美洲从南部Sonora至Oaxaca一带。其独特的黄色和绿色相间的羽毛以及醒目的黄色眉纹是其最显著的特征。","appearance":"体型小而略显粗壮，拥有较长的尾巴，上体主要为黄绿色，下体为黄色，最吸引人的特征是其鲜明的黄色眉纹。雄鸟和雌鸟外观相似，但幼鸟的冠部和上体带有棕色色调，下体颜色较淡。","call":"金莺雀的鸣唱是一系列响亮的chu-chu-chu-chu音符，通常在警戒时会发出鼻音的斥责声。","habits":"栖息于低地和山麓地带的热带森林和林地，活动于各种树木和灌木丛中，有时加入混杂物种的鸟群。它在所有层次觅食，常在结果的树和灌木附近寻找食物。","breeding":"具体繁殖细节未详述，但其通常在适宜的季节进行繁殖，可能包括筑巢、产卵和孵化等一系列过程。","identification":"与黑头威森莺的区别在于，金莺雀体型较大且更结实，具有更宽的浅色眉纹、更强壮的喙和蓝灰色的腿脚，而黑头威森莺通常有黑色的顶冠斑块。","protection":"IUCN状态未知，未被列入华盛顿公约(CITES)附录或中国国家重点保护野生动物名录。","distribution":"分布于中美洲墨西哥西部，自南部Sonora南至Oaxaca，包括Tres Marias群岛。在海拔从海平面到至少1900米的范围内均可发现。","other":"金莺雀有三个亚种，其中一个仅限于Nayarit附近的Tres Marias群岛。"},{"name":"歌莺雀","english_name":"Warbling Vireo","scientific_name":"Vireo gilvus","overview":"歌莺雀（英文名：Warbling Vireo，学名：Vireo gilvus），是雀形目莺雀科绿鹃属的鸟类。以其复杂而甜美的春日鸣唱著称。这种灰橄榄色的小鸟，腹部白色，有时略带淡黄色，更以歌声而非外观引人注目。遍布北美至墨西哥和佛罗里达狭长地带的开放落叶林和混交林，西部墨西哥和北中美洲是其越冬地。东部与西部亚种在大小、颜色上有细微差别。","appearance":"歌莺雀体型中等，约12-13厘米长，体重10-16克。上体主要呈灰橄榄绿色，冠部稍暗，下体白色，两胁及臀部常带有淡黄色。脸部有一条模糊的白眉纹，眼线灰色，其余羽毛平淡无奇，缺乏醒目的翼斑。幼鸟比成鸟更暗淡，翼斑呈淡肉桂色或淡黄色。雄雌羽色相似，但在年龄、性别和亚种间有轻微差异。","call":"鸣唱为连续的颤音，旋律悦耳，音调粗糙，与画眉雀和紫红雀类似，但东部与西部鸟之间存在微妙差异。","habits":"栖息于落叶林和混交林，偏好沿溪流和河流的棉木或白杨树丛。迁徙期间，它们会出现在各种有高大树木的生境中。主要以昆虫为食，也会吃浆果，尤其是迁徙前和越冬地。飞行平稳，活动范围广泛。","breeding":"营巢于树叉间，高度自1至40米，常见于人类居住区附近的树木。繁殖期，雄鸟参与孵卵，可能从巢中鸣唱。秋季换羽发生在繁殖地，而西部群体在离开后完成。","identification":"与费城莺雀容易混淆，但歌莺雀侧身颜色更亮，眼线较淡，尾巴较长，喙稍长而细。西部群体较东部小，冠部更暗。与褐顶莺雀的区别在于后者有棕色的冠部和较暗的橄榄褐色上体。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美至墨西哥和佛罗里达狭长地带，越冬于西部墨西哥和北中美洲。东部群体在加拿大南部至美国大部分地区繁殖，越冬于南至尼加拉瓜。","other":"东部和西部亚种在形态和歌声上有诊断性差异。"},{"name":"褐顶莺雀","english_name":"Brown-capped Vireo","scientific_name":"Vireo leucophrys","overview":"褐顶莺雀（英文名：Brown-capped Vireo，学名：Vireo leucophrys），是雀形目莺雀科绿鹃属的鸟类。主要栖息于中美洲和安第斯山脉的高海拔森林中，北至墨西哥南部，南达玻利维亚北部。其最显著的特征为橄榄绿色上部和褐色的顶冠，以及黄色的下腹部。","appearance":"褐顶莺雀体型较小，全长约12-12.7厘米，体重约12克。成鸟拥有橄榄绿色的背部，顶冠呈深褐色，眼睛周围有一条深色线，眉纹白色。面部和喉部颜色偏灰白，下腹部黄色，两胁略带橄榄色。幼鸟上部淡棕色，眉纹不明显。","call":"鸣声为清脆的‘twiist’叫声，歌唱声丰富而婉转，类似‘here you see me hear me sing so sweet’的旋律，与歌莺雀的歌声相似。","habits":"栖息于光照林地的树冠层和中间层次，森林边缘和其他半开放生境，海拔高度介于500至2500米之间。以毛虫和其他昆虫为食，亦会食用小果实，常加入混合物种觅食群。","breeding":"关于筑巢的描述尚未明确记录。","identification":"与歌莺雀较为相似，但后者上部颜色较浅，顶冠为灰色而非褐色。","protection":"IUCN状态未知，具体保护级别需查阅最新资料。","distribution":"分布于中美洲和南美洲，范围从墨西哥南部至玻利维亚北部，包括安第斯山脉地区。","other":"过去曾被认为与歌莺雀是同一物种，现确认为独立种类。"},{"name":"费城莺雀","english_name":"Philadelphia Vireo","scientific_name":"Vireo philadelphicus","overview":"费城莺雀（英文名：Philadelphia Vireo，学名：Vireo philadelphicus），是雀形目莺雀科绿鹃属的鸟类。小型的北美鸣禽，属于绿鹃科的莺雀科。以亮黄色的喉部和腹部、灰色的冠部和暗色的眼线为显著特征。分布于加拿大中部和南部至美国中北部和东北部，在繁殖季节活跃于落叶和混合林边缘。尽管名称源于费城，但在该城市并不常见。","appearance":"费城莺雀体型小巧，约10.7-12.5厘米长，体重10.8-13.0克。上体橄榄灰，臀部稍淡，冠部灰白，脸颊深色，眉纹白色，眼深褐色，下体淡黄，喉部最浅，胸腹部颜色最深。雌雄同形同色，较红眼莺雀小，喙与翼较短，羽色更黄。幼鸟的背部木褐色，翅膀和尾巴暗棕色带橄榄绿色边缘，腹部淡黄色。","call":"其鸣唱是一连串大约三音节的短语，有时以升调或降调结束，仿佛在反复提问和回答问题，与红眼莺雀的歌声相似，但音节间隔略长，音调更高。","habits":"费城莺雀栖息于落叶和混交林的边缘，偏好较年轻的林地，如白桦或山杨树区。迁徙时途经各种树林和灌木丛，冬季在中美洲度过。它们主要以昆虫为食，尤其是毛虫，也吃浆果，尤其是在迁徙前。","breeding":"繁殖期间，它们在树干分叉处建造篮状杯巢，通常位置较高。雌鸟产下3到5枚斑点白蛋，双亲共同孵化，孵化期长达14天。幼鸟由双亲共同抚育。","identification":"与歌莺雀相比，费城莺雀下体更黄，暗色的脸颊部分更为明显。与红眼莺雀的区别在于喙较短，下体更黄。与田纳西林莺的区别在于体型略大，喙较粗，眼后纹更宽且更清晰。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拿大中部和南部至美国中北部和东北部，非繁殖季节迁徙至中美洲和南美西北部。","other":"此物种的名称虽然源自费城，但在当地并不常见，仅在迁徙季节出现。"},{"name":"红眼莺雀","english_name":"Red-eyed Vireo","scientific_name":"Vireo olivaceus","overview":"红眼莺雀（英文名：Red-eyed Vireo，学名：Vireo olivaceus），是雀形目莺雀科绿鹃属的鸟类。特征为橄榄绿色上体、白色下体，具有独特的红眼睛和灰色头冠，边缘有黑色线条。红眼莺雀以连续不断的歌唱而闻名，尤其是在夏季的午后。在成熟的落叶林中繁殖，冬季迁徙至南美洲。","appearance":"成年红眼莺雀体长约12-13厘米，体重12-26克。头部呈现灰蓝至蓝灰色，与橄榄绿色的背部形成对比，有明显的白色眉纹。头顶两侧的边缘与眉纹上方形成黑色线状边界，从鼻孔延伸至眼后逐渐模糊。耳羽和颈部侧面为淡橄榄灰色，比背部颜色更浅且偏灰。下体白色，新鲜时带有淡黄色调。红眼莺雀的眼睛为鲜亮的红色至深红色，少数个体可能呈棕色。翼式、翼长、尾长和喙长是识别的重要特征，第十初级飞羽（p10）退化或极短（3-9毫米短于最长的初级覆羽），p5比p9短4-8毫米。","call":"红眼莺雀以其持续不断的歌唱著称，歌曲由一系列滑音组成，通常以降调或升调结束，随后是停顿，仿佛鸟儿在提问然后回答，循环往复。一天中，它们能够发出超过20,000首歌，是鸟类界中最勤奋的歌手之一。","habits":"红眼莺雀偏好在开阔的森林地带繁殖，如加拿大和美国东部及西北部的成熟落叶林。它们迁徙到南美洲过冬，几乎可以在任何林木覆盖的生境中找到它们的身影。红眼莺雀主要以昆虫为食，特别喜爱毛虫和蚜虫，有时会悬停捕食。在热带地区，它们常参与混合物种的觅食群，通常在树冠较高处活动。在迁徙前和冬季，它们会食用浆果。","breeding":"红眼莺雀在繁殖季节于树叉中建造杯状巢，主要由雌鸟承担筑巢、孵卵和照料幼鸟的责任。它们的巢可能受到牛鹂（如褐头牛鹂和紫辉牛鹂）的寄生，导致幼鸟被替代。红眼莺雀也可能受到Haemoproteus和trypanosoma等寄生虫的影响。","identification":"与红眼莺雀外观相似的有黄绿莺雀、南美红眼莺雀、黑髭莺雀和尤卡坦莺雀。通过下体颜色、翼斑、头部图案、喙色和声音的不同，可以区分这些种类。南美红眼莺雀的下体更明亮的黄色，虹膜颜色为棕红色而非鲜红色。黑髭莺雀有特征性的黑色颊纹和较大的喙，上体颜色较暗，下体颜色变化较大，从淡黄色到缓冲色。费城莺雀和歌莺雀也有类似红眼莺雀的羽色模式，但缺乏黑色边框的眉纹，头部图案更简单。","protection":"IUCN：LC（无危）","distribution":"红眼莺雀在繁殖季节分布于加拿大和美国中东部，非繁殖季节迁徙至南美中部。在北美，它们遍布加拿大和美国的中东部地区；冬季，它们迁徙至南美，主要在亚马逊盆地东侧的安第斯山脉以东地区过冬。","other":"红眼莺雀是北美最常见和最广泛的繁殖鸣禽之一，其连续的歌唱声在整个白天都可听到。它们在迁徙期间可能访问加利福尼亚州和其他西部州份，也是欧洲最常见的北美鸣禽迷鸟之一，主要在爱尔兰和英国被记录。"},{"name":"巴西莺雀","english_name":"Noronha Vireo","scientific_name":"Vireo gracilirostris","overview":"巴西莺雀（英文名：Noronha Vireo，学名：Vireo gracilirostris），是雀形目莺雀科绿鹃属的鸟类。仅在巴西东北部的费尔南多·迪诺罗尼亚群岛发现，为该岛仅有的两种本土鸣禽之一。","appearance":"该鸟体长约14厘米，体重介于11.5至25.1克之间。头部和背部呈暗灰橄榄色，下背、臀部和尾巴颜色略显绿色。眼先呈褐色，眉纹淡黄色。初级飞羽和次级飞羽的外缘带有绿色边缘。喉咙和腹部为淡黄白色。虹膜棕色。喙上部和尖端为角质棕色，下部较浅。腿脚淡蓝灰色。与红眼莺雀（亚种Chivi）相比，巴西莺雀色彩更暗淡，虹膜呈褐色，喙明显更长更细，尾巴显著较长，翅膀更加圆润，主翼羽延伸较短。雌雄相似，幼鸟的冠羽、背部和次级飞羽覆羽为丰富的锈褐色。","call":"其鸣唱为悦耳的'weet a weet, chewegoo, whit, whit'。叫声包括警戒时的'tschrrr'，责骂般的尖锐'skeeur'，以及高音薄哨声。在争斗情况下会发出喙响。","habits":"广泛觅食，从树梢到地面均有其踪迹，表现得非常温顺。在没有其他鸣禽竞争的情况下，发展出了多样化的觅食技巧。它会倒挂着从叶子和花朵的下表面觅食，也会空中捕食。有时用脚固定猎物以便肢解。","identification":"与红眼莺雀相比，巴西莺雀的羽毛颜色更为暗淡，喙更长，尾巴更长。","protection":"IUCN：VU（易危）","distribution":"仅分布于巴西东北部的费尔南多·迪诺罗尼亚群岛。"},{"name":"黄绿莺雀","english_name":"Yellow-green Vireo","scientific_name":"Vireo flavoviridis","overview":"黄绿莺雀（英文名：Yellow-green Vireo，学名：Vireo flavoviridis），是雀形目莺雀科绿鹃属的鸟类。属于莺雀科。其特征为橄榄绿色的背部，灰顶冠带暗边，眼上方有一白色眉纹，下体白色而两侧和胁部黄色。分布于中美洲至巴拿马，冬季迁徙至南美洲北部和东部安第斯山脉以及亚马逊盆地西部。","appearance":"体长约14-14.7厘米，体重约18.5克。成鸟上体橄榄绿，头顶部灰色带暗边，眼周暗线延伸至红棕色眼睛，下体白色，胸侧和胁部黄色。幼鸟色泽较淡，背部带褐色调，下体黄色较少，眼睛为棕色。","call":"发出鼻音的nyaaah叫声，歌曲为重复的vereeveree，fee'er vireo viree，比红眼莺雀的歌曲更短更快。","habits":"栖息于轻林木冠层和中层、森林边缘和花园，海拔从海平面至1500米。以树冠中的昆虫为食，偏好毛虫和甲虫，也吃小果实，包括槲寄生浆果。","breeding":"筑巢由雌鸟完成，巢为杯状，直径约6.5厘米，由多种植物材料构成，通常离地面1.5-3.5米，有时高达12米。每窝产2-3枚白色带褐色斑点的蛋，由雌鸟单独孵化，雄鸟参与喂养幼鸟。繁殖季节为3月至6月。","identification":"与红眼莺雀区分，具有更黄的下体，灰顶冠无黑色边，更黄的上体和不同的眼色。在某些个体中，即使在手中也难以区分。","distribution":"繁殖于美国德克萨斯州南部，中美洲至巴拿马；冬季迁徙至南美洲北部和东部安第斯山脉以及亚马逊盆地西部。"},{"name":"黑髭莺雀","english_name":"Black-whiskered Vireo","scientific_name":"Vireo altiloquus","overview":"黑髭莺雀（英文名：Black-whiskered Vireo，学名：Vireo altiloquus），是雀形目莺雀科绿鹃属的鸟类。主要分布于美国东南部的沿海红树林与硬木林，以及广阔的加勒比海地区。与近缘物种红眼莺雀和黄绿莺雀相似，但独特的黑色侧喉纹（俗称‘髭’）和略带褐色的背部帮助区分它们。在美国，其分布限于佛罗里达州南部，而在加勒比海则广泛分布。","appearance":"体型较大，长约14至15厘米，翼展约25厘米，体重介于17至19克之间。上身橄榄绿色偏暗，下身白色，侧翼及尾下覆羽呈淡黄色。头部特征包括灰色冠羽、红眼、暗色眼线以及显著的白色眉纹。最明显的特征是两侧颈部的黑色条纹，即所谓的‘髭’，但在密集植被中可能难以观察到。喙厚实，腿蓝灰色。幼鸟与成鸟相似，但眼色为棕红色。","call":"歌声由一系列短促悦耳的2至3音节短语组成，各短语间有明显的停顿，与红眼莺雀的歌声相似，但更尖锐，音调变化更突然。","habits":"偏好开放的落叶林区和耕作地带，尤其是佛罗里达州的红树林。以树冠层的昆虫和少量浆果为食，有时会悬停觅食。迁徙习性部分依赖于地理位置，北部种群如佛罗里达和巴哈马群岛的种群迁往亚马逊盆地低地森林越冬，而南部岛屿的种群全年留驻。","breeding":"在树叉处搭建杯状巢，每窝产2至3枚白色蛋。在佛罗里达州，面临紫辉牛鹂的寄生问题，导致繁殖成功率下降。","identification":"与红眼莺雀相比，黑髭莺雀上体更暗淡、更棕色，且有黑色髭纹标记。黄绿莺雀和尤卡坦莺雀在其分布范围内不重叠，但在迁徙季节可能在尤卡坦半岛东海岸相遇。相较于这三种莺雀，黑髭莺雀具有更厚重的喙、更宽的眼线，且无黑色边缘覆盖白色眉纹。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要在北美东南部的佛罗里达州和整个西印度群岛，向南延伸至委内瑞拉的离岸岛屿。非繁殖季节分布于南美的北部地区。","other":"在某些地区，如圣卢西亚岛和波多黎各西南部，紫辉牛鹂对其造成的寄生率高达50%，严重影响了繁殖成功率。"},{"name":"尤卡莺雀","english_name":"Yucatan Vireo","scientific_name":"Vireo magister","appearance":"该鸟整体呈现较为暗淡的色彩，上体橄榄灰，下体灰白，具有一条宽而明亮的眉纹，与浓厚的黑色眼纹形成鲜明对比。喙部强壮，略带钩状，呈灰色，基部较浅。头部冠羽色泽暗淡。翅膀和尾巴深色，边缘带有橄榄绿色调，腿脚呈蓝灰色。","habits":"尤卡坦莺雀栖息于热带森林、灌木丛和杂草丛生的空地，活动范围广泛，从低层至树冠层均有发现。其食性多样，包括昆虫和浆果。在许多情况下，它会被发现正在进食浆果。","identification":"与其他莺雀科物种相比，尤卡坦莺雀具有较为独特的外形特征，尤其是其宽大的眉纹和浓厚的黑色眼纹，以及橄榄灰色的上体和灰白色的下体。","protection":"IUCN：LC（无危）","distribution":"尤卡坦莺雀主要分布于中美洲，包括墨西哥、伯利兹、洪都拉斯，以及开曼群岛。在美国，仅有一例记录于1984年的得克萨斯州高岛。","other":"已确认四个亚种，大量亚种的存在反映了其在偏远岛屿和一小片大陆地带的分散分布。"},{"name":"南美红眼莺雀","english_name":"Chivi Vireo","scientific_name":"Vireo chivi","overview":"南美红眼莺雀（英文名：Chivi Vireo，学名：Vireo chivi），是雀形目莺雀科绿鹃属的鸟类。原被视为红眼莺雀的亚种，现确认为独立物种。体长约12-14厘米，以橄榄绿至黄绿色为主，腹部偏白，头冠灰，虹膜棕色。广泛分布于南美洲北部、东部和中部，遍及亚马逊雨林，至阿根廷中部。","appearance":"成鸟上体橄榄绿至黄绿色，下体偏白，带绿调的侧腹和胸侧。喙色从黑色到灰暗，脚色浅棕至淡灰。头部具灰色冠羽，眉纹延伸至耳羽上方，眼下方呈偏白色。幼鸟上体褐色或赭色，覆羽端部呈褐绿色，头部图案较成鸟少对比。嘴腔内颜色直至6个月大仍比成鸟浅。","call":"发出简单曲调，间歇性的音乐声，南方亚种的歌曲通常为\"chew-lee chew-lew wee-chee chew leee\"，griseobarbatus亚种则是反复的\"tche-wit ... tche-wut\"，solimoensis亚种歌声较短且重复，迁徙亚种歌声更复杂。","habits":"主要栖息于亚马逊森林的树冠和次生林，适应多种环境，包括干燥至湿润的森林，河流边，灌木丛，甚至受干扰的栖息地。高度从海平面至约2600米。主要以昆虫为食，尤其偏好毛虫和其他昆虫幼虫，部分亚种也吃水果，可能帮助传播种子。","breeding":"繁殖期因地区而异，南端亚种在春季筑巢，北端亚种在年中筑巢。巢为杯状，由草、纤维和少量植物绒毛构成，产卵2-4枚，孵化期10-16天，幼鸟发育期10-13天，仅母鸟孵卵。","identification":"与红眼莺雀相似，但可通过声音和分布区区分，红眼莺雀迁往北美，而南美红眼莺雀全年留在南美洲。","protection":"IUCN：LC（无危）","distribution":"广泛分布于南美洲北部、东部和中部，从亚马孙雨林西部和西南部至阿根廷中部，遍布亚马逊地区，至哥伦比亚东北部、委内瑞拉、圭亚那、巴西东部等地。","other":"共有九个亚种，部分亚种为迁徙性，而多数为留鸟。"},{"name":"棕顶绿莺雀","english_name":"Rufous-crowned Greenlet","scientific_name":"Hylophilus poicilotis","overview":"棕顶绿莺雀（英文名：Rufous-crowned Greenlet，学名：Hylophilus poicilotis），是雀形目莺雀科绿莺雀属的小型鸟类。其最显著的外部特征是亮栗色的头顶，与橄榄绿色的背部形成鲜明对比。分布于南美洲的巴拉圭东部、阿根廷东北部及巴西东南部，包括环绕帕拉瓜河南部地区的潘塔纳尔湿地。","appearance":"体长约12.5厘米，体重9至12克。头顶呈鲜艳的栗褐色，与橄榄绿色的背部和肩部形成强烈对比，腰背和臀部呈现更鲜亮的绿色。飞行羽为暗灰黑色，初级飞羽和次级飞羽边缘具细窄的绿色镶边，闭合翅膀时显现出绿色调。耳羽呈暗灰黑色，带有较淡的灰色斑点。喉部颜色为暗淡的浅灰色，胸部变为黄灰色，至腹部逐渐转为暗黄色，腹部和胁部的颜色更加鲜亮。虹膜为深红棕色，偶尔会呈现灰棕色或灰色，可能与年龄相关。喙上部为暗黑色，下部为灰色至暗粉色。腿为灰色。雌雄两性外观相似。幼鸟与成鸟类似，但下体颜色更亮丽，背部更偏橄榄色。","call":"发出快速重复的‘swee-swee-swee’鸣叫声。","habits":"栖息于湿润森林的树冠层和次生林，常伴随混种鸟类群。其自然栖息地包括亚热带或热带湿润低地森林、亚热带或热带湿润山地森林，以及严重退化的前森林区域。","identification":"与灰眼绿莺雀相似，但后者眼睛为灰色而非深色。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，具体包括巴西东南部（从马托格罗索州南部至圣埃斯皮里图，南至里奥格兰德州）、巴拉圭东部和阿根廷北部（米西奥内斯省）。"},{"name":"灰眼绿莺雀","english_name":"Grey-eyed Greenlet","scientific_name":"Hylophilus amaurocephalus","overview":"灰眼绿莺雀（英文名：Grey-eyed Greenlet，学名：Hylophilus amaurocephalus），是雀形目莺雀科绿莺雀属的鸟类。小型绿色的类似鸫的鸟类。其特征为拥有灰褐色的额顶和头顶，灰白色的耳羽和眼周斑点，以及明显的灰色眉纹。背部为暗灰棕色，逐渐变为带有绿色调的背部、肩部和臀部。上翼覆羽和初级飞羽呈暗灰黑色，外侧羽缘带绿色，使得闭合的翅膀呈现出绿色外观。尾巴的中央羽毛为灰绿色，外侧边缘更亮。下体颜色从淡白色下巴至灰褐色的胸部、腹部和臀部，两胁带黄色。虹膜呈浅灰色或中灰色。喙上部为灰色，下部为灰棕色。腿色深灰色。雄雌相似。幼鸟的虹膜为棕色。广泛分布在巴西东北部至西南部，以及玻利维亚北部。","appearance":"灰眼绿莺雀体型小，长度约12.5-13厘米。头部特征显著，额顶和头顶为灰褐色，耳羽和眼周斑点为灰白相间，眉纹灰白分明。背部颜色自上而下由暗灰棕色渐变为带有绿色调，肩部和臀部尤为明显。上翼覆羽和飞羽为暗灰黑色，外侧边缘带绿色光泽，使闭合的翅膀呈现绿色。尾羽灰绿色，外侧边缘色泽更为亮丽。下体颜色变化多样，从下巴的淡白色至胸腹部的灰褐色，两胁带有黄色调。虹膜颜色独特，为浅灰色或中灰色。喙的颜色上部为灰色，下部为灰棕色。腿部颜色为深灰色。性别之间外观相似，但幼鸟虹膜为棕色。","call":"灰眼绿莺雀的鸣叫声为缓慢重复的‘tchui-tchui-tchui’，歌唱时发出多个音节连续重复的‘tooweeder, tooweeder…’，与棕顶绿莺雀的鸣声相比更加复杂，音节结尾音调降低。雌鸟也可能鸣唱，发出不同的歌曲‘dec-terwee-ter-tee-bit’，音符有调节，有时与雄鸟的鸣叫形成二重奏。","habits":"灰眼绿莺雀栖息于Caatinga林地、森林边缘、灌木丛和灌木牧场，观察到它以昆虫和其他节肢动物为主食，同时也会食用大量植物物质，包括Struthanthus concinnus的果实。曾观察到它从蜘蛛网中取食蜘蛛，并用一只脚固定住猎物进行肢解。觅食高度一般在地面以上1-10米。秋季时，有时会以3-4个个体的小群体活动，可能是家庭群，也以成对出现，伴侣之间保持一定距离。经常出现在混合物种的鸟群中。","breeding":"筑巢活动最早在1月1日被观察到，1月21日在不同地点发现了刚离巢的幼鸟。已知的一个巢穴是由绿色苔藓和白色植物绒毛构成的薄杯状结构，悬挂在密集藤蔓的叉枝上，位于小树4.5米的高度。关于繁殖的其他信息目前尚未可知。","identification":"灰眼绿莺雀与棕顶绿莺雀相似，但区别在于灰眼绿莺雀的眼睛为灰色而非深色。此外，其鸣声更为复杂，音节结尾音调较低。","protection":"IUCN：LC（无危）","distribution":"灰眼绿莺雀分布于南美洲巴西东部至西南部，以及玻利维亚北部。具体分布包括巴西的Piauí、Ceará、Bahia、Minas Gerais至São Paulo，以及Mato Grosso do Sul和Bolivia的Beni。","other":"灰眼绿莺雀在适应能力方面较强，能在大量被改造的生境中生存，包括再生牧场和不规律烧毁的林地，这比更为显著。"},{"name":"里约绿莺雀","english_name":"Lemon-chested Greenlet","scientific_name":"Hylophilus thoracicus","overview":"里约绿莺雀（英文名：Lemon-chested Greenlet，学名：Hylophilus thoracicus），是雀形目莺雀科绿莺雀属的鸟类。分布于南美洲北部、中部及东南部，包括巴西、哥伦比亚、厄瓜多尔等国。其最显著的特征是淡色眼睛与黄色胸部和绿色头部及上体形成鲜明对比。","appearance":"成鸟长约12至13厘米，重13.5至14克。前额赭橄榄色，冠部灰橄榄色略带绿色边缘，面部及眼周泛绿，与灰色的冠部形成对比。上体呈暗绿色，翼羽及次级飞羽为暗灰黑色，翼缘略显绿色，次级覆羽内缘亮黄色；尾羽呈暗绿色，外缘更鲜艳。下颌及喉部灰白，胸黄色明亮，腹部淡奶油色，腕关节及翼下覆羽亮柠檬黄。虹膜棕色，边缘淡黄色；喙及腿灰色。雌雄相似。幼鸟冠部灰褐色，眼先及耳羽白色，下体白色区域有淡褐色污迹，两侧灰色；虹膜深灰棕色。","call":"叫声为穿透力强的一系列6至10个音符，'chew-ew chew-ew chew-ew'，有时在系列结尾声音加大，可长时间持续发出。偶尔发出类似'灰颈绿莺雀的'REE trr'r'r'r'r'r'r'声。另一种叫声为丰富而哨音般的'where-it'，有时会重复两次。","habits":"栖息于湿润森林和高大的次生林，包括restinga环境，偶尔出现在灌木丛和低矮林地，包括城市公园。海拔高度记录在大约1000米，但主要生活在600米以下。以昆虫及其幼虫和小果实为主食，常在树冠层活跃觅食，经常倒挂。通常非常领域性，单只或成对加入混群，包括乌顶绿莺雀或黄颊绿莺雀等物种组成的群体，但也独立于它们之外觅食。","breeding":"繁殖信息未知。","identification":"与前同种H. griseiventris的歌声基本相同，一系列6至8个音符，'chew-ew chew-ew chew-ew'或'dewEE, dewEE, dewEE'，有时在结尾声音变大，混合有'spet, spet'叫声，但最高频率更高。警告时发出'kray'音。","protection":"IUCN：LC（无危）","distribution":"分布于巴西南部、中部、东南部（圣埃斯皮里图、里约热内卢、东北圣保罗），在委内瑞拉南部和厄瓜多尔东部仅限于terra firme森林，但在其他地方也有季节性洪水森林（várzea）的记录。海拔可达900米（委内瑞拉）和850米（秘鲁东部），但在厄瓜多尔东部主要生活在400米以下。"},{"name":"灰胸绿莺雀","english_name":"Grey-chested Greenlet","scientific_name":"Hylophilus semicinereus","overview":"灰胸绿莺雀（英文名：Grey-chested Greenlet，学名：Hylophilus semicinereus），是雀形目莺雀科绿莺雀属的小型鸟类，以其橄榄色背部和前额与淡色腹部形成鲜明对比而著称。常见于南美的亚马逊雨林区域，包括玻利维亚、巴西、哥伦比亚、法属圭亚那、秘鲁和委内瑞拉。","appearance":"体长约12厘米，体重约13克。前额呈灰色至绿色，头部后部颜色较暗；耳羽边缘灰黄色，上体绿色；初级飞羽和次级飞羽黑色带绿边，使闭合翅膀呈现绿色外观；尾羽橄榄绿，边缘更亮的绿色；胸部灰色带有强烈的黄绿色调，侧面更显亮绿黄色；腹面淡黄白色，侧面偏灰黄色，下腹灰白微黄；翼下覆羽和腕部区域鲜黄色；虹膜白色至灰色；喙灰色，尖端和上部灰色，下部及切割边缘暗粉红色；腿色为暗灰褐色。雌雄相似，幼鸟特征未详述。不同亚种之间存在细微差异，如viridiceps亚种头部灰色少于标准种，胸部绿色较淡；juruanus亚种头部和颈背橄榄棕色明显，上体颜色比标准种淡，喉部和胸部颜色较浅，胸侧黄色较少，翼下覆羽和飞羽内缘黄色较淡。","call":"鸣唱为一系列快速连续的‘wee-wee-wee’音符。","habits":"栖息于次生林、湿润森林的树冠层，偏好较低的树冠环境，如永久性水淹区。主要以小型昆虫为食，常在树冠和藤蔓间觅食，多在外围树叶中活动，有时会倒挂采食叶片上的食物。经常加入混合物种群。","breeding":"繁殖信息暂无。","identification":"与里约绿莺雀的区别在于后者胸部有黄色带状斑纹。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美洲亚马逊雨林区域，包括玻利维亚、巴西、哥伦比亚、法属圭亚那、秘鲁和委内瑞拉。"},{"name":"灰颈绿莺雀","english_name":"Ashy-headed Greenlet","scientific_name":"Hylophilus pectoralis","overview":"灰颈绿莺雀（英文名：Ashy-headed Greenlet，学名：Hylophilus pectoralis），是雀形目莺雀科绿莺雀属的鸟类。以其独特的灰头和橄榄绿色背部著称。在南美洲的亚马孙雨林北部、中部广泛分布，常在多种轻度树林环境中发现，包括森林边缘、灌木丛乃至花园，有时相当常见。","appearance":"灰颈绿莺雀体长约12厘米，体重介于10.3至12.4克之间。头部（前额、头顶和颈背）呈暗灰色，眉纹淡灰白色，耳羽灰色；上体包括翅膀上部和尾巴呈现暗绿色，飞羽和尾羽边缘更鲜亮一些；下颏白色，喉咙处斑驳的灰白色，胸部绿色偏黄，侧面颜色更鲜艳，腹部淡白色，两胁灰白色。虹膜为棕色或橙棕色，喙上部深棕色，下部较浅，腿肉棕色。雄雌外观相似。幼鸟相比成鸟头部灰色较淡，更偏向土黄色。","call":"灰颈绿莺雀的鸣唱为快速连续的颤音‘peeerr-peeerr-peeerr-prreeee’，后半部分为标志性的颤音。","habits":"生活在落叶林、次生林、种植园、花园及红树林边缘地带，海拔高度从海平面到400米。似乎是定居型鸟类。食物以昆虫为主，如鳞翅目幼虫、直翅目昆虫、鞘翅目甲虫、蚁类、蝽类（包括同翅目），偶尔也会摄取一些植物物质，如槲寄生浆果。活跃于树冠层外侧，常参与混群觅食。","breeding":"繁殖季节较长，在苏里南地区，1月初已发现带有卵的巢穴，9月中旬见到刚离巢的小鸟。巢由两性共同建造，是一个开放式的杯子状巢，编织在两根树枝间。每窝产卵2枚，蛋壳白色，钝端有黑色斑点，两性共同孵化。其他繁殖细节未知。","identification":"与其他绿莺雀科成员相比，灰颈绿莺雀的头部灰色较为独特，同时其橄榄绿色的背部和黄色的胸部也是辨识关键。","protection":"IUCN：LC（无危）。在部分地区如苏里南非常普遍或数量众多。适应性强，可在受干扰的生境中生存。在巴西的分布范围似乎正在向南扩展。","distribution":"分布于南美北部和中部，具体包括委内瑞拉东北部（Delta Amacuro）、圭亚那、苏里南北部、法属圭亚那北部、巴西北部和东部（从亚马孙河下游东至马拉尼昂，南至朗多尼亚州、南马托格罗索州、圣保罗州西北部和戈亚斯州），以及玻利维亚北部和东部；在秘鲁东北部（圣马丁）有一个分离的种群。"},{"name":"褐头绿莺雀","english_name":"Brown-headed Greenlet","scientific_name":"Hylophilus brunneiceps","overview":"褐头绿莺雀（英文名：Brown-headed Greenlet，学名：Hylophilus brunneiceps），是雀形目莺雀科绿莺雀属的小型鸟类，分布于南美的亚马逊盆地西部，主要在巴西中部、哥伦比亚和委内瑞拉北部。其自然栖息地为热带干灌木丛。","appearance":"体长约11.4至11.5厘米，体重约8至11.5克。头部冠部呈棕色或暗褐色，略带淡黄色调，与橄榄绿色上体形成对比；翼羽暗灰色，边缘绿色；尾部橄榄绿色；头部侧面暗棕色，喉部及上胸部分为脏白色，微带橄榄色；下胸至腹部灰白色，两胁黄色，臀部浅绿黄色；虹膜灰色或近白色，有时为深色（可能为幼鸟）；喙上部棕色，下部粉红色；腿脚粉色。雌雄相似，幼鸟未详述。","call":"领地歌唱声为响亮而缓慢的“seeeeearn, seeeeearn”，每音节向下弯曲，每秒一音节；当受刺激时，会发出一系列颤音，接着是4至5个柔和的音符和一连串下降的响亮音符，重复多次。","habits":"常栖息于稀树草原森林、沙质地低矮灌木林、黑水区域以及高大瓦尔泽亚森林和溪流边界的边缘地带。似乎具有定居习性，以昆虫和毛虫为食，活跃觅食，高度在5至12米间，从叶片密集区倒挂取食，有时悬停以从叶片下表面获取食物。成对或家庭群活动，偶尔加入混群。","breeding":"繁殖信息暂无记载。","identification":"通过其独特的棕色头部和橄榄绿色的上体与其它绿莺雀属物种相区分。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的亚马逊盆地西部，包括巴西中部、哥伦比亚东部（维查达、瓜尼亚和瓦佩斯）和委内瑞拉南部（阿马索尼和玻利瓦尔），以及巴西西北部（亚马逊州和罗赖马州的黑河流域）。"},{"name":"灌丛绿莺雀","english_name":"Scrub Greenlet","scientific_name":"Hylophilus flavipes","overview":"灌丛绿莺雀（英文名：Scrub Greenlet，学名：Hylophilus flavipes），是雀形目莺雀科绿莺雀属的鸟类。分布于中美洲的哥斯达黎加至南美洲的委内瑞拉北部，常见于低海拔的灌木丛生地带，如废弃香蕉种植园中的竹林和油棕榈种植园。其羽毛颜色为橄榄绿色，腹部偏黄，头部灰暗，具有一双尖而粉红的喙，眼色随亚种而异。","appearance":"体长约10.5至12.5厘米，体重介于9.5至14克之间，灌丛绿莺雀上半身呈深灰色橄榄色，下半身橄榄黄至淡黄色，翅膀和尾羽为暗绿色，翼缘有绿黄边，尾羽呈暗绿灰色。眼虹膜颜色多样，从黄色到白色不等，喙色由灰至粉红，腿色为蓝灰或暗粉色。幼鸟的特征包括暗色的喙和虹膜，但仍保留着橄榄绿的背部和黄色的胸腹部。不同亚种间在整体羽毛色调和眼色上有细微差异。","call":"发出一系列滑音或双音节的鸣叫，如“chi-cheer, chi-cheer”或“du-wee, du-wee”，重复5至20次，节奏缓慢，不同于其他绿莺雀种类。还有鼻音的责骂声“nyaa-nyaa-nyaa”和其他尖锐的声音。","habits":"灌丛绿莺雀栖息于低矮密集的灌木丛、油棕榈种植园和废弃香蕉种植园中的竹林，海拔高度从海平面至1200米，主要生活在450米以下。它们以蜘蛛、耳虫、鳞翅目幼虫和其他小型昆虫为食，偶尔食用种子和植物碎片。通常在低树和高灌木丛中觅食，有时会悬停捕捉叶底下的猎物，常以成对或3至4个个体的小群体活动，可能代表家庭群。","breeding":"繁殖季节从4月至7月，也有记录在12月筑巢的情况。在哥斯达黎加，它们的巢是由细软的纤维制成的半球形吊篮，外部有时覆盖绿色苔藓，悬挂于树枝的细横叉上，高度4至10米。每次产卵2至3枚，蛋壳呈白色，带有巧克力棕色细斑点。幼鸟可能会被紫辉牛鹂寄生。在托巴哥岛，巢是一个深杯状结构，由叶子、茎和草构成，离地面1.7至10米，每次产卵三枚，蛋壳同样为白色，有稀疏的棕色斑点。","identification":"灌丛绿莺雀与金额绿莺雀的区别在于缺乏褐色前额冠和较浅的黄色下体饱和度。亚种间的主要区别在于整体羽毛色彩和眼色的不同。","protection":"IUCN：LC（无危）。灌丛绿莺雀在多数地区被视为常见或丰富，可能因为适应了高度改变或再生的栖息地而数量有所增加。在托巴哥岛上，尽管局限于这个面积仅为295平方公里的岛屿，但由于依赖于改变和破碎化的林地环境，被认为风险较小。","distribution":"繁殖区域包括哥斯达黎加至委内瑞拉北部，非繁殖区域未明确提及。在中美洲南部和南美洲北部，从委内瑞拉至哥伦比亚均有分布，特别在托巴哥岛有其独特的亚种。","other":"灌丛绿莺雀能够倒挂觅食，以提高觅食效率和防范捕食者。"},{"name":"橄榄绿莺雀","english_name":"Olivaceous Greenlet","scientific_name":"Hylophilus olivaceus","overview":"橄榄绿莺雀（英文名：Olivaceous Greenlet，学名：Hylophilus olivaceus），是雀形目莺雀科绿莺雀属的小型鸣禽。分布于南美洲的东安第斯山脉云雾森林，主要在厄瓜多尔和秘鲁的东部斜坡地区。其独特的黄色下体和头顶、淡色眼睛及粉红色喙，有助于与其它相似物种区分开来。","appearance":"该鸟体型小巧，拥有醒目的黄色下体和头顶，淡色的眼睛和粉红色的喙，这些特征明显区别于其分布范围内的其他物种。通常栖息于树冠层，偶尔加入混合物种的鸟群。","call":"橄榄绿莺雀的鸣声频繁而响亮，发出一系列尖锐有时单调的音符，如“twee-twee-twee…”或“soowe-soowe-soowe …”，其声音在林间回荡。","habits":"栖息于亚热带或热带湿润的山地森林，主要活动于树冠层。具有跟随混合物种鸟群的习性，常在高处活动。","identification":"通过黄色的下体和头顶、淡色眼睛及粉红色喙，可以与同域的其他物种相区分。","distribution":"分布于南美洲的东安第斯山脉，具体在厄瓜多尔（从纳波省南部至萨莫拉钦奇佩省）和秘鲁（包括卡哈马卡、南亚马逊、圣马丁，以及从瓦努科省南部到胡宁省北部）。"},{"name":"棕颈绿莺雀","english_name":"Rufous-naped Greenlet","scientific_name":"Pachysylvia semibrunnea","overview":"棕颈绿莺雀（英文名：Rufous-naped Greenlet，学名：Pachysylvia semibrunnea），是雀形目莺雀科 Pachysylvia 属的鸟类。与灰白的脸部和下体形成鲜明对比，背部呈橄榄绿色。分布于南美洲的委内瑞拉西北部、哥伦比亚和厄瓜多尔北部的山地森林中。","appearance":"成年棕颈绿莺雀的冠羽、颈背和耳羽为丰富的棕红色，脸部的颊纹、眼周区域为灰白色。喉部白色，与黄色胸部由一道带点棕红色的胸带分隔。腹部、侧腹、肛周和下尾覆羽淡黄色。上背和肩羽橄榄绿色，翼羽暗绿色边缘较浅。下翼覆羽淡黄色，飞羽和尾羽暗绿色，边缘橄榄绿。雌雄同色。关于幼鸟的描述目前未见报道。","call":"其叫声独特，是识别该物种的重要依据。","habits":"棕颈绿莺雀主要栖息在海拔1000-2000米的山地森林中，常见于次生林和边缘地带。它们通常单独或成对出现，随混合物种群在森林树冠层觅食。","breeding":"关于棕颈绿莺雀的繁殖生态细节尚未充分研究。","identification":"与其他绿莺雀的区别在于其较高的海拔分布和独特的冠羽颜色。与本地同域的褐顶绿莺雀相比，后者有淡色眼环和较深的下体，缺乏颈背的棕红色，鸣声简单，栖息于林下层。","protection":"IUCN状态未知。","distribution":"分布于南美，从委内瑞拉西北部至厄瓜多尔东部，主要在安第斯山脉的区域。"},{"name":"金额绿莺雀","english_name":"Golden-fronted Greenlet","scientific_name":"Pachysylvia aurantiifrons","overview":"金额绿莺雀（英文名：Golden-fronted Greenlet，学名：Pachysylvia aurantiifrons），是雀形目莺雀科 Pachysylvia 属的鸟类。小型的莺雀科鸟类，分布于南美洲北部，包括巴拿马、哥伦比亚、委内瑞拉和特立尼达岛。其显著特征为头部前额的金色，但这一标志在野外观察时并不明显。","appearance":"体长约11至12厘米，体重平均9.5克。头顶呈淡褐色，前额更显橄榄赭色；上体绿色偏褐，臀部转为黄绿色；翅膀覆羽及肩部暗绿褐色；初级和次级飞羽灰黑色，边缘绿色，闭合时翅膀呈现绿色调；尾羽橄榄绿色；下体颜色较淡，胸腹部灰色偏黄，侧面颜色更鲜艳；下腹及臀部黄色；虹膜棕色或黑色；喙上部暗角质色，下部粉红带暗；腿灰色或铅色。性别相似，幼鸟描述未正式记录。","call":"鸣叫为简短的颤音短语，通常被描述为chee-veee。","habits":"栖息于森林及次生林地带，活动于树冠中层。以昆虫和蜘蛛为主要食物来源，通常在树冠的上中层觅食，常形成小群。","breeding":"筑巢于树枝或藤蔓上，巢型为深杯状。每窝产卵三枚，卵白色带有棕色斑点。寄生现象常见，如被闪亮牛鹂寄生。","identification":"与近似种的区别在于头部前额的金色，尽管在自然环境下不易察觉。颜色模式和体型有助于区分。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲北部，包括巴拿马、哥伦比亚、委内瑞拉和特立尼达岛。","other":"无"},{"name":"乌顶绿莺雀","english_name":"Dusky-capped Greenlet","scientific_name":"Pachysylvia hypoxantha","overview":"乌顶绿莺雀（英文名：Dusky-capped Greenlet，学名：Pachysylvia hypoxantha），是雀形目莺雀科 Pachysylvia 属的鸟类。活跃于南美亚马逊雨林的鸟类。其特征为上体呈淡绿色，头部为橄榄棕色，下体黄色，喙部淡桃色。性别间无明显差异。","appearance":"体长约11.5至12厘米，体重约17克。头冠及颈背为暗橄榄棕色，背部逐渐变为黄褐色，翼上覆羽和肩部黄绿色，尾羽基部和外缘较亮。下体包括翅膀下覆羽均为淡黄色，略带黄褐色调。喙上部深棕色，下部淡棕色或粉红色，腿灰色。幼鸟特征未详述。亚种间颜色略有差异，如fuscicapillus亚种上体更偏棕色，flaviventris亚种背部呈柠檬黄色调，icterica亚种上体更鲜亮，albigula亚种头顶色更深，inornata亚种头顶为赤褐色，胸腹部灰橄榄色。","call":"鸣声为短促的颤音，类似\"whitchy-whéét-wééu\"，重音在最后两个音节，交替出现\"pu-whitchy-wééu\"；叫声为嘶哑的\"dee-dee\"。","habits":"栖息于湿润森林的树冠层，通常在低地，海拔高度从近海平面至200米以上，在委内瑞拉可达200米，在秘鲁高达1100米。生活方式似乎定居，以昆虫为主食，包括毛虫。在森林上层活跃觅食，常倒挂于叶间觅食；常在觅食时鸣唱。常见于混合鸟群中。","identification":"与其他绿莺雀属物种相比，乌顶绿莺雀的头部颜色较为独特，上体色彩变化和下体的黄色有助于辨识。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲亚马逊流域，包括玻利维亚、巴西、哥伦比亚、厄瓜多尔、秘鲁和委内瑞拉的热带湿润低地森林。"},{"name":"黄颊绿莺雀","english_name":"Buff-cheeked Greenlet","scientific_name":"Pachysylvia muscicapina","overview":"黄颊绿莺雀（英文名：Buff-cheeked Greenlet，学名：Pachysylvia muscicapina），是雀形目莺雀科 Pachysylvia 属的小型鸟类。其显著特征为橄榄绿色的翅膀和背部与淡黄色脸颊和胸部形成鲜明对比。该物种主要栖息于南美洲亚马逊雨林的树冠层，常见于混合物种的鸟群中。","appearance":"黄颊绿莺雀体长约11.5至12厘米，体重介于9.5到13.5克之间。成鸟的头部侧边呈淡黄褐色，带有黑色灰色斑点的耳羽覆盖物；额头为灰棕色，头顶和颈背呈现清澈的蓝灰色，背部和肩部绿色，臀部颜色更为鲜亮；初级飞羽和次级飞羽为暗黑灰色，外羽缘宽而带绿色，闭合的翅膀呈现黄绿色外观；尾羽为暗绿色；下巴为灰白色，胸部为灰黄色，腹部灰白，上腹两侧淡黄色；虹膜为赤褐色、棕色或灰色；喙上部黑色，下部淡粉色；腿为浅粉色或淡灰色。雄雌外观相似，幼鸟特征未详述。griseifrons亚种比指名亚种更亮绿，头部侧面和眉纹更深的黄红色，前额纯灰无黄褐色调，喉部和胸部更黄。","call":"黄颊绿莺雀的鸣唱为响亮而清脆的'whitchy-ta-whééu'声，类似于新世界莺鸟（Parulidae）的叫声，频繁重复。","habits":"栖息于湿润森林的树冠和中层，既可见于高地森林，也可见于低洼地带的森林。通常在树叶密集处觅食，有时会倒挂。以昆虫（Orthoptera）和蜘蛛（Araneae）为食，成对或小群体活动，经常加入混合鸟群，偶尔与其他绿莺雀种混群。","breeding":"在委内瑞拉（Bolívar）的12月至5月期间，黄颊绿莺雀的鸣唱达到高峰，这可能指示着该时期的繁殖活动。除此之外，关于其繁殖的其他信息尚不明确。","identification":"黄颊绿莺雀与其他绿莺雀的区别在于其独特的颜色组合，尤其是脸颊和胸部的淡黄色，以及头部和背部的颜色差异。","protection":"IUCN：LC（无危）；黄颊绿莺雀在其分布范围内普遍常见，特别是在委内瑞拉，但由于它们容易被忽视，实际数量可能被低估。","distribution":"黄颊绿莺雀的分布区域集中在南美的亚马逊雨林，包括玻利维亚、巴西、法属圭亚那、圭亚那、苏里南和委内瑞拉。","other":"尽管黄颊绿莺雀在其自然栖息地中常见，但因其隐秘的生活习性，对于其生态习性的了解仍有待深入研究。"},{"name":"灰头绿莺雀","english_name":"Lesser Greenlet","scientific_name":"Pachysylvia decurtata","overview":"灰头绿莺雀（英文名：Lesser Greenlet，学名：Pachysylvia decurtata），是雀形目莺雀科 Pachysylvia 属的鸟类。广泛分布于中美洲至南美洲的热带森林地带，自墨西哥东北部至秘鲁西北部。以其灰蓝色头部（在墨西哥和中美地区）和单调重复的鸣声为显著特征。","appearance":"灰头绿莺雀身长9.4-10.2厘米，体重6.6-10.3克。头顶和侧面呈灰色，眼圈白色，上体明亮的橄榄绿色，尾羽橄榄绿，翅膀外缘绿色，下体白色带淡柠檬黄色胸部，两翼下方和腹部黄绿色。幼鸟上体呈淡橄榄色，下体带有褐色调。存在多个亚种，其中minor亚种冠部更偏向灰色。","call":"其鸣声被描述为一系列愉悦而略显安静的2-3个乐句，连续重复并转换成不同的旋律，‘chi-chi-cher cher cher’。","habits":"栖息于低地到海拔1000米的湿润常绿森林、森林边缘和半落叶林。以昆虫和少量果实为食，活跃于树冠层，偶尔也会在灌木丛中觅食。通常成对或家庭群活动，常见于混合鸟群中。","breeding":"繁殖期从3月开始，筑巢时间可延续至6月末。巢为深杯状，由枯叶、竹条和草构成，内衬精细植物纤维，高悬于4-14米的树枝分叉处。每窝产2枚白色蛋，带有棕色斑点，孵化期约16天，雏鸟由双亲共同喂养，离巢期约为12天。","identification":"灰头绿莺雀与黄绿莺雀的区别在于灰头绿莺雀的鸣叫声更为缓慢且悦耳。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲，具体包括墨西哥东部至秘鲁西北部，从海平面至海拔1200米的高度。","other":"能够适应多种生境，包括再生林区，显示了较强的环境适应能力。"},{"name":"褐顶绿莺雀","english_name":"Tawny-crowned Greenlet","scientific_name":"Tunchiornis ochraceiceps","overview":"褐顶绿莺雀（英文名：Ochre-crowned Greenlet，学名：Tunchiornis ochraceiceps），是雀形目莺雀科 Tunchiornis 属的鸟类。分布于墨西哥南部至厄瓜多尔西北部的低地潮湿森林，体小羽绿，顶冠黄褐，鸣唱为清晰哨音，是林下层不易察觉却常见的林莺类鸟。","appearance":"体长9.5–12.5厘米，体重8.4–13.5克。头顶黄褐至橙褐，前额近嘴基更黄；上体橄榄褐，腰羽微绿；翼覆羽及飞羽深灰黑，外缘浅褐，合翼呈褐色调；尾羽暗褐，羽缘肉桂褐；耳羽灰褐，喉灰带淡黄绿，胸橙赭，腹部中央鲜黄，两胁灰黄；虹膜淡灰，嘴灰上部较深，脚粉至灰色。雌雄同色。幼鸟虹膜较深，头和上体带酒红，下体赭色。pallidipectus 胸色较淡，腹部黄色更浅；nelsoni 与 pallidipectus 近似但总体更绿；bulunensis 喉部灰色范围小，下体灰绿，背部暗橄榄绿而与橙褐冠成对比。","call":"鸣唱为高频、哀怨似虫声的“wheee”或“swee”，次数不定，偶有前颤；叫声为重复的粗哑鼻音“doy-doy-doy”。在秘鲁，鸣唱为清晰下滑或偶上升的长哨“heeeeeeeeu”；叫声为低哑啁啾“djreeee…”或鼻音“naaa”。","habits":"栖于潮湿常绿或半落叶林的林下植被，偶尔在中层活动；海拔自海平面至1200米（巴拿马最高1550米）。主要食节肢动物（蟑螂、毛虫、蚂蚁、蜘蛛）及少量肉质小果；常在森林中下层倒挂取食，常与小林莺、霸鹟等混群。","breeding":"繁殖期记录：哥斯达黎加4月有卵、5月有雏；巴拿马7月中旬筑巢；1月底雌鸟输卵管有卵；墨西哥瓦哈卡5月底雄鸟生殖腺膨大；委内瑞拉2月与4月雄鸟生殖腺膨大；哥伦比亚2月配对。巢为半球形深杯，外覆苔藓，中层细纤维，内层种子绒及细纤维，用边缘固定于水平枝叉，离地1–7米。每窝2枚卵，白底紫灰斑或乳白底褐斑，约18.3×13.1毫米，重1.73克。雌鸟孵卵15天，双亲育雏，雏期11–14天。","identification":"与橄圭亚那绿莺雀相比，本种头顶明显黄褐而非橄榄，鸣唱为单哨音而非双哨句；与帕拉绿莺雀相比，本种虹膜浅灰。亚种间差异：pallidipectus 胸色最淡；nelsoni 更绿；bulunensis 下体灰绿且背冠对比明显。","protection":"IUCN: LC（无危）。整体常见，厄瓜多尔稀少。对因刀耕火种造成的小片森林碎片化敏感。","distribution":"繁殖区：墨西哥南部（韦拉克鲁斯、瓦哈卡）向东经尤卡坦半岛至危地马拉北部和伯利兹；热带洪都拉斯至巴拿马西部；巴拿马奇里基至西达连；东达连及相邻哥伦比亚西至厄瓜多尔西北。","other":"原褐顶绿莺雀复合体中指名亚种与 ochraceiceps、pallidipectus、nelsoni 与 bulunensis 共五个亚种独立成种。"},{"name":"白腹凤鹛","english_name":"White-bellied Erpornis","scientific_name":"Erpornis zantholeuca","overview":"白腹凤鹛（英文名：White-bellied Erpornis，学名：Erpornis zantholeuca），是雀形目莺雀科白腹凤鹛属的鸟类。白腹凤鹛属的唯一物种。体小，约11-13厘米，重8-17克，拥有突出的冠羽，颜色为橄榄绿或金褐色，下体灰白色，尾下覆羽黄色。广泛分布于喜马拉雅山脉至婆罗洲，常见于多种森林环境中。","appearance":"白腹凤鹛的上体呈黄绿色，下体灰白，尾下覆羽明亮的黄色。具有短而直立的冠羽，方形尾巴，喙大部分淡色、尖锐且略弯，腿较短且纤细。成鸟和雌雄相似，幼鸟较暗，上体和次级飞羽带棕色调。","call":"鸣声为短暂高音的下降颤音“si’i’i’i’i”，或升降的“ss ss ss se se se se”，或仅上升且快速连续的颤音“chechecheche”。典型叫声为响亮刺耳的鼻音“nher-nher”或“jeeer-jeeer-jeeer”，穿插着嘁嘁喳喳的音符和干涩的颤音。","habits":"白腹凤鹛主要以小型蚱蜢、蟋蟀和其他昆虫及其幼虫为食，也吃浆果、软无花果和花蜜，偶尔食用种子。它不如其他凤鹛类群居，全年可见单个个体，有时成对或小群活动，经常与莺类和其他小型鸟群混合。频繁出现在树冠下层和较高的灌木丛中，常倒挂如山雀。","breeding":"繁殖习性信息缺失。","identification":"与色彩相似的莺类相比，白腹凤鹛的特征在于其明显的羽冠。不同亚种间颜色差异主要表现在上体更绿或下体更灰，某些亚种上体带有轻微的棕色调。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括喜马拉雅山脉至婆罗洲，具体国家有孟加拉国、不丹、文莱、柬埔寨、中国、印度、印度尼西亚、老挝、马来西亚、缅甸、尼泊尔、新加坡、台湾、泰国和越南。","other":"白腹凤鹛曾被误认为是'白腹凤鹛'，实际是与鸣禽中的Vireonidae科关系最近的物种，目前归入Vireonidae科，成为少数旧世界代表之一。"},{"name":"棕腹鵙鹛","english_name":"Black-headed Shrike-babbler","scientific_name":"Pteruthius rufiventer","overview":"棕腹鵙鹛（英文名：Black-headed Shrike-babbler，学名：Pteruthius rufiventer），是雀形目莺雀科鵙鹛属的大头鸣禽。其雄鸟和雌鸟的羽毛颜色截然不同，雄鸟具有橙色背部、白色喉咙、橙黄色腹部以及黑色头部和翅膀；而雌鸟则呈现出绿色翅膀、灰色头部，头顶较暗，耳后有一三角形斑块，腹部呈现温暖的鲑鱼粉红色而非雄鸟的橙黄色。棕腹鵙鹛主要栖息于成熟的丘陵森林，常见于混合物种觅食群中。","appearance":"雄鸟拥有醒目的橙色背部，白色喉咙，橙黄色腹部，黑色头部和翅膀。雌鸟则是绿色翅膀，灰色头部，头顶深色，耳后有三角形斑块，腹部为温暖的鲑鱼粉红色。下胸及臀部为酒红褐色，尾端和次级飞羽末端有窄带的栗色。","habits":"棕腹鵙鹛通常结成小群体活动，经常加入由山雀和其他鵙鹛类组成的‘鸟潮’。它们对人类表现出漠然的态度，不怕生。","identification":"雄鸟与雌鸟羽毛颜色差异显著，可通过头部颜色、翅膀颜色以及腹部色调进行区分。","distribution":"分布于喜马拉雅山脉至缅甸北部，中国南部以及越南西北部。具体分布区域包括远东地区的喜马拉雅山脉至北缅甸，南中国和越南西北部。"},{"name":"爪哇红翅鵙鹛","english_name":"Pied Shrike-babbler","scientific_name":"Pteruthius flaviscapis","overview":"爪哇红翅鵙鹛（英文名：Pied Shrike-babbler，学名：Pteruthius flaviscapis），是雀形目莺雀科鵙鹛属的鸟类。独特的中等体型鸟类，别称源自其独特的黑白相间的外观与鲜明的黄色翼斑。该物种仅分布于印度尼西亚的爪哇岛山区。","appearance":"雄性爪哇红翅鵙鹛上部深色，下部白色，头部黑色，眼眉处有一显著的白色条纹，翅膀上有一块醒目的黄色区域。雌鸟颜色较为暗淡，上部灰橄榄色，翅膀和尾巴橄榄黄，眼眉较弱。成年雄鸟的冠羽、颊部、耳羽为黑色，眼眉白色，背部中灰色，臀部更灰色，上翼和尾部黑色带蓝光泽，翼内侧有黄色部分和栗色边缘，翼端白色。雌鸟头部灰橄榄色，上体同样色调，下体淡白色带橄榄色晕染。幼鸟的特征介于两性之间。","call":"其鸣唱为一系列清脆但略显单调的3至5个音节，通常表现为‘wi-chew-chew’或‘wi-chew-ba-chew-ba’。","habits":"爪哇红翅鵙鹛栖息于山地和亚山地森林的中层和高层，海拔高度在1000至3000米之间。它们以昆虫为食，常在枝叶丛中觅食，有时会加入混合鸟群。","breeding":"繁殖信息知之甚少，但有记录显示4月间有雄鸟和雌鸟在巢中被拍摄到，而1月末有仍然依赖父母的已离巢幼鸟。","identification":"雄鸟与雌鸟的辨识主要依据色彩差异，雌鸟颜色更为柔和，眼眉不那么明显。与前属种红翅鵙鹛的区别在于结构上的差异。","protection":"IUCN：LC（无危）。爪哇红翅鵙鹛是爪哇和巴厘森林特有种，总体分布范围估计为148,000平方公里，数量从少见至相对常见，但总体趋势下降。","distribution":"分布于爪哇岛的山区。","other":"过去被认为是红翅鵙鹛的一个亚种，但现在已被确认为独立物种。"},{"name":"喜山红翅鵙鹛","english_name":"Himalayan Shrike-babbler","scientific_name":"Pteruthius ripleyi","overview":"喜山红翅鵙鹛（英文名：Himalayan Shrike-babbler，学名：Pteruthius ripleyi），是雀形目莺雀科鵙鹛属的鸟类。中等体型的鵙鹛。雄鸟头部黑色，胸部有明显的白色条纹，背部灰色；雌鸟头部灰褐色，翅膀和尾巴边缘绿色。分布于喜马拉雅山脉西部，常见于巴基斯坦北部至印度和尼泊尔中部。此物种曾被认为是爪哇红翅鵙鹛的一个亚种。","appearance":"体长约14厘米，体重29至44克。雄鸟具黑色冠羽和白色腹部，上体灰色，翼羽和尾羽边缘有明显的白色斑点。雌鸟头部灰褐色，翅膀和尾羽边缘绿色，下体白色带淡黄色调。不同亚种在羽毛颜色细节上有显著差异。","call":"鸣唱为连续响亮、节奏感强的音符系列，通常由4至6个音节组成，带有短暂的弱音前奏，声音持续约1至1.5秒。叫声包括短促的'pink'声和受惊时发出的刺耳的颤音。","habits":"栖息于常绿阔叶林、橡树杜鹃林、针叶林和高山植被区，海拔高度从900米至2700米，冬季可能降至300米。以昆虫为主食，包括蚱蜢、蛾类、毛虫和甲虫，也吃浆果、果实和种子。通常单独、成对或小群（6至15只）活动，常与其他鸟类混合群聚。","breeding":"繁殖季节在印度、缅甸和中国为4月至6月，泰国和越南南部为1月至4月，老挝为4月，马来西亚半岛为2月至6月。巢建于树干枝叉处，离地面4.6至13米，由根须、纤维和少量树枝构成，外表覆盖苔藓和地衣，内部衬以细根须，一次产卵2至5枚，卵色为白色或粉白色，带有深紫色斑点。","identification":"雄鸟的黑色头部和白色眼后条纹，以及雌鸟头部的灰褐色和翼尾的绿色边缘是识别的关键特征。与爪哇红翅鵙鹛的区别在于羽毛颜色和分布区域。","protection":"IUCN：LC（无危）","distribution":"分布于喜马拉雅山脉西部，包括巴基斯坦北部、印度、尼泊尔中部、西藏、东南亚大陆以及苏门答腊和婆罗洲的部分地区。","other":"曾被错误分类为旧世界鵙鹛科，分子研究表明其与新世界莺科关系密切，现已归入莺科。"},{"name":"红翅鵙鹛","english_name":"White-browed Shrike-babbler","scientific_name":"Pteruthius aeralatus","overview":"红翅鵙鹛（英文名：White-browed Shrike-babbler，学名：Pteruthius aeralatus），是雀形目莺雀科鵙鹛属的小型鸟类，广泛分布于东部喜马拉雅山脉和东南亚地区，从北部缅甸至柬埔寨南部。雄鸟羽毛独特，腹部清洁白色，背部黑色，灰背，具有白色眉毛和两道鲜艳的橙色条纹接近翼尖；雌鸟外观相似，但色彩较淡，黑色替换为灰色，橙色变为黄绿色。通常在山地森林中成对或小群体活动。","appearance":"红翅鵙鹛体型健壮，雄鸟头部黑色，具显著白色眉毛，翅膀黑色带有鲜明的黄色至栗色次级飞羽，尾巴短黑；雌鸟头部灰色，有时带微弱的浅灰色眉毛，上体褐色至橄榄绿，翼部橄榄绿色，下体颜色更淡。幼鸟特征不详。成年雄鸟头、颈略呈光泽黑色，与白色超眼纹形成对比，背部灰蓝色，尾部均匀黑色，翼部黑色，仅部分初级飞羽有白色边缘，形成飞行中的醒目白色楔形图案。","call":"鸣唱为有力的系列音符，每二至三音节间有轻微停顿：“dyudyu-dyu-dyudyu！”","habits":"红翅鵙鹛栖息于山地森林，常加入混合鸟群，偏好在中海拔森林的树冠层活动，以多种昆虫和浆果为食。在非繁殖季节，它们常被观察到在混合物种群中活动。","identification":"雄性红翅鵙鹛的独特组合——白色超眼纹、白色下体和明亮的栗色次级飞羽——在整个分布范围内独一无二。雌鸟与棕腹鵙鹛类似，但后者上体橄榄绿，喉部灰色，下体橙黄色，容易通过良好视角区分。","protection":"IUCN：LC（无危）","distribution":"分布于喜马拉雅山脉西部，从巴基斯坦、尼泊尔、不丹、孟加拉国、缅甸、柬埔寨、老挝、越南、马来半岛、印度尼西亚的苏门答腊岛和婆罗洲，以及中国西藏、四川、广西、福建、云南、海南等地。","other":"红翅鵙鹛曾被认为是爪哇红翅鵙鹛的一个亚种，近年来的分子遗传学研究支持其独立物种地位。"},{"name":"越南鵙鹛","english_name":"Dalat Shrike-babbler","scientific_name":"Pteruthius annamensis","overview":"越南鵙鹛（英文名：Dalat Shrike-babbler，学名：Pteruthius annamensis），是雀形目莺雀科鵙鹛属的鸟类。是亚洲特有的一种小型鸟类，原被认为是旧世界鵙科的一员，但最新的研究表明其与美洲鵙有亲缘关系，可能归类于Vireonidae科。在越南南部的Da Lat高原上广泛分布，是该地区的特有种。","appearance":"成年越南鵙鹛体长约14厘米，体重介于29至44克之间。雄鸟具有黑色的冠羽和白色的下体，背部呈灰色，最显著的特征是大胆的白色眼上纹。雌鸟的头部为灰色，翅膀和尾巴边缘带有绿色。不同亚种在羽毛细节上存在明显差异，如validirostris亚种雄鸟翼部暗栗色，雌鸟冠羽具灰色，ricketti亚种雄鸟耳羽灰蓝，雌鸟翼部栗色减少，annamensis亚种雄鸟上体稍暗，雌鸟下体较淡，schauenseei亚种雌鸟翼部几乎无栗色，cameranoi亚种雌鸟非常相似，robinsoni亚种大小介于爪哇红翅鵙鹛和其他大陆亚种之间。","call":"鸣唱由重复的响亮、尖锐、节奏感强的音符系列组成，通常在印尼为4至6个音符，在马来西亚半岛为4至5个，在尼泊尔为3至6个，持续时间为1至1.5秒。叫声包括短促的‘pink’声，以及受惊时的刮擦声。","habits":"栖息于常绿阔叶林、橡树杜鹃林、针叶林和山地石楠植被中，高度范围从900至2700米，在印度次大陆局部可低至300米（可能仅冬季）。以昆虫为主食，包括蚱蜢、蛾类、毛虫和甲虫，也吃浆果、果实和种子。单个、成对或小群体活动，通常与大型鵙类混群。觅食时动作缓慢而有条理，主要在树冠层活动，沿着树枝侧向移动，检查苔藓和地衣，寻找昆虫和浆果。","breeding":"繁殖季节在印度、缅甸和中国为4月至6月，在泰国和越南南部为1月至4月，在老挝为4月，在马来西亚半岛为2月至6月，在婆罗洲北部为2月和3月。巢为松散但结实的摇篮状或浅杯状，由根须、纤维、藤蔓和少量枝条构成，外层涂覆苔藓和地衣，内部衬以根须，悬挂于树木水平分叉处4.6至13米高。每次产卵2至5枚，蛋壳颜色为白色或粉白，遍布深紫色或紫棕色细点和斑点。","identification":"越南鵙鹛与同属其他物种的区别在于其独特的头冠颜色和下体色彩，以及特定的鸣唱模式。不同亚种在羽毛颜色和图案上有细微差别。","protection":"IUCN：LC（无危）。在巴基斯坦、尼泊尔、不丹、印度等地常见。在不丹的温带区域，密度达到每公里道路3.9个领地，使其成为该海拔区域最常见的森林鸟类之一。","distribution":"分布于印度次大陆、中国西藏、东南亚大陆、苏门答腊岛和婆罗洲。在印度次大陆的高度范围从900至2700米，在中国西藏为2000至2135米，在东南亚大陆为700至2500米，在苏门答腊为950至2700米，在婆罗洲为750至3100米。","other":"越南鵙鹛在某些地区是较为常见的森林鸟类，但在巴基斯坦的Murree Hills较为普遍，而在其他地区则稀少且分布零散。"},{"name":"淡绿鵙鹛","english_name":"Green Shrike-babbler","scientific_name":"Pteruthius xanthochlorus","overview":"淡绿鵙鹛（英文名：Green Shrike-babbler，学名：Pteruthius xanthochlorus），是雀形目莺雀科鵙鹛属的小型鸟类，体长约12-13厘米，具有橄榄绿色上体和独特的白色眼圈。头部略圆，喙短而粗厚，看似柳莺但体型更为粗壮。分布于喜马拉雅山脉至缅甸东北部，栖息于山地森林。","appearance":"雄鸟头部灰色，背部橄榄绿色，喉部和胸部呈淡灰白色，腹部和臀部黄色，翼线亦黄。雌鸟色彩较暗淡，头部灰褐色，背部略带绿黄色。初级覆羽灰，具浅色翼斑。两性均具白色的厚实眼圈。","habits":"栖息于海拔2100-3000米的山地森林，偏好温带湿润环境。冬季可能降至更低海拔。以昆虫如蚂蚁、甲虫及浆果、种子为食。","breeding":"繁殖季节主要在5月至6月，巢通常建在距地面3-8米的高度。","identification":"与其他鵙鹛属鸟类相比，其白色眼圈和黄腹是显著的辨识特征。","distribution":"分布于喜马拉雅山脉至缅甸东北部，包括不丹、中国、印度、缅甸、尼泊尔、巴基斯坦和越南的部分地区。在中国大陆，见于西藏东部、云南西北部、四川西部、甘肃南部、陕西南部等地。"},{"name":"栗喉鵙鹛","english_name":"Black-eared Shrike-babbler","scientific_name":"Pteruthius melanotis","overview":"栗喉鵙鹛（英文名：Black-eared Shrike-babbler，学名：Pteruthius melanotis），是雀形目莺雀科鵙鹛属的色彩斑斓的小型鸟类。主要分布在尼泊尔至中国西南及东南亚地区，其自然栖息地位于喜马拉雅山脉至马来西亚西部的东洋界，偏好居住在亚热带或热带湿润的山地森林中。","appearance":"该鸟拥有卡通般的圆眼外观，两性均呈现鲜艳的黄色腹部，黄绿色背部，以及暗锈色的喉咙。雌鸟相比雄鸟略显苍白，标记也不那么鲜明。其虹膜呈红褐色，上喙深灰色，下喙颜色稍淡，脚部为浅褐色。","call":"其鸣唱高亢、快速且重复，常被描述为“tweeweeweeweeweeweewee”的声音。","habits":"栗喉鵙鹛栖息于山地森林中，常与山雀、柳莺及燕尾等混群活动。它们的行为显得较为懒散，站立时姿态十分挺直。","identification":"与Clicking和Trilling Shrike-Babblers极为相似，但缺乏额头上任何红色色调，拥有更广泛的银白色眉纹和颈背，整体颜色更深沉。","distribution":"分布于喜马拉雅山脉至马来西亚西部，主要在东洋界的亚热带或热带湿润山地森林中。"},{"name":"爪哇栗额鵙鹛","english_name":"Trilling Shrike-babbler","scientific_name":"Pteruthius aenobarbus","overview":"爪哇栗额鵙鹛（英文名：Trilling Shrike-babbler，学名：Pteruthius aenobarbus），是雀形目莺雀科鵙鹛属的鸟类。色彩鲜艳的小型鸟类，以独特的外观和声音活跃于印度阿萨姆至中国南方的云南和广西、东南亚及爪哇的山区森林中。","appearance":"雄性爪哇栗额鵙鹛拥有明亮的黄色腹部，黑色和白色的翼带在阳光下闪烁，深色的面颊和醒目的红褐色喉咙。雌鸟则较为朴素，带有肉桂色和灰色的翼带，前额和眉线前半部分略带淡肉桂色。两性均有亮银色的眼圈和穿过眼睛的暗线。","call":"其歌声为响亮且重复的高音系列，叫声干涩而有嗡嗡声。","habits":"通常栖息于山区森林的中上层，有时会加入混合鸟群中活动。","identification":"雄鸟的独特颜色组合和雌鸟的肉桂灰翼带使其易于识别。","distribution":"该物种分布于爪哇岛的山区，是爪哇特有的鸟类。","other":"曾被认为是栗额鵙鹛的指名亚种，现已确认为独立物种。"},{"name":"栗额鵙鹛","english_name":"Clicking Shrike-babbler","scientific_name":"Pteruthius intermedius","overview":"栗额鵙鹛（英文名：Clicking Shrike-babbler，学名：Pteruthius intermedius），是雀形目莺雀科鵙鹛属的体小而色彩亮丽的鸟。分布于印度阿萨姆至中国南方的云南和广西、东南亚及爪哇等地。曾与爪哇栗额鵙鹛视为同一物种，后分拆为两个独立种。","appearance":"整体呈明亮的黄色，喉部和眼周带有如同干涸血液的污渍色斑，眼环和翼纹为黑银相间。细长的喙尖端呈银色并带微钩，用于从树叶上捕获昆虫。","call":"发出强烈、持续且重复的“wiCHE, wiCHE, wiCHE, wiCHE”叫声。","habits":"栖息于山地森林的矮树顶部，常见于混群中，偏好亚热带湿润低地森林和山地森林。","identification":"与栗额鵙鹛相比，本物种具有独特的颜色标记和鸣叫声，以及不同的分布区域。","protection":"IUCN：LC（无危）","distribution":"分布于东洋界，具体包括印度阿萨姆邦、印度、缅甸东部至中国南部（云南、广西）、越南南部。","other":"关于该鸟的影像资料较为匮乏。"},{"name":"北岛鸫鹟","english_name":"North Island Piopio","scientific_name":"Turnagra tanagra","overview":"北岛鸫鹟（英文名：North Island Piopio，学名：Turnagra tanagra），是雀形目黄鹂科新西兰鸫鹟属的鸟类。新西兰北岛特有种。以独特的外观和行为习性而著称。","appearance":"北岛鸫鹟的体态特征尚需详细描述，包括其羽毛颜色、大小和性别差异。","habits":"这种鸟类生活在新西兰北岛的特定生境中，其活动范围、觅食习惯和迁徙模式有待进一步阐述。","identification":"与同属的其他物种相比，北岛鸫鹟的独特之处在于其分布区域和可能的行为特征。","distribution":"北岛鸫鹟仅分布在新西兰北岛，具体而言，其栖息地覆盖了北岛的多个生态区域。"},{"name":"纽西兰鸫鹟","english_name":"South Island Piopio","scientific_name":"Turnagra capensis","appearance":"南岛鸫鹟呈现橄榄褐色的主色调，翅膀和尾巴则带有红褐色，胸部点缀着斑点。它们的体型适中，是一种视觉上较为吸引人的鸣禽，同时表现出对人类相对不怕的态度。","habits":"南岛鸫鹟是杂食性的鸟类，其栖息地主要位于澳新界的新西兰南岛和斯图尔特岛，它们的活动范围和觅食方式适应了当地的环境条件。","distribution":"南岛鸫鹟主要分布于新西兰南岛和斯图尔特岛，这两个岛屿位于澳新界，构成了其核心的生存环境。"},{"name":"绿裸眼鹂","english_name":"Green Figbird","scientific_name":"Sphecotheres viridis","overview":"绿裸眼鹂（英文名：Green Figbird，学名：Sphecotheres viridis），是雀形目黄鹂科裸眼鹂属的鸟类。雄鸟具有独特的苔绿色体羽和黑色头部，配以鲜艳的红色面部皮肤；雌鸟呈褐色，腹部条纹明显，面部皮肤呈蓝灰色或粉红色。这种鸟主要分布于印尼的小巽他群岛中的罗地岛和帝汶岛，是当地特有种。","appearance":"雄性绿裸眼鹂拥有烟熏黑的头部至肩部，橄榄黄色的背部带暗色条纹，翼部深色，初级飞羽有白色边缘，次级飞羽和上覆羽有橄榄色边缘；中央尾羽深色，带有橄榄色浸染，内侧有白色端斑；喉咙和胸部为橄榄绿色，下胸颜色较浅，逐渐过渡到腹部的淡黄色和尾下覆羽的近白色。雌鸟的面部皮肤呈蓝灰色，上体棕色，有深色条纹，翼部深色，次级飞羽边缘呈绿色，尾羽暗棕色，带轻微的绿黄色洗染和微弱的白色尖端；下体奶油白色，重叠有深棕色条纹，从喉咙至胸上部偏黄。幼鸟类似雌鸟，但标记不那么鲜明。","call":"绿裸眼鹂的鸣唱包括模仿、喋喋不休和叽叽喳喳的声音，同时也发出尖锐的“wit”，“burr”和颤音：“klerr-wit-wit-wit-wit”。","habits":"通常成对或小群出现在低地的森林、林缘、林地和红树林中。它们以果实为主食，如无花果（Ficus），单独或结伴在树冠层觅食，也会在灌木较低处活动，经常加入混合物种的鸟群。","identification":"雄性绿裸眼鹂与更广泛分布的澳大利亚裸眼鹂相似，但体型较小，除肛周区域颜色较淡外，整个下体均为黄橄榄色（包括喉咙）。雌鸟与同属其他物种相比，可通过其独特的面部皮肤颜色和体色模式加以区分。","protection":"IUCN：LC（无危）。绿裸眼鹂在其分布范围内适度常见，但由于其栖息地的丧失和农业扩张，需对其种群进行监测。","distribution":"绿裸眼鹂分布于印尼的小巽他群岛中的罗地岛和帝汶岛，一般在海拔160米以下，但在某些地区，如山丘地带，曾有标本在850米高度被采集。"},{"name":"白腹裸眼鹂","english_name":"Wetar Figbird","scientific_name":"Sphecotheres hypoleucus","overview":"白腹裸眼鹂（英文名：Wetar Figbird，学名：Sphecotheres hypoleucus），是雀形目黄鹂科裸眼鹂属的鸟类。但由于近期对其数量的估计比原先的预期更为乐观，国际鸟盟和IUCN已将其保护级别下调至'Least Concern'（低危）。与更知名的澳裸眼鹂相似，但体型较小，雄鸟的下部全白。","appearance":"雄性白腹裸眼鹂具有醒目的外观，头部黑色，眼睛周围有红色裸露皮肤，上身橄榄绿色，下部洁白。雌鸟全身灰棕色，下部有显著的条纹。幼鸟类似雌鸟，但条纹较淡。成年个体长约26厘米，体重介于75至80克。","call":"雄鸟的复杂鸣唱包含模仿当地鸟类的声音，其叫声为尖锐的'WICK!'。","habits":"这种鸟常以群体形式出现在森林、边缘地带、灌木丛和耕作区。它们的飞行和活动特点尚未详尽记录。","breeding":"有关其繁殖行为的详细资料缺乏，但基于其生态习性，可以推测其繁殖模式可能与其他同类物种相似。","identification":"雄性白腹裸眼鹂的独特外观使其容易识别；而雌鸟的密集条纹和健壮体型与范围内的其他物种截然不同。","protection":"IUCN：LC（无危）","distribution":"仅分布于印尼的小巽他群岛中的Wetar岛。","other":"尽管Wetar岛上雨林覆盖率依然广泛，但该物种主要分布在岛的西北部。目前尚无保护区设立，但有提议建立一个约450平方公里的保护区，这可能对该物种的保护有益。"},{"name":"澳裸眼鹂","english_name":"Australasian Figbird","scientific_name":"Sphecotheres vieilloti","overview":"澳裸眼鹂（英文名：Australasian Figbird，学名：Sphecotheres vieilloti），是雀形目黄鹂科裸眼鹂属的鸟类。中型鸣禽，广泛分布于澳大利亚北部和东部、新几内亚南部以及印尼卡伊群岛的多种林地环境中。该鸟以裸露的眼周皮肤和粗壮的喙为显著特征。雄鸟上体橄榄色，下体黄色至灰喉，具有红眼周皮肤和黑色头冠与尾羽。雌鸟上体橄榄棕色，下体淡色并带细纹，眼周皮肤呈灰色，尾羽橄榄棕色。在果实丰富的树丛、公园和花园常见，通常以嘈杂的群居形式活动。","appearance":"雄鸟总长27–29.5厘米，体重97–146克。头部、脸、耳羽和颈为深黑色，眼周裸皮粉红或红色，上背灰色，下背、肩羽和臀部橄榄绿色，翅膀深褐，次级飞羽外缘橄榄绿，尾羽深色，最外侧三对尾羽外缘白色尖端，内缘大块白色斑点。下体灰至橄榄绿，腹部黄色和白色相间。雌鸟眼周裸皮暗紫灰色，头顶、颈和上背棕色，下背和背部橄榄棕色，臀部纯橄榄绿。翼部暗褐，初级飞羽窄白边，次级飞羽绿染，边缘淡黄白色。尾羽褐色，内羽上方绿染，外羽小白色尖端。下体淡色，胸至腹重褐色条纹，腹白色，具微弱条纹。幼鸟似雌鸟，但标记不明显。不同亚种在羽毛颜色和图案上有差异。","call":"鸣唱为犹豫的简单无旋律哨音系列，结尾下滑，例如“tu-tu-heer, tu-heer, tu-heer”。叫声包括短促尖锐的吠声“pow pow pow”和响亮的“scluck”；还有响亮的“see-kew”，重复无规律。能模仿其他鸟类的声音，包括各种鹦鹉、淡色杜鹃和同科其他鸟。","habits":"栖息于各种林地环境，如雨林、河流旁的大树、桉树林、沿海次生林、红树林、椰子种植园以及果树林，甚至出现在草原、城市公园和花园。主要分布在沿海地带，最高可达新几内亚海拔500米。群居，以寻找果树林为主，小群由年长个体组成，移动较少，而大群主要由年轻个体构成，移动距离更远。数百只可能在黄昏时聚集在栖息地。","breeding":"繁殖期在南部分布区为10月至次年2月，在北部分布区为9月至次年3月（偶尔4月和8月），每年产一到两窝。在松散的群体中繁殖，偶尔出现合作繁殖。巢为脆弱的深碗状，由藤蔓和细枝编织，置于树枝末端水平叉上，常位于高处，树种如无花果或纸皮树。巢有时被普通鹰鹃寄生。","identification":"雌鸟与橄榄背 Oriole 的区别在于后者嘴较长，眼红色，背部更绿。雄鸟中，flaviventris 亚种头部和颈部光泽黑色与橄榄绿上体界限分明，下体统一硫磺黄色；ashbyi 亚种背部更亮，腹部为中等黄色；cucullatus 亚种体型较大，喙较长，下体黄色更深；salvadorii 亚种与指名亚种相似，但体型较小，下胸、上腹和两侧主要为黄色，带橙色调。","protection":"IUCN：LC（无危）","distribution":"分布于印尼卡伊群岛（印尼摩鹿加群岛东南部）、新几内亚东南部、澳大利亚北部和东部。在澳大利亚北部和东部以及新几内亚南部为常见物种。","other":"曾被视为绿裸眼鹂的亚种，现已独立为单一物种。"},{"name":"杂色林鵙鹟","english_name":"Northern Variable Pitohui","scientific_name":"Pitohui kirhocephalus","overview":"杂色林鵙鹟（英文名：Northern Variable Pitohui，学名：Pitohui kirhocephalus），是雀形目黄鹂科林鵙鹟属的有毒鸟类。广泛分布于新几内亚北部及周边岛屿，栖息于低地和山麓的次生森林边缘，拥有变化多端的羽毛色彩。","appearance":"体长20-25.5厘米，体重74-103克，依亚种不同而异。头部颜色变化大，上体呈深红褐色，翅膀和尾巴为暗褐色。喉咙灰白，腹部铁锈色或淡黄色。虹膜红棕色至深红色，喙部颜色可为浅色、棕色或角质色，腿灰色。性别间外观相似，幼鸟与成鸟相似。亚种间的差异主要体现在羽毛的颜色和图案上。","call":"其鸣唱为响亮、音乐般的哨音与刮擦声混合的杂乱系列，起初音调较短，随后变得响亮和延长，常含上升的哨音，两个音符中第二个比第一个高，如“tow-hu, towhíhu-uwuwu”。叫声为上升的音节。","habits":"栖息于低海拔的次生森林和森林边缘，常见于低地灌木丛。其分布密度受地理位置影响，某些地区极为常见，可达当地鸟类总数的约2%。","identification":"与锈色林鵙鹟类似，但缺乏白色眼圈。黑色头部个体几乎与黑头林鵙鹟相同，但北方变种略大且栖息于更低海拔。","protection":"IUCN：LC（无危）。在某些区域非常常见，但在其他地方罕见或不存在。","distribution":"主要分布于新几内亚北部及邻近岛屿，属于澳新界的地理分布范围。","other":"2013年，基于分类学修订，从Variable Pitohui中分离出褐头林鵙鹟和棕背林鵙鹟，北方变种由此得名。"},{"name":"褐头林鵙鹟","english_name":"Raja Ampat Pitohui","scientific_name":"Pitohui cerviniventris","overview":"褐头林鵙鹟（英文名：Raja Ampat Pitohui，学名：Pitohui cerviniventris），是雀形目黄鹂科林鵙鹟属的鸟类。中型鸟类，分布于澳新界的Waigeo和印尼萨拉瓦蒂岛（四王群岛西北部，新几内亚附近）。拥有独特的锈色腹部，灰褐色头部，胸部和背部，翅膀和尾羽呈棕色。","appearance":"身长约为20-21厘米，头顶和头部两侧颜色较背部更浅、更偏灰色，上体呈现灰褐色，翅膀和尾部颜色更深，更偏向棕色。喉咙同样为灰褐色，下体（包括尾下覆羽）为铁锈色。喙黑色，虹膜深棕色。性别之间外观相似，幼鸟与成鸟类似。亚种之间差异不大，仅pallidus亚种在下体颜色上更为苍白，头、喉、上胸、背和臀部呈现淡灰黄色，翅膀和尾部颜色略深，胸部和腹部为淡黄褐色，翼展稍大。","call":"鸣唱为一系列间隔开的悠扬而复杂的哨音，通常由5至15个音符组成，每秒约1.0-1.2个音符的速度。短促低音哨声与急剧上升或下降的哨声交替，例如'wit...chow...wheEEo...weet...chlweEE...'。与棕背林鵙鹟和杂色林鵙鹟的鸣唱相比，本物种的鸣叫声明显更高，频率范围更宽。","habits":"生活在低地森林，具体的生活习性信息有限。","identification":"在范围内无其他鸟类具有相同的色彩模式。棕鵙鹟体型较小，锈色林鵙鹟体型较大且眼白色。","protection":"IUCN：LC（无危）。尽管对数量和状态了解甚少，但目前认为这种新确认的物种没有受到威胁。","distribution":"局限于西巴布亚低地EBA的较小区域，具体分布于Waigeo和Salawati（Raja Ampat Islands，新几内亚西北部）。"},{"name":"棕背林鵙鹟","english_name":"Southern Variable Pitohui","scientific_name":"Pitohui uropygialis","overview":"棕背林鵙鹟（英文名：Southern Variable Pitohui，学名：Pitohui uropygialis），是雀形目黄鹂科林鵙鹟属的鸟类。分布于新几内亚及其邻近岛屿，常见于低地的次生森林边缘。其羽毛颜色变化多样，雄鸟通常具有黑色头部、翅膀和尾巴，背部、腹部呈现栗色或橙棕色，而雌鸟头部和胸部可能更多巧克力棕色。少数已知有毒的鸟类之一，羽毛和皮肤中含有毒化合物homobatrachotoxins。","appearance":"体长22至25.5厘米。成年鸟与黑头林鵙鹟相似，但体型更大，颜色更深更丰富。指名亚种上背部、下胸和腹部呈深红棕色，其余羽毛为黑色；喙黑色，虹膜红色到红棕色，腿和脚灰色到深棕色。雌雄基本相似，尽管报道雌鸟的头罩更巧克力棕色，不延伸到胸部。幼鸟与成年鸟类似。各亚种间差异如下：nigripectus亚种雄鸟背部栗色，腹部铁锈色，余部羽毛黑色；aruensis亚种腹部色泽更深，更接近栗色，胸部混有黑色；meridionalis亚种头部、喉咙、上胸（有时下胸）、翅膀、下臀和尾巴黑色，背部锈色栗色，腹部和下尾羽覆羽红褐色；brunneiceps亚种头部和喉咙灰棕色到深棕色，背部锈红色，翅膀和尾巴棕色，下体深赭色，两性相似。","call":"brunneiceps亚种的鸣唱是一系列不同的柔和笛声，几乎不间断，例如'wee..wooh..wuw..weeoee..wuuw..'，常以突然的短促爆发形式发出，附近雄鸟会进行反唱。叫声为尖锐的责骂声'krrrreeuw'。不同亚种间的声音差异较大，但具体差异尚不清楚。与褐头林鵙鹟相比，本物种的鸣叫声明显音调更低，频率范围更窄，与杂色林鵙鹟相比也是如此，尽管后者有更复杂的鸣唱曲目。","habits":"以昆虫和果实为食，活动范围从林下层到树冠，经常隐藏在茂密的植被中。常加入混合物种觅食群。","identification":"与黑头林鵙鹟极为相似，但通常生活在较低海拔，尾巴基部以上为黑色而非棕色。不同亚种间的辨识要点主要在于颜色差异。","protection":"IUCN：LC（无全球性威胁）。在某些地区非常普遍，但在其他地区稀少或不存在。在极为常见的地方，可占当地总鸟类数量的约2%。","distribution":"分布于新几内亚西北部和南部，以及附近的印尼萨拉瓦蒂岛（Salawati）和Misool（四王群岛西北部），印尼阿鲁群岛（Aru Islands，新几内亚西南部）。","other":"2013年从杂色林鵙鹟中分离出来成为独立物种。"},{"name":"黑头林鵙鹟","english_name":"Hooded Pitohui","scientific_name":"Pitohui dichrous","overview":"黑头林鵙鹟（英文名：Hooded Pitohui，学名：Pitohui dichrous），是雀形目黄鹂科林鵙鹟属的中型鸣禽，分布于新几内亚的山地森林和边缘地带，包括印尼亚彭岛。其最显著的特征是拥有黑色头部、胸部、翅膀和尾巴，而身体其余部分呈红褐色。罕见的有毒鸟类，含有多种蝙蝠毒素化合物。","appearance":"成年黑头林鵙鹟体长约22至23厘米，体重介于65至76克之间。具有黑色上翼、头部、下巴、喉咙、上胸和尾部，其余羽毛为红褐色。喙和腿为黑色，虹膜颜色可为红褐色、深褐色或黑色。雌雄外观相似，幼鸟与成鸟相似，但尾羽和翼羽的边缘带有棕色色调。","call":"发出复杂多变的哨声，包括一系列低沉的、类似织布鸟的颤音、狼哨和咔哒声。其中一些叫声听起来像是‘pi-to-hui’。","habits":"栖息于从海平面到海拔2000米的雨林、森林边缘和次生植被区，常见于山丘和低山区。以水果、种子、昆虫和其他无脊椎动物为食，有时可能也会捕食小型脊椎动物。它们通常在小群体中活动，常参与混合物种觅食群，甚至担任领导者。","breeding":"繁殖期从10月持续到次年2月。巢建于离地面约2米处，由藤蔓构成，内衬更细的藤蔓，悬挂于细枝上。每窝产1至2枚蛋，尺寸约为27至32.8毫米×20.5至22.2毫米，表面有奶油色或粉红色底色，带棕色至黑色斑点和斑块，孵化期未知。幼鸟出生时覆盖白色绒毛，随后发育成成年羽毛。","identification":"与南方和北方可变林鵙鹟非常相似，但通常在更高海拔发现。通过声音辨识，黑头林鵙鹟的声音更低沉。此外，其独特的羽毛颜色模式也有助于识别。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚主岛和附近的亚彭岛。常见于海拔350至1700米的地区，偶尔下降至海平面，最高可达2000米。","other":"毒性对其自身有保护作用，既防掠食者又防寄生虫。当地猎人熟知其毒性，因此避免捕猎。"},{"name":"褐鹂","english_name":"Brown Oriole","scientific_name":"Oriolus szalayi","overview":"褐鹂（英文名：Brown Oriole，学名：Oriolus szalayi），是雀形目黄鹂科黄鹂属的鸟类。拥有深色头部和脸颊，橙色暗淡的喙，以及带有明显条纹的浅色下体。广泛分布于新几内亚低地至山脚地带，包括森林、红树林、种植园和灌木丛等多种生境。","appearance":"褐鹂体型中等，长度约25至28厘米，重量79至115克。上体呈中等棕色，头部颜色较淡，冠部有黑色条纹，肩部条纹较少；脸部和耳羽黑色，带有白色条纹，与颈部侧面和后冠形成对比；上翼深棕色；尾巴深棕色，除中央羽毛外，其余羽毛内侧有模糊的淡色尖端；下体淡黄色，下巴、喉咙和胸部有重黑色条纹，腹部条纹较轻；眼睛深红棕色；喙深红色、红棕色或深粉色；腿灰色或深棕色至黑色。雌雄相似，幼鸟有明显的白色眉纹和栗色上翼覆羽边缘；眼睛棕色，喙黑色。","call":"褐鹂发出响亮的笛音叫声，模仿盔吮蜜鸟的‘du-du-hooo’声，还有清晰的模仿其他多种鸟类的声音。其叫声包括下降的短音节和上升的双音节滑音，如‘titu-witu-whiew’，‘tip-top-tertertu’或‘nn-dudu-tiew’。","habits":"褐鹂主要栖息于受干扰的环境，如森林边缘和次生林，同时也能在低地和山脚雨林、季风林、沼泽林、画廊林、灌木丛、茂密的草原、红树林和种植园（如柚木、橡胶树、南洋杉松和花园）找到它们的身影。它们生活在海拔1850米以下，通常低于1200米的高度。褐鹂是定居性鸟类，主要在树冠中单独、成对或小群体觅食，以果实、昆虫（如毛虫、蛹）、草籽和可能的花蜜为食。","breeding":"筑巢活动在8月至9月间被报道，产卵发生在4月至5月和9月至11月，4月观察到孵卵的成鸟，1月发现雏鸟，9月见到离巢的幼鸟。它们建造粗糙的开放杯状巢，由树皮条编织，有时还包括树皮碎片和其他纤维，内部铺有细草和小枝条，像吊床一样悬挂在离地面2.5至15米高的细水平叉枝上。巢通常靠近盔吮蜜鸟的聚居地，有时也靠近胡德肉垂鸟巢附近。一窝产卵1至2枚，蛋壳颜色为褐色黄白，带有集中于钝端的巧克力棕色、橄榄棕色和灰褐色斑点，尺寸约为31至32.3×20.9至22.8毫米。雏鸟以果实和可能的幼虫为食。","identification":"与纹头吸蜜鸟通过红色的喙和缺乏白色髭纹区分开，与雌鸟榕鸟通过红色的喙区别，与橄榄背鹂通过对比鲜明的暗头部外观和下体较暗淡的颜色加以区分。","protection":"IUCN：LC（无危）。在部分分布区内常见，估计分布范围约为100,000至1,000,000平方公里。低地雨林密度估计为每公顷0.4只个体，沿海草原为每公顷0.07只个体。","distribution":"澳新界：四王群岛（西北部，新几内亚）和新几内亚（Trans-Fly除外）。分布在新几内亚的低地和较低的山区，包括森林、红树林、种植园和灌木丛。"},{"name":"暗褐鹂","english_name":"Dusky-brown Oriole","scientific_name":"Oriolus phaeochromus","overview":"暗褐鹂（英文名：Dusky-brown Oriole，学名：Oriolus phaeochromus），是雀形目黄鹂科黄鹂属的鸟类。中等体型的黄鹂科黄鹂属鸟类，全身呈均匀的土褐色，外观不起眼。在北摩鹿加群岛的哈马黑拉岛（Halmahera）上发现，主要栖息于低地至海拔1200米的原始森林和成熟次生林中，也可见于农耕区。其别称包括暗色黄鹂、格雷黄鹂、哈马黑拉黄鹂和摩鹿加黄鹂。","appearance":"暗褐鹂长约26厘米，全身羽毛为单调的深褐色，前脸、胸部至颈侧稍显灰淡，飞羽和尾部同样保持暗褐色调，初级飞羽边缘呈淡棕色。虹膜深褐色，喙和腿黑色。性别间无明显差异，幼鸟特征未详述。","call":"发出一种清脆、略带力度的两音节哨声，持续约0.75秒，首两个音节几乎不可闻，最后一音‘kweeow’响亮有力，间隔约8秒重复。","habits":"暗褐鹂通常在森林中层到树冠活动，独自或成对觅食，有时加入混合物种群。以昆虫和其他小型节肢动物及小果实为食，生活方式被认为是定居型。","breeding":"关于繁殖的信息极为有限，仅知成年鸟在11月被观察到喂养雏鸟。","identification":"与暗吮蜜鸟极为相似，但在视觉上更一致，头部无条纹或淡色标记，这有助于区分两者。","protection":"IUCN：LC（无危）；暗褐鹂是北方摩鹿加群岛特有种，常见于部分地区的森林，约20,000至50,000平方公里范围内。阿凯塔瓦洛洛巴塔国家公园（Aketajawe-Lolobata National Park）覆盖了具有极高生物多样性价值的山地和低地雨林，但森林仍面临伐木和农业开发威胁。","distribution":"主要分布于北摩鹿加群岛的哈马黑拉岛，属于澳新界的地理范围。"},{"name":"灰领鹂","english_name":"Grey-collared Oriole","scientific_name":"Oriolus forsteni","overview":"灰领鹂（英文名：Grey-collared Oriole，学名：Oriolus forsteni），是雀形目黄鹂科黄鹂属的鸟类。体型略小、颜色较为暗淡的黄鹂科鸟类，仅见于印尼摩鹿加群岛中的Seram岛。其最显著的特征是颈部有一圈灰色的项圈，整体羽毛呈橄榄褐色。","appearance":"灰领鹂身长约31厘米，体重介于105至113克之间。上体橄榄褐色，头部较浅色并带有深色条纹，与较深的橄榄色背部由灰色颈环明显分隔。脸部侧面为更深的灰棕色，眼周有灰色裸皮。翅膀深橄榄色，初级飞羽边缘绿黄色。尾巴深橄榄褐色，底面更浅，内侧羽尖更浅。下颌和喉部灰绿色，带深色条纹；胸部温暖金橄榄色，斑驳深色，逐渐过渡到较淡的土黄色腹部和臀部。虹膜浅棕色至红棕色，喙黑色，腿黑褐色。两性相似，幼鸟特征未详述。","call":"灰领鹂发出笛声般的叫声，先是连续的轻柔音符，随后是一个爆炸性的音符，形成\"p’p’p’p’POW!\"的叫声。","habits":"灰领鹂栖息于低地至海拔1100米的山地原始森林，偏好低海拔地带。它们通常单独或成对活动，从林中层到树冠层觅食，有时加入混合物种群。其食物主要包括昆虫和一些肉质红色果实及其种子。","identification":"灰领鹂与灰颈吮蜜鸟极为相似，很难在野外区分。灰领鹂稍小，眼睛周围没有裸露皮肤，头部形状更圆，前额更陡峭，喙更粗钝。","protection":"IUCN：LC（无危）。灰领鹂在其分布范围内分布广泛，覆盖面积达2万至5万平方公里，目前在Seram岛上森林覆盖率尚好，故暂无灭绝风险。Manusela国家公园保护了Seram岛约10%的土地面积，包括全部森林生态系统。","distribution":"灰领鹂仅分布于印尼摩鹿加群岛的Seram岛，即澳新界的印尼斯兰岛中东部。"},{"name":"黑耳鹂","english_name":"Black-eared Oriole","scientific_name":"Oriolus bouroensis","overview":"黑耳鹂（英文名：Black-eared Oriole，学名：Oriolus bouroensis），是雀形目黄鹂科黄鹂属的鸟类。原描述在Philemon属内。主要分布在印尼的布鲁岛，栖息于低地和山地森林、次生林、被砍伐的森林、落叶季雨林、次生林地、红树林和轻度林木覆盖的农耕区。","appearance":"大型灰棕色黄鹂，拥有直而粗重的喙。显著特征为脸部模糊的深色面罩。下部比上部颜色浅。幼鸟翅膀边缘呈锈红色。成鸟面部有黑色至棕褐色斑块，眼上有一条淡白色至棕褐色的眉纹，耳羽后方的颈侧白色；上身暗棕色，包括翅膀和尾巴，头顶有较深的条纹，尾羽末端有较淡的斑点（几乎不可见）；下身颜色更浅，下巴和喉咙白色带深色条纹，胸部和其余下部纯淡橄榄褐色；虹膜红棕色；喙黑色；腿黑色，脚趾铅灰色。雌雄相似。幼鸟翼羽有锈色边缘。","call":"模仿黑脸吮蜜鸟的叫声，一系列三个响亮的上升笛音，例如“p’po’eee”，持续约0.6秒。","habits":"通常单独或成对在中层树冠活动，常与黑脸吮蜜鸟一起。活动范围从海平面到海拔1460米。","breeding":"关于繁殖细节尚无信息。","identification":"与黑脸吮蜜鸟极为相似，通过略小的体型、更直的喙和脸部无裸露皮肤来区分。","protection":"IUCN：LC（无危）","distribution":"澳新界：印尼布鲁岛（印尼摩鹿加群岛中西部）。主要栖息地为低地和山地原生森林、次生林和被砍伐的森林。","other":"直到2008年，褐耳鹂曾被归类为黑耳鹂的一个亚种，但这一分类已被一些权威机构认可为独立物种。"}];
